insert into platform_topic_master (subject_slug, topic_slug, page_name, sections)
values
('sport-studies', '1-1-user-groups', '1.1 User Groups', '{"learn": {"enabled": true, "items": [{"title": "What a ''user group'' is — and why it matters", "html": "<h4>The idea</h4>\n<ul>\n<li>A <strong>user group</strong> is a category of people who share a characteristic that affects <strong>whether, why and how</strong> they take part in sport.</li>\n<li>Examples of characteristics used to sort people into groups include their age, their gender, whether they have a disability, their family situation and whether they are in work.</li>\n</ul>\n<h4>Why anyone bothers grouping people</h4>\n<ul>\n<li>Leisure centres, clubs, councils and national governing bodies want <strong>more people to take part</strong>. To do that, they have to understand who is <em>not</em> taking part and why.</li>\n<li>The key point the exam keeps testing: <strong>different user groups can have different needs, goals and requirements.</strong> A session that suits one group may put another off completely.</li>\n<li>So a provider thinks about each group separately — its timing, price, activities and facilities — instead of assuming one offer fits everyone.</li>\n</ul>", "check": {"question": "Which of these is the best description of a ''user group''?", "options": ["A category of people who share a feature affecting how they take part in sport", "A group of dedicated fans who follow the same professional team to every home and away match", "The panel of officials a governing body uses to referee a competition", "A single fitness class that is open only to complete beginners"], "answer": 0, "explain": "A user group is a category of people (such as teenagers or carers) who share a characteristic affecting their participation — not fans, officials, or one particular class."}}, {"title": "The user groups you need to know", "html": "<p>The specification groups participants by shared characteristics. It helps to sort them into four themes, and to remember <strong>what each group typically needs</strong>.</p>\n<h4>By life stage</h4>\n<ul>\n<li><strong>Young children</strong> (birth to the end of primary school) — need safe, supervised, play-based activity.</li>\n<li><strong>Teenagers</strong> (secondary school age) — often want sociable, low-cost and flexible activities that fit around school.</li>\n<li><strong>Retired people / people over 60</strong> — often prefer low-impact, sociable activities that suit a range of fitness levels.</li>\n</ul>\n<h4>By family role</h4>\n<ul>\n<li><strong>Families with children</strong> and <strong>parents</strong> (single or couples) — need family-friendly timing and activities they can do together.</li>\n<li><strong>People with family commitments</strong> and <strong>carers</strong> (looking after relatives, the elderly, or siblings) — need flexible timings and sometimes childcare so they can attend at all.</li>\n</ul>\n<h4>By work situation</h4>\n<ul>\n<li><strong>People who work</strong> — usually need early-morning, evening or weekend sessions.</li>\n<li><strong>Unemployed / economically disadvantaged people</strong> — often need free or reduced-price sessions.</li>\n</ul>\n<h4>By identity</h4>\n<ul>\n<li><strong>Gender</strong> — different genders can have different needs, goals and requirements from sport.</li>\n<li><strong>People from different ethnic groups</strong> — may have different cultural needs or preferences a provider should respect.</li>\n<li><strong>People with disabilities</strong> — need accessible facilities and inclusive coaching. This covers a <em>range</em> of disabilities, not only wheelchair users.</li>\n</ul>", "check": {"question": "The specification says ''people with disabilities'' as a user group should be understood to include...", "options": ["only people who use a wheelchair", "only people who have a visible, physical disability of some kind", "a range of disabilities, not just physical ones", "only people who cannot take part in any sport"], "answer": 2, "explain": "The group covers a range of disabilities — physical, sensory and hidden — so providers must think more widely than wheelchair access alone."}}, {"title": "Different needs, goals and requirements — the exam skill", "html": "<h4>Naming a group is only the start</h4>\n<ul>\n<li>Weak answer: <em>\"A user group is teenagers.\"</em> That names a group but shows no understanding.</li>\n<li>Strong answer: <em>\"Teenagers are a user group who often need low-cost, sociable sessions after school, because they usually have little money and want to take part with friends.\"</em></li>\n<li>The mark almost always comes from <strong>linking the group to what it needs, and why</strong> — not from the name on its own.</li>\n</ul>\n<h4>How needs differ — quick examples</h4>\n<ul>\n<li>A <strong>working parent</strong> may need a crèche and evening classes; a <strong>teenager</strong> may need a cheap after-school club; an <strong>over-60</strong> may need a gentle, sociable session.</li>\n<li>The same activity, at the same time and price, would suit one of them and lose the other two.</li>\n</ul>\n<h4>People belong to more than one group</h4>\n<ul>\n<li>A person can sit in several groups at once — a <strong>working single parent</strong> who is also <strong>over 60</strong> — and their needs stack up.</li>\n<li>People in the <em>same</em> group still differ: two 15-year-olds might want completely different things, one to compete and one to socialise.</li>\n</ul>", "check": {"question": "A question asks you to explain the needs of teenagers as a user group. What is most likely to earn the marks?", "options": ["Just writing the word ''teenagers''", "Saying what teenagers need from sport and why", "Listing every user group you can remember", "Describing your own favourite sport in detail"], "answer": 1, "explain": "Explain questions reward linking the group to a specific need and a reason — naming the group, or listing other groups, adds nothing."}}]}, "terms": {"enabled": true, "pairs": [{"term": "User group", "definition": "A category of people who share a feature affecting their participation in sport"}, {"term": "Young children", "definition": "Birth to end of primary; need safe, supervised, play-based activity"}, {"term": "Teenagers", "definition": "Secondary-school age; often want sociable, affordable, flexible activities"}, {"term": "Retired / over-60s", "definition": "Often prefer low-impact, sociable activities for mixed fitness levels"}, {"term": "Carers", "definition": "Look after a relative; need flexible times and sometimes childcare"}, {"term": "People with disabilities", "definition": "Need accessible facilities and inclusive coaching — not only wheelchair users"}, {"term": "People who work", "definition": "Job hours mean they need early-morning, evening or weekend sessions"}, {"term": "Economically disadvantaged", "definition": "Low income; often need free or reduced-price sessions"}]}, "mcq": {"enabled": true, "questions": [{"question": "What is meant by a ''user group'' in sport?", "options": ["A category of people who share a feature affecting whether and how they take part", "A crowd of supporters who follow the same professional team to matches every single week", "The officials a national governing body trains to referee competitive fixtures", "A fitness class that is aimed only at complete beginners"], "answer": 0, "explain": "A user group is a category of people — such as teenagers, carers or over-60s — who share a characteristic that affects their participation. Fans, officials and a single class are not user groups."}, {"question": "Which of these is a user group named in the specification?", "options": ["People who have watched at least one live sporting fixture in a stadium this year", "People who own the most expensive branded sports equipment on the market", "People with family commitments", "People who have represented their country at an international competition"], "answer": 2, "explain": "''People with family commitments'' is one of the named groups. Watching live sport, owning expensive gear, or playing for your country are not the groups the specification lists."}, {"question": "A carer looks after an elderly relative. What do they most need in order to take part in sport?", "options": ["A guarantee that they will win every competition they choose to enter at the centre", "Flexible session times, and sometimes support with caring, so they can attend", "Only the most advanced elite coaching that is available in the region", "A private facility that no other user group is ever allowed to enter"], "answer": 1, "explain": "Carers are often short of free time, so flexible timing and help with their caring role are what let them take part — not guaranteed wins, elite coaching or a private venue."}, {"question": "Two people are both 15 but want different things from sport — one to compete, one to socialise. This best shows that...", "options": ["teenagers are not really a user group at all", "everyone who belongs to the same user group always wants precisely the same thing from sport", "user groups should be banned from all leisure centres", "even within one user group, people can still have different needs and goals"], "answer": 3, "explain": "People in the same group still differ, which is why ''name the group'' is never enough — you have to think about the individual''s needs."}, {"question": "Which group is most likely to need free or reduced-price sessions to take part?", "options": ["People who work full-time in very highly paid professional careers", "Unemployed or economically disadvantaged people", "People who already own a fully equipped private gym at home", "Performers who receive large amounts of commercial sponsorship money"], "answer": 1, "explain": "Cost is the main barrier for economically disadvantaged people, so free or reduced-price sessions help most. The other groups can already afford to take part."}, {"question": "A provider wants more disabled people to take part. Which change best fits that group''s needs?", "options": ["Removing all seating so that nobody is able to rest during a session", "Making every activity far more physically demanding than it was before", "Adding accessible facilities and inclusive, well-trained coaching", "Only running sessions in venues reached by a long flight of stairs"], "answer": 2, "explain": "Accessible facilities and inclusive coaching remove real barriers for a range of disabilities. Removing seating, raising the difficulty, or using stairs-only venues would each shut people out."}]}, "fib": {"enabled": true, "questions": [{"text": "A user group is a [category] of people who share characteristics that affect their participation."}, {"text": "Providers study user groups because each one can have different needs, [goals] and requirements."}, {"text": "Retired people and the over-60s often prefer [low]-impact activities that are also sociable."}, {"text": "A carer may need [flexible] session times so they can fit sport around looking after a relative."}, {"text": "Unemployed or economically [disadvantaged] people often need free or reduced-price sessions."}, {"text": "People with [disabilities] may need accessible facilities and inclusive coaching to take part."}]}, "tf": {"enabled": true, "questions": [{"statement": "A user group is a category of people who share a characteristic that affects their participation in sport.", "answer": true, "explain": "That''s the definition — the shared feature (age, work, disability, family role and so on) is what shapes how and whether they take part."}, {"statement": "Naming a user group means the same thing as naming a barrier to participation.", "answer": false, "explain": "A user group is WHO takes part (a category of people). A barrier is WHAT stops participation (like cost or transport). They are different ideas."}, {"statement": "Everyone who belongs to the same user group wants exactly the same thing from sport.", "answer": false, "explain": "People in the same group still differ — two teenagers might want completely different things, so you cannot treat a whole group as identical."}, {"statement": "''People with disabilities'' as a user group refers only to wheelchair users.", "answer": false, "explain": "It covers a range of disabilities — physical, sensory and hidden — so providers must think far more widely than wheelchair access."}, {"statement": "People who work often need early-morning, evening or weekend sessions.", "answer": true, "explain": "Their job hours usually block the daytime, so sessions outside working hours are what let them take part."}, {"statement": "The best way to help economically disadvantaged people take part is to raise prices.", "answer": false, "explain": "Cost is their main barrier, so raising prices makes things worse — free or reduced-price sessions are what help this group."}]}, "misc": {"enabled": true, "items": [{"myth": "To answer a question on user groups, I just need to name some groups, like ''teenagers'' or ''carers''.", "truth": "Naming is only the first mark at most. The examiner is looking for you to link the group to what it NEEDS and WHY. Level 1 answer: \"A user group is teenagers.\" Full-marks answer: \"Teenagers are a user group who often need cheap, sociable sessions after school, because they usually have little money and want to take part with friends.\" The difference is the need and the reason.", "check": {"question": "An ''Explain'' question asks about the needs of one user group. What earns the marks?", "options": ["Naming as many different user groups as you possibly can", "Naming the group, then its need and a reason", "Writing the group''s name in bold", "Describing your own weekend sport"], "answer": 1, "explain": "Explain = point + reason. Naming the group alone, or listing lots of groups, does not show the understanding the mark scheme rewards."}}, {"myth": "A ''user group'' and a ''barrier'' are basically the same thing.", "truth": "They are two different ideas that the exam keeps side by side. A user group is a category of PEOPLE (who might take part). A barrier is something that STOPS people taking part (cost, transport, lack of provision). A question can ask you to link them — ''what barrier affects this group?'' — but they are not the same word.", "check": {"question": "Which of these is a user group, not a barrier?", "options": ["Lack of transport", "Retired people and the over-60s", "A lack of any disposable income to spend", "No local facilities"], "answer": 1, "explain": "Retired people/over-60s are a category of people — a user group. Transport, income and facilities are barriers that could stop a group taking part."}}, {"myth": "Everyone in a user group is the same, and a person can only ever be in one group.", "truth": "Both halves are wrong. People in the same group differ (two 15-year-olds can want very different things). And a person belongs to several groups at once — a working single parent who is also over 60 sits in three groups, and their needs add up. Good answers notice this overlap.", "check": {"question": "A working single parent who is also over 60 shows that...", "options": ["user groups never overlap", "a person can belong to several user groups at once", "only one single group is ever allowed to use a centre at any one time", "over-60s cannot have jobs"], "answer": 1, "explain": "People sit in several groups at once, and their needs stack up — which is exactly why providers plan around real individuals, not just labels."}}, {"myth": "''Gender'' as a user group must mean it is only about women''s sport.", "truth": "''Gender'' as a user group simply means that different genders can have different needs, goals and requirements from sport — it applies to everyone, not only women. For example, a provider might notice that one gender is under-represented in a particular activity and adjust how it promotes or runs it.", "check": {"question": "What does ''gender'' as a user group actually mean?", "options": ["Sport is only for one gender", "Different genders can have different needs and goals", "Gender has absolutely no effect on how people take part in sport", "Only women count as a user group"], "answer": 1, "explain": "It is about recognising that needs and goals can differ by gender — for all genders — so provision can be adjusted to widen participation."}}]}, "tips": {"enabled": true, "items": [{"title": "Command words for this topic — what each one wants", "html": "<p>User-group questions are usually short. Match your answer length to the command word:</p>\n<ul>\n<li><strong>Identify / State</strong> — just name it. \"Identify two user groups\" = write two group names, nothing more. 1 mark each.</li>\n<li><strong>Describe</strong> — say what it is or what it is like. \"Describe the needs of one user group\" = give the features of those needs.</li>\n<li><strong>Explain</strong> — give a reason. Use the word <em>because</em>. \"Explain why teenagers may not take part\" = a barrier <em>plus</em> why it stops them.</li>\n</ul>\n<p><strong>Read the mark tariff:</strong> [1] wants one point; [2] usually wants two points, or one point developed; [4] in Section B wants points applied to the scenario.</p>", "check": {"question": "A question says: ''Identify two user groups [2]''. What is the safest answer?", "options": ["A long paragraph about one group", "Two user group names", "One group name explained in detail", "A list of six groups"], "answer": 1, "explain": "''Identify'' + [2] = two names, one mark each. Explaining one group, or listing six, wastes time and risks the examiner marking only the first two anyway."}}, {"title": "The golden rule: name the group AND its need", "html": "<p>The single most common way to lose marks here is stopping at the name. Build every answer as <strong>group → need → reason</strong>:</p>\n<ul>\n<li><strong>❌ 0–1 marks:</strong> \"Carers.\"</li>\n<li><strong>✅ full marks:</strong> \"Carers need flexible session times, because they have to fit sport around looking after a relative.\"</li>\n</ul>\n<p>In <strong>Section B</strong> the question gives you a scenario (a named leisure centre, a named person). Then you must use a detail <em>from that scenario</em>, not a general example.</p>", "check": {"question": "In a Section B scenario question about a named leisure centre, your example should come from...", "options": ["absolutely any sport that you happen to like", "the scenario you are given", "a famous athlete", "your own school only"], "answer": 1, "explain": "Section B is applied — the marks are for using the scenario in front of you. A general example that ignores the scenario is capped."}}, {"title": "Where user groups appear + sentence starters", "html": "<p><strong>Where it shows up:</strong> user groups appear as quick recall in <strong>Section A</strong> (identify/state), and as applied points in <strong>Section B</strong> scenarios about increasing participation. They also feed <strong>Section C</strong> 8-mark answers about how a provider could get more people taking part.</p>\n<p><strong>Three punchy tips:</strong></p>\n<ul>\n<li>Learn the groups in themes (life stage, family, work, identity) so you can always recall a few.</li>\n<li>For every group, memorise <em>one</em> typical need — that need is usually where the mark is.</li>\n<li>Watch for overlap: a person can be in several groups at once, which is a great evaluation point.</li>\n</ul>\n<p><strong>Sentence starters for a longer answer:</strong></p>\n<ul>\n<li>\"One user group affected here is… because…\"</li>\n<li>\"This group would need… so the centre could…\"</li>\n<li>\"However, the same change might not suit… because…\"</li>\n</ul>", "check": {"question": "Why is ''overlap'' between user groups a useful point in a longer answer?", "options": ["It fills space", "It shows one person can have several needs at once", "It means groups do not exist", "It completely replaces the need to give any examples at all"], "answer": 1, "explain": "Noticing that one person belongs to several groups (so their needs stack up) shows deeper understanding — the kind of point that lifts a Section C answer."}}]}, "exam": {"enabled": true, "questions": [{"question": "Identify <strong>two</strong> different user groups who take part in sport.", "marks": 2, "hint": "Just name two — pick from age, work, family or identity groups (for example teenagers, carers, over-60s, disabled people, working people).", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks (AO1)</h5>\n<p><strong>1 mark for each correct user group named, to a maximum of two. Accept any two different groups from the specification, including:</strong></p>\n<ul>\n<li>Gender / people of a particular gender</li>\n<li>People from different ethnic groups</li>\n<li>Retired people / people over 60</li>\n<li>Families with children / parents</li>\n<li>Carers / people with family commitments</li>\n<li>Young children</li>\n<li>Teenagers</li>\n<li>People with disabilities</li>\n<li>People who work</li>\n<li>Unemployed / economically disadvantaged people</li>\n</ul>\n<p>Do not credit the same group written twice.</p>\n</div>"}, {"question": "Which user group is most likely to need free or reduced-price sessions in order to take part?", "marks": 1, "hint": "Think about which group faces cost as its main barrier.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: B — Unemployed or economically disadvantaged people.</strong></p>\n<ul>\n<li>Cost is the main barrier for this group, so free or reduced-price sessions remove it.</li>\n<li>The other groups can already afford to take part, so price is not their key barrier.</li>\n</ul>\n</div>"}, {"question": "Explain how Meadowbank could meet the different needs of these <strong>two</strong> user groups.", "marks": 4, "hint": "Take each group in turn. Say what that group NEEDS, then a change the centre could make to meet it. Use details from the scenario (the daytime timing and the £8 price).", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (AO2: application)</h5>\n<p><strong>Up to 2 marks per user group: 1 for identifying a relevant need, 1 for a change that meets it using the scenario. Answers may include:</strong></p>\n<ul>\n<li><strong>Working parents of young children</strong> — need childcare and/or family-friendly timing (the 10am–3pm slot clashes with work). Meadowbank could run a crèche, or add early-morning, evening or weekend sessions.</li>\n<li><strong>Teenagers</strong> — need low cost and sociable, after-school timing (£8 is a lot for a teenager). Meadowbank could offer cheaper concession sessions after school that they can attend with friends.</li>\n</ul>\n<p>Accept any other reasonable, applied answer. A need with no change, or a change not linked to the scenario, earns 1 of the 2 marks for that group.</p>\n</div>"}, {"question": "Discuss how a leisure centre like Meadowbank could use its understanding of different user groups to increase overall participation.", "marks": 8, "hint": "Choose two or three user groups. For each, explain the need and the change that meets it. Then weigh it up — what are the limits or costs of doing this? Finish with a judgement on how much it would really help.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 8 marks (level-of-response). Read the band you fit, then pick a mark.</h5>\n<ul>\n<li><strong>Band 3 (thorough), 6–8:</strong> a balanced, well-applied discussion of several user groups, showing clearly how meeting their needs would raise participation AND weighing the limits (cost, staffing, one change not suiting every group), ending in a justified judgement.</li>\n<li><strong>Band 2 (reasonable), 3–5:</strong> sound understanding applied to more than one group with some analysis, but the discussion may be one-sided or the judgement unsupported.</li>\n<li><strong>Band 1 (basic), 1–2:</strong> names groups and/or needs with little application and no real evaluation; largely a list.</li>\n<li><strong>0 marks:</strong> nothing creditworthy.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Indicative content (indicative, not a checklist — reward valid alternatives)</h5>\n<ul>\n<li><strong>Older residents / over-60s:</strong> low-impact, sociable sessions in the quiet daytime hours could bring in a group with free time during the day.</li>\n<li><strong>People in low-paid work / economically disadvantaged:</strong> concession pricing or free taster sessions removes cost as a barrier.</li>\n<li><strong>Working parents / families:</strong> a crèche and evening/weekend family sessions open up times they can actually attend.</li>\n<li><strong>Teenagers:</strong> cheap, sociable after-school clubs.</li>\n<li><strong>Evaluation:</strong> understanding groups only helps if the centre can afford the changes (staff, a crèche, lower prices cut income); one change can suit one group but clash with another (a busy family session may put off over-60s wanting calm); the biggest gains may come from targeting the largest under-served group first.</li>\n<li><strong>Judgement:</strong> understanding user groups is powerful because it lets the centre remove the <em>specific</em> barrier each group faces — but it increases participation only if the centre can resource the changes and accepts it cannot perfectly suit everyone at once.</li>\n</ul>\n</div>"}]}}'::jsonb),
('sport-studies', '1-2-barriers-to-participation', '1.2 Barriers to Participation', '{"learn": {"enabled": true, "items": [{"title": "What a ''barrier'' is — and why it''s not the same as a user group", "html": "<h4>The idea</h4>\n<ul>\n<li>A <strong>barrier</strong> is anything that stops or discourages someone from taking part in sport — a practical, personal or social obstacle in their way.</li>\n<li>This is a different idea from a <strong>user group</strong>, which you met in 1.1. A user group is <em>WHO</em> might take part (such as teenagers or carers). A barrier is <em>WHAT</em> stops them.</li>\n</ul>\n<h4>The exam skill: link the barrier to a group, and explain why</h4>\n<ul>\n<li>Weak answer: <em>\"A barrier is lack of transport.\"</em> That names a barrier but shows no understanding.</li>\n<li>Strong answer: <em>\"Lack of transport is a barrier that particularly affects people without a car, such as some carers, because they cannot physically reach a leisure centre that is far from public transport routes.\"</em></li>\n<li>The mark almost always comes from <strong>naming the barrier, saying who it affects most, and explaining why</strong> — not from the name on its own.</li>\n</ul>\n<h4>One barrier can affect several groups</h4>\n<ul>\n<li>A barrier is rarely limited to one group. Lack of disposable income can affect unemployed people, some carers and some teenagers all at once — but the exam still rewards a clear, well-explained link to one named group.</li>\n</ul>", "check": {"question": "Which of these best explains the difference between a ''user group'' and a ''barrier''?", "options": ["A user group is a category of people; a barrier is something that stops or discourages them from taking part", "They are two different names for exactly the same idea, so either word can always be used instead of the other", "A barrier is a category of people, and a user group is what stops them taking part in sport", "A user group only ever refers to teenagers, while a barrier only ever refers to cost"], "answer": 0, "explain": "A user group is WHO might take part; a barrier is WHAT stops them. They are related, but they are not interchangeable words, and ''barrier'' is not limited to cost."}}, {"title": "Barriers of money, time and getting there", "html": "<p>Several of the most commonly tested barriers come down to <strong>having enough money, enough free time, or a way to get there</strong>.</p>\n<h4>Work and money</h4>\n<ul>\n<li><strong>Employment</strong> — people in work can face long or awkward hours (shifts, evenings, weekends) that clash with the times sessions run.</li>\n<li><strong>Unemployment</strong> — people without a job often have very little spare money, so cost becomes the barrier instead of time.</li>\n<li><strong>Lack of disposable income</strong> — even people in work may not have money left over for the cost of kit, a membership fee and the travel to get there. All three add up.</li>\n</ul>\n<h4>Time and family</h4>\n<ul>\n<li><strong>Family commitments</strong> and <strong>being a carer</strong> — looking after children or a relative leaves little free time to take part, and sessions rarely fit around caring duties.</li>\n</ul>\n<h4>Getting there</h4>\n<ul>\n<li><strong>Lack of transport</strong> — even a great, affordable session is no use if someone cannot physically reach the venue, especially in areas with poor public transport.</li>\n</ul>", "check": {"question": "A person works irregular evening shifts and says they can never get to a 6pm class. Which barrier is this?", "options": ["Lack of transport", "Employment (long or awkward working hours)", "Lack of positive family role models", "Unequal media coverage of the sport they want to play"], "answer": 1, "explain": "Their working hours, not transport, role models or media coverage, are what clash with the session time — this is the employment barrier."}}, {"title": "Barriers of role models, provision and awareness", "html": "<h4>Role models</h4>\n<ul>\n<li><strong>Lack of positive sporting role models</strong> — without visible people to admire or copy in a sport, it can feel like \"not for someone like me\", which lowers the urge to try it.</li>\n<li><strong>Lack of positive family role models or family support</strong> — if the adults around someone never took part in sport or actively discourage it, a young person gets far less encouragement to start.</li>\n</ul>\n<h4>Provision</h4>\n<ul>\n<li><strong>Lack of appropriate activity provision</strong> — sometimes there is simply no suitable session, club or facility near enough to someone, for their age, ability or interest.</li>\n<li><strong>Lack of awareness of appropriate provision</strong> — this is a different problem: the session or facility already exists locally, but the person has never heard about it, so it might as well not exist for them.</li>\n</ul>\n<h4>Why the exam separates these two \"provision\" barriers</h4>\n<ul>\n<li>Examiners reward you for spotting the difference: one is \"it isn''t there\", the other is \"it''s there, but nobody told them\". A good promotion campaign fixes the second even when nothing new has been built.</li>\n</ul>", "check": {"question": "A leisure centre already runs a low-cost beginners'' swimming class, but almost nobody local knows it exists. Which barrier is this?", "options": ["Lack of positive sporting role models", "Lack of transport to the leisure centre", "Lack of awareness of appropriate provision", "Lack of appropriate activity provision for this specific age group"], "answer": 2, "explain": "The session already exists — the problem is that people don''t know about it. That is awareness of provision, not a missing session, transport or role models."}}, {"title": "Media coverage — and the exam skill in action", "html": "<h4>Unequal media coverage</h4>\n<ul>\n<li>Some sports, genders and ethnic groups get far less media coverage than others. Less coverage means <strong>fewer visible role models</strong> to inspire people, and sometimes lazy stereotyping about who \"should\" play a sport.</li>\n<li>This is a barrier because it works on people''s <em>attitudes</em> before they even reach a leisure centre — if you rarely see people like you competing on TV, it can feel like the sport isn''t meant for you.</li>\n<li>Unequal coverage by <strong>gender</strong> and by <strong>ethnicity</strong> are both named in the specification, and both work the same way: less visibility, fewer role models, lower participation.</li>\n</ul>\n<h4>Worked example of the exam skill</h4>\n<ul>\n<li><strong>Barrier:</strong> unequal media coverage by gender.</li>\n<li><strong>Group it affects:</strong> girls and women taking up a sport that is rarely shown on TV.</li>\n<li><strong>Why:</strong> with few elite women visible in that sport, girls have fewer role models to copy and may not realise the pathway exists — so fewer take it up.</li>\n</ul>\n<h4>Putting it all together</h4>\n<ul>\n<li>Whatever barrier you are asked about, the strongest answers always finish the sentence: \"...which stops or discourages [named group], because [reason].\"</li>\n</ul>", "check": {"question": "Why does unequal media coverage by gender or ethnicity reduce participation?", "options": ["It gives fewer visible role models and can reinforce stereotypes about who plays a sport", "It has no real effect at all on whether people choose to take part in a sport", "It always makes tickets for live matches more expensive to buy", "It only affects people who already play sport at a professional, elite level, not anyone starting out"], "answer": 0, "explain": "Fewer visible role models and reinforced stereotypes lower participation before someone even tries a sport — it is not really about ticket prices, and it affects beginners, not only elite performers."}}]}, "terms": {"enabled": true, "pairs": [{"term": "Barrier to participation", "definition": "Anything that stops or discourages someone from taking part in sport"}, {"term": "Employment", "definition": "Long or awkward working hours that can clash with sessions"}, {"term": "Unemployment", "definition": "Very little spare money because a person is without a job"}, {"term": "Family commitments / being a carer", "definition": "Looking after children or a relative, leaving little free time"}, {"term": "Lack of disposable income", "definition": "No spare money for kit, membership and travel"}, {"term": "Lack of transport", "definition": "No practical way to physically reach a venue"}, {"term": "Lack of role models (sporting or family)", "definition": "Nobody visible to admire, copy or encourage them"}, {"term": "Lack of awareness of provision", "definition": "Not knowing a suitable local session already exists"}]}, "mcq": {"enabled": true, "questions": [{"question": "What is meant by a ''barrier to participation''?", "options": ["A category of people who share a feature affecting their participation in sport", "Something that stops or discourages someone from taking part in sport", "A national governing body''s official list of registered members", "The score a team needs to reach to qualify for a major competition"], "answer": 1, "explain": "A barrier stops or discourages participation. Option A is actually the definition of a user group, not a barrier — a common mix-up."}, {"question": "A single parent works full-time and says they simply have no spare time to attend evening sessions. Which barrier does this best show?", "options": ["Lack of transport", "Lack of disposable income", "Family commitments and being a carer, combined with employment", "Unequal media coverage of the specific sport this parent would like to try"], "answer": 2, "explain": "Caring for children alongside a full-time job leaves no free time — this is family commitments and employment together, not transport, income or media coverage."}, {"question": "Which pair correctly matches a barrier with the specific problem it describes?", "options": ["Lack of awareness of provision — a suitable club exists locally but people do not know about it", "Lack of appropriate provision — a suitable club exists locally and is well advertised to everyone", "Lack of transport — a person owns a car but simply prefers to walk to their local gym", "Lack of disposable income — a person has plenty of money but simply dislikes exercising"], "answer": 0, "explain": "Awareness of provision is exactly this: the session exists, but people don''t know. B describes the opposite (good provision, well advertised), and C/D describe personal choice, not a barrier."}, {"question": "Which of these is most likely to reduce participation by removing visible role models for a group?", "options": ["Lack of transport links to the leisure centre", "Unequal media coverage by gender or ethnicity", "A short-term rise in the price of replica kit for one single season only", "A minor change to a competition''s kick-off time"], "answer": 1, "explain": "Unequal media coverage directly reduces how visible role models are for a group. Transport, kit prices and kick-off times are barriers, but they don''t remove role models."}, {"question": "Someone knows a low-cost, beginner-friendly class exists two streets from their house, but has never been able to attend because there is no bus route and they don''t drive. Which barrier is most directly shown here?", "options": ["Lack of awareness of appropriate provision", "Lack of positive sporting role models", "Lack of appropriate activity provision", "Lack of transport"], "answer": 3, "explain": "They already know the class exists and it''s suitable — the problem is physically getting there, which is lack of transport, not awareness or role models."}, {"question": "A teenager says nobody in their family has ever really done sport, and nobody at home encourages them to try a new club. Which barrier does this describe?", "options": ["Lack of positive family role models or family support", "Lack of transport to any sports facility that is reasonably nearby", "Unequal media coverage of the sport in question", "Lack of disposable income to pay for equipment"], "answer": 0, "explain": "No sporting habit or encouragement at home is a lack of positive family role models/support — not transport, media coverage or cost, which aren''t mentioned here."}]}, "fib": {"enabled": true, "questions": [{"text": "A barrier to participation is anything that stops or [discourages] someone from taking part in sport."}, {"text": "People in work can face long or [awkward] hours that clash with when sessions run."}, {"text": "A lack of [disposable] income means there is no spare money for kit, membership or travel."}, {"text": "Even a great session is no use if someone cannot physically reach it because of a lack of [transport]."}, {"text": "Lack of [awareness] of appropriate provision means a session already exists locally, but people have never heard about it."}, {"text": "Unequal media [coverage] by gender or ethnicity means fewer visible role models for some groups."}]}, "tf": {"enabled": true, "questions": [{"statement": "A ''barrier'' and a ''user group'' mean exactly the same thing.", "answer": false, "explain": "A user group is WHO might take part. A barrier is WHAT stops or discourages them. They are related ideas but not the same thing."}, {"statement": "Lack of disposable income can include the added-up cost of kit, membership fees and travel.", "answer": true, "explain": "All three costs can combine, so someone in work can still be short of the spare money needed to take part."}, {"statement": "Lack of transport can only ever be a barrier for people who do not own a car.", "answer": false, "explain": "It can also affect car owners if the nearest suitable facility is too far, or if fuel and parking costs are too high — it''s about practically reaching the venue, not just car ownership."}, {"statement": "''Lack of appropriate provision'' and ''lack of awareness of provision'' describe exactly the same problem.", "answer": false, "explain": "One means no suitable session exists; the other means a suitable session exists but people don''t know about it. The exam rewards spotting the difference."}, {"statement": "Positive role models can come from within a person''s own family, not only from elite sport.", "answer": true, "explain": "A family member who takes part in and encourages sport is a positive role model too, just as much as a professional athlete can be."}, {"statement": "Unequal media coverage by gender or ethnicity can reduce participation by reducing the number of visible role models.", "answer": true, "explain": "Less coverage means fewer visible role models for that group, which can make a sport feel less ''for them'' before they even try it."}]}, "misc": {"enabled": true, "items": [{"myth": "To answer a barriers question, I just need to name a barrier, like ''lack of transport''.", "truth": "Naming is only the first mark at most. The examiner is looking for you to link the barrier to a GROUP it affects and WHY. Level 1 answer: \"A barrier is lack of transport.\" Full-marks answer: \"Lack of transport is a barrier for carers who don''t drive, because they cannot physically reach a leisure centre without a reliable bus route.\" The difference is the group and the reason.", "check": {"question": "An ''Explain'' question asks about a barrier to participation. What earns the marks?", "options": ["Naming as many different barriers as you possibly can, without explaining any of them", "Naming the barrier, then the group it affects and a reason", "Writing the barrier''s name in bold", "Describing your own weekend sport in detail"], "answer": 1, "explain": "Explain = point + reason, applied to a group. Naming the barrier alone, or listing several, does not show the understanding the mark scheme rewards."}}, {"myth": "A ''barrier'' and a ''user group'' are basically the same thing.", "truth": "They are two different ideas the exam keeps side by side. A user group is a category of PEOPLE (who might take part). A barrier is something that STOPS people taking part (cost, transport, lack of provision). A question can ask you to link them — ''which barrier affects this group?'' — but they are not the same word.", "check": {"question": "Which of these is a barrier, not a user group?", "options": ["Teenagers", "Lack of disposable income", "People with disabilities", "Retired people and the over-60s"], "answer": 1, "explain": "Lack of disposable income is something that stops participation — a barrier. The other three are categories of people — user groups."}}, {"myth": "''Lack of appropriate provision'' and ''lack of awareness of appropriate provision'' both just mean ''there''s no session''.", "truth": "They describe two different problems. Lack of appropriate provision means no suitable session or facility actually exists nearby. Lack of awareness of provision means a suitable session DOES exist, but the person has never heard about it — so, from their point of view, it might as well not exist. Fixing the first needs new provision; fixing the second just needs better promotion.", "check": {"question": "A council already runs a free wheelchair basketball session, but hardly anyone locally knows about it. Which barrier is shown?", "options": ["Lack of appropriate activity provision for that age or ability group", "Lack of awareness of appropriate provision", "Lack of positive sporting role models", "Lack of disposable income"], "answer": 1, "explain": "The session already exists — the problem is that people don''t know about it, which is lack of awareness, not a missing session, role models or cost."}}, {"myth": "Unequal media coverage as a barrier only really matters to people who want to become professional athletes.", "truth": "It affects far more than future professionals. Media coverage shapes whether ORDINARY people feel a sport is ''for them'' at all. If a group rarely sees people like themselves competing on TV, that can put someone off ever trying a beginner session — long before elite performance is anywhere in the picture.", "check": {"question": "Who can unequal media coverage put off from taking part in a sport?", "options": ["Only people who are already competing at a professional, elite level, and nobody else at all", "Beginners deciding whether to try a sport at all, not just elite performers", "Nobody — media coverage has no effect on participation", "Only people who already own a season ticket"], "answer": 1, "explain": "Fewer visible role models can put off a complete beginner from ever trying a sport — the effect starts long before anyone reaches elite level."}}]}, "tips": {"enabled": true, "items": [{"title": "Command words for this topic — what each one wants", "html": "<p>Barriers questions are usually short. Match your answer length to the command word:</p>\n<ul>\n<li><strong>Identify / State</strong> — just name it. \"Identify one barrier to participation [1]\" = write one barrier name, nothing more.</li>\n<li><strong>Describe</strong> — say what the barrier is or how it works. \"Describe a barrier facing unemployed people [2]\" = give the features of that barrier.</li>\n<li><strong>Explain</strong> — give a reason. Use the word <em>because</em>. \"Explain why lack of transport can stop someone taking part\" = the barrier <em>plus</em> why it stops them.</li>\n</ul>\n<p><strong>Read the mark tariff:</strong> [1] wants one point; [2] usually wants two points, or one point developed; [4] in Section B wants points applied to the scenario.</p>", "check": {"question": "A question says: ''Identify two barriers to participation [2]''. What is the safest answer?", "options": ["A long paragraph about one barrier", "Two barrier names", "One barrier name explained in detail", "A list of six barriers"], "answer": 1, "explain": "''Identify'' + [2] = two names, one mark each. Explaining one barrier, or listing six, wastes time and risks the examiner marking only the first two anyway."}}, {"title": "The golden rule: name the barrier, the group, AND why", "html": "<p>The single most common way to lose marks here is stopping at the name. Build every answer as <strong>barrier → group it affects → reason</strong>:</p>\n<ul>\n<li><strong>❌ 0–1 marks:</strong> \"Lack of transport.\"</li>\n<li><strong>✅ full marks:</strong> \"Lack of transport is a barrier for people without a car, because they cannot physically reach a leisure centre that isn''t on a bus route.\"</li>\n</ul>\n<p>In <strong>Section B</strong> the question gives you a scenario (a named place, a named person). Then you must use a detail <em>from that scenario</em>, not a general example.</p>", "check": {"question": "In a Section B scenario question about a named person facing a barrier, your explanation should come from...", "options": ["absolutely any barrier that you happen to remember", "the scenario you are given", "a famous athlete''s biography", "your own school only"], "answer": 1, "explain": "Section B is applied — the marks are for using the scenario in front of you. A general point that ignores the scenario is capped."}}, {"title": "Where barriers appear + sentence starters", "html": "<p><strong>Where it shows up:</strong> barriers appear as quick recall in <strong>Section A</strong> (identify/state/describe), and as applied points in <strong>Section B</strong> scenarios about a named person or centre. They also feed <strong>Section C</strong> 8-mark answers about how a provider could increase participation by tackling barriers.</p>\n<p><strong>Three punchy tips:</strong></p>\n<ul>\n<li>Learn the barriers in themes (money/time, getting there, role models, provision, media) so you can always recall a few.</li>\n<li>For every barrier, memorise <em>one</em> typical group it affects, and <em>why</em> — that reason is usually where the mark is.</li>\n<li>Never confuse \"lack of provision\" (nothing suitable exists) with \"lack of awareness of provision\" (it exists but nobody knows) — the exam tests the difference.</li>\n</ul>\n<p><strong>Sentence starters for a longer answer:</strong></p>\n<ul>\n<li>\"One barrier affecting this group is… because…\"</li>\n<li>\"This barrier stops them because… so the provider could…\"</li>\n<li>\"However, this change might not remove every barrier, because…\"</li>\n</ul>", "check": {"question": "Why is it useful to link a barrier to a specific reason it stops a group, rather than just naming it?", "options": ["It fills space in the answer", "It shows understanding of HOW and WHY participation is affected", "It means the barrier no longer applies", "It replaces the need to name any barrier at all, so nothing else is required"], "answer": 1, "explain": "Naming plus a reason shows real understanding of how the barrier works — the kind of point the mark scheme is built to reward."}}]}, "exam": {"enabled": true, "questions": [{"question": "Identify <strong>two</strong> different barriers that can stop people taking part in sport.", "marks": 2, "hint": "Just name two — pick from money/time, getting there, role models, provision or media coverage (for example lack of transport, lack of disposable income, unemployment).", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks (AO1)</h5>\n<p><strong>1 mark for each correct barrier named, to a maximum of two. Accept any two different barriers from the specification, including:</strong></p>\n<ul>\n<li>Employment (long/awkward hours)</li>\n<li>Unemployment</li>\n<li>Family commitments / being a carer</li>\n<li>Lack of disposable income</li>\n<li>Lack of transport</li>\n<li>Lack of positive sporting role models</li>\n<li>Lack of positive family role models / support</li>\n<li>Lack of appropriate activity provision</li>\n<li>Lack of awareness of appropriate provision</li>\n<li>Unequal media coverage (gender or ethnicity)</li>\n</ul>\n<p>Do not credit the same barrier written twice.</p>\n</div>"}, {"question": "Which barrier best describes someone who cannot afford membership fees, kit or travel costs?", "marks": 1, "hint": "Think about which barrier is about spare money overall, not any single cost on its own.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: B — Lack of disposable income.</strong></p>\n<ul>\n<li>Membership, kit and travel are all costs that add up — this is a lack of spare (disposable) income.</li>\n<li>The other options describe different barriers that are not about affording these specific costs.</li>\n</ul>\n</div>"}, {"question": "Explain <strong>two</strong> barriers to participation shown in this scenario, and how each one affects Aiden.", "marks": 4, "hint": "Take each barrier in turn. Say what the barrier is, then explain why it stops Aiden using a detail from the scenario (his shift times, or the bus times).", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (AO2: application)</h5>\n<p><strong>Up to 2 marks per barrier: 1 for identifying a relevant barrier, 1 for explaining it using the scenario. Answers may include:</strong></p>\n<ul>\n<li><strong>Employment (long/awkward hours)</strong> — Aiden''s shifts often finish at 9pm, which clashes with evening sessions at Riverside.</li>\n<li><strong>Lack of transport</strong> — Aiden does not drive, and the last bus home leaves at 7pm, so he cannot get home safely after a normal evening session.</li>\n</ul>\n<p>Accept any other reasonable, applied barrier (e.g. lack of disposable income if travel cost is discussed). A barrier with no explanation, or an explanation not linked to the scenario, earns 1 of the 2 marks for that barrier.</p>\n</div>"}, {"question": "Discuss how Riverside could reduce the barriers facing local people, in order to increase participation.", "marks": 8, "hint": "Choose two or three barriers shown in the scenario. For each, explain the barrier and a change that would reduce it. Then weigh it up — what are the limits or costs of doing this? Finish with a judgement on how much it would really help.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 8 marks (level-of-response). Read the band you fit, then pick a mark.</h5>\n<ul>\n<li><strong>Band 3 (thorough), 6–8:</strong> a balanced, well-applied discussion of several barriers, showing clearly how reducing them would raise participation AND weighing the limits (cost, one change not suiting every barrier, staffing), ending in a justified judgement.</li>\n<li><strong>Band 2 (reasonable), 3–5:</strong> sound understanding applied to more than one barrier with some analysis, but the discussion may be one-sided or the judgement unsupported.</li>\n<li><strong>Band 1 (basic), 1–2:</strong> names barriers and/or effects with little application and no real evaluation; largely a list.</li>\n<li><strong>0 marks:</strong> nothing creditworthy.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Indicative content (indicative, reward valid alternatives)</h5>\n<ul>\n<li><strong>Employment:</strong> the 10am–4pm timing clashes with shift workers'' hours, so adding early-morning, evening or weekend sessions would open up times they can attend.</li>\n<li><strong>Lack of disposable income:</strong> £6 a session adds up for low-income residents, so concession pricing or free taster sessions would remove cost as a barrier.</li>\n<li><strong>Lack of transport:</strong> families without a car may not reach the hub at all, so a shuttle bus or a satellite session at a closer, smaller venue would help.</li>\n<li><strong>Lack of awareness of provision:</strong> in-building posters only reach people who already visit, so advertising through local schools, workplaces or social media would reach people who don''t yet know Riverside exists.</li>\n<li><strong>Evaluation:</strong> reducing barriers only helps if the centre can resource the changes (a shuttle bus and lower prices both cost money); one change can suit one barrier but not another (evening sessions help shift workers but not people who still can''t get there); the biggest gains may come from tackling the barrier stopping the largest group first.</li>\n<li><strong>Judgement:</strong> understanding these barriers is powerful because it lets Riverside target the SPECIFIC obstacle each group faces — but it increases participation only if the hub can afford the changes and accepts that no single change removes every barrier at once.</li>\n</ul>\n</div>"}]}}'::jsonb),
('sport-studies', '1-3-solutions-to-barriers', '1.3 Solutions to Barriers', '{"learn": {"enabled": true, "items": [{"title": "Linking a solution to its barrier and its user group — the exam skill", "html": "<h4>Why ''just listing solutions'' fails</h4>\n<ul>\n<li>Every solution in this topic exists to remove a specific <strong>barrier</strong> (Topic 1.2) for a specific <strong>user group</strong> (Topic 1.1). A solution written on its own, with no barrier and no group named, earns little or nothing.</li>\n<li>Weak answer: <em>\"Leisure centres could run more taster sessions.\"</em> This names a solution but shows no understanding of what it actually fixes.</li>\n<li>Strong answer: <em>\"Free taster sessions remove the cost barrier facing unemployed people, letting them try an activity before committing any money.\"</em></li>\n</ul>\n<h4>Build every answer the same way</h4>\n<ul>\n<li>Step 1 — name the <strong>solution</strong>.</li>\n<li>Step 2 — say which <strong>barrier</strong> it removes.</li>\n<li>Step 3 — say which <strong>user group</strong> it helps, and why.</li>\n</ul>\n<p>This three-step shape is what most Section B marks in this topic actually reward — not the name of the solution by itself.</p>", "check": {"question": "Which of these shows the strongest understanding of a solution to a barrier?", "options": ["A description linking the solution to the specific barrier it removes and the group it helps", "A long list naming every single possible solution a leisure centre could ever possibly consider offering", "The name of one solution with nothing else added", "A description of a barrier with no solution mentioned at all"], "answer": 0, "explain": "Marks come from linking a solution to the specific barrier it removes and the group it helps — not from a long list, a bare name, or a barrier alone with no fix."}}, {"title": "Provision, promotion and transport", "html": "<h4>Provision — the right programme, at the right time</h4>\n<ul>\n<li><strong>Provision</strong> means offering appropriate programmes, sessions, activities and <strong>times</strong> aimed at a specific user group, rather than one timetable expected to suit everybody.</li>\n<li>Example: a crèche-supported morning class for parents; a low-impact, sociable daytime session for retired people; a cheap after-school club for teenagers.</li>\n</ul>\n<h4>Promotion — telling the right people, in the right way</h4>\n<ul>\n<li><strong>Targeted advertising and promotion</strong> reaches a specific group directly, instead of one generic advert aimed at nobody in particular.</li>\n<li>Using <strong>role models</strong> from a group (or connected to it) can make an activity feel like \"people like me do this\".</li>\n<li><strong>Initiatives and incentives</strong> — such as a free taster session — let a group try an activity with nothing to lose, which can remove the fear of an unfamiliar or costly commitment.</li>\n</ul>\n<h4>Transport — getting there in the first place</h4>\n<ul>\n<li>A brilliant session is no use if a group cannot reach the venue. <strong>Increased and appropriate transport</strong> (extra buses, a pick-up service, better links to public transport) removes this barrier directly.</li>\n</ul>", "check": {"question": "A leisure centre features a well-known local wheelchair basketball player in its adverts. This is mainly an example of...", "options": ["improved access to the building itself", "using a role model as a promotion strategy", "appropriate pricing for a user group", "increasing the transport available to the site"], "answer": 1, "explain": "Featuring a figure connected to a group in adverts is a promotion strategy (a role model), not a change to access, price or transport."}}, {"title": "Facilities, equipment and access", "html": "<h4>Appropriate facilities and equipment</h4>\n<ul>\n<li>Different user groups need different physical adjustments to take part safely and independently. Examples the specification highlights include:</li>\n<li><strong>Pool hoists</strong> — allow a person with limited mobility to enter and exit a swimming pool safely.</li>\n<li><strong>Hearing loops</strong> — let a person with a hearing impairment follow instructions or announcements clearly.</li>\n<li><strong>Braille or tactile signage</strong> — lets a person with a visual impairment navigate a building independently.</li>\n<li>These are examples for a <strong>range of disabilities</strong>, not only wheelchair users — the right piece of equipment should match the specific barrier a group actually faces.</li>\n</ul>\n<h4>Improved access</h4>\n<ul>\n<li><strong>Access</strong> is broader than one piece of equipment — it means the whole route into and around a facility (ramps, wide doorways, ground-floor changing rooms, clear paths) is usable by all user groups, not just the majority.</li>\n</ul>", "check": {"question": "A hearing loop fitted in a sports hall is a solution that mainly addresses...", "options": ["a transport barrier for people who live a very long way indeed from the venue", "a facilities and equipment barrier for people with a hearing impairment", "a pricing barrier for economically disadvantaged people", "a promotion barrier caused by a lack of advertising"], "answer": 1, "explain": "A hearing loop removes a specific facilities-and-equipment barrier — it does not change transport, price, or how the session is advertised."}}, {"title": "Pricing solutions", "html": "<h4>Appropriate pricing for all user groups</h4>\n<ul>\n<li>Cost is one of the most common barriers (Topic 1.2), so pricing is one of the most tested solutions.</li>\n<li><strong>Concessions</strong> — reduced prices for groups such as students, unemployed people or over-60s.</li>\n<li><strong>Free taster sessions</strong> — let a group try an activity before paying anything at all.</li>\n<li><strong>Free or reduced-price equipment</strong> — removes the barrier of needing to buy kit before you can even start.</li>\n</ul>\n<h4>Pricing must actually fit the group</h4>\n<ul>\n<li>A concession that is still too expensive for the group it targets fixes nothing. Good answers check that the pricing change realistically removes the cost barrier for that specific group.</li>\n</ul>", "check": {"question": "Which of these is the best example of an ''appropriate pricing'' solution?", "options": ["Raising every single price so that the centre simply earns more money overall", "Offering a free taster session so a group can try an activity before paying", "Removing the reception desk from the building entirely", "Running the same single advert on local radio for every group"], "answer": 1, "explain": "A free taster session removes the cost barrier before anyone commits money. Raising prices, removing reception, or a single generic advert are not pricing solutions at all."}}]}, "terms": {"enabled": true, "pairs": [{"term": "Provision", "definition": "Appropriate programmes, sessions, activities and times aimed at a specific user group"}, {"term": "Targeted promotion", "definition": "Advertising aimed directly at a particular user group, not a general audience"}, {"term": "Role model", "definition": "A person from or connected to a group whose example encourages that group to take part"}, {"term": "Taster session", "definition": "A free trial that lets a group try an activity before paying anything"}, {"term": "Transport solution", "definition": "Extra buses, pick-up services or better links that help a group reach a venue"}, {"term": "Accessible facilities/equipment", "definition": "Pool hoists, hearing loops, braille/tactile signage — matched to the barrier"}, {"term": "Improved access", "definition": "Ramps, wide doorways and clear paths that make a venue usable for all groups"}, {"term": "Concessionary pricing", "definition": "A reduced price aimed at a group such as students, over-60s or unemployed people"}]}, "mcq": {"enabled": true, "questions": [{"question": "A leisure centre currently only runs sessions during the working week daytime. Which change is the clearest example of the ''provision'' solution?", "options": ["Printing a brand new leaflet that only describes the sessions already running in the daytime", "Adding an evening or weekend session aimed at people who work in the daytime", "Charging slightly less money for the existing daytime sessions", "Employing an extra receptionist to answer the phone during the day"], "answer": 1, "explain": "Provision means changing WHAT is on offer — new sessions at new times. A new leaflet is promotion, a lower price is pricing, and extra reception staff changes neither the offer nor who can attend."}, {"question": "A local swimming club wants more teenage girls to join. Which action best uses a ''promotion'' solution?", "options": ["Fitting a hearing loop in the changing rooms for members with a hearing impairment", "Adding extra car-parking spaces outside the venue for visiting families", "Featuring a respected female swimmer from the local area in its adverts", "Building a wheelchair-accessible ramp at the main entrance"], "answer": 2, "explain": "Using a local role model in adverts targets the group directly — that''s promotion. Hearing loops, parking and ramps are facilities, transport and access changes, not promotion."}, {"question": "Several older residents say they would attend a gentle exercise class but have no way of reaching the venue. Which solution most directly removes this barrier?", "options": ["A free taster session with absolutely no charge at all for the very first visit", "A dedicated pick-up service or an extra bus route to the venue", "A louder advert broadcast on local commercial radio", "A slightly cheaper price for the same weekly class"], "answer": 1, "explain": "The barrier described is getting there, not cost or awareness — so a pick-up service or extra bus route is the solution that actually removes it."}, {"question": "A member with a visual impairment struggles to find their way around a large sports centre. Which solution addresses this specific barrier?", "options": ["Braille or tactile signage placed clearly around the building", "A free taster session offered to new visually impaired members", "An extra evening class added to the existing weekly timetable", "A reduced membership price for the first three months"], "answer": 0, "explain": "Braille or tactile signage lets a visually impaired person navigate independently. A taster session, a new class time, and a lower price do not solve a navigation barrier."}, {"question": "A centre has a step at the main entrance and narrow changing-room doorways. Which change best improves ''access'' for wheelchair users?", "options": ["Running more sessions later in the evening for working members", "Advertising the centre repeatedly using a well-known local wheelchair athlete", "Fitting a ramp at the entrance and widening the changing-room doorways", "Offering a discount for the first month of membership"], "answer": 2, "explain": "A ramp and wider doorways change the physical route into and around the building — that is access. The other options are provision, promotion and pricing instead."}, {"question": "Which of these answers best links a solution to both a barrier and a user group?", "options": ["Leisure centres should really try to offer more activities generally", "Free taster sessions remove the cost barrier for unemployed people, so they can try an activity first", "Free taster sessions are honestly thought to be a fantastic idea for absolutely every leisure centre in the entire country", "Cost is sometimes a problem for people who do not have very much money"], "answer": 1, "explain": "This option names the solution, the exact barrier (cost) and the exact group (unemployed people). The others are vague, generic, or name a barrier with no linked fix."}]}, "fib": {"enabled": true, "questions": [{"text": "Offering the right programmes, sessions and [times] for a specific user group is called provision."}, {"text": "Using a well-known figure connected to a user group in adverts is called using a [role] model."}, {"text": "A free [taster] session lets a group try an activity before paying anything at all."}, {"text": "Fitting a pool hoist or a hearing loop is an example of appropriate facilities and [equipment]."}, {"text": "Widening doorways and adding ramps around a venue is an example of improved [access]."}, {"text": "A reduced price aimed at a group such as students or over-60s is called a [concession]."}]}, "tf": {"enabled": true, "questions": [{"statement": "A solution only earns full marks in the exam when it is linked to a specific barrier and a specific user group.", "answer": true, "explain": "Naming a solution on its own rarely earns the marks — the mark scheme rewards the solution PLUS the barrier it removes PLUS the group it helps."}, {"statement": "Provision means advertising an activity, rather than changing its timing or sessions.", "answer": false, "explain": "Provision changes WHAT is on offer — new sessions, activities or times. Advertising an existing offer differently is promotion, a separate solution."}, {"statement": "A pool hoist is an example of appropriate facilities and equipment for some user groups.", "answer": true, "explain": "A pool hoist lets a person with limited mobility enter and exit a pool safely — a facilities-and-equipment solution matched to that barrier."}, {"statement": "Braille or tactile signage is only ever useful for wheelchair users.", "answer": false, "explain": "Braille and tactile signage help people with a visual impairment. ''People with disabilities'' covers a wide range, so the right solution must match the actual barrier."}, {"statement": "A free taster session is an example of an initiative that can help remove the cost barrier.", "answer": true, "explain": "A taster session lets a group try an activity before paying anything, which removes the fear of committing money to something unfamiliar."}, {"statement": "Improving access always means exactly the same thing as adding more car-parking spaces.", "answer": false, "explain": "Access covers the whole route into and around a venue — ramps, doorways, ground-floor changing rooms and clear paths — not only parking."}]}, "misc": {"enabled": true, "items": [{"myth": "If I just name a solution like ''more taster sessions'', that should get me the marks.", "truth": "Naming a solution alone rarely earns the marks. Weak answer: \"Centres could run more taster sessions.\" Full-marks answer: \"Free taster sessions remove the cost barrier facing unemployed people, letting them try an activity before paying anything.\" The mark is for the barrier AND the group, not the solution''s name by itself.", "check": {"question": "What is missing from the answer ''Centres could run more taster sessions''?", "options": ["Nothing — the answer is already complete", "The specific barrier it removes and the user group it helps", "A much longer list of other possible solutions that could be tried", "The exact price of the taster session"], "answer": 1, "explain": "The name of the solution alone shows no understanding — the marks need the barrier it removes and the group it helps attached to it."}}, {"myth": "Provision and promotion are basically the same thing — they''re both about getting more people to sessions.", "truth": "They are two different solutions. Provision changes WHAT is on offer (the sessions, times and activities themselves). Promotion changes whether people KNOW about it and want to attend (adverts, role models, incentives). A centre can have perfect provision that nobody has ever heard of, and perfect promotion for a timetable that suits nobody.", "check": {"question": "A centre adds a new Saturday morning class. This is an example of...", "options": ["promotion, because it might attract new members", "provision, because it changes what sessions are on offer", "pricing, because Saturday classes usually cost more", "transport, because it is generally easier to reach on a Saturday"], "answer": 1, "explain": "Adding a new session changes the offer itself — that is provision, not promotion, pricing or transport."}}, {"myth": "Facilities-and-equipment solutions like hearing loops or braille signage are only relevant to wheelchair users.", "truth": "These solutions target specific, different disabilities — a hearing loop helps a hearing impairment, braille/tactile signage helps a visual impairment, a pool hoist helps limited mobility. ''People with disabilities'' covers a wide range, so a strong answer picks the solution that matches the actual barrier, rather than defaulting to ''wheelchair access'' every time.", "check": {"question": "Which solution best matches a member who has a visual impairment?", "options": ["A much wider doorway added for wheelchair access", "Braille or tactile signage around the building", "A pool hoist for entering the water", "An extra evening session"], "answer": 1, "explain": "Braille/tactile signage matches a visual impairment specifically. The other options solve different barriers for different groups."}}, {"myth": "Any lower price automatically counts as an ''appropriate pricing'' solution.", "truth": "A price cut only works as a solution if it actually removes the barrier for that specific group. A concession that is still unaffordable for an unemployed person fixes nothing. Strong answers check the pricing change realistically matches the group''s real situation, not just that a number went down.", "check": {"question": "A centre lowers its price from £20 to £18 for unemployed members. Why might this NOT be an ''appropriate'' pricing solution?", "options": ["Because the price has changed at all", "Because £18 may still be unaffordable for this group", "Because the centre should never change any prices", "Because pricing solutions are never allowed in this topic"], "answer": 1, "explain": "A small reduction that is still unaffordable does not remove the real barrier — the change has to genuinely fit the group it targets."}}]}, "tips": {"enabled": true, "items": [{"title": "Command words and mark tariffs for this topic", "html": "<p>Solutions questions vary a lot in length. Match your answer to the command word:</p>\n<ul>\n<li><strong>Identify / State</strong> — just name a solution. \"Identify one solution to a transport barrier\" = one named idea, 1 mark.</li>\n<li><strong>Describe</strong> — say what the solution involves. \"Describe one way a centre could improve access\" = give the feature (e.g. a ramp, wider doorways).</li>\n<li><strong>Explain</strong> — give the reason, using the barrier AND the group. \"Explain how a centre could increase participation among carers\" = a solution <em>plus</em> the barrier it removes for that group.</li>\n</ul>\n<p><strong>Read the mark tariff:</strong> [1] wants one point; [2] usually wants two points, or one point developed with a reason; [4] in Section B wants points applied to the scenario, one barrier/group pair at a time.</p>", "check": {"question": "A question says: ''Identify one solution that could improve transport to a venue [1]''. What is the safest answer?", "options": ["A full explanation of every possible transport solution", "One named transport solution", "A description of a transport barrier instead", "A list of five different solutions"], "answer": 1, "explain": "''Identify'' + [1] = one named idea, nothing more. Explaining fully or listing five solutions wastes time for no extra marks."}}, {"title": "The golden rule: solution → barrier → group", "html": "<p>The single most common way to lose marks here is stopping at the solution''s name. Build every answer as <strong>solution → barrier it removes → group it helps</strong>:</p>\n<ul>\n<li><strong>❌ 0–1 marks:</strong> \"More taster sessions.\"</li>\n<li><strong>✅ full marks:</strong> \"Free taster sessions remove the cost barrier facing unemployed people, so they can try an activity before paying anything.\"</li>\n</ul>\n<p>In <strong>Section B</strong> the question gives you a scenario (a named centre, named groups). You must use a barrier and a group <em>from that scenario</em>, not a general example.</p>", "check": {"question": "In a Section B scenario about a named leisure centre, your solution should be linked to...", "options": ["absolutely any barrier you happen to remember", "the barrier and group given in the scenario", "a famous athlete you personally admire", "your own local gym only"], "answer": 1, "explain": "Section B is applied — the marks are for linking your solution to the specific barrier and group described in the scenario in front of you."}}, {"title": "Where solutions appear + sentence starters", "html": "<p><strong>Where it shows up:</strong> solutions appear as quick recall in <strong>Section A</strong> (identify/state a solution), as applied points in <strong>Section B</strong> scenarios about increasing participation, and as the basis for <strong>Section C</strong> 8-mark answers evaluating how effective a range of solutions would really be.</p>\n<p><strong>Three punchy tips:</strong></p>\n<ul>\n<li>Learn the six solution types (provision, promotion, transport, facilities/equipment, access, pricing) so you can always recall a few.</li>\n<li>For every solution, memorise <em>one</em> barrier it removes and <em>one</em> group it helps — that pairing is usually where the mark is.</li>\n<li>In longer answers, weigh up limits (cost to the centre, one change not suiting every group) — that is where the top marks live.</li>\n</ul>\n<p><strong>Sentence starters for a longer answer:</strong></p>\n<ul>\n<li>\"One solution here is… which removes the barrier of… for…\"</li>\n<li>\"This works because…\"</li>\n<li>\"However, this solution might not fully work if… because…\"</li>\n</ul>", "check": {"question": "Why is weighing up a solution''s limits a useful point in a longer answer?", "options": ["It fills space with extra words", "It shows deeper understanding of how effective the solution really is", "It means the solution should never be attempted", "It completely replaces the need for mentioning any barrier or group at all"], "answer": 1, "explain": "Noticing a real limit (cost, or one group''s needs clashing with another''s) shows evaluation — the skill that lifts a Section C answer into the top band."}}]}, "exam": {"enabled": true, "questions": [{"question": "Identify <strong>two</strong> different types of solution that could help increase participation among under-represented user groups.", "marks": 2, "hint": "Pick two from provision, promotion, transport, facilities/equipment, access or pricing.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks (AO1)</h5>\n<p><strong>1 mark for each correct type of solution named, to a maximum of two. Accept any two different solutions, including:</strong></p>\n<ul>\n<li>Appropriate provision (programmes, sessions, activities or times for a user group)</li>\n<li>Targeted promotion, including using role models</li>\n<li>Initiatives or incentives, such as free taster sessions</li>\n<li>Increased or appropriate transport availability</li>\n<li>Appropriate facilities and equipment (e.g. pool hoists, hearing loops, braille/tactile signage)</li>\n<li>Improved access to facilities</li>\n<li>Appropriate pricing (concessions, taster sessions, free/reduced-price equipment)</li>\n</ul>\n<p>Do not credit the same type of solution written twice.</p>\n</div>"}, {"question": "Which of these is the best example of using transport to remove a barrier to participation?", "marks": 1, "hint": "Think about what actually changes whether a group can physically reach a venue.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: B — Running a free pick-up minibus service from a nearby estate to the leisure centre.</strong></p>\n<ul>\n<li>A pick-up service directly solves a transport barrier by getting people to the venue.</li>\n<li>A price list, a website photo, and reception hours are pricing, promotion and staffing changes, not transport.</li>\n</ul>\n</div>"}, {"question": "Explain how Northgate Community Sports Centre could address the barriers facing these <strong>two</strong> user groups.", "marks": 4, "hint": "Take each group in turn. Name a solution, then link it to the specific barrier that group faces in the scenario (the step/doorways, or the £6 price).", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (AO2: application)</h5>\n<p><strong>Up to 2 marks per user group: 1 for identifying the relevant barrier from the scenario, 1 for a solution that removes it. Answers may include:</strong></p>\n<ul>\n<li><strong>Wheelchair users</strong> — the step and narrow doorways are an access barrier. Northgate could fit a ramp at the entrance and widen the changing-room doorways.</li>\n<li><strong>Unemployed residents</strong> — the £6 price is a cost barrier. Northgate could offer a concessionary price or a free taster session for this group.</li>\n</ul>\n<p>Accept any other reasonable, applied answer. A solution with no barrier named, or a solution not linked to the scenario, earns 1 of the 2 marks for that group.</p>\n</div>"}, {"question": "Evaluate how effective a range of solutions would be in increasing overall participation at Northgate Community Sports Centre.", "marks": 8, "hint": "Choose two or three user groups. For each, give a solution and the barrier it removes. Then weigh it up — what limits how well it would actually work? Finish with a judgement.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 8 marks (level-of-response). Read the band you fit, then pick a mark.</h5>\n<ul>\n<li><strong>Band 3 (thorough), 6–8:</strong> a balanced, well-applied discussion of several solutions, clearly linked to the barrier and group each one removes, weighing genuine limits (budget, one change not suiting every group), ending in a justified judgement.</li>\n<li><strong>Band 2 (reasonable), 3–5:</strong> sound understanding applied to more than one solution with some evaluation, but the discussion may be one-sided or the judgement unsupported.</li>\n<li><strong>Band 1 (basic), 1–2:</strong> names solutions and/or barriers with little application and no real evaluation; largely a list.</li>\n<li><strong>0 marks:</strong> nothing creditworthy.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Indicative content (indicative, not a checklist — reward valid alternatives)</h5>\n<ul>\n<li><strong>Wheelchair users:</strong> a ramp and wider doorways remove the access barrier caused by the step and narrow changing rooms.</li>\n<li><strong>Unemployed residents:</strong> a concession or free taster session removes the £6 cost barrier.</li>\n<li><strong>Teenagers:</strong> a cheap, sociable after-school session, promoted through a local role model, could remove cost and awareness barriers together.</li>\n<li><strong>Retired residents:</strong> a gentle, sociable daytime session (provision) suited to their availability and fitness could bring in a group with free daytime hours.</li>\n<li><strong>Evaluation:</strong> solutions only work if Northgate can afford them (a ramp and lower prices both cost money on a limited budget); a change for one group can clash with another (a lively teenage session may put off retired residents wanting calm); the biggest gain likely comes from fixing the barrier facing the largest under-served group first.</li>\n<li><strong>Judgement:</strong> a range of targeted solutions is powerful because each removes the specific barrier a group faces — but it only raises participation as far as the limited budget allows, so Northgate should prioritise the cheapest, highest-impact changes first.</li>\n</ul>\n</div>"}]}}'::jsonb),
('sport-studies', '1-4-popularity-of-sport-in-the-uk', '1.4 Popularity of Sport in the UK', '{"learn": {"enabled": true, "items": [{"title": "What makes a sport popular — participation, facilities and climate", "html": "<h4>Popularity moves up and down</h4>\n<ul>\n<li>A sport''s popularity in the UK is not fixed. Several factors push it <strong>up</strong> or <strong>down</strong> over time, and the same factor can work in either direction depending on what happens.</li>\n<li>The exam skill: don''t just name a factor — say which <strong>direction</strong> it pushed popularity in your example, and explain the <strong>effect</strong> this had.</li>\n</ul>\n<h4>Factor 1 — the number of people participating</h4>\n<ul>\n<li>When more people take part in a sport, its overall popularity tends to rise — participants often go on to watch it, follow it and talk about it too.</li>\n<li>If participation falls (perhaps because a sport is seen as old-fashioned or hard to access), popularity can shrink alongside it.</li>\n</ul>\n<h4>Factor 2 — the provision of facilities</h4>\n<ul>\n<li>A sport needs somewhere to be played. Plenty of accessible, well-maintained venues and equipment make it easy to take up, which raises popularity.</li>\n<li>Where facilities are scarce, expensive to hire, or a long way from where people live, they cannot get involved even if they want to, so popularity stays low.</li>\n</ul>\n<h4>Factor 3 — environmental and climate influences</h4>\n<ul>\n<li>The UK''s weather and geography make some activities easy to access all year (such as pitch and court sports) but limit others that need conditions like reliable snow, ice, open water or warm temperatures.</li>\n<li>A sport that depends on conditions the UK rarely provides will struggle to build mass popularity here, however popular that sport is in other countries.</li>\n</ul>", "check": {"question": "A sport can only be played on natural ice that forms reliably for several months a year. Which factor best explains why this limits its popularity across most of the UK?", "options": ["Environmental and climate influences, because the UK rarely provides those conditions consistently", "Social acceptability, because wider society has generally decided the sport is not respectable enough to watch or take part in", "The number and range of positive role models available to encourage newcomers to try it", "Live spectator opportunities, because grounds selling tickets to matches are always too expensive"], "answer": 0, "explain": "The UK''s climate rarely gives reliable natural ice for long periods, so environment/climate is the factor limiting this sport — not role models, acceptability or ticket prices."}}, {"title": "Watching it happen — spectators, media coverage and elite success", "html": "<h4>Factor 4 — live spectator opportunities</h4>\n<ul>\n<li>When people can go and watch a sport live — affordably, nearby, with a good atmosphere — it builds a following, and some spectators go on to become new participants themselves.</li>\n<li>If tickets are expensive, venues are far away, or few live fixtures are staged at all, the sport stays out of sight and popularity struggles to grow.</li>\n</ul>\n<h4>Factor 5 — the amount and range of media coverage</h4>\n<ul>\n<li>Regular TV, radio, print and online coverage keeps a sport in the public eye, attracts sponsorship money and inspires new fans and participants.</li>\n<li>A sport that receives little coverage, or coverage of only one narrow part of it, struggles to reach new audiences even if it is genuinely exciting to watch.</li>\n</ul>\n<h4>Factor 6 — the high-level success of individuals and teams</h4>\n<ul>\n<li>When UK athletes or teams succeed at the highest level (winning a major tournament or an international medal), the sport usually gets a short-term surge in interest, participation and coverage — sometimes called a <strong>feel-good bounce</strong>.</li>\n<li>A long run of poor results at major competitions can have the opposite effect, and public interest can quietly fade away.</li>\n</ul>", "check": {"question": "A UK team wins a major international trophy for the first time in years, and club enquiries rise the following week. What does this best show?", "options": ["Elite success can cause a short-term surge in a sport''s participation and popularity", "Winning a major trophy always guarantees that a sport stays popular permanently from that point onward", "Media coverage is completely unrelated to how well a national team happens to perform", "Only players on the winning team personally benefit from any rise in popularity"], "answer": 0, "explain": "High-level success often produces a temporary ''feel-good bounce'' in interest and participation — it is not permanent, and it is not limited to the players themselves."}}, {"title": "Role models, social acceptability — and the exam skill: up or down?", "html": "<h4>Factor 7 — the number and range of positive role models</h4>\n<ul>\n<li>Athletes who are visible, respected, and easy to relate to (across gender, ethnicity, disability and background) encourage people who see themselves reflected in that role model to get involved.</li>\n<li>A narrow range of role models — or role models linked to bad publicity — gives fewer people a reason to see a sport as \"for them\", which can hold its popularity back.</li>\n</ul>\n<h4>Factor 8 — social acceptability</h4>\n<ul>\n<li>A sport tends to grow when wider society sees it as safe, fair and appropriate to take part in or to watch.</li>\n<li>Concerns about violence, cruelty (to people or animals), or unfairness can make a sport socially unacceptable to some people, which can lower both participation and popularity.</li>\n</ul>\n<h4>The exam skill: always say UP or DOWN, and why</h4>\n<ul>\n<li>Every one of the eight factors above can work in either direction. Weak answer: <em>\"Media coverage affects popularity.\"</em> Strong answer: <em>\"Extensive TV coverage of a major tournament exposed the sport to new audiences, which raised participation as more people wanted to try it after watching.\"</em></li>\n<li>This same skill reappears later in the course — in 1.5 (why emerging sports grow or stall) and in Topic 5 (the effects of technology and media on sport) — so it is worth mastering here first.</li>\n</ul>", "check": {"question": "Which sentence uses the exam skill correctly (names a factor, a direction, AND an effect)?", "options": ["Positive role models generally make a sport feel a little more interesting to people who already enjoy watching it", "A wider range of visible role models can raise popularity, as more people relate to them and take part", "Role models are simply one of the eight factors mentioned somewhere in the specification for this particular topic", "Some sports currently have more famous role models attached to them than other sports do"], "answer": 1, "explain": "Only this option names the factor, states the direction (raise), and gives the effect (more people relate and take part) — the others stop at naming or describing without direction and effect."}}]}, "terms": {"enabled": true, "pairs": [{"term": "Participation numbers", "definition": "How many people take part; a rise tends to raise overall popularity"}, {"term": "Provision of facilities", "definition": "Access to venues/equipment; more accessible provision raises popularity"}, {"term": "Environmental/climate influences", "definition": "UK weather/terrain allow some sports easily but limit those needing snow, ice or warmth"}, {"term": "Live spectator opportunities", "definition": "Watching in person; affordable, accessible opportunities can create new fans"}, {"term": "Media coverage", "definition": "TV/radio/print/online exposure; more coverage reaches new audiences"}, {"term": "High-level success", "definition": "Elite wins can cause a short-term ''feel-good bounce'' in interest"}, {"term": "Positive role models", "definition": "Relatable, visible performers who encourage others to take part"}, {"term": "Social acceptability", "definition": "Whether society sees a sport as safe, fair and appropriate"}]}, "mcq": {"enabled": true, "questions": [{"question": "Which best explains how a rise in the number of people playing a sport tends to affect its popularity?", "options": ["More participants usually raise overall popularity, since players often go on to watch, follow and talk about the sport too", "It has no real connection to popularity whatsoever, because participation numbers and general popularity are always two entirely separate and unrelated things", "It always causes the sport to be added permanently to the school national curriculum the following year", "It automatically doubles the amount of prize money available at every professional competition"], "answer": 0, "explain": "Rising participation tends to raise popularity because players often become fans, spectators and word-of-mouth promoters too. The other options invent effects the factor doesn''t actually have."}, {"question": "A town removes its only public swimming pool. What effect is this most likely to have on swimming''s local popularity?", "options": ["None, because facility provision never has any influence on whether people can take part in a sport", "Swimming becomes instantly more popular, because people enjoy a challenge when facilities disappear", "It is likely to lower popularity, because people can no longer easily access somewhere to swim", "It has no effect locally, but it makes swimming much more popular in every neighbouring town instead"], "answer": 2, "explain": "Losing the only local facility removes easy access, which tends to lower participation and popularity — it does not raise it, and it doesn''t magically boost swimming elsewhere."}, {"question": "Why does the UK produce relatively few elite alpine skiers compared with mountainous countries?", "options": ["British people have never once shown any interest in snow sports of any kind", "The UK''s climate and terrain rarely provide the reliable snow and mountains that skiing needs", "Skiing has been officially banned by every national governing body across the whole of the UK", "No UK television channel has ever broadcast any footage of a ski competition at all"], "answer": 1, "explain": "Environmental and climate influences are the real reason — the UK''s terrain and weather rarely give the reliable snow and mountains skiing needs, unlike a lack of interest, a ban, or zero coverage."}, {"question": "A new stadium opens with cheap tickets and a great matchday atmosphere for a local team. What effect is this likely to have on that sport''s popularity?", "options": ["It falls, because larger crowds at a cheaper new stadium always make the atmosphere feel worse for loyal regular fans", "It stays exactly the same, because where people go to watch sport never really changes their genuine interest in it", "It only affects popularity among the small number of people who already owned season tickets at the old ground", "It rises, because affordable live opportunities can turn spectators into new fans and participants"], "answer": 3, "explain": "Cheap, accessible live spectator opportunities tend to raise popularity by turning casual watchers into fans and even participants — not lower it or leave it unchanged."}, {"question": "A sport that used to get almost no TV coverage suddenly gets a full season broadcast live every week. What effect does this tend to have?", "options": ["Popularity tends to rise, because regular coverage reaches new audiences and attracts sponsorship", "Popularity always falls, because loyal fans much prefer to attend a fixture in person rather than ever watch it on TV at home", "There is no effect at all, because television coverage has never once influenced any sport''s popularity in any way", "The sport is instantly removed from all live fixture listings published in national newspapers"], "answer": 0, "explain": "Regular media coverage tends to raise popularity by reaching new audiences and attracting sponsors — coverage does not automatically reduce attendance or get a sport dropped from listings."}, {"question": "A UK team wins a major international tournament for the first time in decades. What short-term effect does this typically have on the sport?", "options": ["None, because results at major tournaments never change public interest in a sport", "The opposite of what you''d expect — interest and participation usually fall straight away", "A surge in interest, participation and coverage, sometimes called a feel-good bounce", "It only affects the players on that specific team and nobody else who follows the sport"], "answer": 2, "explain": "High-level success typically produces a short-term ''feel-good bounce'' — a surge in interest, participation and coverage — rather than no change, a fall, or an effect limited only to the players."}]}, "fib": {"enabled": true, "questions": [{"text": "A sport tends to become more popular when the number of people [participating] in it increases."}, {"text": "Plentiful, accessible sports [facilities] make it easier for people to take up a sport in the first place."}, {"text": "A sport that needs reliable snow or ice can struggle to grow across the UK because of the [climate]."}, {"text": "Extensive media [coverage] keeps a sport visible to the public and can attract new fans."}, {"text": "A wider range of positive role [models] encourages more people who relate to them to get involved."}, {"text": "Concerns about violence or cruelty can lower a sport''s social [acceptability] to some people."}]}, "tf": {"enabled": true, "questions": [{"statement": "Every one of the eight popularity factors can only ever raise a sport''s popularity, never lower it.", "answer": false, "explain": "Each factor can push popularity in EITHER direction — for example, poor facility provision lowers popularity just as good provision raises it."}, {"statement": "A short-term surge in interest after a major tournament win is sometimes called a feel-good bounce.", "answer": true, "explain": "That''s the term used for the temporary rise in participation, interest and coverage that often follows high-level success."}, {"statement": "The UK''s climate and terrain can limit how popular certain snow- or ice-based sports become nationally.", "answer": true, "explain": "Environmental and climate influences are a genuine factor — the UK rarely provides the conditions some sports need all year round."}, {"statement": "Social acceptability has no connection to concerns about violence or fairness in a sport.", "answer": false, "explain": "Social acceptability IS partly about this — concerns about violence, cruelty or unfairness can make a sport less socially acceptable and lower its popularity."}, {"statement": "A wider range of positive role models tends to help more people see a sport as ''for them''.", "answer": true, "explain": "Role models people can relate to (across gender, ethnicity, disability and background) encourage more people to get involved."}, {"statement": "Removing an accessible local facility for a sport usually has no effect on how popular it stays.", "answer": false, "explain": "Losing easy access to facilities tends to lower participation, since people can no longer take part as easily — that in turn can lower popularity."}]}, "misc": {"enabled": true, "items": [{"myth": "If I just name a factor like ''media coverage'', that explains why a sport''s popularity changed.", "truth": "Naming the factor is only the start. The mark is for saying which DIRECTION it pushed popularity and the EFFECT this had. Weak: \"Media coverage affects popularity.\" Full marks: \"Extensive TV coverage of a tournament exposed the sport to new audiences, which raised participation as more people wanted to try it.\"", "check": {"question": "An ''Explain'' question asks how a factor affected a sport''s popularity. What earns the marks?", "options": ["Naming as many of the eight different popularity factors as you can possibly remember", "Naming the factor, the direction it pushed popularity, and the effect", "Writing the factor''s name in capital letters for emphasis", "Describing a sport you personally enjoy watching"], "answer": 1, "explain": "Explain = factor + direction + effect. Naming the factor alone, or listing several factors, does not show the understanding the mark scheme rewards."}}, {"myth": "These eight factors only ever make a sport MORE popular — they can''t work the other way.", "truth": "Every factor can push popularity up OR down. Good facility provision raises popularity; losing facilities lowers it. Strong media coverage raises popularity; almost no coverage limits it. Always check which direction your example actually shows before you write the effect.", "check": {"question": "A sport loses most of its live TV coverage over several years. What is the most likely effect on its popularity?", "options": ["It rises, because every one of these factors can only ever raise a sport''s popularity", "It is likely to fall, because losing exposure to audiences can reduce interest", "There is no possible effect on popularity from any change in coverage", "The sport instantly becomes an emerging sport as a result"], "answer": 1, "explain": "Losing coverage removes exposure to new audiences, so popularity is likely to fall — the same factor that can raise popularity can also lower it."}}, {"myth": "Participation and popularity are two totally separate ideas with no real link between them.", "truth": "They are closely linked, which is exactly why ''the number of people participating'' is one of the eight factors. More participants tend to raise overall popularity (players often become fans and promoters too); fewer participants can shrink it. They are not identical ideas, but they clearly affect each other.", "check": {"question": "Why is ''the number of people participating'' listed as a factor affecting a sport''s popularity?", "options": ["Because participation and popularity have no meaningful connection to one another at all, ever", "Because participants often go on to watch, follow and promote a sport too, which can raise popularity", "Because only fully professional, highly paid athletes ever count as genuine participants in any sport", "Because participation always falls whenever popularity rises"], "answer": 1, "explain": "Participants frequently become spectators, fans and word-of-mouth promoters, which is why rising participation tends to raise a sport''s wider popularity."}}, {"myth": "Social acceptability is just about whether a sport looks ''cool'' — it has nothing to do with things like violence or fairness.", "truth": "Social acceptability is specifically about whether wider society views a sport as safe, fair and appropriate. Concerns about violence, cruelty to people or animals, or unfairness are the main things that can lower it — ''looking cool'' is not the concept being tested.", "check": {"question": "What does ''social acceptability'' as a popularity factor actually refer to?", "options": ["Whether a sport currently looks fashionable and trendy to teenagers specifically", "Whether wider society sees a sport as safe, fair and appropriate", "Whether a sport is expensive to take part in", "Whether a sport has an official national governing body"], "answer": 1, "explain": "Social acceptability concerns whether society sees a sport as safe, fair and appropriate — concerns about violence, cruelty or unfairness are what can lower it."}}]}, "tips": {"enabled": true, "items": [{"title": "Command words for this topic — what each one wants", "html": "<p>Popularity questions can be short recall or longer applied answers. Match your answer length to the command word:</p>\n<ul>\n<li><strong>Identify / State</strong> — just name it. \"Identify two factors affecting popularity\" = two factor names, nothing more. 1 mark each.</li>\n<li><strong>Explain</strong> — name the factor, give the direction (up or down), and give the effect. Use \"because\" to link them.</li>\n<li><strong>Discuss</strong> — weigh up more than one factor, applied to a scenario, and reach a judgement about which matters most or how far it would work.</li>\n</ul>\n<p><strong>Read the mark tariff:</strong> [1]–[2] wants one or two points; [4] in Section B wants points applied to the scenario given; [8] levelled wants balance across factors and a justified judgement.</p>", "check": {"question": "A question says: ''Identify two factors that affect a sport''s popularity [2]''. What is the safest answer?", "options": ["A long paragraph about one single factor", "Two factor names", "One factor explained in great detail", "A list of all eight factors"], "answer": 1, "explain": "''Identify'' + [2] = two names, one mark each. Explaining one factor in depth, or listing all eight, wastes time and risks the examiner marking only the first two anyway."}}, {"title": "The golden rule: factor, direction, effect", "html": "<p>The single most common way to lose marks here is stopping at the factor''s name. Build every answer as <strong>factor → direction → effect</strong>:</p>\n<ul>\n<li><strong>❌ 0–1 marks:</strong> \"Media coverage.\"</li>\n<li><strong>✅ full marks:</strong> \"Wider media coverage raised the sport''s popularity, because it exposed new audiences to the sport who then wanted to try it themselves.\"</li>\n</ul>\n<p>In <strong>Section B</strong> the question gives you a scenario (a named sport, club or event). You must use a detail <em>from that scenario</em>, not a general example from a different sport.</p>", "check": {"question": "In a Section B scenario about a named sports club, your example should come from...", "options": ["absolutely any sport that you happen to prefer", "the scenario you are given", "a famous athlete not mentioned anywhere in the question", "your own personal experience of a completely different sport"], "answer": 1, "explain": "Section B is applied — the marks are for using the scenario in front of you. A general example that ignores the scenario is capped."}}, {"title": "Where this topic appears + sentence starters", "html": "<p><strong>Where it shows up:</strong> popularity factors appear as quick recall in <strong>Section A</strong> (identify/state), as applied points in <strong>Section B</strong> scenarios about a specific sport or event, and they feed <strong>Section C</strong> 8-mark answers discussing how to grow a sport''s popularity. The same skill links forward to 1.5 (emerging sports) and Topic 5 (technology and media).</p>\n<p><strong>Three punchy tips:</strong></p>\n<ul>\n<li>Learn the eight factors as a checklist so you can always recall several under pressure.</li>\n<li>For every factor, memorise one \"up\" example and one \"down\" example — direction is where the mark often sits.</li>\n<li>In a longer answer, weigh factors against each other rather than just listing them one after another.</li>\n</ul>\n<p><strong>Sentence starters for a longer answer:</strong></p>\n<ul>\n<li>\"One factor affecting popularity here is… which raised/lowered it because…\"</li>\n<li>\"This mattered because it changed…\"</li>\n<li>\"However, on its own this factor might not be enough because…\"</li>\n</ul>", "check": {"question": "Why is it useful to know an ''up'' example AND a ''down'' example for the same factor?", "options": ["It simply fills useful space in a longer written answer without really needing to add anything new or relevant to it", "Because the exam can ask about either direction, and a fixed ''always up'' answer would be wrong for a ''down'' question", "Because every one of these eight factors only ever works in a single, fixed direction anyway", "It completely replaces the need to apply the factor to any scenario given in the question"], "answer": 1, "explain": "Every factor can raise OR lower popularity, so knowing both directions means you''re ready whichever way a question is framed — you still need to apply it to the scenario too."}}]}, "exam": {"enabled": true, "questions": [{"question": "Identify <strong>two</strong> factors that can affect the popularity of a sport in the UK.", "marks": 2, "hint": "Just name two — pick from participation numbers, facility provision, climate/environment, live spectator opportunities, media coverage, elite success, role models or social acceptability.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks (AO1)</h5>\n<p><strong>1 mark for each correct factor named, to a maximum of two. Accept any two different factors, including:</strong></p>\n<ul>\n<li>The number of people participating</li>\n<li>The provision of facilities</li>\n<li>Environmental / climate influences</li>\n<li>Live spectator opportunities</li>\n<li>The amount and range of media coverage</li>\n<li>The high-level success of individuals and teams</li>\n<li>The number and range of positive role models</li>\n<li>Social acceptability of the sport</li>\n</ul>\n<p>Do not credit the same factor written twice.</p>\n</div>"}, {"question": "Which factor is most likely to explain why a sport gets a short-term surge in interest immediately after a national team wins a major trophy?", "marks": 1, "hint": "Think about what has just happened in the question — a win at the highest level.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: B — The high-level success of individuals and teams.</strong></p>\n<ul>\n<li>A major win at the highest level typically causes a short-term \"feel-good bounce\" in interest, participation and coverage.</li>\n<li>The other options describe ongoing factors, not the immediate cause of a surge right after a single tournament win.</li>\n</ul>\n</div>"}, {"question": "Explain how these <strong>two</strong> factors are likely to be affecting the popularity of hockey at Fenmoor.", "marks": 4, "hint": "Take each factor in turn. Name it, say which direction it is pushing popularity, and explain the effect using details from the scenario (reaching the final, the live broadcast, the rise in enquiries).", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (AO2: application)</h5>\n<p><strong>Up to 2 marks per factor: 1 for identifying the factor and correct direction, 1 for an effect linked to the scenario. Answers may include:</strong></p>\n<ul>\n<li><strong>High-level success</strong> — reaching a national final for the first time is raising popularity; it has generated a \"feel-good bounce\" shown by the rise in junior enquiries.</li>\n<li><strong>Media coverage</strong> — the first-ever live broadcast is raising popularity; showing the semi-final to a wider audience exposed the club to new potential participants.</li>\n</ul>\n<p>Accept any other reasonable, applied answer. A factor named with no scenario-linked effect earns 1 of the 2 marks for that factor.</p>\n</div>"}, {"question": "Discuss how far focusing on facility provision, media coverage and high-level success could raise the popularity of rowing in the UK.", "marks": 8, "hint": "Take two or three factors. For each, explain how it could raise popularity in this scenario. Then weigh it up — what limits how much it could achieve on its own? Finish with a judgement on which matters most, or whether they are needed together.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 8 marks (level-of-response). Read the band you fit, then pick a mark.</h5>\n<ul>\n<li><strong>Band 3 (thorough), 6–8:</strong> a balanced, well-applied discussion of several factors, showing clearly how each could raise popularity AND weighing the limits (cost, the UK''s terrain limiting where rowing can be based, one factor alone not being enough), ending in a justified judgement.</li>\n<li><strong>Band 2 (reasonable), 3–5:</strong> sound understanding applied to more than one factor with some analysis, but the discussion may be one-sided or the judgement unsupported.</li>\n<li><strong>Band 1 (basic), 1–2:</strong> names factors with little application and no real evaluation; largely a list.</li>\n<li><strong>0 marks:</strong> nothing creditworthy.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Indicative content (indicative, not a checklist — reward valid alternatives)</h5>\n<ul>\n<li><strong>Facility provision:</strong> new, accessible boathouses in more towns could let far more people try rowing who currently have no nearby access.</li>\n<li><strong>Media coverage:</strong> a weekly highlights show could raise the sport''s public profile and attract sponsors, reaching audiences who currently never see it.</li>\n<li><strong>High-level success:</strong> funding elite performers could produce a future feel-good bounce if they succeed internationally, inspiring new participants.</li>\n<li><strong>Evaluation:</strong> the budget is limited, so funding all three fully may be impossible; rowing also needs suitable water nearby (an environmental limit), so boathouses only help where geography allows; elite success is not guaranteed and could take years to arrive, while media coverage without new facilities may create interest with nowhere local to act on it.</li>\n<li><strong>Judgement:</strong> facility provision arguably has the most reliable, immediate effect because it removes the barrier of access directly — but real, lasting growth is more likely if provision is paired with media coverage or eventual elite success rather than relying on any single factor alone.</li>\n</ul>\n</div>"}]}}'::jsonb),
('sport-studies', '1-5-emerging-and-new-sports', '1.5 Emerging and New Sports', '{"learn": {"enabled": true, "items": [{"title": "What is an ''emerging'' or ''new'' sport? — examples in the UK today", "html": "<h4>The idea</h4>\n<ul>\n<li>An <strong>emerging (or new) sport</strong> is a sport that is <strong>newly growing</strong> in popularity, provision and participation in the UK — more people are starting to play it, and more places are starting to offer it.</li>\n<li>It does not have to be a brand-new invention. Many emerging sports already existed elsewhere, or on a small scale, and are only now becoming widely available in the UK.</li>\n</ul>\n<h4>Examples you can use in the exam</h4>\n<ul>\n<li><strong>Padel</strong> — a racket sport played in a small, walled court, usually in doubles. New courts have appeared at leisure centres and tennis clubs across the UK over recent years.</li>\n<li><strong>Walking football</strong> — a slower, no-running version of football, originally aimed at people who want to keep playing without the impact of the full-speed game.</li>\n<li><strong>Ultimate frisbee</strong> — a non-contact team sport where players score by catching a flying disc in an end zone; growing at universities and club level.</li>\n<li><strong>Competitive gaming (esports)</strong> — organised, competitive video-game play, watched live and via streaming, now run through organised leagues and school/college clubs.</li>\n<li>You can use any genuine example you know, as long as you can explain <em>why</em> it counts as newly growing.</li>\n</ul>", "check": {"question": "Which of these best describes an ''emerging'' or ''new'' sport?", "options": ["A sport that is newly growing in popularity, provision and participation in the UK", "A sport that has stayed exactly the same size and popularity in the UK for over half a century", "A sport that only exists at full-time, professional, elite level", "A sport that has been removed from a major international competition"], "answer": 0, "explain": "An emerging sport is newly growing — in players, provision and participation. A sport that never changes, or has been removed from competition, is the opposite of that."}}, {"title": "How emerging sports develop — and the opportunities to take part", "html": "<h4>Where the growth comes from</h4>\n<ul>\n<li><strong>New clubs and facilities</strong> — as a sport grows, leisure centres, schools and private operators start to offer it, so there are simply more places to try it.</li>\n<li><strong>Media exposure</strong> — TV highlights, online clips and news coverage introduce people to a sport they might never otherwise see.</li>\n<li><strong>Social media</strong> — short clips and online content can make a sport look exciting almost overnight, reaching audiences that traditional TV coverage misses.</li>\n<li><strong>Accessible, low-cost formats</strong> — many emerging sports are deliberately kept cheap and simple to start (free taster sessions, adapted rules, borrowed equipment), which removes cost and confidence as barriers.</li>\n<li><strong>Role models</strong> — a well-known player, or even a respected local coach, can persuade people who would not otherwise try the sport to give it a go.</li>\n</ul>\n<h4>The opportunities this creates</h4>\n<ul>\n<li>Beginners can join at a genuinely beginner level, because the whole sport is still new — there is less pressure to already be skilled.</li>\n<li>New clubs often need people to help shape the sport locally, as coaches, organisers or committee members — a different kind of opportunity to joining an already-established sport.</li>\n</ul>", "check": {"question": "Which factor most directly explains why a brand-new club can suddenly attract first-time participants?", "options": ["Short clips of the sport are shared widely and reach people who had never seen it before", "The sport has existed completely unchanged in the UK for over a century without any promotion", "The national governing body has decided to increase membership fees for every beginner", "Local facilities offering the sport have permanently stopped running any sessions at all"], "answer": 0, "explain": "Wide exposure (media/social media) is what introduces a growing sport to new people. An unchanged, unpromoted sport, higher fees, or closed facilities would not attract first-timers."}}, {"title": "The exam skill: link the sport''s growth to the FACTOR driving it", "html": "<h4>Don''t just describe the sport — explain WHY it''s growing</h4>\n<ul>\n<li>Weak answer: <em>\"Padel is becoming popular.\"</em> That''s a statement with no explanation.</li>\n<li>Strong answer: <em>\"Padel is becoming popular because new courts have opened at local leisure centres, and short clips of matches are shared widely on social media, which introduces the sport to people who had never seen it played before.\"</em></li>\n</ul>\n<h4>This links straight back to 1.4 Popularity</h4>\n<ul>\n<li>The same factors that make ANY sport more or less popular — <strong>media coverage, role models, provision/facilities, accessibility (including cost) and social acceptability</strong> — also explain why an emerging sport grows.</li>\n<li>So when a question asks about an emerging sport, apply the popularity factors you already know to the NEW example, rather than learning a separate list.</li>\n</ul>\n<h4>Common trap</h4>\n<ul>\n<li>Simply naming an emerging sport (\"padel\", \"walking football\") earns very little on its own. The marks are for the FACTOR driving its growth and the REASON that factor matters.</li>\n</ul>", "check": {"question": "A question asks why an emerging sport is increasing its participation. Which answer is most likely to score well?", "options": ["Naming the factor behind the growth (e.g. media coverage) and explaining why it increases participation", "Writing only the name of the emerging sport, with nothing else added at all", "Describing the official rules of the sport in as much extensive technical detail as you possibly can manage", "Listing as many different emerging sports as you are able to remember from revision"], "answer": 0, "explain": "Explain questions reward a factor plus a reason. Naming the sport, describing its rules, or listing more sports does not show the understanding the mark scheme rewards."}}]}, "terms": {"enabled": true, "pairs": [{"term": "Emerging / new sport", "definition": "A sport newly growing in popularity, provision and participation in the UK"}, {"term": "Padel", "definition": "A racket sport played in a small, walled court, usually in doubles"}, {"term": "Walking football", "definition": "A slower, no-running version of football aimed at lower-impact play"}, {"term": "Ultimate frisbee", "definition": "A non-contact team sport scored by catching a flying disc in an end zone"}, {"term": "Provision (growth factor)", "definition": "New clubs, facilities or sessions giving people somewhere nearby to try a sport"}, {"term": "Media/social media exposure", "definition": "Coverage and online clips that introduce a sport to people who wouldn''t otherwise see it"}, {"term": "Role model (growth factor)", "definition": "A well-known player or coach who persuades new people to try the sport"}]}, "mcq": {"enabled": true, "questions": [{"question": "What best defines an emerging or new sport?", "options": ["A sport that is newly growing in popularity, provision and participation in the UK", "A sport that has kept exactly the same number of players and clubs for decades without any change", "A sport that can only ever be played by full-time professional athletes", "A sport that has been removed from a major international competition programme"], "answer": 0, "explain": "An emerging sport is one newly growing in popularity, provision and participation. Staying unchanged for decades, being elite-only, or being dropped from competition are the opposite of ''emerging''."}, {"question": "Which of these is a genuine example of a sport that has recently been growing in the UK?", "options": ["A sport that has stayed at exactly the same participation level in the UK for over half a century", "Padel — a racket sport played in a small, walled court, usually in doubles", "A sport that no UK leisure centre or club currently offers to anyone", "A sport played only by full-time Olympic gold medallists at elite level"], "answer": 1, "explain": "Padel is a real example of a sport with newly opened courts and clubs across the UK. A stagnant, unavailable, or elite-only activity is not ''emerging''."}, {"question": "Which change is most likely to help an emerging sport grow by making it easier to actually try?", "options": ["A national governing body removes every beginner session from its yearly calendar", "The sport''s only professional league doubles its ticket prices for spectators", "A local leisure centre opens a new facility so people have somewhere nearby to try the sport", "All existing facilities and every beginner session for the sport are permanently closed without warning"], "answer": 2, "explain": "New, nearby provision is what lets first-timers actually try a sport. Removing sessions, raising prices, or closing facilities would all make it harder, not easier."}, {"question": "How can social media help an emerging sport attract new participants?", "options": ["It guarantees that every single viewer will immediately join a local sports club on that very same day without exception", "It only reaches people who already compete in the sport at an elite, professional level", "It replaces the need for any coaches, clubs or facilities to ever exist at all", "Short clips of matches and taster sessions can reach people who would never otherwise see the sport"], "answer": 3, "explain": "Social media widens exposure to people who wouldn''t otherwise see the sport. It doesn''t guarantee instant sign-ups, doesn''t only reach elite players, and doesn''t remove the need for real facilities."}, {"question": "Why can a well-known role model help an emerging sport grow?", "options": ["Role models are legally required by law to try out every single emerging sport once a year without any exception whatsoever", "A respected player or coach can persuade people who would not otherwise try the sport to give it a go", "A role model automatically funds every new facility that the sport will ever need to succeed", "Role models only ever affect sports that are already extremely well established and popular"], "answer": 1, "explain": "A role model''s example builds trust and interest, encouraging new people to try the sport. There''s no legal requirement, no automatic funding, and role models can help sports at any stage, not only established ones."}, {"question": "A student explains padel''s growth by writing only ''padel is popular now''. What is missing from this answer?", "options": ["Nothing at all — naming the sport is already enough to gain full marks here", "A complete, highly technical list of every single rule used in an official padel match, printed out in full", "A specific factor driving the growth (e.g. new facilities or media coverage) and a reason why it matters", "The exact date and country in which padel was first ever invented anywhere"], "answer": 2, "explain": "The marks come from a named factor plus a reason it drives growth — not from the sport''s name alone, its rulebook, or its invention date."}]}, "fib": {"enabled": true, "questions": [{"text": "An emerging sport is one that is newly [growing] in popularity, provision and participation in the UK."}, {"text": "Padel is a racket sport played in a small, walled [court], usually in doubles."}, {"text": "Walking football is a slower, no-running version of football aimed at players who want lower [impact]."}, {"text": "New clubs and facilities give people somewhere [nearby] to try an emerging sport for the first time."}, {"text": "Short clips shared on social [media] can introduce a sport to people who would never otherwise see it."}]}, "tf": {"enabled": true, "questions": [{"statement": "An emerging sport must be a completely new invention that has never existed anywhere in the world.", "answer": false, "explain": "Many emerging sports already existed elsewhere, or on a small scale, for years. ''Emerging'' means newly growing in UK popularity, provision and participation, not necessarily brand new."}, {"statement": "Padel is an example of a racket sport that has recently been growing in the UK.", "answer": true, "explain": "New padel courts and clubs have opened at leisure centres and tennis clubs across the UK in recent years, making it a genuine emerging-sport example."}, {"statement": "Media coverage and social media can help introduce an emerging sport to people who would not otherwise see it.", "answer": true, "explain": "Wider exposure through TV, news or online clips is one of the main ways an emerging sport reaches people who had never come across it before."}, {"statement": "Naming an emerging sport is enough on its own to earn full marks in an ''explain'' question.", "answer": false, "explain": "Explain questions need a factor driving the growth plus a reason it matters — naming the sport alone earns very little."}, {"statement": "Walking football is designed to be a slower, lower-impact version of football.", "answer": true, "explain": "It removes running and reduces impact, which is exactly why it can attract people who want to play without the demands of the full-speed game."}, {"statement": "New facilities and low-cost taster sessions have no real effect on whether people try an emerging sport.", "answer": false, "explain": "New, nearby facilities and free or low-cost sessions remove distance, cost and confidence as barriers, which can have a big effect on whether people take part."}]}, "misc": {"enabled": true, "items": [{"myth": "An ''emerging sport'' just means a brand new sport that nobody has ever played before anywhere in the world.", "truth": "''Emerging'' means newly growing in UK popularity, provision and participation — not necessarily a brand-new invention. Many examples (like padel) already existed elsewhere, or on a small scale, and are only now becoming widely available here.", "check": {"question": "Which is the most accurate description of an ''emerging sport''?", "options": ["A sport that has only just been invented and never existed anywhere before", "A sport that is newly growing in popularity, provision and participation, even if it already existed elsewhere", "A sport that has been played at fully professional level in the UK continuously for well over a hundred years without any change", "A sport that has recently been removed from a major international competition"], "answer": 1, "explain": "Emerging just means newly growing here — the sport does not have to be a brand-new invention, and being long-established or removed from competition is the opposite idea."}}, {"myth": "If a sport just gets media coverage, that''s the only thing that helps it grow — local facilities don''t matter.", "truth": "Growth usually needs more than one factor together. Media coverage builds awareness, but if there is nowhere nearby to actually try the sport, that interest cannot easily turn into participation. Provision and exposure work together.", "check": {"question": "A sport gets a lot of media coverage but has no local clubs or facilities nearby. What is most likely?", "options": ["Interest will still convert fully into participation with absolutely no other changes needed", "People who become interested may struggle to actually take part without nearby provision", "Media coverage always guarantees that new facilities will appear immediately", "Facilities have no effect whatsoever on whether people can take part in a sport"], "answer": 1, "explain": "Awareness alone does not create participation — without nearby provision, interested people have nowhere to actually try the sport."}}, {"myth": "Naming an emerging sport like ''padel'' or ''walking football'' is enough to answer an explain question.", "truth": "Naming the sport earns very little. The marks come from identifying the FACTOR driving its growth (media, provision, role models, accessible/low-cost formats) and explaining WHY that factor increases participation.", "check": {"question": "An exam question asks you to explain why an emerging sport is growing. What earns the marks?", "options": ["Simply writing the name of the sport with nothing else added at all", "Naming the factor behind the growth and explaining why it increases participation", "Listing every emerging sport that you happen to know about", "Describing the exact, official rules of the sport in complete technical detail from memory"], "answer": 1, "explain": "The mark scheme rewards a named factor plus a reason it drives participation, not the sport''s name, a list of sports, or its rulebook."}}, {"myth": "Emerging sports only appeal to young, fit, sporty people.", "truth": "Many emerging sports are deliberately designed to be accessible to a wide range of ages and abilities (walking football is a clear example), which is part of why they can grow quickly among people who felt excluded from the traditional version.", "check": {"question": "Why might an emerging sport like walking football appeal to a wider range of people?", "options": ["It is deliberately designed as a slower, lower-impact format accessible to more people", "It is only ever played by elite, full-time professional athletes", "It requires exactly the same high level of competitive fitness as senior traditional football", "It has stricter age restrictions than the traditional version of the sport"], "answer": 0, "explain": "Its slower, lower-impact design is exactly what widens who can take part, compared with the traditional, more demanding version."}}]}, "tips": {"enabled": true, "items": [{"title": "Command words for this topic — what each one wants", "html": "<p>Emerging-sport questions range from short recall to longer applied or evaluative answers. Match your answer to the command word:</p>\n<ul>\n<li><strong>Identify / State</strong> — just name it. \"Identify one emerging sport\" = one name, 1 mark.</li>\n<li><strong>Describe</strong> — say what the sport or the change involves, without necessarily giving a reason.</li>\n<li><strong>Explain</strong> — give a reason, using \"because\". Link the sport''s growth to a FACTOR (media coverage, role models, provision, accessibility, cost).</li>\n<li><strong>Discuss / Evaluate</strong> — weigh up more than one factor, apply them to a scenario, and reach a judgement about which matters most.</li>\n</ul>\n<p><strong>Read the mark tariff:</strong> [1] wants one point; [4] in Section B usually wants two factors applied to the scenario; [6]/[8] levelled answers want balance and a justified judgement.</p>", "check": {"question": "A question says: ''Identify one emerging sport currently growing in the UK [1]''. What is the safest answer?", "options": ["A one-line explanation of why the sport is popular right now", "The name of one emerging sport, nothing more", "A full paragraph describing the sport''s entire history", "A list of every emerging sport you can possibly think of"], "answer": 1, "explain": "''Identify'' + [1] = one name, one mark. Explaining, writing a history, or listing several sports wastes time and risks marks being capped at one anyway."}}, {"title": "The golden rule: name the FACTOR and explain WHY it drives growth", "html": "<p>The most common way to lose marks here is naming the sport with no factor. Build every answer as <strong>factor → effect on participation</strong>:</p>\n<ul>\n<li><strong>❌ 0–1 marks:</strong> \"Padel is growing.\"</li>\n<li><strong>✅ full marks:</strong> \"Padel is growing because new courts have opened at local leisure centres, giving people somewhere nearby to try it for the first time.\"</li>\n</ul>\n<p>In <strong>Section B</strong> you are given a scenario. Use a detail <em>from that scenario</em> (a named club, a named change) rather than a general example.</p>", "check": {"question": "In a Section B scenario about a named club promoting an emerging sport, your explanation should be based on...", "options": ["any emerging sport that you personally happen to enjoy the most", "the details given in the scenario you are given", "a professional athlete not mentioned anywhere in the question", "your own school''s usual PE lesson only, regardless of the scenario"], "answer": 1, "explain": "Section B is applied — the marks are for using the scenario in front of you, not a general example that ignores it."}}, {"title": "Where this appears + sentence starters", "html": "<p><strong>Where it shows up:</strong> emerging sports appear as quick recall in <strong>Section A</strong> (name a sport/factor), as applied points in <strong>Section B</strong> scenarios about a club or provider promoting a new sport, and can feed a <strong>Section C</strong> Discuss/Evaluate answer about increasing participation.</p>\n<p><strong>Three punchy tips:</strong></p>\n<ul>\n<li>Keep two or three real examples ready (e.g. padel, walking football, ultimate frisbee) so you always have something to apply.</li>\n<li>For every example, memorise ONE factor driving its growth — that factor is usually where the mark is.</li>\n<li>Link back to 1.4 Popularity: the same factors (media, role models, provision, accessibility, social acceptability) explain growth here too.</li>\n</ul>\n<p><strong>Sentence starters for a longer answer:</strong></p>\n<ul>\n<li>\"One way [sport] could increase its participation is… because…\"</li>\n<li>\"This matters because it removes the barrier of…\"</li>\n<li>\"However, this change might not help everyone, because…\"</li>\n</ul>", "check": {"question": "Why is it useful to link an emerging sport''s growth back to the popularity factors from 1.4?", "options": ["Because it lets you reuse understanding you already have, applied to a new example", "Because emerging sports use a completely different, unrelated set of factors", "Because the exam never asks about emerging sports in Section B or C", "Because popularity factors only ever apply to sports that are already well established"], "answer": 0, "explain": "The same factors (media, role models, provision, accessibility, social acceptability) explain growth for both established and emerging sports, so you can reuse what you already know."}}]}, "exam": {"enabled": true, "questions": [{"question": "Identify <strong>two</strong> examples of emerging or new sports currently growing in the UK.", "marks": 2, "hint": "Pick any two real emerging sports — for example padel, walking football, ultimate frisbee, or a fast-growing form of competitive gaming.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks (AO1)</h5>\n<p><strong>1 mark for each correct, DIFFERENT emerging or new sport named, to a maximum of two. Accept any genuine example, including:</strong></p>\n<ul>\n<li>Padel</li>\n<li>Walking football</li>\n<li>Ultimate frisbee</li>\n<li>Competitive gaming / esports</li>\n<li>Any other sport the student can justify as newly growing in the UK</li>\n</ul>\n<p>Do not credit the same sport written twice.</p>\n</div>"}, {"question": "Which factor is most likely to help an emerging sport attract first-time participants?", "marks": 1, "hint": "Think about what actually introduces new people to a sport they''ve never seen before.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: B — Short clips of the sport being shared widely on social media.</strong></p>\n<ul>\n<li>Wide social media exposure introduces the sport to people who would never otherwise see it played.</li>\n<li>Removing sessions, closing facilities or raising prices would each make it harder, not easier, to attract first-timers.</li>\n</ul>\n</div>"}, {"question": "Explain how Northfield Padel Club''s launch could help padel grow as an emerging sport.", "marks": 4, "hint": "Look for TWO separate factors in the scenario (a role model/media point, and a low-cost/accessible point) and explain why each one helps growth.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (AO2: application)</h5>\n<p><strong>Up to 2 marks per factor: 1 for identifying a relevant factor from the scenario, 1 for explaining why it helps growth. Answers may include:</strong></p>\n<ul>\n<li><strong>Role model / media exposure</strong> — the ex-professional player and the social media clips reach people who would never otherwise see padel being played, raising awareness that the sport, and the club, exist.</li>\n<li><strong>Free, accessible entry point</strong> — the free open day removes cost as a barrier, letting unsure or curious people try padel with nothing to lose.</li>\n</ul>\n<p>Accept any other reasonable, scenario-linked answer. A factor with no explanation, or an explanation not linked to the scenario, earns 1 of the 2 marks for that factor.</p>\n</div>"}, {"question": "Discuss how a new or emerging sport could increase its participation in the UK.", "marks": 8, "hint": "Choose two or three factors (media/role models, provision/facilities, accessible/low-cost formats). Explain how each helps, then weigh up the limits. Finish with a judgement on which matters most.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 8 marks (level-of-response). Read the band you fit, then pick a mark.</h5>\n<ul>\n<li><strong>Band 3 (thorough), 6–8:</strong> a balanced, well-applied discussion of several factors, showing clearly how each could raise participation AND weighing the limits (funding, whether exposure is followed up with real provision, one factor not being enough alone), ending in a justified judgement.</li>\n<li><strong>Band 2 (reasonable), 3–5:</strong> sound understanding applied to more than one factor with some analysis, but the discussion may be one-sided or the judgement unsupported.</li>\n<li><strong>Band 1 (basic), 1–2:</strong> names factors and/or sports with little application and no real evaluation; largely a list.</li>\n<li><strong>0 marks:</strong> nothing creditworthy.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Indicative content (indicative, not a checklist — reward valid alternatives)</h5>\n<ul>\n<li><strong>Media coverage / role models:</strong> a well-known player or online clips introduce the sport to people who had never seen it, raising awareness.</li>\n<li><strong>Provision / facilities:</strong> new courts, clubs or sessions give newly-aware people somewhere nearby to actually try the sport.</li>\n<li><strong>Accessible, low-cost formats:</strong> free taster sessions or adapted rules remove cost and confidence as barriers, especially for beginners.</li>\n<li><strong>Evaluation:</strong> awareness rarely converts into participation if no local provision follows it up; new facilities depend on funding that councils or clubs may not always have; a role model''s effect may fade quickly if there is nothing local to join afterwards.</li>\n<li><strong>Judgement:</strong> combining exposure with genuine, affordable local provision is more likely to sustain growth than any single factor alone, because awareness without a place to try the sport rarely leads anywhere.</li>\n</ul>\n</div>"}]}}'::jsonb),
('sport-studies', '2-1-values-promoted-through-sport', '2.1 Values Promoted Through Sport', '{"learn": {"enabled": true, "items": [{"title": "What ''values promoted through sport'' means", "html": "<h4>The idea</h4>\n<ul>\n<li>Taking part in sport is not only about physical activity — it can also build <strong>positive attitudes and behaviours</strong> that matter in everyday life, both on the pitch and off it.</li>\n<li>The specification names seven values that sport can promote: <strong>team spirit, fair play, citizenship, tolerance and respect, inclusion, national pride</strong> and <strong>excellence</strong>.</li>\n</ul>\n<h4>The trap the exam is designed to catch</h4>\n<ul>\n<li><strong>\"Tolerance and respect\" is ONE combined value, not two.</strong> Students often write them as two separate values to try to pick up two marks — that loses marks rather than gaining them, because the mark scheme only credits it once.</li>\n<li>Together they mean gaining a <strong>greater understanding of other cultures</strong> and ways of doing things through contact with people in sport.</li>\n</ul>\n<h4>How to answer well</h4>\n<ul>\n<li>Every mark on this topic rewards <strong>naming the value AND giving a sporting example</strong> that actually shows it happening — never the name on its own.</li>\n</ul>", "check": {"question": "How many separate values does the specification treat ''tolerance'' and ''respect'' as?", "options": ["One — tolerance and respect are treated as a single combined value in the specification", "Two — tolerance and respect are two entirely separate values in the specification", "Three — tolerance, respect and understanding are three separate values in the specification", "Zero — neither tolerance nor respect appears anywhere in the specification"], "answer": 0, "explain": "Tolerance and respect are always marked as ONE combined value — writing them as two separate values does not earn two marks."}}, {"title": "Team spirit, fair play and citizenship", "html": "<h4>Team spirit</h4>\n<ul>\n<li><strong>Team spirit</strong> — supporting and encouraging your teammates as everyone works together toward a shared goal.</li>\n<li>Sporting example: a substitute who has not been picked to play still shouts encouragement from the bench, and players cover for a tired teammate rather than criticising them.</li>\n</ul>\n<h4>Fair play</h4>\n<ul>\n<li><strong>Fair play</strong> — following the rules honestly, never trying to cheat, and accepting decisions made by officials even when you disagree.</li>\n<li>Sporting example: a footballer tells the referee that the ball crossed the line for a throw-in even though the referee missed it and had given the decision the player''s way.</li>\n</ul>\n<h4>Citizenship</h4>\n<ul>\n<li><strong>Citizenship</strong> — using sport to build positive links and connections within the local community.</li>\n<li>Sporting example: players from a local club volunteer as coaches for a youth team, building stronger relationships across the neighbourhood.</li>\n</ul>", "check": {"question": "A substitute who is not selected to play still calls out encouragement to teammates working toward the same shared goal. Which value is this showing?", "options": ["Team spirit — supporting and encouraging teammates as everyone works toward a shared goal", "Fair play — following the written rules honestly and accepting every decision officials make", "Citizenship — using sport to build positive links within the local community", "Excellence — striving to be your best by giving maximum effort in competition"], "answer": 0, "explain": "Encouraging teammates toward a shared goal, even from the bench, is team spirit — not fair play, citizenship or excellence."}}, {"title": "Tolerance and respect, inclusion, national pride and excellence", "html": "<h4>Tolerance and respect (ONE value)</h4>\n<ul>\n<li>A greater understanding and appreciation of people from <strong>other cultures</strong> and backgrounds, gained through contact in sport.</li>\n<li>Sporting example: after the final whistle, two opponents from different countries swap shirts and thank each other for a hard-fought game.</li>\n</ul>\n<h4>Inclusion</h4>\n<ul>\n<li>Giving people from <strong>every social group</strong> an equal opportunity to take part, whatever their background, ability or gender.</li>\n<li>Sporting example: a walking-football session is deliberately opened up to players of any age, gender or fitness level.</li>\n</ul>\n<h4>National pride</h4>\n<ul>\n<li>Supporting a national team in a way that creates a <strong>shared sense of identity and unity</strong> among very different people.</li>\n<li>Sporting example: thousands of fans from many different backgrounds come together to cheer for the same national team at a major tournament.</li>\n</ul>\n<h4>Excellence</h4>\n<ul>\n<li>Striving to be your best by giving <strong>maximum effort</strong> and always trying to improve.</li>\n<li>Sporting example: an athlete pushes through a demanding training block purely to improve their own personal best time.</li>\n</ul>", "check": {"question": "A council builds stronger links across its town by running free sessions through local sports clubs. Which value does this best describe?", "options": ["National pride — supporting a national team creates one shared sense of identity and unity for everyone", "Citizenship — using sport to build positive links and connections within the local community", "Inclusion — giving people from every social group an equal opportunity to take part", "Tolerance and respect — a greater understanding and appreciation of another culture"], "answer": 1, "explain": "Building links within the local community through sport is citizenship, not national pride, inclusion or tolerance and respect."}}, {"title": "Naming a value isn''t enough — the exam skill", "html": "<h4>Naming is only the start</h4>\n<ul>\n<li>Weak answer: <em>\"A value sport promotes is fair play.\"</em> That names a value but shows no understanding.</li>\n<li>Strong answer: <em>\"Fair play is a value sport can promote — for example, a player telling the referee the ball crossed the line for a throw-in, even though the decision had gone their way.\"</em></li>\n<li>The mark almost always rewards <strong>linking the value to a real sporting example</strong>, not the name on its own.</li>\n</ul>\n<h4>Build every answer the same way</h4>\n<ul>\n<li><strong>Value → sporting example → what it shows.</strong> State the value, describe a moment in sport, then explain why that moment demonstrates the value.</li>\n<li>In a Section B scenario, use a detail <strong>from that scenario</strong> as your example rather than a general one you already had prepared.</li>\n</ul>", "check": {"question": "A question asks you to explain how sport can promote one named value. What is most likely to earn the marks?", "options": ["Naming the value and giving a sporting example that shows it happening", "Writing the value''s name clearly, underlined, in capital letters for emphasis", "Listing as many of the seven values as you can remember", "Describing your own favourite sporting fixture in detail"], "answer": 0, "explain": "Explain questions on this topic reward the value plus a sporting example that shows it — naming the value alone, or listing every value, earns little."}}]}, "terms": {"enabled": true, "pairs": [{"term": "Team spirit", "definition": "Supporting and encouraging teammates as everyone works toward a shared goal"}, {"term": "Fair play", "definition": "Following the rules honestly, never cheating, accepting officials'' decisions"}, {"term": "Citizenship", "definition": "Using sport to build positive links within the local community"}, {"term": "Tolerance and respect (ONE value)", "definition": "A greater understanding of other cultures gained through sport"}, {"term": "Inclusion", "definition": "Giving people from every social group an equal opportunity to take part"}, {"term": "National pride", "definition": "Supporting a national team creates a shared sense of identity and unity"}, {"term": "Excellence", "definition": "Striving to be your best by giving maximum effort and improving"}]}, "mcq": {"enabled": true, "questions": [{"question": "Which two ideas does the specification treat as ONE single combined value, not two separate values?", "options": ["Team spirit and fair play, because supporting teammates and following the rules are always the same thing", "Tolerance and respect, which together mean gaining a greater understanding of other cultures and backgrounds", "Inclusion and national pride, since giving everyone a fair chance to play is identical to supporting a country", "Citizenship and excellence, because building local community links is the same as striving to be your best"], "answer": 1, "explain": "Tolerance and respect are always marked as a single combined value. The other three pairs (team spirit/fair play, inclusion/national pride, citizenship/excellence) are all separate values."}, {"question": "A substitute who has not been picked to play still shouts encouragement to teammates chasing a shared goal. Which value is this?", "options": ["Team spirit — supporting and encouraging teammates while everyone works toward the same shared goal", "Fair play — following the written rules of the game and never attempting to cheat an opponent", "National pride — supporting a national team so that lots of very different people feel one shared sense of identity", "Excellence — pushing yourself with maximum effort so that your own performance keeps improving"], "answer": 0, "explain": "Encouraging teammates toward a shared goal, even without playing, is team spirit — the other options describe fair play, national pride and excellence instead."}, {"question": "A local sports club runs free junior coaching sessions and builds stronger links across its neighbourhood. Which value does this best show?", "options": ["Inclusion — making sure people from every social group get an equal opportunity to take part", "Citizenship — using sport to build positive links and connections within the local community", "National pride — creating a shared sense of identity by supporting the same national team", "Fair play — competing honestly, following the rules and accepting decisions made by officials"], "answer": 1, "explain": "Building links within the local community through a club''s coaching sessions is citizenship — not inclusion, national pride or fair play."}, {"question": "After the final whistle, two opponents from different countries swap shirts and thank each other for a hard-fought game. Which value does this best show?", "options": ["National pride — a shared sense of identity created by supporting the same national team", "Excellence — striving to be your best and always giving maximum effort in competition", "Tolerance and respect — a greater understanding and appreciation of another culture", "Team spirit — supporting teammates as they work together toward one shared goal"], "answer": 2, "explain": "Appreciating an opponent from a different culture after the game shows tolerance and respect, not national pride, excellence or team spirit."}, {"question": "A walking-football session is deliberately opened up to players of any age, gender or fitness level. Which value does this best show?", "options": ["Fair play — following the agreed rules of the game and accepting the referee''s decisions", "Excellence — trying your hardest to keep improving your own personal performance", "Inclusion — giving people from every social group an equal opportunity to take part", "Citizenship — building positive links and connections within the local community"], "answer": 2, "explain": "Welcoming every age, gender and fitness level is inclusion — not fair play, excellence or citizenship."}, {"question": "Thousands of fans from many different backgrounds come together to cheer for the same national team at a major tournament. Which value does this best show?", "options": ["Citizenship — using sport to build stronger links and connections within a local community", "Fair play — competing honestly, following the rules, and accepting the officials'' decisions", "Inclusion — giving people from every social group an equal chance to take part in sport", "National pride — supporting a national team creates a shared sense of identity and unity"], "answer": 3, "explain": "Fans of different backgrounds uniting behind one national team is national pride — not citizenship, fair play or inclusion."}]}, "fib": {"enabled": true, "questions": [{"text": "Team [spirit] means supporting and encouraging your teammates as you work together toward a shared goal."}, {"text": "Fair play means following the rules honestly and never trying to [cheat] an opponent."}, {"text": "Citizenship means using sport to build positive links within the local [community]."}, {"text": "Tolerance and respect together mean gaining a greater understanding of other [cultures]."}, {"text": "Inclusion means giving people from every social group an equal [opportunity] to take part."}, {"text": "Excellence means striving to be your best by giving maximum [effort]."}]}, "tf": {"enabled": true, "questions": [{"statement": "Tolerance and respect are treated as one combined value in the specification, not two separate values.", "answer": true, "explain": "Writing them as two separate values does not earn extra marks — the mark scheme only credits this once, as a single combined value."}, {"statement": "Team spirit only applies to players who are actually selected to play in a match.", "answer": false, "explain": "A substitute or non-playing squad member can still show team spirit by encouraging and supporting the team from the sidelines."}, {"statement": "Citizenship in this context means the same thing as legally holding a passport for a country.", "answer": false, "explain": "Citizenship here means building positive links within the local community through sport — it has nothing to do with passports or nationality."}, {"statement": "National pride can bring people from very different backgrounds together to support the same team.", "answer": true, "explain": "Supporting a national team can create a shared sense of identity and unity across people who otherwise have little in common."}, {"statement": "Inclusion means that only people with a disability should be given the opportunity to take part.", "answer": false, "explain": "Inclusion means giving people from every social group an equal opportunity — not restricting participation to just one group."}, {"statement": "Excellence simply means winning every competition you enter.", "answer": false, "explain": "Excellence means striving to be your best and giving maximum effort to improve — it is not the same as always winning."}]}, "misc": {"enabled": true, "items": [{"myth": "Tolerance and respect are two separate values, so I can list them separately to pick up two marks.", "truth": "They are always marked as ONE combined value. Writing ''tolerance'' and ''respect'' as two different values on an ''identify two values'' question does not earn two marks — it usually earns one at most, because the examiner sees it as the same value written twice.", "check": {"question": "On an ''identify two values'' question, writing ''tolerance'' then ''respect'' as your two answers usually earns...", "options": ["Two marks, because they are two separate values in the specification", "One mark at most, because they are one combined value written twice", "Zero marks, because neither word appears in the specification at all", "Bonus marks for extra detail beyond what was asked"], "answer": 1, "explain": "Tolerance and respect count as one value, so giving both words as your ''two'' values usually earns only one mark, not two."}}, {"myth": "National pride is basically the same idea as citizenship, because both are about people coming together.", "truth": "They are different ideas the exam keeps side by side. National pride is about supporting a national TEAM, creating a shared identity across the whole country. Citizenship is about building links within a LOCAL community, such as through a club. A question can ask about either, so keep the scale (national vs local) clear.", "check": {"question": "What is the key difference between national pride and citizenship?", "options": ["There is no real difference at all — the two ideas mean exactly the same thing, always", "National pride is about a national team; citizenship is about local community links", "Citizenship only applies to professional athletes, never to amateurs", "National pride can only be shown by people who play for their country"], "answer": 1, "explain": "National pride works at a national scale (supporting the national team); citizenship works at a local scale (community links through sport)."}}, {"myth": "Naming a value like ''fair play'' is enough to get the mark on its own.", "truth": "Naming is only the first step. The mark scheme rewards linking the value to a sporting example that actually shows it happening. Weak answer: \"Fair play.\" Full-marks answer: \"Fair play — a player tells the referee the ball crossed the line even though the decision had gone their way.\"", "check": {"question": "A question asks you to explain how sport promotes one value. What is needed for full marks?", "options": ["The value''s name only, written out clearly and neatly on the line", "The value''s name PLUS a sporting example that shows it", "A list of every value you can remember", "A description of your own favourite team"], "answer": 1, "explain": "Full marks need the value named and a sporting example linked to it — the name alone does not show understanding."}}, {"myth": "Excellence just means winning every match or competition you take part in.", "truth": "Excellence means striving to be your best and giving maximum effort, whether or not you actually win. An athlete who trains hard and improves their personal best is showing excellence even in a competition they lose.", "check": {"question": "Which of these best shows the value of excellence?", "options": ["An athlete who wins a competition very easily without ever trying that hard at all", "An athlete who trains hard and improves their personal best, even after losing", "A team that refuses to shake hands with the opposition after a narrow defeat", "A crowd that boos the away team throughout an entire match"], "answer": 1, "explain": "Excellence is about maximum effort and self-improvement, not the result — the athlete who improves their best time shows it even in defeat."}}]}, "tips": {"enabled": true, "items": [{"title": "Command words for this topic — what each one wants", "html": "<p>Values questions are usually short. Match your answer length to the command word:</p>\n<ul>\n<li><strong>Identify / State</strong> — just name it. \"Identify two values sport can promote\" = write two value names, nothing more. 1 mark each.</li>\n<li><strong>Describe</strong> — say what the value looks like in practice, without needing a full reason.</li>\n<li><strong>Explain</strong> — give a sporting example and link it to the value. \"Explain how sport can promote fair play\" = name fair play, then give an example that shows it.</li>\n</ul>\n<p><strong>Read the mark tariff:</strong> [1] wants one point; [2] usually wants two points, or one point developed with an example; [4] in Section B wants points applied to the given scenario.</p>", "check": {"question": "A question says: ''Identify two values sport can promote [2]''. What is the safest answer?", "options": ["A long paragraph describing one value in detail", "Two value names, nothing more", "One value name with a full sporting example attached", "A list of six or seven different values"], "answer": 1, "explain": "''Identify'' + [2] = two names, one mark each. Explaining one value in depth, or listing extra values, wastes time without extra credit."}}, {"title": "The golden rule: value AND a sporting example", "html": "<p>The single most common way to lose marks here is stopping at the value''s name. Build every answer as <strong>value → sporting example → what it shows</strong>:</p>\n<ul>\n<li><strong>❌ 0–1 marks:</strong> \"Fair play.\"</li>\n<li><strong>✅ full marks:</strong> \"Fair play — a player tells the referee the ball crossed the line even though the decision had gone in their favour.\"</li>\n</ul>\n<p>In <strong>Section B</strong> the question gives you a scenario (a named event, club or person). Then you must use a detail <em>from that scenario</em> as your example, not one you already had prepared.</p>", "check": {"question": "In a Section B scenario question about a named event, your sporting example should come from...", "options": ["absolutely any sport you happen to like", "the scenario you are given", "a famous athlete not mentioned in the scenario", "your own school sports day only"], "answer": 1, "explain": "Section B is applied — the marks are for using the scenario in front of you, not a prepared general example."}}, {"title": "Where values appear + sentence starters", "html": "<p><strong>Where it shows up:</strong> values appear as quick recall in <strong>Section A</strong> (identify/state), as applied points in <strong>Section B</strong> scenarios about a club or event, and feed <strong>Section C</strong> 8-mark answers about how far sport really promotes positive values.</p>\n<p><strong>Three punchy tips:</strong></p>\n<ul>\n<li>Learn the seven values in threes — team spirit/fair play/citizenship, then tolerance & respect/inclusion, then national pride/excellence — so you can always recall a few.</li>\n<li>For every value, memorise <em>one</em> ready-made sporting example — that example is usually where the mark is.</li>\n<li>Never split tolerance and respect into two values — it is one, and treating it as two costs marks rather than gaining them.</li>\n</ul>\n<p><strong>Sentence starters for a longer answer:</strong></p>\n<ul>\n<li>\"One way sport promotes positive values is… because…\"</li>\n<li>\"This matters because it shows…\"</li>\n<li>\"On the other hand, this value might not always be shown, because…\"</li>\n</ul>", "check": {"question": "Why is it risky to write ''tolerance'' and ''respect'' as two separate answers on an ''identify'' question?", "options": ["It is not risky at all, and it always earns full marks either way, every time", "They are one combined value, so it usually earns only one mark, not two", "The examiner will refuse to mark the question at all", "It means you cannot use either word anywhere else in the exam"], "answer": 1, "explain": "Because tolerance and respect are one combined value, giving both words as separate answers usually earns only one mark rather than two."}}]}, "exam": {"enabled": true, "questions": [{"question": "Identify <strong>two</strong> values that sport can promote.", "marks": 2, "hint": "Pick from team spirit, fair play, citizenship, tolerance and respect (as one value), inclusion, national pride, or excellence.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks (AO1)</h5>\n<p><strong>1 mark for each correct value named, to a maximum of two. Accept any two DIFFERENT values, including:</strong></p>\n<ul>\n<li>Team spirit</li>\n<li>Fair play</li>\n<li>Citizenship</li>\n<li>Tolerance and respect (counts as ONE value)</li>\n<li>Inclusion</li>\n<li>National pride</li>\n<li>Excellence</li>\n</ul>\n<p>Do not credit the same value written twice, and do not credit ''tolerance'' and ''respect'' as two separate answers.</p>\n</div>"}, {"question": "Two opponents from different countries swap shirts after a match, showing an appreciation of each other''s culture. Which value does this show?", "marks": 1, "hint": "Think about which value is specifically about understanding people from other cultures.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: B — Tolerance and respect.</strong></p>\n<ul>\n<li>Appreciating an opponent''s culture after a hard-fought game is the definition of tolerance and respect.</li>\n<li>The other options describe national pride, excellence and team spirit instead, none of which is about understanding another culture.</li>\n</ul>\n</div>"}, {"question": "Explain how the Bellmoor Community Sports Day could promote <strong>two</strong> different values covered in this topic.", "marks": 4, "hint": "Take each value in turn. Name the value, then use a detail FROM the scenario (the local clubs, or the mixed-ability tournament) as your sporting example.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (AO2: application)</h5>\n<p><strong>Up to 2 marks per value: 1 for naming a relevant value, 1 for linking it to a detail from the scenario. Answers may include:</strong></p>\n<ul>\n<li><strong>Citizenship</strong> — local clubs running sessions together builds links and connections within the Bellmoor community.</li>\n<li><strong>Inclusion</strong> — the mixed-ability five-a-side tournament gives people of any age or experience an equal opportunity to take part.</li>\n</ul>\n<p>Accept any other reasonable, applied value (e.g. team spirit, if linked to players supporting each other in the tournament). A value named with no scenario detail earns 1 of the 2 marks for that value.</p>\n</div>"}, {"question": "Discuss the extent to which an event like Northfield''s Mini Games promotes positive values among the students who take part.", "marks": 8, "hint": "Choose two or three values. For each, use a detail from the scenario as your example. Then weigh it up — are there limits to how much the event really changes attitudes? Finish with a judgement.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 8 marks (level-of-response). Read the band you fit, then pick a mark.</h5>\n<ul>\n<li><strong>Band 3 (thorough), 6–8:</strong> a balanced, well-applied discussion of several values, showing clearly how the event promotes them AND weighing the limits (a one-off day, values only lasting if reinforced), ending in a justified judgement.</li>\n<li><strong>Band 2 (reasonable), 3–5:</strong> sound understanding applied to more than one value with some analysis, but the discussion may be one-sided or the judgement unsupported.</li>\n<li><strong>Band 1 (basic), 1–2:</strong> names values with little application to the scenario and no real evaluation; largely a list.</li>\n<li><strong>0 marks:</strong> nothing creditworthy.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Indicative content (indicative, not a checklist — reward valid alternatives)</h5>\n<ul>\n<li><strong>Team spirit:</strong> mixed-year house teams push students to support classmates they do not normally play alongside.</li>\n<li><strong>Inclusion:</strong> a wheelchair-accessible relay open to all students gives every student an equal opportunity to take part, not just the most able.</li>\n<li><strong>National pride (at school scale):</strong> parading each house''s flag builds a shared sense of identity within that house.</li>\n<li><strong>Evaluation:</strong> values shown on a single sports day may not carry over into everyday school life unless reinforced regularly; some students may still be left out if the day is dominated by the most competitive teams; the impact likely depends on how the school follows the day up.</li>\n<li><strong>Judgement:</strong> an event like the Mini Games is a strong opportunity to promote values such as inclusion and team spirit in one focused day — but it only builds lasting positive attitudes if the school reinforces those values afterwards, rather than treating it as a one-off.</li>\n</ul>\n</div>"}]}}'::jsonb),
('sport-studies', '2-2-the-olympic-paralympic-movement', '2.2 The Olympic & Paralympic Movement', '{"learn": {"enabled": true, "items": [{"title": "The Olympic Creed — the idea behind it", "html": "<h4>What the Creed is</h4>\n<ul>\n<li>The <strong>Olympic Creed</strong> is a short statement of the philosophy behind Olympic competition — it sums up what the Games are really meant to be about.</li>\n<li>Its core idea, in plain terms: genuine sporting achievement comes from the honesty of your effort and the personal challenge of competing at your very best — not simply from whether you walk away with a medal.</li>\n</ul>\n<h4>Why this trips people up</h4>\n<ul>\n<li>Some students read this and think it means \"trying doesn''t matter, just show up.\" That is the <strong>opposite</strong> of the idea — the Creed is about giving a maximum, honest effort in the contest itself, whatever the final result turns out to be.</li>\n<li>An athlete who competes flat-out and finishes eighth has lived out the Creed far more than one who wins by cheating or by barely trying at all.</li>\n<li>Exam answers that just say \"it means taking part\" without mentioning honest effort or personal best usually miss the real point the mark scheme is after.</li>\n</ul>", "check": {"question": "Which of these best captures the idea behind the Olympic Creed?", "options": ["The Creed says that simply turning up to the stadium is enough, and no real effort is required once the event actually begins at all", "The Creed says that only athletes who win a medal have achieved anything worth celebrating at the Games", "The Creed says that genuine sporting success comes from an honest, maximum effort in competing, not only from winning", "The Creed says that athletes should beat their rivals by whatever method proves necessary to win"], "answer": 2, "explain": "The Creed is about honest, maximum effort in the competition itself — not about turning up without trying, not about medals alone, and not about winning by any means necessary."}}, {"title": "The Olympic symbol — the five rings", "html": "<h4>What the symbol shows</h4>\n<ul>\n<li>The Olympic symbol is <strong>five interlocking rings</strong>.</li>\n<li>The rings represent the <strong>coming together of the five continents of the world through sport</strong> — the whole point is unity, athletes from every part of the globe meeting in one competition.</li>\n</ul>\n<h4>The trap to avoid</h4>\n<ul>\n<li>A common mistake is assuming each ring is permanently \"assigned\" to one specific continent by its colour, as if it were a fixed key. The exam-relevant idea is simpler and more important: the rings are <strong>interlocking</strong> (linked, not separate) to show connection and unity, not a strict colour-to-continent code.</li>\n<li>If a question asks what the rings represent, the safe, testable answer is \"the coming together of the five continents through sport\" — not a list of which colour belongs to which continent.</li>\n</ul>", "check": {"question": "What do the five interlocking rings on the Olympic symbol represent?", "options": ["The coming together of the five continents of the world through sport", "Five colours that are each permanently fixed to one particular continent", "Five nations that are the only countries ever allowed to host the Games", "Five separate sports that must always feature at every single Olympic Games"], "answer": 0, "explain": "The rings symbolise unity — the five continents coming together through sport. They are not a fixed colour-to-continent code, a list of host nations, or a list of sports."}}, {"title": "The Olympic values: Excellence, Friendship, Respect", "html": "<h4>The three Olympic values</h4>\n<ul>\n<li><strong>Excellence</strong> — striving to give your very best performance and to keep improving, measured against your own personal standard as well as against other competitors.</li>\n<li><strong>Friendship</strong> — the relationships, understanding and connections that competing together can build between people from different countries and backgrounds.</li>\n<li><strong>Respect</strong> — fair play, and consideration for the rules, for your opponents, for officials, and for yourself (including competing without banned substances).</li>\n</ul>\n<h4>How to use them in an answer</h4>\n<ul>\n<li>Don''t just name the value — link it to a behaviour. \"Excellence\" on its own earns little; \"Excellence, because the athlete kept improving their own personal best time\" shows real understanding.</li>\n<li>These three values belong to the <strong>Olympic</strong> Games specifically — keep them separate in your memory from the Paralympic set below.</li>\n</ul>", "check": {"question": "Which three values are the Olympic values?", "options": ["Excellence, Friendship and Respect", "Courage, Determination and Inspiration", "Speed, Power and Endurance", "Excellence, Determination and Equality"], "answer": 0, "explain": "The three Olympic values are Excellence, Friendship and Respect. The other options either mix in Paralympic values or use words that aren''t official values at all."}}, {"title": "The Paralympic values: Courage, Determination, Inspiration, Equality", "html": "<h4>The four Paralympic values</h4>\n<ul>\n<li><strong>Courage</strong> — the mental strength to face a real challenge and perform under pressure, even when the odds feel stacked against you.</li>\n<li><strong>Determination</strong> — refusing to give up despite setbacks, and pushing on to reach your full potential.</li>\n<li><strong>Inspiration</strong> — using your performance to motivate other people and change how they see what is possible.</li>\n<li><strong>Equality</strong> — showing that every competitor deserves the same fair opportunity to take part and to be recognised on equal terms, whatever their impairment.</li>\n</ul>\n<h4>The #1 trap the exam tests</h4>\n<ul>\n<li>Students very often mix up which set a value belongs to — for example, writing \"Courage\" as an Olympic value, or \"Excellence\" as a Paralympic value. They are two separate, named lists: <strong>Olympic</strong> = Excellence/Friendship/Respect; <strong>Paralympic</strong> = Courage/Determination/Inspiration/Equality.</li>\n<li>\"Equality\" here is broader than just fairness after the event — it is about equal opportunity to compete and be valued as an athlete in the first place.</li>\n</ul>", "check": {"question": "Which four values are the Paralympic values?", "options": ["The four Paralympic values are Courage, Determination, Inspiration and Equality", "The four Paralympic values are Excellence, Friendship, Respect and Equality", "The four Paralympic values are Strength, Speed, Power and Precision", "The four Paralympic values are Determination, Excellence, Respect and Courage, in that order"], "answer": 0, "explain": "The four Paralympic values are Courage, Determination, Inspiration and Equality. The other options either borrow Olympic values or use words that aren''t the official set."}}]}, "terms": {"enabled": true, "pairs": [{"term": "Olympic Creed", "definition": "The idea that honest, maximum effort in competing matters as much as the final result"}, {"term": "Excellence", "definition": "Olympic value: striving to reach your own personal best, not only beating others"}, {"term": "Friendship", "definition": "Olympic value: the bonds and understanding competing together can build across cultures"}, {"term": "Respect", "definition": "Olympic value: fair play and consideration for rules, opponents and yourself"}, {"term": "Courage", "definition": "Paralympic value: the mental strength to face and overcome a real challenge"}, {"term": "Determination", "definition": "Paralympic value: refusing to give up despite setbacks, pushing toward a goal"}, {"term": "Inspiration", "definition": "Paralympic value: using a performance to motivate people and change their thinking"}, {"term": "Equality", "definition": "Paralympic value: every competitor given the same fair chance to take part and be recognised"}]}, "mcq": {"enabled": true, "questions": [{"question": "A student says the Olympic Creed means ''you don''t need to try, just turn up.'' What is wrong with this understanding?", "options": ["Nothing is wrong — turning up without trying is exactly what the Creed asks of every athlete taking part", "The Creed actually asks for an honest, maximum effort during the competition itself, not just attendance", "The Creed is only about winning medals, so how hard an athlete tries does not matter at all", "The Creed has nothing to do with how much effort an athlete puts in once the competition starts"], "answer": 1, "explain": "The Creed is about giving an honest, maximum effort in the event itself — not about attendance alone, and not that effort is irrelevant."}, {"question": "Why are the five Olympic rings drawn interlocking rather than as five separate shapes?", "options": ["To show the continents connecting and coming together through sport", "To show that each continent must compete completely separately from every other continent", "To make the symbol easier to print in a single colour on flags and posters", "To represent five different events that always take place at every single Games"], "answer": 0, "explain": "Interlocking rings show connection and unity between the continents. They are not about printing convenience, separation, or a fixed set of events."}, {"question": "''Inspiration'' as an official sporting value is most closely associated with which movement?", "options": ["The Olympic Movement only, and never the Paralympic Movement", "The Paralympic Movement", "Neither movement — inspiration is not an official value of either one", "Only one-off events that have no connection to the Olympic or Paralympic Games"], "answer": 1, "explain": "Inspiration is one of the four Paralympic values (with Courage, Determination and Equality) — it is not one of the three Olympic values."}, {"question": "A performer trains hard to beat their own personal best time, even though they already know they will not win a medal this time. Which Olympic value does this best show?", "options": ["Excellence — striving to reach your personal best, not only aiming to beat other people", "Friendship — building relationships with competitors from other countries and backgrounds", "Equality — making sure every competitor is given the same fair opportunity to take part", "Courage — finding the mental strength needed to perform well under real pressure"], "answer": 0, "explain": "Chasing your own personal best, regardless of the medal outcome, is Excellence. Friendship is about relationships, Equality about fair opportunity, and Courage is a Paralympic value, not Olympic."}, {"question": "Two competitors shake hands and congratulate one another after a hard-fought, fairly contested race. Which Olympic value does this best demonstrate?", "options": ["Friendship — the bonds and understanding that competing together can build between people", "Respect — for the rules, for each other, and for the spirit of fair competition", "Determination — refusing to give up despite the real difficulty of the challenge faced", "Inspiration — using a performance to motivate and change how other people think"], "answer": 1, "explain": "Fair, gracious behaviour toward an opponent after a clean contest is Respect. Friendship is about wider bonds, and Determination/Inspiration are Paralympic values, not Olympic."}, {"question": "An athlete recovering from a serious injury refuses to give up on training and eventually competes again. Which Paralympic value does this best show?", "options": ["Equality — showing that every competitor deserves the same fair chance to take part", "Excellence — striving to reach the highest personal standard that you possibly can", "Determination — refusing to give up despite setbacks, and pushing on toward a goal", "Respect — following the rules and treating opponents and officials fairly"], "answer": 2, "explain": "Pushing through setbacks without giving up is Determination. Equality is about fair opportunity, Excellence is an Olympic value, and Respect is about fair play, not perseverance."}]}, "fib": {"enabled": true, "questions": [{"text": "The Olympic symbol is made up of five interlocking [rings]."}, {"text": "The five rings represent the coming together of the five [continents] through sport."}, {"text": "The three Olympic values are Excellence, Friendship and [Respect]."}, {"text": "The four Paralympic values are Courage, Determination, Inspiration and [Equality]."}, {"text": "The Olympic Creed teaches that honest effort matters as much as the final [result]."}, {"text": "Determination is a Paralympic value about refusing to give [up] despite setbacks."}]}, "tf": {"enabled": true, "questions": [{"statement": "The Olympic Creed teaches that honest, maximum effort matters as much as the final result.", "answer": true, "explain": "That is the core idea — genuine sporting success comes from the honesty of your effort, not only from whether you win."}, {"statement": "The five Olympic rings represent five specific nations that are the only countries ever allowed to host the Games.", "answer": false, "explain": "The rings represent the coming together of the five continents through sport — they are not a fixed list of host nations."}, {"statement": "Excellence, Friendship and Respect are the three Olympic values.", "answer": true, "explain": "Correct — these three values belong to the Olympic Games specifically."}, {"statement": "Courage, Determination, Inspiration and Equality are the four Olympic values.", "answer": false, "explain": "These four are the Paralympic values, not the Olympic values. Mixing the two sets up is a very common mistake."}, {"statement": "Determination is a Paralympic value about refusing to give up despite setbacks.", "answer": true, "explain": "Correct — Determination is about pushing on toward a goal even when things go wrong."}, {"statement": "The Olympic Creed means an athlete never needs to try hard once the competition begins.", "answer": false, "explain": "The opposite is true — the Creed is specifically about giving an honest, maximum effort during the competition."}]}, "misc": {"enabled": true, "items": [{"myth": "Students often think the Olympic Creed means trying doesn''t matter, as long as you show up.", "truth": "It means the opposite. The Creed is about giving an honest, maximum effort in the contest itself — the taking part has to involve genuinely trying your best, not just being present. An athlete who competes flat-out and finishes last has lived out the idea far more than one who barely tries.", "check": {"question": "What is wrong with saying the Olympic Creed means ''just show up, effort doesn''t matter''?", "options": ["Nothing is wrong — that is exactly what the Creed asks of every competitor, regardless of effort, at all", "The Creed actually requires an honest, maximum effort during the event itself, not just attendance", "The Creed only ever applies to athletes who go on to win an official medal", "The Creed was written specifically to discourage athletes from trying their hardest"], "answer": 1, "explain": "The Creed asks for genuine, maximum effort in the competition — attendance alone, without trying, is not what the idea describes."}}, {"myth": "Some students think each of the five Olympic rings is permanently tied to one single, fixed continent by its colour.", "truth": "The exam-relevant idea is unity, not a colour key. The rings are drawn interlocking specifically to show the continents connecting and coming together through sport — that is the point being tested, not a strict one-ring-one-continent colour code.", "check": {"question": "What is the exam-relevant point about the five interlocking Olympic rings?", "options": ["Each ring''s colour is permanently and officially fixed to one single specific continent", "The rings show the continents connecting and coming together through sport", "The rings represent five completely different sports played at every single Games", "The rings show exactly which nations are allowed to host only the Winter Games"], "answer": 1, "explain": "The tested idea is unity — the continents coming together — not a colour-to-continent lookup table, a list of sports, or host nations."}}, {"myth": "A very common mistake is mixing up which values belong to the Olympics and which belong to the Paralympics — for example, saying ''Courage'' is an Olympic value.", "truth": "Keep the two lists completely separate. Olympic values = Excellence, Friendship, Respect (three values). Paralympic values = Courage, Determination, Inspiration, Equality (four values). If your answer swaps a value between the two lists, it loses the mark even if the value itself is spelled correctly.", "check": {"question": "Which of these correctly sorts a value into its own movement?", "options": ["Courage is officially counted as one of the three Olympic values", "Respect is officially counted as one of the four Paralympic values", "Determination is one of the four Paralympic values", "Friendship is officially counted as one of the four Paralympic values"], "answer": 2, "explain": "Determination is genuinely one of the four Paralympic values. The other options wrongly place a value in the opposite movement''s list."}}, {"myth": "Students sometimes think ''Equality'' as a Paralympic value only means para-athletes should be treated the same as everyone else once the Games are already over.", "truth": "Equality is broader than that. It is about every competitor being given the same fair opportunity to take part and to be recognised as an athlete in the first place — before, during and after competition — whatever their impairment, not just a rule about treatment after the event has finished.", "check": {"question": "What does ''Equality'' as a Paralympic value actually cover?", "options": ["Only how athletes are treated once the Olympic and Paralympic Games have already finished", "Fair opportunity to take part and be recognised as an athlete, at every stage", "Making sure that every single athlete wins exactly the same number of medals", "Only which particular sports are included in the Paralympic programme itself"], "answer": 1, "explain": "Equality covers fair opportunity and recognition throughout, not only post-event treatment, medal counts, or the sports programme."}}]}, "tips": {"enabled": true, "items": [{"title": "Command words for this topic — what each one wants", "html": "<p>Questions on the Creed, the symbol and the values are usually short and precise. Match your answer length to the command word:</p>\n<ul>\n<li><strong>Identify / State</strong> — just name it. \"Identify two Olympic values [2]\" = two correct names, nothing more.</li>\n<li><strong>Describe</strong> — say what it is or what it involves. \"Describe the Olympic symbol [2]\" = the rings, interlocking, representing the continents.</li>\n<li><strong>Explain</strong> — give a reason, using the word <em>because</em>. \"Explain how an athlete showed Determination\" = name the value <em>and</em> link it to what they actually did.</li>\n</ul>\n<p><strong>Read the mark tariff:</strong> [1] wants one point; [2] usually wants two points, or one point plus a short reason; higher tariffs in Section B/C want the value applied to the scenario, not just named.</p>", "check": {"question": "A question says: ''Identify two Paralympic values [2]''. What is the safest answer?", "options": ["A long paragraph describing one value in detail", "Two correct Paralympic value names", "One value name plus a lengthy explanation", "A list of all seven Olympic and Paralympic values"], "answer": 1, "explain": "''Identify'' + [2] = two correct names, one mark each. A long paragraph on one value, or a list of every value, wastes time for no extra credit."}}, {"title": "Don''t muddle Olympic and Paralympic values", "html": "<p>The single most common way to lose marks on this topic is placing a value in the wrong list. Learn them as two separate groups, and check every answer against the count:</p>\n<ul>\n<li><strong>Olympic values (three):</strong> Excellence, Friendship, Respect.</li>\n<li><strong>Paralympic values (four):</strong> Courage, Determination, Inspiration, Equality.</li>\n</ul>\n<p>If an answer names four \"Olympic values\" or three \"Paralympic values\", the count itself tells you a value has been placed in the wrong list before you even check which one.</p>", "check": {"question": "A student writes that the Olympic values are ''Excellence, Friendship, Respect and Courage'' — four values. What is the quickest way to spot the error?", "options": ["There is absolutely nothing wrong with including a fourth, different value in that same list of values itself", "The Olympic values are only three, so a fourth name means one has been borrowed from the Paralympic list", "Courage should simply replace Excellence as the third value in that same list", "The order that the four values happen to be written in is what is incorrect"], "answer": 1, "explain": "The Olympic values are exactly three (Excellence, Friendship, Respect). A fourth name — Courage — signals a Paralympic value has been mixed in by mistake."}}, {"title": "Where this topic appears + sentence starters", "html": "<p><strong>Where it shows up:</strong> the Creed, the symbol and the two value lists appear as quick recall in <strong>Section A</strong> (identify/state/describe), and as applied points in <strong>Section B</strong> scenarios about a sporting event or a performer''s behaviour. They can also feed a longer discussion of how sport promotes positive attitudes.</p>\n<p><strong>Three punchy tips:</strong></p>\n<ul>\n<li>Learn the two lists by their <em>count</em> first — three Olympic, four Paralympic — then the names.</li>\n<li>Never name a value alone; always link it to a behaviour (\"Determination, because the athlete kept training despite the injury\").</li>\n<li>Keep the Creed and the values separate in your head — the Creed is about effort vs. result, the values are named qualities.</li>\n</ul>\n<p><strong>Sentence starters for a longer answer:</strong></p>\n<ul>\n<li>\"One value shown here is… because…\"</li>\n<li>\"This matters because it links to the idea that…\"</li>\n<li>\"However, this value alone does not guarantee… because…\"</li>\n</ul>", "check": {"question": "Why is it important to link a named value to a specific behaviour in a scenario answer?", "options": ["It simply fills space and takes up extra time in the answer", "It shows understanding of what the value actually means, not just its name", "It completely replaces any need to name the value at all in the answer", "It guarantees full marks automatically, regardless of the accuracy given each time"], "answer": 1, "explain": "Naming a value alone shows recall; linking it to a behaviour in the scenario shows the understanding that scenario-based marks actually reward."}}]}, "exam": {"enabled": true, "questions": [{"question": "Identify <strong>two</strong> of the four Paralympic values.", "marks": 2, "hint": "Choose any two from Courage, Determination, Inspiration and Equality.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks (AO1)</h5>\n<p><strong>1 mark for each correct Paralympic value named, to a maximum of two. Accept any two, different values from:</strong></p>\n<ul>\n<li>Courage</li>\n<li>Determination</li>\n<li>Inspiration</li>\n<li>Equality</li>\n</ul>\n<p>Do not credit an Olympic value (Excellence, Friendship, Respect) or the same value written twice.</p>\n</div>"}, {"question": "Which of these is one of the three Olympic values?", "marks": 1, "hint": "Remember: the Olympic values are Excellence, Friendship and Respect — the other three names belong to the Paralympic list.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1)</h5>\n<p><strong>Answer: B — Friendship.</strong></p>\n<ul>\n<li>Friendship is one of the three Olympic values (with Excellence and Respect).</li>\n<li>Courage, Inspiration and Equality are Paralympic values, not Olympic values.</li>\n</ul>\n</div>"}, {"question": "Explain how Priya''s participation shows <strong>two</strong> Olympic or Paralympic values.", "marks": 4, "hint": "Take each value in turn. Name the value, then link it to something Priya (or the crowd) actually did in the scenario — her recovery and finishing, and the crowd''s reaction.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (AO2: application)</h5>\n<p><strong>Up to 2 marks per value: 1 for naming a relevant value, 1 for linking it to the scenario. Answers may include:</strong></p>\n<ul>\n<li><strong>Determination</strong> — Priya kept training and returned to competition despite a long injury lay-off, refusing to give up on reaching the start line.</li>\n<li><strong>Courage</strong> — Priya faced the mental challenge of racing (and finishing last) in public, in front of a crowd, so soon after injury.</li>\n<li><strong>Respect / Friendship</strong> — the crowd''s warm applause for a fairly completed race, regardless of finishing position, shows respect for effort and a friendly, supportive atmosphere.</li>\n</ul>\n<p>Accept any two different, reasonable values, each linked to a detail from the scenario. A value named with no link to the scenario earns 1 of the 2 marks for that value.</p>\n</div>"}, {"question": "Discuss how effective this change could be in promoting positive attitudes among students, and evaluate any limitations.", "marks": 8, "hint": "Pick two or three values. For each, explain how recognising it could shape positive attitudes. Then weigh up the limits (some students may still only care about winning, judging effort fairly is harder than judging a stopwatch). Finish with a judgement.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 8 marks (level-of-response). Read the band you fit, then pick a mark.</h5>\n<ul>\n<li><strong>Band 3 (thorough), 6–8:</strong> a balanced, well-applied discussion of how recognising values could shape positive attitudes AND a clear evaluation of real limitations, ending in a justified judgement.</li>\n<li><strong>Band 2 (reasonable), 3–5:</strong> sound understanding applied to the scenario with some analysis, but the discussion may be one-sided or the judgement unsupported.</li>\n<li><strong>Band 1 (basic), 1–2:</strong> names values with little application to Greenfield and no real evaluation; largely a list.</li>\n<li><strong>0 marks:</strong> nothing creditworthy.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Indicative content (indicative, not a checklist — reward valid alternatives)</h5>\n<ul>\n<li><strong>Determination:</strong> recognising students who kept trying despite setbacks could encourage more students to take part, even if they are unlikely to win.</li>\n<li><strong>Friendship / Respect:</strong> rewarding supportive, fair behaviour toward competitors could reduce students who drop out because they fear finishing last.</li>\n<li><strong>Excellence:</strong> recognising personal-best performances (not only race winners) could motivate a wider range of students to improve.</li>\n<li><strong>Evaluation:</strong> some students and parents may still see trophies for winning as the \"real\" prize, so attitudes may not shift quickly; judging qualities like Determination or Friendship is more subjective than a stopwatch time, which could feel unfair or inconsistent between staff; the change works best if explained clearly and applied consistently across every event.</li>\n<li><strong>Judgement:</strong> the change is likely to help broaden what students value about Sports Day, because it rewards effort and behaviour that a winners-only system ignores — but it will only shift attitudes if it is judged fairly and explained well, not treated as a token add-on to the existing trophies.</li>\n</ul>\n</div>"}]}}'::jsonb),
('sport-studies', '2-3-initiatives-and-campaigns', '2.3 Initiatives and Campaigns', '{"learn": {"enabled": true, "items": [{"title": "What is an initiative, campaign or event?", "html": "<h4>Three different tools, one job</h4>\n<ul>\n<li>An <strong>initiative</strong> is a planned scheme, set up by an organisation, that works towards a goal — such as getting more people from a particular group taking part in sport.</li>\n<li>A <strong>campaign</strong> is an organised effort, usually with a clear message, that runs over a period of time to raise awareness of an issue or change attitudes — for example, encouraging more respectful behaviour towards officials.</li>\n<li>An <strong>event</strong> is a specific, staged occasion — a festival, a tournament, an open day — that brings people together on the day itself to promote a value or attract new participants.</li>\n<li>All three exist to promote one or more of the <strong>sporting values</strong> from 2.1: team spirit, fair play, citizenship, tolerance and respect, inclusion, national pride and excellence.</li>\n</ul>\n<h4>Why organisations bother</h4>\n<ul>\n<li>Initiatives, campaigns and events give sport a way to <strong>put a value into action</strong>, rather than just naming it. A club can say it values inclusion, but an open day for newcomers of any ability actually demonstrates it.</li>\n<li>The exam rarely tests whether you can just name one — it tests whether you can say <strong>which value</strong> it promotes and <strong>how</strong> it does that.</li>\n</ul>", "check": {"question": "Which of these best describes a ''campaign''?", "options": ["An organised effort with a clear message, run over time to raise awareness or change attitudes", "A single one-off training session that only professional, full-time athletes are permitted to attend", "A permanent change to the official written rules of how a sport is played", "A private members-only social event with no wider promotional purpose"], "answer": 0, "explain": "A campaign is an organised effort with a message that runs over time. A one-off elite session, a rule change, or a private social event are not campaigns."}}, {"title": "Local, regional and national — same values, different reach", "html": "<h4>Three levels of reach</h4>\n<ul>\n<li><strong>Local</strong> — run by one club, school or leisure centre for its own community. Example: a local football club holds an open day where new players of any ability are paired with an experienced member for their first session, promoting <strong>inclusion</strong>.</li>\n<li><strong>Regional</strong> — run across a county or area, often by several clubs or a regional partnership working together. Example: a regional schools'' festival gives an award to the side that supports its opponents best after a defeat, not only to the winners, promoting <strong>fair play</strong> and <strong>team spirit</strong>.</li>\n<li><strong>National</strong> — run by a national governing body, or across the whole country, often timed around a major competition. Example: a national campaign asks players and spectators at every level of the game to show more respect towards match officials, promoting <strong>tolerance and respect</strong>.</li>\n</ul>\n<h4>The level does not decide the value</h4>\n<ul>\n<li>Any value can be promoted at any level — a local club can promote national pride just as easily as a national campaign can promote inclusion.</li>\n<li>What changes between the levels is <strong>the size of the audience and who organises it</strong>, not the value itself.</li>\n</ul>", "check": {"question": "A scheme run across one county by several schools working together, encouraging good sporting conduct, is operating at which level?", "options": ["Local, because it only ever involves students from a single school site", "Regional", "National, because a governing body must personally organise every single entry", "International, because it copies an idea first used in another country"], "answer": 1, "explain": "Several schools working together across a county is a regional scheme — bigger than one club or school, smaller than a nationwide one."}}, {"title": "Awareness and take-up — how initiatives actually change behaviour", "html": "<h4>Two jobs, in order</h4>\n<ul>\n<li><strong>Raising awareness</strong> comes first — getting people to notice and think about a value or issue, often through publicity, a launch event or media coverage.</li>\n<li><strong>Encouraging take-up</strong> comes next — turning that awareness into action, by making it easy for new or lapsed participants to actually start (free taster sessions, discounted membership, a buddy to go with).</li>\n<li>A strong initiative usually does both: for example, a national campaign about inclusion might use adverts to raise awareness, while local clubs run free taster sessions in the same week so people who noticed the campaign can immediately try something.</li>\n</ul>\n<h4>Building an exam answer</h4>\n<ul>\n<li>Weak answer: <em>\"There is a campaign about respect.\"</em> — names something but shows no understanding.</li>\n<li>Strong answer: <em>\"A national campaign encourages respect for match officials by asking players and fans to applaud decisions rather than argue with them. This raises awareness of the value of respect and, alongside training for new referees, encourages more people to take up officiating.\"</em></li>\n<li>The mark almost always comes from linking the initiative to the <strong>value</strong> it promotes, the <strong>level</strong> it operates at, and <strong>how</strong> it raises awareness or encourages take-up.</li>\n</ul>", "check": {"question": "An initiative gives out free taster sessions straight after a media campaign about a value. The taster sessions are mainly intended to...", "options": ["guarantee that every single attendee eventually becomes a full-time professional performer", "encourage take-up by making it easy for people to actually start", "replace the campaign''s job of raising any awareness at all", "reduce the total number of people who are allowed to try the sport"], "answer": 1, "explain": "Taster sessions turn awareness into action — they encourage take-up. They do not guarantee professional careers, replace the awareness stage, or limit numbers."}}]}, "terms": {"enabled": true, "pairs": [{"term": "Initiative", "definition": "A planned scheme set up by an organisation to work towards a goal"}, {"term": "Campaign", "definition": "An organised effort with a message, run over time, to raise awareness or change attitudes"}, {"term": "Event", "definition": "A specific, staged occasion, such as a festival or open day"}, {"term": "Local level", "definition": "Run by one club, school or leisure centre for its own community"}, {"term": "Regional level", "definition": "Run across a county or area by several clubs or a partnership"}, {"term": "National level", "definition": "Run by a governing body, or across the whole country, often around a major event"}, {"term": "Raising awareness", "definition": "Getting people to notice and think about a value or issue"}, {"term": "Encouraging take-up", "definition": "Making it easy for new or lapsed participants to actually start"}]}, "mcq": {"enabled": true, "questions": [{"question": "Which of these is the best definition of an ''initiative'' in sport?", "options": ["A single, one-off training session that is only ever open to elite, full-time professional performers", "A permanent change to the official laws of how a sport is refereed", "A planned scheme, set up by an organisation, that works towards a participation or values goal", "A private club social evening with no wider promotional aim"], "answer": 2, "explain": "An initiative is a planned scheme working towards a goal, such as more people taking part. A one-off elite session, a law change, or a private social evening are not initiatives."}, {"question": "A sporting campaign is best described as...", "options": ["An organised effort with a message, run over time, to raise awareness or change attitudes", "A single trophy presented once a year to the most successful full-time professional team in the country", "A new law passed by a national government that has nothing to do with sport", "A one-off friendly match with no promotional message attached to it at all"], "answer": 0, "explain": "A campaign is an organised effort with a message, run over time. A trophy, a law, or a plain friendly match are not campaigns."}, {"question": "A national governing body runs a scheme across the whole country, timed around a major tournament, encouraging respect for officials. This is operating at which level?", "options": ["Local, because the idea was first suggested by one grassroots club committee", "Regional", "International, because it copies an idea used somewhere else in the world", "National"], "answer": 3, "explain": "A scheme run by a governing body across the whole country is national — bigger than one club (local) or one area (regional)."}, {"question": "A local club''s open day pairs every new member with an experienced player for their first session, whatever their ability. This mainly promotes...", "options": ["Excellence, because it is designed to identify future full-time professional performers", "National pride", "Citizenship, and nothing about welcoming new members at all", "Inclusion"], "answer": 3, "explain": "Welcoming and supporting newcomers of any ability is inclusion. It is not about spotting elite talent, national pride, or citizenship."}, {"question": "Which of these best shows a campaign ''raising awareness'', rather than ''encouraging take-up''?", "options": ["A free, six-week taster course that is fully funded and open to any new participant who wants to join", "A television and social media advert explaining why respecting match officials matters", "A discounted membership price offered only during the very first month of joining", "A qualified buddy assigned to every single beginner who attends a session"], "answer": 1, "explain": "An advert that explains why a value matters raises awareness. Taster courses, discounted prices and buddies are all ways of encouraging take-up instead."}, {"question": "A regional schools'' festival gives its award to the side that supports its opponents best after losing, not only to the winners. Which values does this mainly promote?", "options": ["Excellence only, because just the single best-performing team can ever win it", "National pride, and nothing connected to how teams treat each other", "Tolerance and respect only, with no connection to teamwork", "Fair play and team spirit"], "answer": 3, "explain": "Rewarding good conduct towards opponents, win or lose, promotes fair play and team spirit — not simply rewarding the best performance or national pride."}]}, "fib": {"enabled": true, "questions": [{"text": "An [initiative] is a planned scheme set up by an organisation to work towards a goal."}, {"text": "A campaign is an organised effort with a message, run over [time], to change attitudes."}, {"text": "An event is a specific, [staged] occasion, such as a festival or open day."}, {"text": "A scheme run by one club for its own community is operating at [local] level."}, {"text": "A scheme run by a governing body across the whole country is operating at [national] level."}, {"text": "Free taster sessions mainly encourage [take]-up rather than raise awareness."}]}, "tf": {"enabled": true, "questions": [{"statement": "An initiative is a planned scheme set up by an organisation to work towards a goal.", "answer": true, "explain": "That''s the definition — a planned scheme aimed at something like increasing participation or promoting a value."}, {"statement": "A campaign and an event are exactly the same thing.", "answer": false, "explain": "A campaign is an organised effort with a message, run over time. An event is one staged occasion. An initiative can include both."}, {"statement": "Initiatives, campaigns and events can only ever operate at national level.", "answer": false, "explain": "They can operate at local, regional or national level — a single club''s open day is just as valid an example as a nationwide campaign."}, {"statement": "Raising awareness and encouraging take-up are the same single step.", "answer": false, "explain": "Raising awareness gets people to notice a value or issue. Encouraging take-up turns that awareness into people actually starting. They are two separate jobs."}, {"statement": "A local club open day that welcomes new members of any ability can promote inclusion.", "answer": true, "explain": "Yes — welcoming and supporting newcomers regardless of ability is a clear, everyday example of promoting inclusion at local level."}, {"statement": "The level an initiative runs at (local, regional or national) decides which value it is allowed to promote.", "answer": false, "explain": "Any value can be promoted at any level. The level is about the size of the audience and who organises it, not which value is allowed."}]}, "misc": {"enabled": true, "items": [{"myth": "As long as I can name an initiative or campaign, I''ll get the marks.", "truth": "Naming is only the first mark at most. The examiner wants you to link the initiative to the VALUE it promotes, the LEVEL it operates at, and HOW it raises awareness or encourages take-up. Weak answer: \"There is a campaign about respect.\" Strong answer: \"A national campaign encourages respect for officials by asking fans to applaud decisions rather than argue, raising awareness of respect and encouraging more people to take up officiating.\"", "check": {"question": "A question asks you to explain how an initiative promotes a sporting value. What earns the marks?", "options": ["Naming as many different initiatives as you can remember", "Writing the initiative''s name in capital letters for emphasis", "Naming the initiative, its value, and how it works", "Describing a sporting event you personally attended"], "answer": 2, "explain": "Explain = name it, then the value it promotes, then how it works. Naming alone, or listing several, does not show that understanding."}}, {"myth": "A campaign and an event are the same thing — anything promoting sport counts as both.", "truth": "They are related but different. An EVENT is one staged occasion on a specific day, like a festival or open day. A CAMPAIGN is an organised effort with a message that runs over a longer period, often using adverts or media. An initiative can use an event as part of a wider campaign, but the words are not interchangeable.", "check": {"question": "Which of these is an example of an event, rather than a campaign?", "options": ["A six-month advertising effort encouraging respect for officials", "A one-day regional schools'' sports festival", "A national media message repeated across an entire year", "A rolling programme of adverts about inclusion shown all season"], "answer": 1, "explain": "A one-day festival is a staged occasion — an event. The others run over a longer period with a message, which makes them campaigns."}}, {"myth": "''Raising awareness'' and ''encouraging take-up'' mean the same thing.", "truth": "They are two separate jobs that often work together. RAISING AWARENESS means getting people to notice and think about a value or issue, often through adverts or media. ENCOURAGING TAKE-UP means making it easy for people to actually start or return, for example through free taster sessions. A campaign can raise awareness without a single new participant turning up unless take-up is also encouraged.", "check": {"question": "A national advert explains why fair play matters, but no local sessions are ever offered afterwards. This campaign has...", "options": ["encouraged take-up through free local sessions but not really raised any awareness", "raised awareness but done little to encourage take-up", "done neither job at all, despite the advert being shown nationally", "done exactly the same job twice over, both raising awareness and encouraging take-up"], "answer": 1, "explain": "An advert alone raises awareness. Without taster sessions, discounts or another route in, it has done little to encourage take-up."}}, {"myth": "Only national campaigns count for this topic — a local club''s small open day doesn''t really count as an ''initiative''.", "truth": "A local scheme is just as valid an example as a national one. The specification expects you to recognise initiatives, campaigns and events at LOCAL, REGIONAL and NATIONAL level. A local club open day that welcomes new members is a perfectly good example — you just need to say which level it operates at and which value it promotes.", "check": {"question": "Which of these could be used as a valid exam example of an initiative promoting a sporting value?", "options": ["Only a scheme that has been personally organised by a national governing body itself", "A local club''s open day for new members of any ability", "Only a scheme that has been shown at some point on national television", "Only a scheme that is directly linked to an international competition"], "answer": 1, "explain": "Local examples are just as valid as national ones — you simply need to identify the correct level and the value it promotes."}}]}, "tips": {"enabled": true, "items": [{"title": "Command words for this topic — what each one wants", "html": "<p>Initiative and campaign questions are usually short. Match your answer length to the command word:</p>\n<ul>\n<li><strong>Identify / State</strong> — just name it. \"Identify two levels at which an initiative can operate\" = write two levels, nothing more. 1 mark each.</li>\n<li><strong>Describe</strong> — say what the initiative looks like or does. \"Describe an initiative that promotes inclusion\" = give its features.</li>\n<li><strong>Explain</strong> — give a reason or a mechanism. Use the word <em>because</em> or <em>by</em>. \"Explain how a campaign encourages take-up\" = what it does, and how that leads to people starting.</li>\n</ul>\n<p><strong>Read the mark tariff:</strong> [1] wants one point; [2] usually wants two points, or one point developed; [4] in Section B wants points applied to the scenario.</p>", "check": {"question": "A question says: ''Identify two levels at which an initiative can operate [2]''. What is the safest answer?", "options": ["A long paragraph describing one national campaign in detail", "Two level names, such as local and national", "One level explained at great length", "A list of every value from 2.1"], "answer": 1, "explain": "''Identify'' + [2] = two names, one mark each. A long paragraph, or an unrelated list of values, wastes time and does not answer the question."}}, {"title": "The golden rule: value, level, and how", "html": "<p>The single most common way to lose marks here is naming an initiative with nothing else. Build every answer as <strong>initiative → value → level → how it works</strong>:</p>\n<ul>\n<li><strong>❌ 0–1 marks:</strong> \"There is a campaign about respect.\"</li>\n<li><strong>✅ full marks:</strong> \"A national campaign promotes respect by asking fans to applaud officials'' decisions rather than argue, raising awareness of the value and encouraging more people to take up officiating.\"</li>\n</ul>\n<p>In <strong>Section B</strong> the question gives you a scenario (a named club or trust). Then you must use a detail <em>from that scenario</em>, not a general example.</p>", "check": {"question": "In a Section B scenario question about a named sports trust, your example should be built around...", "options": ["absolutely any campaign you happen to have seen on television", "the scenario you are given", "a famous athlete you personally admire", "your own school''s sports day only"], "answer": 1, "explain": "Section B is applied — the marks are for using the scenario in front of you. A general example that ignores the scenario is capped."}}, {"title": "Where this topic appears + sentence starters", "html": "<p><strong>Where it shows up:</strong> initiatives and campaigns appear as quick recall in <strong>Section A</strong> (identify a level, identify a value), and as applied points in <strong>Section B</strong> scenarios about a named club or trust. They also feed <strong>Section C</strong> 8-mark answers about how a range of initiatives could work together to promote values.</p>\n<p><strong>Three punchy tips:</strong></p>\n<ul>\n<li>Learn one clear example at each level (local, regional, national) so you can always recall one.</li>\n<li>For every example, memorise the value it promotes AND how it raises awareness or encourages take-up.</li>\n<li>Watch for overlap: one initiative can promote more than one value, and can raise awareness while also encouraging take-up.</li>\n</ul>\n<p><strong>Sentence starters for a longer answer:</strong></p>\n<ul>\n<li>\"One initiative that promotes this value is… run at… level, which works by…\"</li>\n<li>\"This raises awareness by… and encourages take-up by…\"</li>\n<li>\"However, the same initiative might not reach… because…\"</li>\n</ul>", "check": {"question": "Why is it useful to know that one initiative can raise awareness AND encourage take-up?", "options": ["It simply fills space in a longer answer without adding any real understanding", "It shows understanding of both jobs an initiative can do", "It means the initiative has no value attached to it whatsoever", "It completely replaces the need to ever name a level or a value"], "answer": 1, "explain": "Showing that an initiative does both jobs — raising awareness and encouraging take-up — demonstrates the deeper understanding a longer answer rewards."}}]}, "exam": {"enabled": true, "questions": [{"question": "Identify <strong>two</strong> levels at which an initiative, campaign or event promoting a sporting value can operate.", "marks": 2, "hint": "Just name two — pick from local, regional or national.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks (AO1)</h5>\n<p><strong>1 mark for each correct level named, to a maximum of two. Accept any two different levels:</strong></p>\n<ul>\n<li>Local</li>\n<li>Regional</li>\n<li>National</li>\n</ul>\n<p>Do not credit the same level written twice.</p>\n</div>"}, {"question": "Which of these best describes a sporting ''campaign''?", "marks": 1, "hint": "Think about what runs over TIME and carries a MESSAGE.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: B — An organised effort with a message, run over time, to raise awareness or change attitudes.</strong></p>\n<ul>\n<li>A campaign runs over a period and carries a clear message.</li>\n<li>A trophy, a rule change, or a plain friendly match are not campaigns.</li>\n</ul>\n</div>"}, {"question": "Explain how a <strong>local</strong> initiative and a <strong>national</strong> initiative could each promote a sporting value in this scenario.", "marks": 4, "hint": "Take each level in turn. Name a value, then say how a scheme at that level (using details from the scenario) could promote it.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (AO2: application)</h5>\n<p><strong>Up to 2 marks per level: 1 for identifying a relevant value, 1 for how a scheme at that level (using the scenario) promotes it. Answers may include:</strong></p>\n<ul>\n<li><strong>Local (Ashford''s own members):</strong> could promote inclusion or team spirit — for example, a welcome session pairing new members with experienced ones, run only within the Trust''s own clubs.</li>\n<li><strong>National (using the international event''s interest):</strong> could promote national pride or excellence — for example, a country-wide scheme encouraging people to try the athletics event''s sport while public interest is high, run by a national governing body rather than one Trust.</li>\n</ul>\n<p>Accept any other reasonable, applied answer. A value with no explanation of how it is promoted, or an example not linked to the scenario''s level, earns 1 of the 2 marks for that level.</p>\n</div>"}, {"question": "Discuss how initiatives at local, regional and national level could work together to promote sporting values and increase participation around this event.", "marks": 8, "hint": "Choose one example at each level. For each, name the value and explain how it raises awareness or encourages take-up. Then weigh it up — what limits how well they work together? Finish with a judgement.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 8 marks (level-of-response). Read the band you fit, then pick a mark.</h5>\n<ul>\n<li><strong>Band 3 (thorough), 6–8:</strong> a balanced, well-applied discussion covering local, regional AND national initiatives, clearly showing how each raises awareness or encourages take-up, AND weighing the limits (cost, coordination, one level not reaching everyone), ending in a justified judgement.</li>\n<li><strong>Band 2 (reasonable), 3–5:</strong> sound understanding applied to more than one level with some analysis, but the discussion may be one-sided, miss a level, or the judgement may be unsupported.</li>\n<li><strong>Band 1 (basic), 1–2:</strong> names initiatives and/or levels with little application and no real evaluation; largely a list.</li>\n<li><strong>0 marks:</strong> nothing creditworthy.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Indicative content (indicative, not a checklist — reward valid alternatives)</h5>\n<ul>\n<li><strong>Local:</strong> Ashford''s own clubs could run welcome sessions or open days pairing newcomers with experienced members, promoting inclusion and encouraging take-up directly within the town.</li>\n<li><strong>Regional:</strong> a partnership of clubs across the area could run a festival rewarding good conduct as well as results, promoting fair play and team spirit and raising awareness across a wider audience than one club alone.</li>\n<li><strong>National:</strong> a governing body could run a media campaign timed around the international event, promoting national pride and excellence and raising awareness across the whole country, encouraging people everywhere to try the sport.</li>\n<li><strong>Evaluation:</strong> working together only helps if the levels are coordinated — a national advert raising awareness is wasted if no local taster sessions exist to convert it into take-up; regional and national schemes cost more to run and need staff/funding; a single level acting alone reaches a narrower audience and may raise awareness without offering anywhere nearby to actually start.</li>\n<li><strong>Judgement:</strong> combining levels is powerful because national awareness and local take-up routes reinforce each other — but it only increases participation if the levels are properly linked and resourced, rather than running as separate, uncoordinated efforts.</li>\n</ul>\n</div>"}]}}'::jsonb),
('sport-studies', '2-4-1-etiquette-of-performers', '2.4.1 Etiquette of Performers', '{"learn": {"enabled": true, "items": [{"title": "Etiquette: what it is and why performers observe it", "html": "<h4>What ''etiquette'' means in sport</h4>\n<ul>\n<li><strong>Etiquette</strong> is the unwritten code of good conduct and manners a performer is expected to follow — conventions that go beyond what is written in the sport''s official rulebook.</li>\n<li>A performer can obey every written rule of a sport and still behave badly by ignoring etiquette — for example, celebrating right in an injured opponent''s face breaks no written rule, but it is still poor conduct.</li>\n</ul>\n<h4>Why performers observe it — three reasons</h4>\n<ul>\n<li><strong>Fairness</strong> — some conventions exist purely so that no performer gains an advantage that has nothing to do with skill (for example, staying still in an opponent''s eyeline during their shot).</li>\n<li><strong>Safety of fellow participants</strong> — some conventions exist purely to stop performers being hurt (for example, not tackling once play has already stopped).</li>\n<li><strong>Reinforcing positive sporting values</strong> — following etiquette consistently keeps values such as respect and fair play alive within a sport, for everyone taking part and watching.</li>\n</ul>", "check": {"question": "Which of these best explains what ''etiquette'' means for a performer?", "options": ["An unwritten code of good conduct that goes beyond the sport''s official rulebook", "Every written law and regulation that is printed inside the sport''s official rulebook", "A list of skills a performer must master before being allowed to compete at all", "The scoring system used by officials to work out the final result of a match"], "answer": 0, "explain": "Etiquette is unwritten — conventions beyond the rulebook. Option B describes the opposite (written rules), and the others describe skill requirements or scoring, not etiquette."}}, {"title": "Knowing when to be quiet or hold back", "html": "<h4>Recognising the right moment</h4>\n<ul>\n<li>Good etiquette often means a performer recognising a moment when staying quiet, still or out of the way is the appropriate thing to do — without needing to be told.</li>\n<li>Examples across sports: staying silent while an opponent lines up a decisive shot; not walking across the field of play while the ball is live; waiting for a rally to finish before returning a stray ball.</li>\n</ul>\n<h4>Why this matters</h4>\n<ul>\n<li>These moments usually protect the same two reasons as above — interrupting at the wrong time can distract an opponent unfairly, or create a safety risk if performers collide.</li>\n<li>A performer who has to be reminded every single time is showing they do not really understand etiquette — recognising the moment yourself is the mark of a well-mannered competitor.</li>\n</ul>", "check": {"question": "A performer notices their opponent is about to take a shot that will decide the point. What does good etiquette suggest?", "options": ["Call out something distracting at exactly the moment your opponent is about to strike the ball", "Stay completely still and silent until the shot has been taken", "Walk across the playing area to fetch a different ball while play continues", "Ask the referee to pause the whole match until you are ready to keep watching"], "answer": 1, "explain": "Etiquette means holding back at the decisive moment. Calling out, walking across live play, or demanding a pause would all distract or disrupt — the opposite of what is expected."}}, {"title": "Sportsmanship: the letter AND the spirit of the rules", "html": "<h4>The definition to learn</h4>\n<ul>\n<li><strong>Sportsmanship</strong> means playing within the letter of the rules (the written laws) <strong>and</strong> the spirit of the rules (the fairness those laws are trying to protect) — even when nobody is checking.</li>\n<li>A sportsmanlike performer would rather lose fairly than win by exploiting a loophole nobody has noticed.</li>\n</ul>\n<h4>An example</h4>\n<ul>\n<li>In a school football match, a striker notices the ball went out of play just before they scored, but the assistant referee has not seen it. The striker tells the referee the ball was out, giving up the goal, because winning that way would not feel like a genuine win.</li>\n</ul>", "check": {"question": "Which of these best matches the definition of sportsmanship used in this course?", "options": ["Playing strictly within the written rules while still quietly hunting for any legal edge available", "Refusing to compete against any opponent who is clearly stronger than you are", "Playing within the letter and the spirit of the rules, even when no official is checking", "Following only the instructions given personally by your coach or team manager"], "answer": 2, "explain": "Sportsmanship covers BOTH the letter and the spirit of the rules, unchecked. Option A describes gamesmanship instead — legal, but chasing an edge rather than respecting fairness."}}, {"title": "Gamesmanship: bending the rules for an edge", "html": "<h4>The definition to learn</h4>\n<ul>\n<li><strong>Gamesmanship</strong> means bending the rules, or using legal-but-borderline tactics, to gain an advantage — <strong>without technically breaking any written rule</strong>.</li>\n<li>The key difference from cheating: gamesmanship never breaks a written law of the sport. The key difference from sportsmanship: it ignores the spirit of fair competition to chase an edge.</li>\n</ul>\n<h4>Examples</h4>\n<ul>\n<li>A tennis player takes the maximum time allowed between points, every single point, once they start losing momentum — purely to disrupt their opponent''s rhythm.</li>\n<li>A losing team''s substitute takes slightly longer than necessary to leave the pitch in the closing minutes, running down the clock.</li>\n</ul>\n<h4>Sportsmanship vs gamesmanship — the core contrast</h4>\n<ul>\n<li>Sportsmanship respects the spirit of the rules; gamesmanship exploits the letter of the rules while ignoring their spirit.</li>\n<li>Both stay inside the written rulebook — the difference is intention: fairness versus advantage-seeking.</li>\n</ul>", "check": {"question": "Which of these is the best description of gamesmanship?", "options": ["Deliberately and openly breaking a written rule of the sport in order to win", "Following both the written rules and their underlying spirit at every moment", "Refusing to take part in any competition unless the playing conditions are absolutely perfect in every way", "Bending the rules or seeking a legal-but-unfair edge, without technically breaking a written rule"], "answer": 3, "explain": "Gamesmanship stays legal but chases an edge. Option A describes cheating (a rule IS broken), and option B describes sportsmanship instead."}}]}, "terms": {"enabled": true, "pairs": [{"term": "Etiquette", "definition": "Unwritten code of good conduct expected of a performer, beyond the official rulebook"}, {"term": "Sportsmanship", "definition": "Playing within the letter AND spirit of the rules, even when unchecked"}, {"term": "Gamesmanship", "definition": "Bending the rules for an edge, without technically breaking a written rule"}, {"term": "Fairness (reason for etiquette)", "definition": "Stops an advantage that has nothing to do with a performer''s actual skill"}, {"term": "Safety of fellow participants (reason for etiquette)", "definition": "Conventions that exist purely to prevent performers being hurt"}, {"term": "Reinforcing positive sporting values", "definition": "Consistent good conduct keeps values like respect alive within a sport"}, {"term": "Knowing when to be quiet", "definition": "Recognising a moment to hold back, without needing to be told"}, {"term": "Time-wasting", "definition": "A common gamesmanship example: legally using up the clock to protect a lead"}]}, "mcq": {"enabled": true, "questions": [{"question": "Which of these is a genuine reason performers are expected to observe etiquette?", "options": ["It reinforces positive sporting values and protects fairness and safety", "It guarantees that the more experienced performer will always win the contest", "It replaces the need for a referee or official to be present at the match", "It only applies to professional performers, never to school or club sport"], "answer": 0, "explain": "Etiquette exists for fairness, safety and reinforcing values — it never guarantees a result, replaces officials, or applies only to professionals."}, {"question": "A golfer''s playing partner is standing over the ball, about to take a decisive putt. What should the golfer do?", "options": ["Quietly shuffle their feet and check their phone to pass the time", "Stay completely still and silent until the putt has been taken", "Walk onto the green to check where the flag is", "Ask the playing partner to hurry up and take the putt"], "answer": 1, "explain": "Etiquette means holding back completely during a decisive shot. Shuffling, walking onto the green, or rushing the other player would all distract or disrupt."}, {"question": "Which sentence best shows sportsmanship rather than gamesmanship?", "options": ["A player stays carefully inside every written rule while quietly searching out every possible legal advantage they can find", "A player argues with the referee until the decision is changed in their favour", "A player admits fouling even though the referee doesn''t spot it, and accepts the decision going against them", "A player refuses to shake hands with the opposition after losing a close match"], "answer": 2, "explain": "Owning up when nobody is checking shows respect for the spirit of the rules — true sportsmanship. Option A instead describes chasing legal advantages, which is gamesmanship."}, {"question": "Which of these is the clearest example of gamesmanship?", "options": ["Deliberately punching an opponent off the ball whenever the match referee happens to not be looking", "Congratulating an opponent generously after they win a hard-fought contest", "Following every written rule and every unwritten convention of the sport", "Deliberately taking the maximum time allowed between points to unsettle an opponent''s rhythm"], "answer": 3, "explain": "Using the full, legal time allowance purely to disrupt an opponent is gamesmanship — legal, but chasing an edge. Punching an opponent breaks a written rule, so it is cheating, not gamesmanship."}, {"question": "What is the key difference between gamesmanship and cheating?", "options": ["Gamesmanship always breaks a written rule, whereas cheating never breaks any rule at all", "Gamesmanship never breaks a written rule; cheating does break a written rule", "There is no real difference between gamesmanship and cheating at all", "Cheating is only possible in individual sports, never in team sports"], "answer": 1, "explain": "Gamesmanship always stays inside the written rulebook, even while chasing an edge. Cheating actually breaks a written rule — that is the exam-worthy distinction."}, {"question": "A team is known for consistently showing good etiquette and sportsmanship. What is this most likely to do for the sport?", "options": ["Guarantee the team a better result than their skill level deserves", "Remove the need for the sport to have any officials at future matches", "Help reinforce positive sporting values that the sport depends on", "Stop any other team from ever using gamesmanship tactics again"], "answer": 2, "explain": "Consistent good conduct reinforces values like respect and fair play — it does not guarantee results, remove the need for officials, or stop others'' behaviour."}]}, "fib": {"enabled": true, "questions": [{"text": "Etiquette is an [unwritten] code of good conduct that goes beyond a sport''s official rulebook."}, {"text": "Sportsmanship means playing within the letter and the [spirit] of the rules."}, {"text": "Gamesmanship means bending the rules to gain an edge without [technically] breaking a written rule."}, {"text": "One reason performers observe etiquette is [fairness] — stopping an advantage that has nothing to do with skill."}, {"text": "Good etiquette also protects the [safety] of fellow participants during a contest."}, {"text": "Consistent good conduct helps [reinforce] positive sporting values within a sport."}]}, "tf": {"enabled": true, "questions": [{"statement": "Etiquette is the same thing as the sport''s official written rulebook.", "answer": false, "explain": "Etiquette is UNWRITTEN — conventions that go beyond the rulebook, not the rulebook itself."}, {"statement": "Sportsmanship means respecting the spirit of the rules, not just the letter.", "answer": true, "explain": "Sportsmanship covers both the letter AND the spirit — playing fairly even when nobody is checking."}, {"statement": "Gamesmanship involves openly breaking a written rule of the sport.", "answer": false, "explain": "Gamesmanship always stays inside the written rules — it bends them for an edge, but never technically breaks them. Breaking a rule is cheating."}, {"statement": "One reason for observing etiquette is protecting the safety of fellow participants.", "answer": true, "explain": "Safety is one of the three reasons — some conventions exist purely to stop performers being hurt."}, {"statement": "A performer who has to be told every time to stay quiet is showing strong etiquette.", "answer": false, "explain": "Recognising the moment yourself, without being told, is the real mark of good etiquette."}, {"statement": "Gamesmanship and cheating mean exactly the same thing.", "answer": false, "explain": "Gamesmanship never breaks a written rule; cheating does. That distinction is exactly what the exam tests."}]}, "misc": {"enabled": true, "items": [{"myth": "Gamesmanship is basically just another word for cheating, since both are about trying to win unfairly.", "truth": "They are different ideas the exam tests precisely. GAMESMANSHIP stays inside the written rules while chasing a legal-but-unfair edge. CHEATING actually breaks a written rule. A player time-wasting legally is gamesmanship; a player throwing a punch off the ball breaks a rule and is cheating.", "check": {"question": "What is the key difference between gamesmanship and cheating?", "options": ["Cheating always avoids breaking any written rule, while gamesmanship constantly breaks the sport''s rulebook", "Gamesmanship stays inside the written rules of the sport; cheating breaks a written rule", "There is no meaningful difference between the two ideas at all", "Gamesmanship only happens in team sports, never in individual ones"], "answer": 1, "explain": "Gamesmanship never technically breaks a written rule; cheating does. That is the precise distinction the exam rewards."}}, {"myth": "Sportsmanship just means being a good loser and shaking hands at the end.", "truth": "That is only a small, final part of it. The full definition is playing within the letter AND the spirit of the rules THROUGHOUT the whole contest — not just being gracious once it is over. A player could shake hands warmly at the end and still have shown poor sportsmanship during the match itself.", "check": {"question": "Which of these captures the FULL meaning of sportsmanship, not just part of it?", "options": ["Being polite to the officials only after the final whistle has been blown", "Shaking hands warmly with opponents at the end, regardless of how fairly the match itself was played", "Playing within the letter and the spirit of the rules throughout the whole contest", "Applauding your own teammates loudly whenever they happen to score a point"], "answer": 2, "explain": "Sportsmanship applies throughout the contest, not only at the final whistle — a warm handshake alone does not prove fair play took place during the match."}}, {"myth": "As long as I don''t break a written rule, it doesn''t matter how I behave — that''s just part of the game.", "truth": "This ignores etiquette and the spirit of the rules, which matter even when no written rule is broken. A performer can stay entirely legal and still show poor conduct — distracting an opponent, ignoring a safety convention, or refusing to acknowledge a genuine error. Legal is not the same as well-mannered.", "check": {"question": "A performer says ''I never break a written rule, so how I behave doesn''t matter.'' What is missing from this view?", "options": ["It ignores etiquette and the spirit of the rules, which matter even when no written rule is broken", "It ignores the fact that written rules are only ever a small part of everything a referee is actually watching for", "It ignores the exact scoreline of the match at the moment the behaviour happens", "It ignores how many spectators are physically present inside the stadium that day"], "answer": 0, "explain": "Staying legal is not the same as showing good conduct — etiquette and the spirit of fair play matter beyond just the written rulebook."}}, {"myth": "''Knowing when to be quiet'' is only about politeness — it has nothing to do with safety.", "truth": "It links to BOTH reasons for etiquette, not just fairness/politeness. Holding back at the wrong moment can also risk a collision — for example, walking into a live playing area, or moving suddenly near a performer mid-action. Etiquette protects safety just as much as it protects fairness.", "check": {"question": "Why can ''knowing when to be quiet or hold back'' matter for safety, not just politeness?", "options": ["Because staying quiet at the right moment always guarantees that a performer will go on to win their next contest", "Because officials are not allowed to speak until a performer has finished talking", "Because it has no connection to safety and is only a matter of good manners", "Because holding back at the wrong moment can cause a collision or distract someone dangerously"], "answer": 3, "explain": "Interrupting or moving at the wrong moment risks a collision as well as unfair distraction — etiquette serves safety, not just politeness."}}]}, "tips": {"enabled": true, "items": [{"title": "Command words for this topic — what each one wants", "html": "<p>Etiquette questions range from quick recall to a full 8-mark discussion. Match your answer length to the command word:</p>\n<ul>\n<li><strong>Identify / State</strong> — just name it. \"State one reason for observing etiquette [1]\" = write the reason, nothing more.</li>\n<li><strong>Explain</strong> — give a reason, using the word <em>because</em>. \"Explain why a tactic is gamesmanship\" = say what it is, plus why it counts, linked to the scenario.</li>\n<li><strong>Discuss</strong> (the Section C 8-marker) — weigh up both sides (the short-term appeal of gamesmanship AND the longer-term cost) and reach a justified judgement.</li>\n</ul>\n<p><strong>Read the mark tariff:</strong> [1] wants one point; [4] in Section B wants two developed, applied points; [8] wants balance plus a judgement.</p>", "check": {"question": "A question says: ''Identify one reason why performers observe etiquette [1]''. What is the safest answer?", "options": ["A full paragraph explaining fairness, safety and reinforcing values all together", "One named reason, such as fairness or safety", "A list of every user group who might take part in the sport", "A description of the referee''s full matchday routine and duties"], "answer": 1, "explain": "''Identify'' + [1] = one named reason. A full paragraph, a list of user groups, or a description of duties all waste time on a single-mark question."}}, {"title": "The core contrast: never blur sportsmanship and gamesmanship", "html": "<p>The single most common way to lose marks here is defining gamesmanship as cheating, or sportsmanship as only \"being a good loser\". Always state BOTH halves of the real definition:</p>\n<ul>\n<li><strong>❌ 0–1 marks:</strong> \"Gamesmanship is cheating.\"</li>\n<li><strong>✅ full marks:</strong> \"Gamesmanship bends the rules for an advantage without technically breaking them, whereas sportsmanship respects the spirit of the rules even when nobody is checking.\"</li>\n</ul>\n<p>In <strong>Section B</strong> you will usually be given a scenario. Decide first whether the behaviour described breaks a written rule (cheating), stays legal but chases an edge (gamesmanship), or respects fairness throughout (sportsmanship) — then explain using detail from the scenario.</p>", "check": {"question": "Which answer about gamesmanship is most likely to earn full marks?", "options": ["Gamesmanship means cheating by openly and deliberately breaking a written rule of the sport itself", "Gamesmanship is exactly the same idea as good sportsmanship in every sport", "Gamesmanship bends the rules for an advantage, without technically breaking any of them", "Gamesmanship only exists in sports that do not use a professional referee"], "answer": 2, "explain": "Full marks needs the precise definition: bending the rules for an edge WITHOUT breaking them. Calling it cheating, or the same as sportsmanship, misses the exam-worthy distinction."}}, {"title": "Where etiquette appears + sentence starters", "html": "<p><strong>Where it shows up:</strong> etiquette appears as quick recall in <strong>Section A</strong> (identify/state a reason or definition), as an applied point in <strong>Section B</strong> scenarios (deciding whether behaviour is sportsmanship or gamesmanship), and it feeds <strong>Section C</strong> 8-mark answers about the impact of relying on gamesmanship rather than sportsmanship.</p>\n<p><strong>Three punchy tips:</strong></p>\n<ul>\n<li>Always give BOTH halves of the sportsmanship/gamesmanship definitions — never just half.</li>\n<li>In a scenario, check first: does it break a written rule (cheating), stay legal but chase an edge (gamesmanship), or respect fairness throughout (sportsmanship)?</li>\n<li>For an 8-mark Discuss, weigh gamesmanship''s small short-term gain against its longer-term cost to reputation and trust.</li>\n</ul>\n<p><strong>Sentence starters for a longer answer:</strong></p>\n<ul>\n<li>\"One example of gamesmanship here is… because…\"</li>\n<li>\"This differs from sportsmanship because…\"</li>\n<li>\"Overall, the greater impact is… because…\"</li>\n</ul>", "check": {"question": "Why is naming a specific example the strongest way to answer a Section B question here?", "options": ["Because the marks reward applying the idea to the given scenario, not a general definition", "Because writing a specific example always takes far less time to plan than a full definition does", "Because officials only accept answers that contain a specific example", "Because a definition on its own is never accepted by any exam board"], "answer": 0, "explain": "Section B is applied — the marks are for using the scenario in front of you, not just stating a general definition."}}]}, "exam": {"enabled": true, "questions": [{"question": "State <strong>two</strong> reasons why performers are expected to observe etiquette in sport.", "marks": 2, "hint": "Pick two from: fairness, safety of fellow participants, or reinforcing positive sporting values.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks (AO1)</h5>\n<p><strong>1 mark for each correct reason named, to a maximum of two. Accept any two DIFFERENT reasons from:</strong></p>\n<ul>\n<li>Fairness — stops an advantage that has nothing to do with skill</li>\n<li>Safety of fellow participants — protects performers from being hurt</li>\n<li>Reinforcing positive sporting values — keeps values like respect alive</li>\n</ul>\n<p>Do not credit the same reason written twice.</p>\n</div>"}, {"question": "Which of these best describes gamesmanship?", "marks": 1, "hint": "Think about whether a written rule is actually broken or not.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: B — Bending the rules or chasing a legal-but-unfair edge, without technically breaking a written rule.</strong></p>\n<ul>\n<li>Gamesmanship always stays inside the written rulebook while seeking an advantage.</li>\n<li>Openly breaking a rule is cheating, and respecting the letter AND spirit of the rules describes sportsmanship instead.</li>\n</ul>\n</div>"}, {"question": "Explain why Jamila''s behaviour in the scenario is an example of <strong>gamesmanship</strong>, and explain why it would <strong>not</strong> be described as good sportsmanship.", "marks": 4, "hint": "First explain what makes it gamesmanship (an edge sought without breaking a written rule). Then explain what sportsmanship requires that this behaviour is missing.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (AO2: application)</h5>\n<p><strong>Up to 2 marks for explaining the gamesmanship, up to 2 marks for explaining why it is not sportsmanship. Answers may include:</strong></p>\n<ul>\n<li><strong>Gamesmanship (2):</strong> Jamila is trying to disrupt her opponent''s rhythm/concentration to gain an advantage (1), without breaking any written rule of badminton — linked to the scenario detail of delaying before the serve/re-tying laces when not needed (1).</li>\n<li><strong>Not sportsmanship (2):</strong> sportsmanship means respecting the spirit of the rules as well as the letter (1); Jamila''s delay goes against that fairness even though it is legal, so it does not show good sportsmanship (1).</li>\n</ul>\n<p>Accept any other reasonable, applied answer that identifies the advantage-seeking and links it to the scenario.</p>\n</div>"}, {"question": "Discuss the impact that relying on gamesmanship, rather than sportsmanship, could have on performers and on a sport like badminton.", "marks": 8, "hint": "Cover more than one impact — on the individual performer''s reputation and development, and on the sport''s fairness and reputation. Weigh any short-term benefit against the longer-term cost, then reach a judgement.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 8 marks (level-of-response). Read the band you fit, then pick a mark.</h5>\n<ul>\n<li><strong>Band 3 (thorough), 6–8:</strong> a balanced, well-applied discussion of several impacts (on performers AND on the sport), weighing any short-term benefit of gamesmanship against its longer-term cost, ending in a justified judgement.</li>\n<li><strong>Band 2 (reasonable), 3–5:</strong> sound understanding applied to more than one impact with some analysis, but the discussion may be one-sided or the judgement unsupported.</li>\n<li><strong>Band 1 (basic), 1–2:</strong> names an impact and/or the terms with little application and no real evaluation; largely a list.</li>\n<li><strong>0 marks:</strong> nothing creditworthy.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Indicative content (indicative, not a checklist — reward valid alternatives)</h5>\n<ul>\n<li><strong>Short-term:</strong> gamesmanship might unsettle an opponent and help win a close point or match.</li>\n<li><strong>Performer impact:</strong> relying on it can stunt real skill development under pressure, and a reputation for it can put off future opponents, partners or sponsors who prefer fair competitors.</li>\n<li><strong>Sport impact:</strong> if common across a club or sport, it can lower spectators'' and participants'' trust in its fairness, undermining the values the sport depends on.</li>\n<li><strong>Sportsmanship contrast:</strong> builds a performer''s reputation for fair play under pressure and reinforces those values for everyone watching.</li>\n<li><strong>Evaluation:</strong> gamesmanship''s advantage is usually small and short-lived, while sportsmanship''s benefits (trust, respect, development) build over a whole career or sport''s reputation — though occasional gamesmanship differs from a persistent culture of it.</li>\n<li><strong>Judgement:</strong> relying on gamesmanship risks more than it gains for both the performer and the sport, so clubs should encourage sportsmanship despite gamesmanship''s minor short-term appeal.</li>\n</ul>\n</div>"}]}}'::jsonb),
('sport-studies', '2-4-2-etiquette-of-spectators', '2.4.2 Etiquette of Spectators', '{"learn": {"enabled": true, "items": [{"title": "What ''spectator etiquette'' means", "html": "<h4>The idea</h4>\n<ul>\n<li><strong>Etiquette</strong> is the accepted, respectful way of behaving in a situation. For spectators, it means the accepted way to behave while <strong>watching</strong> a sport — not while playing it.</li>\n<li>This is a different topic from performer etiquette (fairness and sportsmanship on the pitch). Here the exam question is always: <strong>how should someone in the crowd behave?</strong></li>\n</ul>\n<h4>Why it matters</h4>\n<ul>\n<li>Sport only works as a spectacle if the crowd lets it happen properly — a performer who cannot concentrate, or a spectator whose enjoyment is ruined by others, both lose out.</li>\n<li>Good spectator etiquette protects three things at once: the <strong>performers''</strong> ability to compete fairly, <strong>other spectators''</strong> enjoyment, and everyone''s <strong>safety</strong>.</li>\n</ul>", "check": {"question": "Spectator etiquette is best described as...", "options": ["the accepted way of behaving in the crowd while watching sport", "a set of tactical rules that only professional performers are trained to follow before a competition", "the official rulebook a referee uses to award points during a match", "a list of penalties for players who commit deliberate fouls during play"], "answer": 0, "explain": "Etiquette for spectators is about how the crowd behaves while watching — not a tactical rulebook for performers, an officials'' scoring system, or a list of foul penalties."}}, {"title": "Appropriate behaviour when watching", "html": "<h4>Quiet at the right moments</h4>\n<ul>\n<li>Some sports need silence at a precise moment because noise can break a performer''s concentration and affect a fair outcome. Classic examples: staying <strong>quiet during a tennis serve</strong>, and staying <strong>quiet while a golfer is putting</strong>.</li>\n<li>This is not the same as staying silent for the whole match — cheering and applause are expected and welcome between points, at the end of a rally, or after a good shot.</li>\n</ul>\n<h4>Not distracting or abusing players and officials</h4>\n<ul>\n<li>Spectators must not deliberately put a performer off — for example shouting during a run-up, waving objects, or using banned lights or flashes near the field of play.</li>\n<li>Etiquette also rules out <strong>abusing</strong> players or officials: no verbal abuse, threats, or aggressive criticism of a decision. Disagreeing with a decision is normal; abusing someone for it is not.</li>\n</ul>", "check": {"question": "Which of these is an example of appropriate spectator behaviour?", "options": ["Staying quiet while a golfer lines up and takes a crucial putt", "Shouting loudly at the exact moment a tennis player begins their serve to put them off", "Screaming personal abuse at the referee every time a decision goes against your team", "Standing up and waving a large flag directly in a sprinter''s line of sight as the race starts"], "answer": 0, "explain": "Staying quiet at a genuinely crucial moment protects a fair contest. Deliberately distracting a server, abusing an official, or blocking a sprinter''s sightline are all etiquette breaches."}}, {"title": "Responsibility to others — and to safety", "html": "<h4>Two audiences to respect</h4>\n<ul>\n<li>A spectator has a responsibility to <strong>fellow spectators</strong> — not blocking their view, not pushing through a crowd, and not spoiling their enjoyment with disruptive or aggressive behaviour.</li>\n<li>A spectator also has a responsibility to <strong>the players</strong> — not intimidating them, not invading their space, and reacting to decisions in a way that does not threaten anyone.</li>\n</ul>\n<h4>Safety — not endangering others</h4>\n<ul>\n<li>Etiquette includes basic safety: never throwing objects onto a pitch, court or course; never invading the playing area; not crowding walkways or blocking an exit.</li>\n<li>A strong exam answer names the <strong>group affected</strong> (fellow spectators, players, or both) and the specific <strong>behaviour or risk</strong> — not just \"be safe\" or \"be nice\".</li>\n</ul>", "check": {"question": "A question asks you to explain a spectator''s responsibility to OTHER spectators. Which answer fits best?", "options": ["Not blocking another spectator''s view or pushing through the crowd", "Staying completely silent for the entire duration of the fixture from start to finish", "Buying the most expensive ticket available for the stand", "Arriving before the players so you get the best seat in the ground"], "answer": 0, "explain": "Responsibility to fellow spectators is about consideration — not blocking views or pushing through crowds — not about silence, ticket price, or arrival time."}}]}, "terms": {"enabled": true, "pairs": [{"term": "Spectator etiquette", "definition": "The accepted, respectful way of behaving while watching sport"}, {"term": "Quiet moments", "definition": "Points such as a tennis serve or golf putt where noise could unfairly distract"}, {"term": "Distracting a performer", "definition": "Deliberately shouting, waving or flashing lights to put them off"}, {"term": "Abusing an official", "definition": "Verbal abuse or threats aimed at a referee over a decision"}, {"term": "Responsibility to fellow spectators", "definition": "Not blocking views or spoiling others'' enjoyment"}, {"term": "Responsibility to players", "definition": "Not intimidating a performer or invading their space"}, {"term": "Safety at a venue", "definition": "Not throwing objects, invading the pitch, or endangering others"}]}, "mcq": {"enabled": true, "questions": [{"question": "Why do spectators stay quiet during a tennis serve or a golf putt?", "options": ["Because sudden noise at that moment could distract the performer and affect a fair outcome", "Because officials can issue a fine to any spectator heard whispering during a changeover", "Because the venue''s insurance policy legally requires total silence throughout the whole match", "Because performers are physically unable to continue if any sound at all is heard nearby"], "answer": 0, "explain": "Quiet at key moments protects concentration and fairness. It has nothing to do with fines, insurance rules, or an inability to continue."}, {"question": "A spectator shouts loudly just as a sprinter is about to start a race, on purpose. This spectator has...", "options": ["shown good etiquette by creating an exciting atmosphere for the crowd around them", "broken etiquette, because they have deliberately tried to distract a performer", "followed the correct procedure for encouraging a nervous competitor before a big race", "committed an action that automatically disqualifies the sprinter from the whole competition"], "answer": 1, "explain": "Deliberately distracting a performer at a crucial moment breaks etiquette — it is not exciting atmosphere, correct procedure, or grounds to disqualify the sprinter."}, {"question": "A supporter disagrees with a refereeing decision. Which reaction best fits spectator etiquette?", "options": ["Shouting personal abuse at the referee until the decision is reversed", "Showing disagreement without abusing or threatening the official", "Invading the pitch to confront the referee face to face immediately", "Refusing to accept any decision the referee makes for the rest of the fixture, however small"], "answer": 1, "explain": "Disagreeing is normal; abuse, invading the pitch, and refusing to accept every future decision are all etiquette breaches, not acceptable reactions."}, {"question": "Which shows good spectator etiquette towards the people sitting around you?", "options": ["Standing up and blocking other people''s view whenever you personally feel like it", "Being considerate of other spectators, for example not pushing through the crowd", "Taking the best seat available regardless of the ticket you originally bought", "Talking as loudly as possible throughout the whole event so everyone can hear you"], "answer": 1, "explain": "Consideration for fellow spectators — not pushing through crowds — is the etiquette point. Blocking views, seat-taking, and constant loud talking all disregard others."}, {"question": "A spectator throws an object onto the pitch during play. This is a problem mainly because...", "options": ["it could injure a player, official or another spectator nearby", "the referee is required to award a penalty to the away team automatically", "the match ball becomes too heavy to kick accurately for the rest of the game", "every spectator in that stand must be moved to a completely different seat"], "answer": 0, "explain": "Throwing objects is primarily a safety risk to people nearby — it does not change the ball''s weight, trigger an automatic penalty, or force a mass reseating."}, {"question": "Which statement about spectator behaviour is most accurate?", "options": ["Spectators should stay completely silent for the full duration of every single fixture", "Spectators can cheer and applaud, but should be quiet at specific key moments", "Spectators are never allowed to make any noise once a competition has begun", "Spectators should always cheer as loudly as possible no matter what is happening"], "answer": 1, "explain": "Cheering and applause are normal; only specific key moments (like a serve or a putt) call for quiet — total silence and constant loud cheering are both wrong."}]}, "fib": {"enabled": true, "questions": [{"text": "Spectator etiquette is the accepted, respectful way of [behaving] while watching a sport."}, {"text": "Spectators should stay [quiet] during a tennis serve or a golf putt, because noise could distract the performer."}, {"text": "Disagreeing with an official''s decision is normal, but [abusing] them is not."}, {"text": "A good spectator is considerate towards [fellow] spectators as well as the players."}, {"text": "Throwing objects onto the playing area can [injure] a player, official or another spectator."}]}, "tf": {"enabled": true, "questions": [{"statement": "Spectators should stay quiet during a tennis serve or a golf putt.", "answer": true, "explain": "Noise at that exact moment could unfairly distract the performer, so quiet at these key moments protects a fair contest."}, {"statement": "Cheering and applause are never acceptable at any point during a sporting fixture.", "answer": false, "explain": "Cheering and applause are normal and welcome between points or after a good shot — only specific key moments call for quiet."}, {"statement": "Disagreeing with a referee''s decision is against spectator etiquette.", "answer": false, "explain": "Disagreeing is normal. What breaks etiquette is HOW you disagree — abusing or threatening the official is the actual problem."}, {"statement": "A spectator who blocks another spectator''s view is showing poor etiquette.", "answer": true, "explain": "Spectators have a responsibility to be considerate of fellow spectators, including not blocking their view."}, {"statement": "Throwing an object onto the pitch during play is a safety issue as well as an etiquette issue.", "answer": true, "explain": "It could injure a player, official or another spectator, so it breaks both safety rules and spectator etiquette."}, {"statement": "Spectator etiquette only concerns how you treat the players, not other people in the crowd.", "answer": false, "explain": "It also concerns responsibility to fellow spectators — not blocking views or spoiling their enjoyment — not just the players."}]}, "misc": {"enabled": true, "items": [{"myth": "Etiquette for spectators just means being quiet all the time.", "truth": "Etiquette means being quiet at specific key moments (like a serve or a putt), but cheering and applause are expected and welcome at other times. Confusing ''quiet at the right moment'' with ''silent the whole match'' misdescribes the behaviour and loses marks.", "check": {"question": "What does spectator etiquette actually say about noise during a fixture?", "options": ["Stay quiet at specific key moments, but cheering and applause elsewhere are normal", "Make no sound whatsoever from the very first whistle to the very last whistle of the game", "Only match officials are permitted to make any noise inside the stadium at any point", "Cheer as loudly as possible without any pause for the entire length of the fixture"], "answer": 0, "explain": "It is quiet at KEY moments, not total silence — the other options describe rules that do not exist."}}, {"myth": "Disagreeing with a referee''s decision breaks spectator etiquette.", "truth": "Disagreement itself is normal and expected — supporters will not always agree with a decision. What breaks etiquette is HOW you disagree: abuse, threats or invading the pitch. The exam rewards naming the specific behaviour (abuse/threats), not just ''disagreeing''.", "check": {"question": "What actually breaks spectator etiquette when you disagree with a referee''s decision?", "options": ["Abusing or threatening the official, rather than simply disagreeing with the decision", "Sitting in complete silence and refusing to react to the decision at all for the rest of the match", "Politely applauding every single decision the referee makes throughout the whole game", "Discussing the decision quietly with the people sitting in the seats around you"], "answer": 0, "explain": "Disagreement is normal; abuse or threats are what break etiquette, not silence, applause, or a quiet discussion with neighbours."}}, {"myth": "Spectator etiquette is only about how you treat the players.", "truth": "It covers responsibility to fellow spectators too — not blocking views, not pushing through crowds, not spoiling others'' enjoyment — as well as responsibility to the players and safety for everyone.", "check": {"question": "Spectator etiquette covers responsibility towards...", "options": ["both fellow spectators and the players, not just one of these groups", "only the performers taking part, with no responsibility owed to anyone else in the crowd at all", "only the match officials, since spectators cannot affect anyone else at a fixture", "nobody in particular, because spectators are not covered by any etiquette rules"], "answer": 0, "explain": "It covers BOTH fellow spectators and players — restricting it to only performers, only officials, or nobody misses half the topic."}}, {"myth": "Etiquette for performers and for spectators is the same thing, so a spectator question can be answered with performer points.", "truth": "They are different topics on the exam. Performer etiquette (2.4.1) is about how competitors behave when they play — fairness and sportsmanship. Spectator etiquette (this topic) is about how the crowd behaves while watching. A question naming ''spectators'' needs spectator-specific points (quiet moments, responsibility to others, safety), not performer points like gamesmanship.", "check": {"question": "A question specifically asks about SPECTATOR etiquette. What should you avoid writing about?", "options": ["Points that are really about performer behaviour, such as gamesmanship on the pitch", "The specific quiet moments and examples of appropriate crowd behaviour that this exact topic wants you to give", "A spectator''s responsibility to the people sitting around them in the crowd", "Basic safety points about not throwing objects onto the playing area"], "answer": 0, "explain": "Performer points like gamesmanship belong to a different topic (2.4.1) — a spectator question needs spectator-specific points, not performer ones."}}]}, "tips": {"enabled": true, "items": [{"title": "Command words for this topic — what each one wants", "html": "<p>Spectator-etiquette questions are usually short. Match your answer length to the command word:</p>\n<ul>\n<li><strong>Identify / State</strong> — just name it. \"Identify one example of appropriate spectator behaviour [1]\" = one named example, nothing more.</li>\n<li><strong>Describe</strong> — say what the behaviour looks like in a bit more detail.</li>\n<li><strong>Explain</strong> — give a reason. Use the word <em>because</em>. \"Explain why spectators should be quiet during a golf putt\" = the behaviour <em>plus</em> why it matters.</li>\n<li><strong>Discuss</strong> — used for the big 8-mark answers; balance points and reach a judgement.</li>\n</ul>\n<p><strong>Read the mark tariff:</strong> [1] wants one point; short Section A items usually want one point per mark; Section C''s 8 marks want a balanced, judged discussion.</p>", "check": {"question": "A question says: ''Identify one example of appropriate spectator behaviour [1]''. What is the safest answer?", "options": ["One clear example, such as staying quiet during a serve", "A full paragraph explaining several different examples in a lot of detail", "A long list of every single example you can possibly think of", "An example of performer behaviour instead of spectator behaviour"], "answer": 0, "explain": "''Identify'' + [1] wants one named example. A paragraph, a long list, or the wrong topic (performers) all waste the mark."}}, {"title": "The golden rule: behaviour → who it affects → why", "html": "<p>The single most common way to lose marks here is naming a behaviour with nothing else. Build every answer as <strong>behaviour → who it affects → why it matters</strong>:</p>\n<ul>\n<li><strong>❌ 0–1 marks:</strong> \"Being quiet.\"</li>\n<li><strong>✅ full marks:</strong> \"Spectators should be quiet during a golf putt, because noise at that moment could distract the golfer and affect a fair outcome.\"</li>\n</ul>\n<p>In <strong>Section B</strong> the question gives you a scenario (a named venue, named incidents). Then you must use a detail <em>from that scenario</em>, not a general example.</p>", "check": {"question": "Which answer about spectator behaviour is most likely to earn full marks?", "options": ["Naming the behaviour, who it affects, and why it matters", "Just naming a behaviour with no further detail at all", "Listing as many different behaviours as you can remember", "Describing your own personal opinion of a professional athlete"], "answer": 0, "explain": "Full marks come from behaviour + who it affects + why — a bare name, a long list, or a personal opinion do not show that understanding."}}, {"title": "Where this topic appears + sentence starters", "html": "<p><strong>Where it shows up:</strong> spectator etiquette appears as quick recall in <strong>Section A</strong> (identify/state), as applied points in <strong>Section B</strong> scenarios about specific incidents, and it feeds <strong>Section C</strong> 8-mark answers discussing behaviour across a whole sport.</p>\n<p><strong>Three punchy tips:</strong></p>\n<ul>\n<li>Always separate \"quiet at key moments\" from \"silent the whole match\" — the exam rewards precision, not blanket rules.</li>\n<li>Name WHO is affected (a performer, fellow spectators, or both) — it shows you understand responsibility, not just rules.</li>\n<li>Remember safety is its own point, distinct from noise or abuse — don''t forget objects, pitch invasions and crowding.</li>\n</ul>\n<p><strong>Sentence starters for a longer answer:</strong></p>\n<ul>\n<li>\"One way spectator behaviour affects this sport is… because…\"</li>\n<li>\"This matters because…\"</li>\n<li>\"However, the extent to which this matters depends on…\"</li>\n</ul>", "check": {"question": "Why is ''safety'' a useful point to add to a longer spectator-etiquette answer?", "options": ["It shows you understand a spectator''s responsibility beyond just noise", "It simply fills space in the answer without needing to explain anything else properly", "It means spectator behaviour has no effect on anyone else nearby", "It replaces the need to mention performers or officials at all"], "answer": 0, "explain": "Safety is a distinct, creditable point showing wider understanding — it is not filler, and it doesn''t remove the need for other points."}}]}, "exam": {"enabled": true, "questions": [{"question": "Identify <strong>two</strong> examples of appropriate spectator behaviour at a sporting event.", "marks": 2, "hint": "Think about quiet moments (a serve, a putt), not distracting performers, or not abusing officials.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks (AO1)</h5>\n<p><strong>1 mark for each correct, DIFFERENT example, to a maximum of two. Accept any genuine example, including:</strong></p>\n<ul>\n<li>Staying quiet during a tennis serve or a golf putt</li>\n<li>Not shouting or waving to distract a performer</li>\n<li>Not abusing or threatening a player or official</li>\n<li>Not blocking another spectator''s view</li>\n<li>Not invading the playing area</li>\n<li>Not throwing objects onto the pitch, court or course</li>\n</ul>\n<p>Do not credit the same example written twice.</p>\n</div>"}, {"question": "Which of these best shows a spectator meeting their responsibility to the people sitting around them?", "marks": 1, "hint": "Think about who is being protected — the people around you in the crowd.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: B — Being considerate of other spectators, for example not pushing through the crowd.</strong></p>\n<ul>\n<li>This directly protects other spectators'' enjoyment and safety.</li>\n<li>The other options describe behaviour that disregards the people around you.</li>\n</ul>\n</div>"}, {"question": "Explain how <strong>each</strong> of these two incidents at Riverside breaks spectator etiquette.", "marks": 4, "hint": "Take each incident in turn. Name who is affected (the sprinter, or the other spectators) and why the behaviour is a problem, using details from the scenario.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (AO2: application)</h5>\n<p><strong>Up to 2 marks per incident: 1 for identifying who is affected and how, 1 for linking it to the etiquette rule broken. Answers may include:</strong></p>\n<ul>\n<li><strong>Shouting at the start of the sprint</strong> — this could distract the sprinter at a crucial moment, breaking the rule that spectators should not deliberately distract a performer during a key moment.</li>\n<li><strong>Pushing to the front of the crowd</strong> — this blocks the view of the families behind, breaking a spectator''s responsibility to be considerate of fellow spectators.</li>\n</ul>\n<p>Accept any other reasonable, applied answer linked to the scenario.</p>\n</div>"}, {"question": "Discuss how the behaviour of both performers and spectators affects a sport like this derby.", "marks": 8, "hint": "Cover both groups: what performers do (fairness, gamesmanship) and what spectators do (quiet moments, abuse, safety). Weigh up the effect of good AND poor behaviour, then give a judgement on which matters most.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 8 marks (level-of-response). Read the band you fit, then pick a mark.</h5>\n<ul>\n<li><strong>Band 3 (thorough), 6–8:</strong> a balanced, well-applied discussion covering BOTH performer and spectator behaviour, showing clearly how each affects fairness, safety and enjoyment, weighing good against poor behaviour, ending in a justified judgement.</li>\n<li><strong>Band 2 (reasonable), 3–5:</strong> sound understanding applied to performer AND/OR spectator behaviour with some analysis, but the discussion may be one-sided (covering only one group) or the judgement is unsupported.</li>\n<li><strong>Band 1 (basic), 1–2:</strong> names behaviours with little application and no real evaluation; largely a list.</li>\n<li><strong>0 marks:</strong> nothing creditworthy.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Indicative content (indicative, not a checklist — reward valid alternatives)</h5>\n<ul>\n<li><strong>Performer behaviour:</strong> arguing with officials undermines respect for decisions and can inflame the crowd; good sportsmanship (accepting decisions, fair play) keeps the derby competitive without conflict.</li>\n<li><strong>Spectator behaviour:</strong> abuse from the sidelines can intimidate players and officials and put off families from attending; quiet, respectful support (and staying off the pitch) keeps the event safe and enjoyable.</li>\n<li><strong>Interaction between the two:</strong> poor performer conduct can encourage worse spectator behaviour, and a hostile crowd can pressure officials or wind up players — the two groups affect each other, not just the sport separately.</li>\n<li><strong>Evaluation:</strong> performer conduct is closer to the action and shapes the atmosphere, but spectator conduct affects far more people (the whole crowd) and long-term attendance.</li>\n<li><strong>Judgement:</strong> both matter, but spectator behaviour may be the bigger long-term risk because it affects whether families feel safe to keep coming — though performer conduct often sets the tone spectators react to.</li>\n</ul>\n</div>"}]}}'::jsonb),
('sport-studies', '2-5-1-why-performers-use-peds', '2.5.1 Why Performers Use PEDs', '{"learn": {"enabled": true, "items": [{"title": "What is a PED, and why do performers use one?", "html": "<h4>Defining a PED</h4>\n<ul>\n<li>A <strong>performance-enhancing drug (PED)</strong> is a banned substance that a performer takes to make their body perform better than training, diet and natural ability alone could achieve.</li>\n<li>A PED is not the same as a legal supplement. A vitamin tablet or a protein shake is allowed; what makes something a PED is that it is <strong>banned</strong> because it gives an artificial edge other performers do not have.</li>\n</ul>\n<h4>Why \"why\" matters</h4>\n<ul>\n<li>This page looks only at the <strong>reasons performers give for using PEDs</strong> — not whether those reasons are acceptable. The health, ethical, legal and career case AGAINST using PEDs is covered on a separate page.</li>\n<li>Very few performers dope for a single reason. Usually several pressures — competitive, financial, physical and psychological — build up together.</li>\n</ul>", "check": {"question": "Which of these best describes what makes a substance a PED?", "options": ["A drink or snack an athlete happens to have shortly before any competition", "A banned substance used to make the body perform better than training alone could", "A legal vitamin supplement that all professional athletes are encouraged to take daily", "A specialist training programme only available to full-time professional athletes"], "answer": 1, "explain": "A PED is defined by being BANNED and giving an artificial edge — legal supplements, pre-match snacks and training programmes are not PEDs."}}, {"title": "Winning, money and the fear that rivals are already doping", "html": "<h4>Pressure to win and succeed</h4>\n<ul>\n<li>Top-level sport can feel like it only rewards first place. Some performers feel intense <strong>pressure to win or succeed</strong> — from themselves, a coach, a country, or years of sacrifice — and see a PED as a shortcut to that success.</li>\n<li>The closer a performer gets to elite level, the smaller the gaps between rivals become, so even a small artificial advantage can feel decisive.</li>\n</ul>\n<h4>Financial reward, fame and sponsorship</h4>\n<ul>\n<li>Winning at the highest level can bring <strong>financial rewards</strong>, media <strong>fame</strong>, and valuable <strong>sponsorship deals</strong>. For some performers, their income and career depend on staying near the top.</li>\n<li>A performer worried about losing funding, a team place, or a sponsor''s support may see doping as protecting their livelihood, not only their pride.</li>\n</ul>\n<h4>\"Everyone else is doing it\"</h4>\n<ul>\n<li>Some performers use PEDs because they <strong>believe their rivals are already doping</strong>. They convince themselves that using one too is the only way to compete on equal terms — even though that belief may be wrong, and it never actually makes doping fair or legal.</li>\n</ul>", "check": {"question": "Why might a performer''s belief about their rivals lead them to use a PED?", "options": ["An official has personally confirmed that doping is now permitted at every level", "They simply want to copy a rival''s kit sponsor because they like the new design", "They believe rivals are already doping, so they feel they must too to keep up", "Their national governing body offers a cash reward for reporting a rival who cheats"], "answer": 2, "explain": "The belief that rivals are already doping — right or wrong — is a genuine reason some performers give, distinct from an official ruling or a kit preference."}}, {"title": "Training harder, recovering faster — and the physical and mental pull", "html": "<h4>Training harder and recovering faster</h4>\n<ul>\n<li>Some PEDs let a performer <strong>train harder and for longer</strong> than their body would naturally allow, and <strong>recover more quickly</strong> from intense training or from an injury.</li>\n<li>A performer under pressure to return from injury quickly — for example before a major competition — may see a PED as a way to speed that recovery up.</li>\n</ul>\n<h4>Physical gains</h4>\n<ul>\n<li>PEDs can produce real physical changes: extra <strong>strength</strong>, extra <strong>speed</strong>, or greater <strong>endurance</strong> — often exactly the gains that separate a good performance from a winning one.</li>\n</ul>\n<h4>Psychological effects</h4>\n<ul>\n<li>Some PEDs affect the mind as well as the body — for example reducing anxiety, raising confidence, or dulling the perception of pain and fatigue during competition. A performer may use a PED partly for this mental lift, not only for a physical gain.</li>\n</ul>", "check": {"question": "Which of these is a PSYCHOLOGICAL reason a performer might give for using a PED, rather than a purely physical one?", "options": ["It can noticeably increase a performer''s muscle size and top running speed", "It can make a performer feel calmer, more confident or less aware of pain", "It can shorten the time a performer needs to recover from a hard session", "It can be bought at a lower price than most legal supplements in a shop"], "answer": 1, "explain": "Feeling calmer or more confident is a mental (psychological) effect. Muscle size, speed and recovery time are physical effects, and price is unrelated to either."}}]}, "terms": {"enabled": true, "pairs": [{"term": "PED", "definition": "A banned substance taken to make the body perform better than training alone could"}, {"term": "Pressure to win/succeed", "definition": "Feeling that only finishing first justifies the sacrifice already made"}, {"term": "Financial reward / sponsorship", "definition": "Income and profile a performer may fear losing if results slip"}, {"term": "Belief rivals are doping", "definition": "Thinking a PED is the only way left to compete on equal terms"}, {"term": "Faster injury recovery", "definition": "Wanting to return to full training sooner than the body naturally allows"}, {"term": "Psychological effect", "definition": "A PED changing how a performer feels, e.g. calmer or more confident"}]}, "mcq": {"enabled": true, "questions": [{"question": "A performer takes a banned substance so their body performs better than training alone could. What is this substance called?", "options": ["A performance-enhancing drug (PED)", "A licensed supplement approved for use by the athlete''s national governing body", "A recovery drink that is sold openly in any supermarket or high-street pharmacy", "A type of monitoring equipment used to record an athlete''s heart rate in training"], "answer": 0, "explain": "This is the definition of a PED. A governing-body-approved supplement, a supermarket drink and monitoring equipment are all legal and are not PEDs."}, {"question": "Which of these best shows ''pressure to win or succeed'' as a reason for using a PED?", "options": ["A performer enjoys watching highlights of other athletes competing at major international events", "A performer feels that only finishing first can justify the sacrifices they have already made", "A performer prefers early morning training sessions rather than joining a full squad session", "A performer changes clubs because the new club happens to train closer to their family home"], "answer": 1, "explain": "Feeling that only winning justifies years of sacrifice is pressure to succeed. Enjoying highlights, a training-time preference and changing clubs for convenience are not this pressure."}, {"question": "How can fame and sponsorship push a performer towards using a PED?", "options": ["Sponsors often ask performers to wear a particular brand of training shoe", "Being well known makes it slightly easier to book a table at a busy restaurant", "Media appearances usually take place on the morning after a big competition", "Losing form could cost them their sponsorship income and their public profile"], "answer": 3, "explain": "The risk of losing income and profile is the real pressure. Wearing sponsored kit, restaurant bookings and appearance timing are unrelated details, not pressures to dope."}, {"question": "A performer suspects several rivals are secretly using banned substances. Why might this push them towards doping too?", "options": ["They plan to publicly accuse those rivals of doping at the next major press conference they attend", "They feel doping is the only way left to compete on what feels like equal terms", "They decide to switch permanently to a completely different sporting event entirely", "They ask their coach to file a formal complaint with the event organisers instead"], "answer": 1, "explain": "Believing rivals already dope can make a performer feel they must do the same to keep up — even though that belief doesn''t make doping fair or legal."}, {"question": "A performer is racing to recover from injury before a major competition. Which reason for using a PED does this describe?", "options": ["Wanting a PED purely because a teammate has recommended trying it out first", "Wanting a PED purely so they can skip the qualifying rounds required before the next major competition", "Wanting a PED to speed up recovery and allow much harder training in the meantime", "Wanting a PED to change which weight category they are allowed to compete in"], "answer": 2, "explain": "Speeding up recovery from injury and enabling harder training is the reason described. Skipping qualifiers, changing categories and peer suggestion are different issues."}, {"question": "Which of these describes a physical, rather than psychological, gain some PEDs are used for?", "options": ["A reduced feeling of anxiety before stepping out in front of a large home crowd", "Increased confidence during the final, most pressured stage of a long and closely fought competition", "A dulled awareness of pain and fatigue while competing near the end of a race", "Extra strength, speed or endurance that can turn a good performance into a winning one"], "answer": 3, "explain": "Strength, speed and endurance are physical gains. Reduced anxiety, increased confidence and dulled pain awareness are all psychological (mental) effects, not physical ones."}]}, "fib": {"enabled": true, "questions": [{"text": "A PED is a [banned] substance taken to make the body perform better than training alone could."}, {"text": "Some performers feel intense pressure to [succeed], which can push them towards doping."}, {"text": "Losing form could cost a performer their income and their [sponsorship] deals."}, {"text": "Believing that rivals are already doping can make a performer feel they must too, to compete on equal [terms]."}, {"text": "Some PEDs can dull the perception of pain, which is a [psychological] rather than physical effect."}]}, "tf": {"enabled": true, "questions": [{"statement": "A PED is defined as a banned substance that boosts performance beyond what training alone could achieve.", "answer": true, "explain": "That is the definition — being BANNED and giving an artificial edge is what makes a substance a PED, not simply that it affects performance."}, {"statement": "A legal vitamin tablet or protein shake counts as a PED.", "answer": false, "explain": "Legal supplements are not banned, so they are not PEDs — even though they may support training and recovery."}, {"statement": "Performers only ever dope for one single reason at a time.", "answer": false, "explain": "Reasons usually combine — competitive pressure, money, injury recovery and psychological effects can all be present together."}, {"statement": "Believing that rivals are already doping makes it fair and legal for a performer to dope too.", "answer": false, "explain": "That belief is a reason performers GIVE — it never actually makes doping fair or legal, even if the belief is genuinely held."}, {"statement": "PEDs can only ever affect the body, never the mind.", "answer": false, "explain": "Some PEDs also produce psychological effects, such as reduced anxiety or increased confidence, alongside any physical change."}, {"statement": "Wanting to recover more quickly from an injury before a major competition can be a reason for using a PED.", "answer": true, "explain": "Faster recovery from injury (and the chance to return to harder training sooner) is one of the recognised reasons performers give."}]}, "misc": {"enabled": true, "items": [{"myth": "Doping is always just about wanting to win — there''s no other reason involved.", "truth": "Winning is a common reason, but it is rarely the only one. Financial pressure (sponsorship and income), the belief that rivals already dope, faster injury recovery, and psychological effects like reduced anxiety can all combine with the wish to win. A strong answer names more than one pressure, not just ''winning''.", "check": {"question": "Which statement best reflects why performers actually give for using PEDs?", "options": ["Winning is genuinely and completely the only reason any performer would ever consider", "Performers only ever dope because a coach personally orders it", "Several different pressures can combine, not just the wish to win", "There is no real pattern to why any performer chooses to dope"], "answer": 2, "explain": "The reasons stack up together — competitive, financial, physical and psychological — so ''just winning'' undersells the topic and loses marks."}}, {"myth": "If a performer believes their rivals are doping, that belief makes it fair for them to dope too.", "truth": "This is a REASON some performers give, not a justification. Believing rivals are already using PEDs does not make doping legal or fair — it is still banned and still against the rules, whatever a performer privately believes about their competition.", "check": {"question": "A performer says: ''Everyone else is doing it, so it''s fine if I do it too.'' What is the accurate view of this?", "options": ["It is a genuine reason some performers give, but it does not make doping fair or legal", "It is completely correct, because doping only becomes banned once a majority stop using it", "It means the performer will automatically be cleared if they are later tested", "It proves that every single one of their rivals must already be using a PED"], "answer": 0, "explain": "The belief explains WHY a performer might dope, but explaining a reason is not the same as the reason making the act fair or legal."}}, {"myth": "PEDs only ever change how strong, fast or fit a performer''s body is.", "truth": "PEDs can also change how a performer FEELS. Alongside physical gains like strength, speed or endurance, some PEDs reduce anxiety, raise confidence, or dull the sense of pain and fatigue — a psychological effect as well as a physical one.", "check": {"question": "What is missing from the claim that PEDs ''only ever affect the body''?", "options": ["It ignores the price that a performer would have to pay to obtain a PED", "It ignores possible psychological effects, such as reduced anxiety or greater confidence", "It ignores the fact that PEDs are always completely undetectable in every single drug test", "It ignores the length of ban an athlete would receive if they were caught"], "answer": 1, "explain": "Physical change is only half the picture — psychological effects (calmer, more confident, less aware of pain) are part of why some performers use PEDs."}}]}, "tips": {"enabled": true, "items": [{"title": "Command words for this topic — what each one wants", "html": "<p>Questions on why performers use PEDs are usually short recall or short application. Match your answer length to the command word:</p>\n<ul>\n<li><strong>Identify / State</strong> — just name the reason. \"State one reason a performer might use a PED [1]\" = one named reason, nothing more.</li>\n<li><strong>Describe</strong> — say what the reason involves. \"Describe one reason...\" = give the features of that pressure.</li>\n<li><strong>Explain</strong> — add why it pushes a performer towards doping. Use the word <em>because</em> and link the reason to the effect it has on the performer.</li>\n</ul>\n<p><strong>Read the mark tariff:</strong> [1] wants one point; [2] usually wants two named reasons, or one point developed; [4] in Section B wants reasons applied to the scenario you are given.</p>", "check": {"question": "A question says: ''Identify two reasons why a performer might use a PED [2]''. What is the safest answer?", "options": ["Two named reasons, nothing more", "One long paragraph exploring a single reason in depth", "A full page listing every reason you can possibly remember", "A description of a famous doping case you once read about"], "answer": 0, "explain": "''Identify'' + [2] = two names, one mark each. A long paragraph on one reason, or a long list, wastes time without earning extra marks."}}, {"title": "The golden rule: name the reason AND link it to the performer", "html": "<p>The most common way to lose marks here is stopping at a bare label. Build every answer as <strong>reason → link to the performer</strong>:</p>\n<ul>\n<li><strong>❌ 0–1 marks:</strong> \"Sponsorship.\"</li>\n<li><strong>✅ full marks:</strong> \"A performer might use a PED because losing form could cost them their sponsorship income, which they may depend on for their career.\"</li>\n</ul>\n<p>In <strong>Section B</strong> the question gives you a scenario (a named performer, a named pressure). You must then use a detail <em>from that scenario</em>, not a generic example.</p>", "check": {"question": "In a Section B scenario about a named performer under pressure, your explanation should come from...", "options": ["any doping story you happen to already know", "your own opinion about whether doping should be legal", "the scenario you are given", "a completely different sport to the one in the scenario"], "answer": 2, "explain": "Section B is applied — the marks are for using the scenario in front of you. A generic reason that ignores the scenario is capped."}}, {"title": "Where this topic appears + sentence starters", "html": "<p><strong>Where it shows up:</strong> reasons for using PEDs appear as quick recall in <strong>Section A</strong> (identify/state/explain), as applied points in a <strong>Section B</strong> scenario about a named performer, and can feed a <strong>Section C</strong> 8-mark Discuss question about doping more broadly.</p>\n<p><strong>Three punchy tips:</strong></p>\n<ul>\n<li>Learn the reasons in groups (competitive, financial, physical, psychological) so you can always recall several.</li>\n<li>For every reason, memorise <em>one</em> way it links to the performer — that link is usually where the mark is.</li>\n<li>Remember that reasons combine — a strong answer rarely relies on just one pressure.</li>\n</ul>\n<p><strong>Sentence starters for a longer answer:</strong></p>\n<ul>\n<li>\"One reason performers may use PEDs is… because…\"</li>\n<li>\"This pressure matters because…\"</li>\n<li>\"However, this reason does not make doping…\"</li>\n</ul>", "check": {"question": "Why is it useful to remember that reasons for doping usually combine, rather than acting alone?", "options": ["It means only one single reason is ever tested in the exam", "It proves that doping should be made completely legal for everyone", "It replaces the need to give any reason at all in your answer", "It shows deeper understanding than naming just one pressure"], "answer": 3, "explain": "Showing that pressures stack up (competitive, financial, physical, psychological) demonstrates the depth of understanding a Section B or C answer rewards."}}]}, "exam": {"enabled": true, "questions": [{"question": "Identify <strong>two</strong> reasons why a sports performer might choose to use a PED.", "marks": 2, "hint": "Pick from the reasons on this page — pressure to win, money/fame/sponsorship, the belief that rivals are doping, faster recovery from injury, physical gains, or psychological effects.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks (AO1)</h5>\n<p><strong>1 mark for each correct, DIFFERENT reason named, to a maximum of two. Accept any two from:</strong></p>\n<ul>\n<li>Pressure to win or succeed</li>\n<li>Financial reward / fame / sponsorship</li>\n<li>Belief that rivals are already doping</li>\n<li>To train harder and recover faster from injury</li>\n<li>Physical gains (strength, speed, endurance)</li>\n<li>Psychological effects (e.g. reduced anxiety, increased confidence)</li>\n</ul>\n<p>Do not credit the same reason written twice, even in different words.</p>\n</div>"}, {"question": "Which of these is a genuine reason some sports performers give for using a PED?", "marks": 1, "hint": "Think about which option matches a reason actually taught on this page.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: C — They believe it will help them recover faster from an injury and train harder.</strong></p>\n<ul>\n<li>Faster recovery and harder training is one of the recognised reasons performers give.</li>\n<li>The other options describe things that are not true of a banned PED (official approval, free availability, referee recommendation).</li>\n</ul>\n</div>"}, {"question": "Using the scenario, explain <strong>two</strong> reasons why Ellie might be tempted to use a PED.", "marks": 4, "hint": "Take each reason in turn. Name the reason, then link it to a detail from the scenario (the sponsorship deadline, the hamstring injury, or the rumour about a rival).", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (AO2: application)</h5>\n<p><strong>Up to 2 marks per reason: 1 for identifying a relevant reason, 1 for linking it to the scenario. Answers may include:</strong></p>\n<ul>\n<li><strong>Financial / sponsorship pressure</strong> — Ellie''s contract depends on a top-three finish, so she may feel she needs an artificial edge to keep her income.</li>\n<li><strong>Faster recovery from injury</strong> — the six-week hamstring injury has cost her training time, so she may see a PED as a way to catch up before the championship.</li>\n<li><strong>Belief a rival is doping</strong> — the rumour about a rival may make Ellie feel she needs to do the same to compete on equal terms.</li>\n</ul>\n<p>Accept any two different, scenario-linked reasons. A reason with no link to the scenario earns 1 of the 2 marks for that reason.</p>\n</div>"}, {"question": "Discuss why some athletes turn to PEDs despite the risks involved.", "marks": 8, "hint": "Cover two or three different reasons (competitive, financial, physical, psychological). For each, explain why it pushes an athlete towards doping. Then weigh it up against the risks, and finish with a justified judgement.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 8 marks (level-of-response). Read the band you fit, then pick a mark.</h5>\n<ul>\n<li><strong>Band 3 (thorough), 6–8:</strong> a balanced, well-applied discussion of several reasons for using PEDs, showing clearly why they push an athlete towards doping AND weighing this against the risks involved, ending in a justified judgement.</li>\n<li><strong>Band 2 (reasonable), 3–5:</strong> sound understanding of more than one reason with some analysis, but the discussion may be one-sided (reasons only, no risks) or the judgement unsupported.</li>\n<li><strong>Band 1 (basic), 1–2:</strong> names reasons with little explanation and no real evaluation; largely a list.</li>\n<li><strong>0 marks:</strong> nothing creditworthy.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Indicative content (indicative, not a checklist — reward valid alternatives)</h5>\n<ul>\n<li><strong>Competitive pressure:</strong> the pressure to win or succeed, especially where career or funding depends on results.</li>\n<li><strong>Financial pressure:</strong> fame, sponsorship and income can depend on staying near the top.</li>\n<li><strong>Belief rivals are doping:</strong> athletes may feel they must dope to compete on equal terms, even though this belief does not make it fair or legal.</li>\n<li><strong>Physical / recovery gains:</strong> training harder, recovering faster from injury, and gains in strength, speed or endurance.</li>\n<li><strong>Psychological effects:</strong> reduced anxiety, increased confidence, or a dulled sense of pain.</li>\n<li><strong>Evaluation:</strong> these pressures are real and can feel overwhelming, but they must be weighed against the risks (health harm, bans, loss of reputation and results); the pressures explain the behaviour without justifying it.</li>\n<li><strong>Judgement:</strong> the pressures on athletes are genuine and can combine to feel inescapable, but because the risks (health, career, reputation) are so serious, understanding \"why\" should lead to better support and education rather than being treated as an excuse.</li>\n</ul>\n</div>"}]}}'::jsonb),
('sport-studies', '2-5-2-why-performers-should-not-use-peds', '2.5.2 Why Performers Should Not Use PEDs', '{"learn": {"enabled": true, "items": [{"title": "The health risks of using PEDs", "html": "<h4>Short-term effects</h4>\n<ul>\n<li>Even a short course of PEDs can bring on sudden mood swings, aggression, disturbed sleep and a higher risk of injury from training harder than the body is ready for.</li>\n<li>Some substances put an immediate strain on the heart and liver as the body tries to cope with them.</li>\n</ul>\n<h4>Long-term effects</h4>\n<ul>\n<li>Months or years of use can leave lasting damage to the heart, liver and kidneys, and can upset the body''s normal hormone balance.</li>\n<li>Some of this damage does not reverse once a performer stops using the substance — the risk does not end when the use does.</li>\n</ul>\n<h4>Why this matters for the exam</h4>\n<ul>\n<li>A vague line such as \"it damages your body\" earns little. Naming a <strong>short-term</strong> effect and a separate <strong>long-term</strong> one shows the depth an examiner is looking for.</li>\n</ul>", "check": {"question": "Which of these is best described as a LONG-TERM health risk of using PEDs, rather than a short-term one?", "options": ["Feeling unusually irritable during the very first week or two of starting the substance", "Lasting damage to organs such as the heart, liver or kidneys after months of use", "A single night of poor sleep straight after an evening training session", "A sudden mood swing that a training partner happens to notice"], "answer": 1, "explain": "Organ damage and disrupted hormones typically build up over months or years of use, and can outlast the use itself — that makes it long-term, unlike a mood swing or one bad night''s sleep."}}, {"title": "Why using PEDs is cheating — and often against the law", "html": "<h4>Unfair on clean athletes</h4>\n<ul>\n<li>Sport is meant to test natural ability, training and skill. A performer who uses PEDs gains an advantage that a clean rival has not agreed to and cannot fairly match, however hard that rival trains.</li>\n<li>This is why using PEDs is <strong>cheating</strong>, not simply a risky personal choice — it can change who actually wins.</li>\n</ul>\n<h4>Against the rules of the sport</h4>\n<ul>\n<li>Every governing body bans PEDs in its own rules. Using them breaks those rules whether or not a performer is ever caught by a test.</li>\n</ul>\n<h4>Often against the law too</h4>\n<ul>\n<li>Many performance-enhancing substances are controlled under UK law, so possessing, using or supplying them can lead to criminal trouble as well as sporting trouble.</li>\n<li>A performer who uses PEDs can end up breaking two separate sets of rules at once: the sport''s own rules, and the law of the land.</li>\n</ul>", "check": {"question": "Why is using PEDs described as ''cheating'', rather than just a risky personal choice?", "options": ["Because it gives an advantage a clean rival has not agreed to and cannot fairly match", "Because every performer who tries it is caught by a drugs test within days", "Because it always costs a lot more money than training naturally without any banned substances", "Because coaches personally disapprove of it on moral grounds in every single case"], "answer": 0, "explain": "The advantage is unearned and cannot be matched by fair training, which is what turns it from a personal risk into cheating that affects the whole competition."}}, {"title": "The fallout: sanctions, career and being a role model", "html": "<h4>Sporting sanctions</h4>\n<ul>\n<li>A performer caught using PEDs can be banned from competing, fined, and stripped of any titles or medals won while using the substance.</li>\n<li>A ban can end a career outright, especially for a performer whose competitive years are already limited.</li>\n</ul>\n<h4>Career and reputation</h4>\n<ul>\n<li>A positive test is usually made public, so a performer can lose sponsorship deals, income and the trust of fans and teammates — often for good.</li>\n</ul>\n<h4>Being a role model</h4>\n<ul>\n<li>Elite performers are watched and copied by young fans. A performer who uses PEDs risks teaching those fans that cheating is an acceptable shortcut to success.</li>\n</ul>", "check": {"question": "Why is ''being a role model'' a genuine reason for a performer not to use PEDs?", "options": ["Because role models are legally banned from ever taking part in competitive sport", "Because young fans may copy the choices they see successful performers make", "Because it has no real connection to a performer''s own personal decisions", "Because only performers who already have sponsorship deals count as role models"], "answer": 1, "explain": "Fans, especially young ones, often copy the behaviour of performers they look up to — so a performer''s choice to use PEDs can spread beyond their own career."}}]}, "terms": {"enabled": true, "pairs": [{"term": "Short-term health risk", "definition": "Mood swings, poor sleep and raised injury risk appearing within days of use"}, {"term": "Long-term health risk", "definition": "Lasting organ damage and disrupted hormones from months or years of use"}, {"term": "Cheating", "definition": "Gaining an advantage a clean rival has not agreed to and cannot fairly match"}, {"term": "Rules and the law", "definition": "PED use breaks a sport''s own ban, and often UK law on controlled substances"}, {"term": "Sporting sanction", "definition": "A ban, fine, or loss of a title/medal for a performer caught using PEDs"}, {"term": "Role-model responsibility", "definition": "Young fans may copy the choices they see elite performers make"}]}, "mcq": {"enabled": true, "questions": [{"question": "A performer has used PEDs for over a year. Which of these is most likely to be a LONG-TERM effect of that use?", "options": ["A single restless night before an important competition", "Lasting damage to the heart, liver or kidneys, and disrupted hormones", "Feeling nervous just before stepping out to compete", "A short burst of extra confidence and energy lasting only for one single afternoon"], "answer": 1, "explain": "Sustained use over months or years is what causes lasting organ damage and hormone disruption. The other options describe brief, one-off feelings, not lasting harm."}, {"question": "A sprinter says, ''It''s not cheating if it just helps me train harder.'' Why is this argument wrong?", "options": ["Because using PEDs gives an advantage a clean rival cannot fairly match, so it is cheating", "Because sprinters are never actually tested for banned substances at all", "Because training harder is always against the rules of every sport", "Because only substances that are completely legal to buy in an ordinary shop count as cheating"], "answer": 0, "explain": "Whatever a performer''s intention, PEDs create an advantage a clean rival has not agreed to and cannot match through training alone — that is what makes it cheating."}, {"question": "Which statement correctly links PED use to the law, not just to sporting rules?", "options": ["PEDs are always freely and completely legally available from any high-street pharmacy", "Many PEDs are controlled substances, so using them can also be a criminal matter", "Sporting rules and UK law always say exactly the same thing about PEDs", "The law only applies to performers who compete at international level"], "answer": 1, "explain": "Because many PEDs are controlled substances, a performer can face criminal consequences on top of sporting ones — sporting rules and the law are separate but can both apply."}, {"question": "A performer is found to have used PEDs during a competition they won. What is a likely sporting sanction?", "options": ["An official warning with absolutely no other consequence attached to it", "Being stripped of the title or medal, alongside a ban and possibly a fine", "A guaranteed place in the following year''s national training squad", "A formal invitation to become an ambassador for the sport''s governing body"], "answer": 1, "explain": "Stripping the title or medal, a ban and a fine are the standard sporting sanctions — the other options describe rewards, which would never follow a positive test."}, {"question": "Why might a positive PED test damage a performer''s career even after any ban ends?", "options": ["Because governing bodies automatically double every performer''s future funding", "Because sponsors and fans may permanently lose trust, costing income and reputation", "Because a ban legally prevents the performer from ever training again", "Because the media are legally required by law to permanently stop reporting on that performer"], "answer": 1, "explain": "Lost sponsorship, income and public trust can outlast the ban itself — reputational damage is often the longer-lasting consequence, not a legal block on training."}, {"question": "A youth coach says PEDs are ''a private choice that only affects the performer using them.'' Why is this misleading?", "options": ["Because young fans may copy the behaviour of performers they admire", "Because it is completely accurate and no one else is ever affected by it", "Because only coaches, and never fans, are influenced by a performer''s choices", "Because private choices are never relevant to any sporting rules whatsoever"], "answer": 0, "explain": "Elite performers are watched and copied, especially by young fans, so a ''private'' choice to use PEDs can spread its influence well beyond the performer themselves."}]}, "fib": {"enabled": true, "questions": [{"text": "Using PEDs can cause serious [health] risks, both straight away and years later."}, {"text": "PED use is a form of [cheating] because it creates an advantage a clean rival cannot fairly match."}, {"text": "Many PEDs are controlled substances, so using them can break the [law] as well as the rules of the sport."}, {"text": "A performer caught using PEDs can be [banned] from competition and lose any titles they won."}, {"text": "Elite performers are role models, so young fans may [copy] risky choices they see them make."}]}, "tf": {"enabled": true, "questions": [{"statement": "PEDs can cause serious health problems that only appear years after a performer stops using them.", "answer": true, "explain": "Long-term damage to organs and hormone balance can build up over time and can outlast the period of use — the risk does not simply end when the substance stops."}, {"statement": "Using PEDs is only a genuine problem if a performer actually gets caught by a drugs test.", "answer": false, "explain": "The health risks and the unfair advantage both exist whether or not a performer is ever tested — getting caught only adds sporting and legal consequences on top."}, {"statement": "PED use can break UK law as well as the rules of a sport.", "answer": true, "explain": "Many PEDs are controlled substances, so possessing, using or supplying them can be a criminal matter in addition to a breach of sporting rules."}, {"statement": "A performer who is banned for using PEDs usually keeps any medals they won while using the substance.", "answer": false, "explain": "Sanctions typically include being stripped of titles or medals won while using the substance, alongside a ban and possibly a fine."}, {"statement": "Losing sponsorship deals is a realistic risk for a performer whose PED use becomes public.", "answer": true, "explain": "A positive test is usually made public, and sponsors can withdraw support once trust with fans and the public is damaged."}, {"statement": "Whether a performer is seen as a role model has nothing to do with whether they should use PEDs.", "answer": false, "explain": "It is directly relevant — young fans often copy the choices of performers they admire, so a performer''s decision can influence people beyond themselves."}]}, "misc": {"enabled": true, "items": [{"myth": "PEDs are only a problem if you get caught — if nobody finds out, no real harm has been done.", "truth": "Getting caught only adds sporting and legal consequences on top of harms that exist either way. The health risks happen to the performer''s own body regardless of any test result, and the unfair advantage over clean rivals exists the moment the substance is used, whether or not anyone ever finds out.", "check": {"question": "What is wrong with the idea that PED use ''doesn''t matter unless you get caught''?", "options": ["Nothing at all — getting caught is genuinely the only real consequence that ever exists", "The health risks and unfair advantage exist regardless of whether anyone finds out", "Drugs tests are so accurate that every single user is always caught immediately", "Being caught actually removes all of the health risks a performer has taken"], "answer": 1, "explain": "The harm to the performer''s own health, and the unfair advantage over clean rivals, both exist the moment PEDs are used — detection only adds further consequences."}}, {"myth": "Using PEDs is basically the same as any other risky training method, such as training too hard.", "truth": "Overtraining is risky, but it is not against the rules or the law, and it does not create an unearned advantage over rivals. PED use is different because it is a deliberate breach of a sport''s rules (and often the law), designed specifically to gain an edge a rival cannot fairly match — that combination is what makes it cheating, not just a training risk.", "check": {"question": "How does PED use differ from a risky training method like overtraining?", "options": ["It doesn''t — the two carry exactly the same risks and consequences for a performer", "PED use deliberately breaks a sport''s rules (and often the law) to gain an unfair edge", "Overtraining is actually more strictly banned by governing bodies than PED use is", "Only PED use can ever possibly lead to any kind of physical injury occurring during training"], "answer": 1, "explain": "Overtraining is not a rule-break; PED use is a deliberate breach of the sport''s rules, and often the law, aimed at gaining an advantage rivals cannot fairly match."}}, {"myth": "The only real consequence of using PEDs is being banned from competing.", "truth": "A ban is just one of several consequences. A performer can also be fined, stripped of titles or medals, lose sponsorship and income, damage their reputation with fans for good, face legal trouble because many PEDs are controlled substances, and risk their own long-term health — a ban rarely stands alone.", "check": {"question": "Besides a ban, which of these is also a realistic consequence of using PEDs?", "options": ["An automatic and guaranteed improvement in the performer''s public reputation", "Being fined, stripped of titles, and losing sponsorship income", "A guaranteed place on the national governing body''s board", "Permanent removal of every health risk the substance caused"], "answer": 1, "explain": "Fines, stripped titles and lost sponsorship commonly accompany a ban — reputation, legal and health consequences can follow too, so a ban is rarely the only outcome."}}]}, "tips": {"enabled": true, "items": [{"title": "Command words and mark tariffs for this topic", "html": "<p>Questions on why performers should not use PEDs are set at every level of demand:</p>\n<ul>\n<li><strong>Identify / State</strong> — just name a reason. \"Identify one reason performers should not use PEDs [1]\" wants a single named reason, nothing more.</li>\n<li><strong>Explain</strong> — give a reason plus a \"because\". \"Explain why PED use is considered cheating [2]\" wants the idea (unfair advantage) plus why that makes it cheating.</li>\n<li><strong>Discuss / Evaluate</strong> — weigh both sides of an issue and reach a justified judgement. These carry the highest tariffs (6 or 8 marks) and appear in Sections B and C.</li>\n</ul>\n<p><strong>Read the mark tariff:</strong> [1] wants one point; [4] in Section B wants points applied to a scenario; [8] in Section C wants balance and a judgement, not a list.</p>", "check": {"question": "A question says: ''Explain one reason why performers should not use PEDs [2]''. What earns full marks?", "options": ["Naming as many reasons as possible without any explanation", "A named reason plus a linked ''because'' that develops it", "A single word with no further detail at all", "A long list of every sanction a performer could ever face"], "answer": 1, "explain": "''Explain'' plus [2] wants a reason developed with a reason why — a bare list, a single word, or an undeveloped list of sanctions would not reach both marks."}}, {"title": "Building a balanced Discuss / Evaluate answer", "html": "<p>The 8-mark question on this topic usually asks you to weigh the risks of PED use against any possible gains, then reach a judgement. Use this shape:</p>\n<ul>\n<li>Give a risk (health, cheating, sanctions, career) and explain why it matters.</li>\n<li>Acknowledge a possible gain a performer might hope for (better performance, faster results), so your answer is balanced, not one-sided.</li>\n<li>Weigh them against each other, then commit to a judgement — don''t just describe both sides and stop.</li>\n</ul>\n<p><strong>Three sentence starters for a longer answer:</strong></p>\n<ul>\n<li>\"One serious risk of using PEDs is… because…\"</li>\n<li>\"However, some performers might feel the possible gain of… is worth it because…\"</li>\n<li>\"Overall, the risks outweigh the gains because…\"</li>\n</ul>", "check": {"question": "Why should a Discuss / Evaluate answer on this topic mention a possible gain, not only the risks?", "options": ["It shouldn''t — only listing risks ever earns any marks at all", "Acknowledging both sides shows the balance a top-band answer needs", "Gains are always more important to mention than any of the risks", "Mentioning gains is required only in Section A multiple-choice questions"], "answer": 1, "explain": "Top-band levelled answers are balanced — they weigh a possible gain against the risks before reaching a judgement, rather than only listing one side."}}, {"title": "Where this topic shows up across the paper", "html": "<p><strong>Where it shows up:</strong> quick recall in <strong>Section A</strong> (identify/state a reason, or a single mark-scheme fact about sanctions); applied Explain questions in <strong>Section B</strong>, often built around a named performer in a scenario; and the topic feeds naturally into a <strong>Section C</strong> Discuss/Evaluate question weighing risks against gains.</p>\n<p><strong>Three punchy tips:</strong></p>\n<ul>\n<li>Learn the six reasons in pairs: health (short/long term), fairness/rules, and consequences (sanctions and reputation).</li>\n<li>In Section B, always link your reason to the named performer or scenario in front of you — a general answer is capped.</li>\n<li>For the 8-mark answer, keep one risk in reserve as your \"however\" point so you never run out of balance.</li>\n</ul>", "check": {"question": "In a Section B scenario about a named performer, your explanation should be linked to...", "options": ["a completely different sport you happen to prefer", "the named performer and details in the scenario given", "a famous athlete not mentioned anywhere in the question", "your own personal opinion of that sport in general"], "answer": 1, "explain": "Section B rewards application — using the scenario''s own details. A general answer that ignores the named performer is capped below full marks."}}]}, "exam": {"enabled": true, "questions": [{"question": "Identify <strong>two</strong> reasons why performers should not use PEDs.", "marks": 2, "hint": "Pick two DIFFERENT reasons — for example health risks, cheating, breaking rules/the law, sanctions, loss of reputation or being a role model.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks (AO1)</h5>\n<p><strong>1 mark for each correct, DIFFERENT reason named, to a maximum of two. Accept any two from:</strong></p>\n<ul>\n<li>Serious health risks (short-term or long-term)</li>\n<li>It is cheating / unfair on clean performers</li>\n<li>It breaks the rules of the sport, and often the law</li>\n<li>Risk of bans, fines or being stripped of titles/medals</li>\n<li>Loss of reputation, sponsorship or career</li>\n<li>Failing the responsibility of being a role model to young fans</li>\n</ul>\n<p>Do not credit the same reason written twice in different words.</p>\n</div>"}, {"question": "Which of these is a sporting sanction a performer could face for using PEDs?", "marks": 1, "hint": "Think about what actually happens to someone caught using a banned substance, not what a performer might hope for.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: B — Being banned from competition and stripped of any titles they won.</strong></p>\n<ul>\n<li>Bans, fines and stripped titles/medals are real sanctions for PED use.</li>\n<li>The other options describe rewards, which would never follow a positive test.</li>\n</ul>\n</div>"}, {"question": "Explain <strong>two</strong> reasons why Jamie should refuse to use the steroids.", "marks": 4, "hint": "Take each reason in turn. Name the reason, then link it to Jamie''s situation (the qualifying deadline, the rivals, Jamie''s own career).", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (AO2: application)</h5>\n<p><strong>Up to 2 marks per reason: 1 for identifying a relevant reason, 1 for linking it to Jamie''s scenario. Answers may include:</strong></p>\n<ul>\n<li><strong>Health risk</strong> — steroids carry short- and long-term health risks; taking them just to catch faster rivals before a deadline does not remove that risk.</li>\n<li><strong>Cheating / unfair</strong> — Jamie''s rivals would not have agreed to Jamie gaining an advantage this way, so closing the gap through steroids would be cheating rather than fair competition.</li>\n<li><strong>Sanctions / career</strong> — if caught, Jamie could be banned and stripped of any result from the championships, damaging the very career the steroids were meant to help.</li>\n</ul>\n<p>Accept any other reasonable, applied answer. A reason with no link to Jamie''s scenario earns 1 of the 2 marks for that reason.</p>\n</div>"}, {"question": "Discuss whether the risks of using PEDs outweigh the possible gains for a performer.", "marks": 8, "hint": "Choose two or three risks (health, cheating/rules, sanctions/career) and explain each. Acknowledge a possible gain a performer might hope for. Weigh them up, then give a clear judgement.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 8 marks (level-of-response). Read the band you fit, then pick a mark.</h5>\n<ul>\n<li><strong>Band 3 (thorough), 6–8:</strong> a balanced, well-applied discussion of several risks AND a genuine possible gain, weighing them against each other, ending in a justified judgement.</li>\n<li><strong>Band 2 (reasonable), 3–5:</strong> sound understanding of more than one risk with some analysis, but the discussion may be one-sided (risks only) or the judgement unsupported.</li>\n<li><strong>Band 1 (basic), 1–2:</strong> names risks and/or sanctions with little explanation and no real evaluation; largely a list.</li>\n<li><strong>0 marks:</strong> nothing creditworthy.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Indicative content (indicative, not a checklist — reward valid alternatives)</h5>\n<ul>\n<li><strong>Health risks:</strong> short-term effects (mood swings, injury risk) and long-term effects (lasting organ or hormone damage) that do not disappear once use stops.</li>\n<li><strong>Cheating / rules:</strong> an unearned advantage over clean rivals, and a breach of the sport''s rules, often the law too.</li>\n<li><strong>Sanctions / career:</strong> bans, fines, stripped titles, lost sponsorship and damaged reputation, which can end a career the substance was meant to help.</li>\n<li><strong>Role-model responsibility:</strong> young fans may copy a performer''s choices, spreading the harm beyond the performer themselves.</li>\n<li><strong>Possible gain (for balance):</strong> a performer may hope for faster results, improved performance or a better chance of selection/income before a deadline.</li>\n<li><strong>Judgement:</strong> the risks are wide-ranging and can be permanent (health, career, reputation), while any gain is short-lived and depends on not being caught — so the risks generally outweigh the gains, especially once sanctions and long-term health are considered.</li>\n</ul>\n</div>"}]}}'::jsonb),
('sport-studies', '2-5-3-the-role-of-wada', '2.5.3 The Role of WADA', '{"learn": {"enabled": true, "items": [{"title": "What WADA is and does", "html": "<h4>The idea</h4>\n<ul>\n<li><strong>WADA</strong> (the World Anti-Doping Agency) is the international organisation that leads the global fight against performance-enhancing drug (PED) use in sport.</li>\n<li>It sets and coordinates a shared set of anti-doping rules and testing standards, so every country and every sport works to the same expectations instead of each nation policing itself differently.</li>\n</ul>\n<h4>What WADA actually does</h4>\n<ul>\n<li>It keeps and reviews the list of substances and methods that are banned, updating it as new PEDs appear.</li>\n<li>It works with national anti-doping organisations and national governing bodies (NGBs), who carry out much of the day-to-day testing on its behalf.</li>\n<li>It funds and promotes research into new detection methods, so doping techniques do not stay ahead of testing.</li>\n<li>Its overall aim is to protect fair competition and protect athletes'' health by detecting, deterring and eventually eradicating PED use.</li>\n</ul>\n<h4>Why a single global body is needed</h4>\n<ul>\n<li>Before a shared system existed, some countries tested rigorously and others barely tested at all, so athletes were not competing on a level playing field.</li>\n<li>One set of rules, applied everywhere, means an athlete cannot simply rely on weaker testing elsewhere to avoid being caught.</li>\n</ul>", "check": {"question": "What is WADA''s main purpose in world sport?", "options": ["To act as the single television broadcaster for every major international sporting competition", "To set shared global anti-doping rules and drive the detection and deterrence of PED use", "To train elite athletes and coach national teams ahead of the Olympic Games", "To design new sports equipment that improves athletic performance in competition"], "answer": 1, "explain": "WADA is the international body that sets global rules and coordinates testing to detect and deter doping — not a broadcaster, a coaching body, or an equipment designer."}}, {"title": "The Whereabouts Rule", "html": "<h4>The idea</h4>\n<ul>\n<li>The <strong>Whereabouts Rule</strong> requires athletes in a registered testing pool to tell anti-doping authorities where they will be, every day, so testers can find them for a test at any time — not only on competition days.</li>\n<li>Athletes typically give their regular schedule for the coming months, plus one specific time slot each day when they guarantee they will be at a stated location and available for testing.</li>\n</ul>\n<h4>Why it exists</h4>\n<ul>\n<li>Most doping happens away from competition — during training, in the off-season — when an athlete might assume nobody is watching. The rule allows genuinely <strong>unannounced, out-of-competition testing</strong> at any point in the year.</li>\n<li>Without it, an athlete could avoid every test at an event, dope during training, and let the substance clear their system before the next competition.</li>\n</ul>\n<h4>What counts as a violation</h4>\n<ul>\n<li>An athlete does not need to fail a drugs test to be sanctioned. Persistently filing inaccurate whereabouts information, or missing tests, can itself be treated as an anti-doping rule violation.</li>\n<li>This is why elite athletes take the paperwork seriously — a pattern of missed tests can damage a career even without a single positive sample.</li>\n</ul>", "check": {"question": "Why does the Whereabouts Rule require athletes to give a daily location and time slot?", "options": ["So that testers can carry out an unannounced test at any point in the year, not just at events", "So that coaches always know exactly where their athletes are staying during a competition week", "So that ticket sales for major stadium events can be planned around athlete travel", "So that sponsors can arrange promotional photos with athletes at short notice"], "answer": 0, "explain": "The rule exists so testers can reach an athlete for a genuinely unannounced test out of competition — not to help coaches, ticketing or sponsors."}}, {"title": "Testing methods", "html": "<h4>The two main sample types</h4>\n<ul>\n<li><strong>Urine tests</strong> — the athlete provides a urine sample, analysed in a laboratory for banned substances or the products they break down into.</li>\n<li><strong>Blood tests</strong> — a blood sample can reveal doping methods urine testing struggles to detect, such as blood doping (artificially boosting red blood cells), and shows an athlete''s blood values.</li>\n</ul>\n<h4>When testing happens</h4>\n<ul>\n<li>Testing is not limited to competition day. <strong>Out-of-competition (random) testing</strong> means officials can turn up unannounced during training, in the off-season, or away from any event — exactly what the Whereabouts Rule makes possible.</li>\n<li>Random, unannounced testing matters because it removes an athlete''s ability to time their doping around when they expect to be tested.</li>\n</ul>\n<h4>The biological passport</h4>\n<ul>\n<li>Instead of judging one sample in isolation, the <strong>biological passport</strong> builds an athlete''s own individual profile of blood and urine readings over months and years.</li>\n<li>A sudden, unusual change away from an athlete''s own normal pattern can flag possible doping — even if the specific banned substance is never directly found in a sample.</li>\n<li>This matters because dopers cannot simply avoid one substance being detected; a suspicious pattern across many tests over time is itself evidence.</li>\n</ul>", "check": {"question": "What makes the biological passport a different approach from a single drugs test?", "options": ["It tracks an athlete''s own readings over time and flags unusual changes from their normal pattern", "It replaces every single urine and blood sample with one large photograph taken at the finish line of the race", "It only ever tests athletes once, on the very last day of their competitive career", "It is used exclusively to check the size and weight of an athlete''s sports equipment"], "answer": 0, "explain": "The passport compares an athlete against their OWN normal pattern over time, rather than judging one isolated sample — unlike a single test, a photograph, or equipment checks."}}]}, "terms": {"enabled": true, "pairs": [{"term": "WADA", "definition": "The World Anti-Doping Agency; sets global rules to detect and deter PED use"}, {"term": "Whereabouts Rule", "definition": "Athletes report their daily location so an unannounced test can happen at any time"}, {"term": "Urine test", "definition": "A sample analysed for banned substances or the products they break down into"}, {"term": "Blood test", "definition": "A sample that can reveal blood doping and show an athlete''s blood values"}, {"term": "Out-of-competition testing", "definition": "Random, unannounced testing during training or the off-season, not only at events"}, {"term": "Biological passport", "definition": "Tracks an athlete''s own readings over time so unusual changes can be flagged"}]}, "mcq": {"enabled": true, "questions": [{"question": "What does WADA stand for and what is its overall aim?", "options": ["The World Athletics Development Association, a group that funds new stadium construction projects", "The World Anti-Doping Agency, an international body aiming to detect and deter PED use", "The Worldwide Amateur Draft Assembly, a body that selects amateur athletes for professional contracts", "The World Athletic Data Analysts, a company that publishes statistics after major events"], "answer": 1, "explain": "WADA is the World Anti-Doping Agency — its job is detecting and deterring doping, not stadium funding, drafting amateurs, or publishing statistics."}, {"question": "An athlete in a WADA testing pool must give anti-doping authorities their daily whereabouts. Why?", "options": ["So that a specific supporters'' club can arrange to meet the athlete after every home match", "So the athlete''s diet can be planned in advance by a national governing body nutritionist", "So an unannounced test can be carried out at any time, including outside of competition", "So travel journalists can accurately report an athlete''s holiday plans to the public"], "answer": 2, "explain": "The Whereabouts Rule exists so an unannounced test can reach the athlete at any time — not to help a supporters'' club, a nutritionist, or journalists."}, {"question": "Which of these is an example of an out-of-competition (random) test?", "options": ["Officials test the reigning winning finalist immediately after the final whistle of a major championship", "Officials interview a retired athlete about their career for a televised documentary", "Officials measure the size of a stadium pitch before a scheduled international fixture", "Officials test a sprinter unannounced during a routine training session in the off-season"], "answer": 3, "explain": "Out-of-competition testing happens away from events, unannounced — such as during off-season training — not at a final, an interview, or a pitch measurement."}, {"question": "What can a blood test detect that a urine test alone often struggles to pick up?", "options": ["Blood doping, such as artificially boosting the number of red blood cells in circulation", "The exact brand and colour of the trainers an athlete happened to be wearing during a specific event", "How many hours of sleep an athlete had the night before a scheduled competition day", "The total number of spectators who attended a stadium on any single competition day"], "answer": 0, "explain": "Blood samples can reveal blood doping and an athlete''s blood values — trainers, sleep and attendance figures are not things a drugs test detects."}, {"question": "A drugs test never finds a banned substance, but an athlete''s blood values change sharply over several tests. What does the biological passport do with this pattern?", "options": ["Ignores it completely and permanently, because only a single positive sample is ever treated as valid evidence", "Flags it as suspicious, because it compares the athlete against their own normal readings over time", "Automatically bans the athlete''s entire national team from the next major competition", "Deletes the athlete''s testing history so a fresh profile can be started from zero"], "answer": 1, "explain": "The passport flags a suspicious change from an athlete''s own normal pattern — it does not ignore the data, ban a whole team, or wipe the history."}, {"question": "Which statement about missing scheduled anti-doping tests is correct?", "options": ["Missing a test has absolutely no consequences at all as long as the athlete formally apologises to the testers afterwards", "Missing a test only matters if it happens during the same week as a major international final", "A pattern of missed tests or filing failures can be treated as a violation, even without a positive sample", "Missing a test simply moves the athlete to the very back of the queue for their next scheduled test"], "answer": 2, "explain": "Persistently missing tests or filing whereabouts incorrectly can itself count as a violation — it is not harmless, timing-dependent, or just a queuing issue."}]}, "fib": {"enabled": true, "questions": [{"text": "WADA stands for the World Anti-Doping [Agency]."}, {"text": "The Whereabouts Rule means athletes must report their daily [location] so testers can find them for a test."}, {"text": "Testing carried out unannounced during training, rather than only at an event, is called out-of-competition or [random] testing."}, {"text": "A blood test can help detect blood [doping], such as an artificial rise in red blood cells."}, {"text": "The biological [passport] tracks an athlete''s own readings over time so any unusual change can be flagged."}]}, "tf": {"enabled": true, "questions": [{"statement": "WADA sets shared global anti-doping rules so that testing standards are consistent across countries.", "answer": true, "explain": "That''s WADA''s core purpose — a single global standard rather than each nation policing itself differently."}, {"statement": "The Whereabouts Rule only applies to athletes during the week of a major competition.", "answer": false, "explain": "It applies all year round, including training and the off-season — catching doping that happens away from events is the whole point."}, {"statement": "An athlete can only be sanctioned if a banned substance is actually found in one of their samples.", "answer": false, "explain": "Persistently missing tests or filing whereabouts incorrectly can itself count as a violation, even with no positive sample."}, {"statement": "Out-of-competition testing means testers can arrive unannounced during an athlete''s normal training.", "answer": true, "explain": "That is exactly what random, out-of-competition testing means — it is not limited to competition day."}, {"statement": "The biological passport compares an athlete against a fixed national average rather than their own readings.", "answer": false, "explain": "It compares an athlete against their OWN normal pattern built up over time, not a shared national average."}, {"statement": "Blood tests can reveal doping methods, such as artificially boosting red blood cells, that urine tests alone may miss.", "answer": true, "explain": "Blood samples can show blood doping and an athlete''s blood values in ways urine testing struggles to match."}]}, "misc": {"enabled": true, "items": [{"myth": "WADA is basically just one laboratory that tests urine samples.", "truth": "WADA is an international coordinating body — it sets the rules, standards and banned-substance list, while national anti-doping organisations and NGBs carry out much of the actual day-to-day testing on its behalf. It also funds research, not just processes samples.", "check": {"question": "What does WADA itself mainly do, compared to national anti-doping organisations?", "options": ["It sets global rules and standards, while national bodies carry out much of the day-to-day testing", "It personally tests every single athlete in every single country using its own dedicated testing staff", "It only broadcasts televised doping scandals to a worldwide audience", "It only sells sports equipment approved for professional competition"], "answer": 0, "explain": "WADA sets the rules and standards; national anti-doping organisations and NGBs do most of the actual testing — WADA is not a broadcaster or an equipment seller."}}, {"myth": "The Whereabouts Rule is only a paperwork formality with no real consequences.", "truth": "Missing scheduled tests, or repeatedly filing inaccurate location information, can itself count as an anti-doping rule violation — treated seriously even if the athlete never actually failed a drugs test. Elite athletes take the reporting seriously because of this.", "check": {"question": "What can happen to an athlete who repeatedly fails to file accurate whereabouts information?", "options": ["Nothing at all, because only a positive drugs test result can ever possibly lead to any kind of formal sanction", "They can be treated as having committed an anti-doping rule violation, even without a positive sample", "They automatically win their next competition without needing to attend at all", "Their national governing body is immediately replaced by a brand new organisation"], "answer": 1, "explain": "Repeated filing failures or missed tests can be treated as a violation in their own right, even with no positive sample — it is not consequence-free."}}, {"myth": "The biological passport only works by directly detecting a specific banned substance in a sample.", "truth": "The biological passport can flag doping indirectly — by tracking an athlete''s own blood and urine readings over time and noticing a suspicious change from their normal pattern, even when no specific banned substance is ever found.", "check": {"question": "How can the biological passport suggest doping without finding a banned substance?", "options": ["By comparing a single sample against a fixed international average reading taken from every other athlete", "By interviewing the athlete''s family, friends and former training partners about their habits", "By flagging an unusual change away from that athlete''s own normal pattern of readings over time", "By checking the make and model of the equipment the athlete used in competition"], "answer": 2, "explain": "The passport flags a change away from the athlete''s OWN pattern over time — it does not use a fixed average, interviews, or equipment checks."}}]}, "tips": {"enabled": true, "items": [{"title": "Command words for this topic — what each one wants", "html": "<p>WADA questions range from quick recall to a full evaluation. Match your answer length to the command word:</p>\n<ul>\n<li><strong>Identify / State</strong> — just name it. \"Identify one testing method WADA-linked authorities use\" = one method, nothing more. 1 mark.</li>\n<li><strong>Describe</strong> — say what it is or how it works. \"Describe the Whereabouts Rule\" = explain what athletes must do.</li>\n<li><strong>Explain</strong> — give a reason, using \"because\". \"Explain why out-of-competition testing matters\" = the method plus why it closes a gap.</li>\n<li><strong>Discuss / Evaluate</strong> — weigh up both sides and reach a judgement, used in the longer levelled questions.</li>\n</ul>\n<p><strong>Read the mark tariff:</strong> [1] wants one point; [2]–[4] wants developed points or point+application; [6]/[8] levelled wants balanced analysis and a judgement.</p>", "check": {"question": "A question says ''Identify one testing method WADA uses [1]''. What is the safest answer?", "options": ["A long paragraph explaining the entire history of anti-doping testing", "One named testing method, such as blood testing or urine testing", "A list of every testing method you can possibly remember", "A description of a famous doping scandal from a past competition"], "answer": 1, "explain": "''Identify'' + [1] wants exactly one named method. A long history, a full list, or a scandal description all waste time for a single mark."}}, {"title": "The golden rule: link the method to WHY it works", "html": "<p>The most common way to lose marks here is naming a method without saying why it matters. Build every answer as <strong>method → what it catches → why that matters</strong>:</p>\n<ul>\n<li><strong>❌ 0–1 marks:</strong> \"WADA does blood tests.\"</li>\n<li><strong>✅ full marks:</strong> \"WADA-linked testers use blood tests because they can reveal blood doping, such as an artificial rise in red blood cells, which a urine test alone might miss.\"</li>\n</ul>\n<p>In <strong>Section B</strong> the question gives you a scenario (a named athlete or event). You must then apply a method to that scenario, not just describe it in general.</p>", "check": {"question": "In a Section B scenario about a named athlete, your answer about WADA''s methods should...", "options": ["ignore the scenario completely and describe any method in general terms", "apply a method to the specific detail given in the scenario", "only repeat the name of the athlete as many times as possible", "describe a completely different topic area instead"], "answer": 1, "explain": "Section B is applied — the marks are for using the detail in the scenario, not ignoring it, repeating a name, or drifting off-topic."}}, {"title": "Where WADA appears + sentence starters", "html": "<p><strong>Where it shows up:</strong> WADA''s role appears as quick recall in <strong>Section A</strong> (identify/describe a method or the Whereabouts Rule), as an applied point in <strong>Section B</strong> scenarios about a doping case, and can feed a <strong>Section C</strong> levelled answer discussing how effective anti-doping testing really is.</p>\n<p><strong>Three punchy tips:</strong></p>\n<ul>\n<li>Always link a testing method to what it can detect that another method might miss.</li>\n<li>Remember the Whereabouts Rule applies ALL year, not just on competition day.</li>\n<li>The biological passport is about a PATTERN over time, not a single sample — say so explicitly.</li>\n</ul>\n<p><strong>Sentence starters for a longer answer:</strong></p>\n<ul>\n<li>\"One method WADA-linked testers use is… because…\"</li>\n<li>\"This matters because it can catch doping that happens…\"</li>\n<li>\"However, a limitation of this method is…\"</li>\n</ul>", "check": {"question": "Why is it useful to say the biological passport tracks a PATTERN over time?", "options": ["It shows you understand it works differently from judging one single isolated sample", "It just fills up space in a longer answer without adding any real understanding at all to it", "It proves that no athlete has ever been caught doping in the history of sport", "It replaces the need to mention any testing method at all in your answer"], "answer": 0, "explain": "Naming the PATTERN-over-time idea shows real understanding of how the passport differs from a single test — it is not filler or a replacement for detail."}}]}, "exam": {"enabled": true, "questions": [{"question": "Identify <strong>two</strong> testing methods used to detect PED use.", "marks": 2, "hint": "Think about the types of sample that can be taken from an athlete''s body, and when testing can happen.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks (AO1)</h5>\n<p><strong>1 mark for each correct testing method named, to a maximum of two. Accept any two from:</strong></p>\n<ul>\n<li>Urine test</li>\n<li>Blood test</li>\n<li>Out-of-competition / random / unannounced testing</li>\n<li>Biological passport (tracking readings over time)</li>\n</ul>\n<p>Do not credit the same method written twice.</p>\n</div>"}, {"question": "Which of these best describes the Whereabouts Rule?", "marks": 1, "hint": "Think about why testers need to know where an athlete will be, even outside of competition.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1)</h5>\n<p><strong>Answer: A — Athletes must report their daily location so testers can carry out an unannounced test at any time.</strong></p>\n<ul>\n<li>This is the purpose of the Whereabouts Rule — allowing testing outside of competition, not only at events.</li>\n<li>The other options describe unrelated ideas (country of competition, diet publishing, retirement age).</li>\n</ul>\n</div>"}, {"question": "Explain how <strong>two</strong> features of anti-doping testing are shown in Priya''s experience.", "marks": 4, "hint": "Look for two separate ideas in the scenario — something about WHEN the tests happened, and something about WHAT kind of sample was taken.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (AO2: application)</h5>\n<p><strong>Up to 2 marks per feature: 1 for identifying a relevant feature, 1 for a linked reason using the scenario. Answers may include:</strong></p>\n<ul>\n<li><strong>Out-of-competition / unannounced testing</strong> — the visits happened with no advance warning, at her training base rather than an event, matching the approach of testing at any time so doping cannot be timed around known tests.</li>\n<li><strong>Blood testing / the Whereabouts Rule</strong> — being in a testing pool and giving a blood sample links to reporting her whereabouts so testers can locate her, and blood tests can reveal doping methods a urine test might miss.</li>\n</ul>\n<p>Accept any other reasonable, applied answer using the scenario. A feature named with no linked reason earns 1 of the 2 marks for that feature.</p>\n</div>"}, {"question": "Discuss how effective WADA''s methods are at stopping doping.", "marks": 8, "hint": "Consider at least two methods (e.g. out-of-competition testing, the biological passport). For each, explain how it helps catch doping, then weigh up a limitation. Finish with a judgement on how effective the overall approach really is.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 8 marks (level-of-response). Read the band you fit, then pick a mark.</h5>\n<ul>\n<li><strong>Band 3 (thorough), 6–8:</strong> a balanced, well-applied discussion of several testing methods, showing clearly how they help detect and deter doping AND weighing genuine limitations (cost, athletes evading detection, indirect evidence being contested), ending in a justified judgement.</li>\n<li><strong>Band 2 (reasonable), 3–5:</strong> sound understanding applied to more than one method with some analysis, but the discussion may be one-sided or the judgement unsupported.</li>\n<li><strong>Band 1 (basic), 1–2:</strong> names methods with little application and no real evaluation; largely a list.</li>\n<li><strong>0 marks:</strong> nothing creditworthy.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Indicative content (indicative, not a checklist — reward valid alternatives)</h5>\n<ul>\n<li><strong>Out-of-competition/random testing:</strong> removes an athlete''s ability to time doping around known test dates, since testers can arrive unannounced during training.</li>\n<li><strong>Blood and urine testing:</strong> together cover a wider range of banned substances and methods, such as blood doping, than either sample alone.</li>\n<li><strong>Biological passport:</strong> can flag doping indirectly through a suspicious pattern over time, catching cases where no single substance is ever found.</li>\n<li><strong>Evaluation — limitations:</strong> testing is costly and cannot cover every athlete equally; determined dopers may still find substances that are hard to detect or clear quickly; a flagged pattern from the passport can be contested rather than proven; testing catches many cases but is unlikely to eliminate doping entirely.</li>\n<li><strong>Judgement:</strong> WADA''s combined approach is effective because it closes the main gaps (timing, sample type, indirect evidence) that a single method alone would leave open — but it reduces rather than eliminates doping, since resourcing and contested evidence still limit it.</li>\n</ul>\n</div>"}]}}'::jsonb),
('sport-studies', '2-5-4-sanctions-against-peds', '2.5.4 Sanctions Against PEDs', '{"learn": {"enabled": true, "items": [{"title": "Bans — the headline sanction for PED use", "html": "<h4>What a sanction is</h4>\n<ul>\n<li>A <strong>sanction</strong> is an official penalty handed out once a performer has been found guilty of using a prohibited substance or method.</li>\n<li>The best-known sanction is a <strong>ban</strong> — the performer cannot train with their squad, enter competitions, or receive funding, for a set period.</li>\n</ul>\n<h4>Bans vary in length</h4>\n<ul>\n<li>A ban is not one fixed punishment — its length changes case by case. A first offence often carries a ban of a <strong>set number of years</strong>, rather than a short suspension.</li>\n<li>A performer caught using PEDs <strong>more than once</strong> can be given a <strong>lifetime ban</strong>, ending their career in that sport completely.</li>\n<li>The exam expects you to know that length reflects seriousness: a longer, or lifetime, ban shows that repeated or serious cheating is treated far more harshly than a single lapse.</li>\n</ul>", "check": {"question": "Which statement about bans as a sanction against PED use is correct?", "options": ["A ban always lasts precisely the same length regardless of whether it is a first or repeat offence", "Ban length can vary, and a performer who repeatedly offends can receive a lifetime ban", "Bans can only ever be given to performers who have never previously failed a drugs test", "A ban means a performer must pay a large fixed sum instead of missing any competitions"], "answer": 1, "explain": "Ban length is not fixed — it varies with the case, and repeat offenders can receive a lifetime ban. A ban is about missing competition, not a payment."}}, {"title": "Fines, and being stripped of medals, titles and records", "html": "<h4>Fines</h4>\n<ul>\n<li>Alongside a ban, a performer found guilty of using PEDs can be given a <strong>fine</strong> — a sum of money they must pay as part of their punishment.</li>\n<li>Fines vary in amount depending on the case, and can be added on top of a ban rather than replacing one.</li>\n</ul>\n<h4>Being stripped of medals, titles and records</h4>\n<ul>\n<li>A guilty performer can also be <strong>stripped of medals, titles and records</strong> won while using a prohibited substance or method.</li>\n<li>This means a medal is returned or reallocated, a title is taken away, and a record is deleted from the record books, as if the result had never happened.</li>\n<li>This sanction targets a performer''s <strong>reputation and achievements</strong>, not only their money or their ability to compete — for many elite performers, losing a title or record hurts more than a fine.</li>\n</ul>", "check": {"question": "What does it mean for a performer to be ''stripped'' of a medal after a PED offence?", "options": ["The medal is cleaned and sent back to the performer in fully restored condition", "The medal, title or record is taken away and the result is removed from the record books", "The performer is instead given a smaller replacement medal made from a cheaper metal", "The performer keeps the medal but must wear it at every single future competition entered"], "answer": 1, "explain": "Being ''stripped'' means the medal, title or record is formally taken away and removed from the record books — the achievement no longer stands."}}, {"title": "Why sanctions exist — deterrence as well as punishment", "html": "<h4>Two jobs, one sanction</h4>\n<ul>\n<li>A sanction does two jobs at once. First, it <strong>punishes</strong> the individual performer who has already broken the rules — through a ban, a fine, or being stripped of what they won.</li>\n<li>Second, it is meant to <strong>deter</strong> — to put other performers off using PEDs in the first place, by making the consequences clear and severe.</li>\n</ul>\n<h4>Building an exam-ready answer</h4>\n<ul>\n<li>Weak answer: <em>\"Cheats get banned.\"</em> That names a sanction but shows no understanding of its purpose.</li>\n<li>Strong answer: <em>\"A lifetime ban deters other performers because it shows repeat cheating ends a career completely, so the risk clearly outweighs any gain.\"</em></li>\n<li>Section C questions often ask you to judge <strong>whether sanctions actually work as a deterrent</strong> — a good answer weighs the size of the punishment against how likely a performer thinks they are to be caught.</li>\n</ul>", "check": {"question": "Besides punishing the individual, what is a sanction against PED use also meant to do?", "options": ["Deter other performers from choosing to use prohibited substances themselves", "Guarantee that particular sport will never again see any further doping case", "Reduce how much training a completely clean performer is allowed to do", "Increase the total prize money available to the eventual winning performer"], "answer": 0, "explain": "A sanction is meant to deter other performers, not just punish the one caught — it cannot guarantee no future case, and it has no effect on clean performers'' training or prize funds."}}]}, "terms": {"enabled": true, "pairs": [{"term": "Sanction", "definition": "An official penalty given once a performer is found guilty of a PED offence"}, {"term": "Ban", "definition": "Stops a performer training/competing for a period; can be a lifetime ban for repeat offenders"}, {"term": "Fine", "definition": "A sum of money a performer must pay as part of a PED sanction"}, {"term": "Stripped of a medal/title/record", "definition": "An achievement gained while using PEDs is formally taken away"}, {"term": "Lifetime ban", "definition": "A ban with no end date, usually for a serious or repeated offence"}, {"term": "Deterrent effect", "definition": "The way a severe sanction is meant to discourage other performers from using PEDs"}]}, "mcq": {"enabled": true, "questions": [{"question": "What is most likely to happen to a performer caught using PEDs for a second time, having already served a ban once before?", "options": ["They receive an identical short suspension to a first-time offender in the same sport", "They may receive a lifetime ban, ending their career in that sport completely", "They are simply asked to apologise publicly with no further ban or fine applied", "They automatically become team captain for their club in the following season"], "answer": 1, "explain": "Repeat offenders face harsher sanctions than first-timers, and a lifetime ban is the most severe option available — the other outcomes describe no real sanction at all."}, {"question": "A performer is fined and stripped of a title after a positive drugs test. Which best explains why both sanctions are used together?", "options": ["One sanction removes their money, while the other removes their reputation and achievements", "The two sanctions cancel each other out, so the performer suffers no real consequence at all", "A fine and losing a title are simply two different names for exactly the same punishment", "Governing bodies choose a sanction completely at random with no consistent reasoning behind it"], "answer": 0, "explain": "A fine and being stripped of a title punish different things — money and reputation/achievement — which is why governing bodies often apply more than one sanction."}, {"question": "Why might a governing body strip a performer of a record they set, rather than only banning them from future competition?", "options": ["Because it removes an achievement gained unfairly, showing the result should not stand", "Because record books can never be changed once a result has been published anywhere", "Because a stripped record automatically increases the performer''s future appearance fees", "Because changing a written record always costs far less than administering any ban"], "answer": 0, "explain": "Stripping a record removes an achievement that was gained through cheating, so the result no longer stands — record books are updated, and this has nothing to do with fees or cost."}, {"question": "A young performer is deciding whether to risk using a banned substance. Which sanction is designed to put them off doing so?", "options": ["Free entry into every future competition no matter what the eventual result is", "The threat of a lengthy ban, a fine, and losing any medals won if they are caught", "A guarantee that drugs testing will never take place at their level of competition", "A private meeting where no written record of any offence is ever kept on file"], "answer": 1, "explain": "Severe, well-known sanctions — a long ban, a fine, losing medals — are exactly what is meant to deter a performer from taking the risk in the first place."}, {"question": "A cyclist banned for two years after a first doping offence tests positive again three years later. Based on how sanctions usually work, what is most likely?", "options": ["The second ban is likely to be equal to or longer than the first, possibly a lifetime ban", "The second offence is ignored completely because the first ban has already been served", "The governing body must reduce any new ban because one has already been served before", "The cyclist instead receives a medal in recognition of admitting to the second failed test"], "answer": 0, "explain": "Repeat offences are treated more, not less, seriously — a second ban is likely to match or exceed the first, up to a lifetime ban, not be reduced or ignored."}, {"question": "What is the main purpose of publicising the sanctions given to performers caught using PEDs?", "options": ["To help the performer''s existing sponsors quickly design a brand new advertising campaign", "To deter other performers by making the real consequences of being caught widely known", "To increase ticket sales across the venue for that performer''s very next scheduled event", "To give sports journalists something new and unrelated to write about each week"], "answer": 1, "explain": "Publicising sanctions is a deterrent — it shows every other performer exactly what being caught actually costs, which is the point of making it public."}]}, "fib": {"enabled": true, "questions": [{"text": "A performer found guilty of a PED offence can receive a [ban], stopping them competing for a period."}, {"text": "Ban length can vary, and a repeat offender may be given a [lifetime] ban with no end date."}, {"text": "As well as a ban, a guilty performer can be ordered to pay a [fine]."}, {"text": "A performer can be [stripped] of medals, titles and records won while using a prohibited substance."}, {"text": "Sanctions are meant to [deter] other performers from choosing to use PEDs in the first place."}]}, "tf": {"enabled": true, "questions": [{"statement": "A ban is always exactly the same length, regardless of whether it is a first or repeat offence.", "answer": false, "explain": "Ban length varies with the case — a first offence may carry a set number of years, while repeat offenders can face a lifetime ban."}, {"statement": "A performer can be fined and banned at the same time for a single PED offence.", "answer": true, "explain": "Sanctions can be combined — a fine punishes financially while a ban stops the performer competing, so both can apply to one offence."}, {"statement": "Being stripped of a record means it is removed from the record books as though it had not happened.", "answer": true, "explain": "Stripping removes the achievement entirely — the record is deleted or reallocated, not just noted as suspicious."}, {"statement": "Sanctions exist only to punish the individual performer and have no effect on anyone else.", "answer": false, "explain": "Sanctions are also meant to deter — by making the consequences clear, they aim to put other performers off using PEDs too."}, {"statement": "A performer who is caught using PEDs more than once can receive a lifetime ban.", "answer": true, "explain": "Repeat offences are treated more severely, and a lifetime ban is the toughest sanction available for persistent cheating."}, {"statement": "Fines for PED offences are always exactly the same amount, whatever the case involves.", "answer": false, "explain": "Fines vary in amount depending on the case — they are not a single fixed sum applied to every offence."}]}, "misc": {"enabled": true, "items": [{"myth": "A ban is the only sanction a governing body can use against PED use.", "truth": "A ban is only one option. Governing bodies can also fine a performer, and strip them of medals, titles and records won while using a prohibited substance — often combining more than one sanction for a single offence, because each targets something different (time, money, reputation).", "check": {"question": "Besides a ban, what else can a governing body use to sanction a PED offence?", "options": ["Nothing else — a ban is always the complete sanction on its own", "A fine, and/or being stripped of medals, titles or records", "A permanent increase in the performer''s future prize money", "A guarantee of a place at the performer''s next major competition"], "answer": 1, "explain": "Fines and being stripped of medals/titles/records are real, separate sanctions that can sit alongside a ban."}}, {"myth": "Sanctions only punish the performer who was caught — they don''t affect anyone else''s choices.", "truth": "Sanctions have a second job: deterrence. By making a ban, fine or stripped record public and severe, governing bodies aim to put other performers off using PEDs, because they can see exactly what being caught actually costs.", "check": {"question": "What is the second purpose of a sanction, alongside punishing the individual performer?", "options": ["Deterring other performers from choosing to use PEDs themselves", "Making sure the sport receives more media coverage each season", "Ensuring no performer is ever tested for banned substances again", "Guaranteeing the performer a route back into the sport next year"], "answer": 0, "explain": "Deterrence is the second purpose — showing other performers the real consequences so they choose not to risk using PEDs."}}, {"myth": "Once a performer has served their ban, the offence is forgotten and any record they set still stands.", "truth": "Serving a ban does not undo being stripped of a medal, title or record — those stay removed from the record books permanently. And the offence itself is not forgotten: if the same performer is caught again, it counts as a repeat offence and can lead to a lifetime ban.", "check": {"question": "After a performer finishes serving a ban, what happens to a record they were stripped of?", "options": ["It is automatically restored back to them once their ban period fully ends", "It stays removed from the record books; serving the ban does not restore it", "It is reassigned permanently to whichever performer finished in second place", "It is kept on hold until the performer''s very next competition begins"], "answer": 1, "explain": "Being stripped of a record is permanent — finishing a ban does not undo it, and a later offence still counts as a repeat."}}]}, "tips": {"enabled": true, "items": [{"title": "Command words for this topic — what each one wants", "html": "<p>Sanctions questions are usually short recall, but can be developed into applied points. Match your answer length to the command word:</p>\n<ul>\n<li><strong>Identify / State</strong> — just name it. \"Identify one sanction used against PED use\" = write one sanction, nothing more. 1 mark.</li>\n<li><strong>Describe</strong> — say what the sanction involves. \"Describe a ban as a sanction\" = explain what happens to the performer.</li>\n<li><strong>Explain</strong> — give a reason. Use the word <em>because</em>. \"Explain why a lifetime ban might be given\" = the sanction <em>plus</em> why (usually a repeat offence).</li>\n</ul>\n<p><strong>Read the mark tariff:</strong> [1] wants one point; [2] usually wants two points, or one point developed; marks in Section B want points applied to the scenario given.</p>", "check": {"question": "A question says: ''Identify two sanctions used against PED use [2]''. What is the safest answer?", "options": ["A long paragraph describing only one sanction in detail", "Two sanction names, such as a ban and a fine", "One sanction explained at great length with no second name given", "A list of six different sanctions written out in full"], "answer": 1, "explain": "''Identify'' + [2] = two names, one mark each. Explaining only one, or listing six, wastes time and risks marks only being credited for the first two anyway."}}, {"title": "The golden rule: name the sanction AND its intended effect", "html": "<p>The single most common way to lose marks here is stopping at the sanction''s name. Build every answer as <strong>sanction → effect → reason</strong>:</p>\n<ul>\n<li><strong>❌ 0–1 marks:</strong> \"A lifetime ban.\"</li>\n<li><strong>✅ full marks:</strong> \"A lifetime ban punishes the performer by ending their career, and deters others because it shows repeat cheating is never worth the risk.\"</li>\n</ul>\n<p>In <strong>Section B</strong> the question gives you a scenario (a named performer, a named offence). Then you must use a detail <em>from that scenario</em> — such as whether it is a first or repeat offence — not a general example.</p>", "check": {"question": "In a Section B scenario question about a named performer''s PED offence, your sanction choice should be based on...", "options": ["absolutely any sanction at all, chosen without reference to the scenario given", "the details given in the scenario, such as whether it is a repeat offence", "the sanction you personally think sounds the most severe", "a sanction used in a completely different named sport"], "answer": 1, "explain": "Section B is applied — the marks are for linking a sanction to the actual detail in the scenario, such as whether the offence is a first or repeat one."}}, {"title": "Where sanctions appear in the exam + sentence starters", "html": "<p><strong>Where it shows up:</strong> sanctions appear as quick recall in <strong>Section A</strong> (identify/state), as applied points in <strong>Section B</strong> scenarios about a named performer''s offence, and they feed <strong>Section C</strong> 8-mark discussions about whether current sanctions are effective enough.</p>\n<p><strong>Three punchy tips:</strong></p>\n<ul>\n<li>Learn the three sanctions together — ban, fine, stripped of medals/titles/records — so you can always recall more than one.</li>\n<li>For every sanction, memorise its <em>intended effect</em> (punish and/or deter) — that link is usually where the mark is.</li>\n<li>Watch for the first-offence vs repeat-offence distinction — it is a great way to justify why one sanction is more severe than another.</li>\n</ul>\n<p><strong>Sentence starters for a longer answer:</strong></p>\n<ul>\n<li>\"One sanction that could be applied here is… because…\"</li>\n<li>\"This sanction is intended to deter other performers by…\"</li>\n<li>\"However, this sanction may not fully stop PED use because…\"</li>\n</ul>", "check": {"question": "Why is the first-offence vs repeat-offence distinction a useful point in a longer answer?", "options": ["It fills space without needing to say anything further", "It justifies why one sanction is harsher than another", "It proves that sanctions are never actually applied at all", "It removes the need to name any sanction whatsoever"], "answer": 1, "explain": "Linking the sanction''s severity to whether it is a first or repeat offence shows deeper understanding — exactly the kind of point that lifts a longer answer."}}]}, "exam": {"enabled": true, "questions": [{"question": "Identify <strong>two</strong> sanctions that can be given to a performer found guilty of using a PED.", "marks": 2, "hint": "Pick two different sanctions — for example a ban, a fine, or being stripped of a medal, title or record.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks (AO1)</h5>\n<p><strong>1 mark for each correct sanction named, to a maximum of two. Accept any two different sanctions, including:</strong></p>\n<ul>\n<li>A ban (of varying length, up to a lifetime ban)</li>\n<li>A fine</li>\n<li>Being stripped of medals, titles or records</li>\n</ul>\n<p>Do not credit the same sanction written twice.</p>\n</div>"}, {"question": "Which sanction removes an achievement a performer has already won, rather than affecting their future participation or finances?", "marks": 1, "hint": "Think about which sanction targets something the performer already achieved, not something they might do or pay in future.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: B — Being stripped of a medal, title or record.</strong></p>\n<ul>\n<li>This sanction removes an achievement already gained, unlike a ban (future participation) or a fine (money).</li>\n</ul>\n</div>"}, {"question": "Explain <strong>two</strong> sanctions that could be applied to Priya as a result of this offence.", "marks": 4, "hint": "Take each sanction in turn. Name it, then link it to a detail in the scenario — the fact it is her first offence, or the fact she set a new record.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (AO2: application)</h5>\n<p><strong>Up to 2 marks per sanction: 1 for naming a relevant sanction, 1 for linking it to the scenario. Answers may include:</strong></p>\n<ul>\n<li><strong>A ban</strong> — of a set length, reflecting that this is a first offence rather than a repeat one.</li>\n<li><strong>Being stripped of her record</strong> — because she set a new club record during the race in which she failed the test, so that result should not stand.</li>\n<li>A fine could also be credited if clearly linked to the scenario.</li>\n</ul>\n<p>Accept any other reasonable, applied answer. A sanction named with no scenario link earns 1 of the 2 marks for that sanction.</p>\n</div>"}, {"question": "Discuss whether sanctions are the best way to stop performers using PEDs in sport.", "marks": 8, "hint": "Explain how sanctions are meant to work (punish and deter), then weigh up their limits (some performers still risk it) against other approaches (like education). Finish with a judgement.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 8 marks (level-of-response). Read the band you fit, then pick a mark.</h5>\n<ul>\n<li><strong>Band 3 (thorough), 6–8:</strong> a balanced, well-applied discussion showing clearly how sanctions punish and deter, AND weighing genuine limits (some performers still risk it, sanctions act after the harm is done, other methods exist), ending in a justified judgement.</li>\n<li><strong>Band 2 (reasonable), 3–5:</strong> sound understanding of sanctions with some analysis, but the discussion may be one-sided or the judgement unsupported.</li>\n<li><strong>Band 1 (basic), 1–2:</strong> names sanctions with little application and no real evaluation; largely a list.</li>\n<li><strong>0 marks:</strong> nothing creditworthy.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Indicative content (indicative, not a checklist — reward valid alternatives)</h5>\n<ul>\n<li><strong>How sanctions are meant to work:</strong> bans, fines and stripped records punish the individual and are publicised to deter others, by showing that being caught costs a career, money and reputation.</li>\n<li><strong>Limits of sanctions:</strong> the League''s own case shows two swimmers still offended despite a strict policy, suggesting some performers accept the risk; sanctions only apply once a performer has already been caught, so they do not stop the initial decision to use PEDs; harsher sanctions may not deter someone confident they will avoid testing.</li>\n<li><strong>Other approaches:</strong> education, and thorough testing (making being caught more likely), work alongside sanctions rather than replacing them.</li>\n<li><strong>Judgement:</strong> sanctions are a necessary part of the system because they give real consequences and some deterrent effect — but the League''s repeat cases show sanctions alone do not guarantee compliance, so they work best combined with strong testing and education.</li>\n</ul>\n</div>"}]}}'::jsonb),
('sport-studies', '2-5-5-education-against-peds', '2.5.5 Education Against PEDs', '{"learn": {"enabled": true, "items": [{"title": "Educating athletes to prevent doping — the big idea", "html": "<h4>Why education, not just punishment</h4>\n<ul>\n<li>Sport does not only rely on catching cheats after the fact — a large amount of anti-doping work happens <strong>before</strong> an athlete ever considers taking a banned substance.</li>\n<li><strong>Education</strong> means teaching athletes the facts, the risks and the values of sport so that they choose not to dope in the first place, instead of only being deterred by the threat of a later sanction.</li>\n<li>Prevention through education matters because a drugs test can only catch someone who has already taken a substance — by that point, damage to health and to the sport''s reputation may already be done.</li>\n</ul>\n<h4>Campaigns that discourage use</h4>\n<ul>\n<li>Governing bodies, clubs and schools run <strong>awareness campaigns</strong> — posters, workshops, talks and online resources — aimed at putting athletes off using performance-enhancing drugs before they are ever tempted.</li>\n<li>A good campaign does more than say \"don''t do it\": it explains the health risks, the unfairness to other competitors, and the personal cost of being caught, in a way that actually changes behaviour rather than being ignored.</li>\n<li>Campaigns often target younger or developing athletes, because the attitudes formed early in a career are the ones most likely to last.</li>\n</ul>", "check": {"question": "What is the main advantage of educating athletes BEFORE they dope, compared with only punishing them afterwards?", "options": ["It removes the need for any drug testing at competitions from that point onwards", "It can stop the health damage and the unfairness from ever happening in the first place", "It guarantees that every athlete who takes part will certainly win a medal at their next event", "It means governing bodies no longer need any written rules about banned substances"], "answer": 1, "explain": "Education tries to stop doping before it starts, so the health damage and unfairness never happen — testing alone can only react once the damage is already done."}}, {"title": "Who does the educating — role models, peers and family", "html": "<h4>Role models</h4>\n<ul>\n<li>A <strong>role model</strong> is someone an athlete looks up to and copies — often a more experienced athlete, a coach, or a well-known performer in their sport.</li>\n<li>When a role model speaks openly about competing clean, and is clearly seen rejecting shortcuts, it makes \"clean sport\" feel like the normal way to behave, rather than a rule forced on athletes from outside.</li>\n<li>A role model who stays silent, or who is seen bending the rules, sends the opposite message — which is why governing bodies use respected role models deliberately in education programmes.</li>\n</ul>\n<h4>Peers and team-mates</h4>\n<ul>\n<li>Athletes spend most of their training time with people of a similar age and ability, so <strong>peers and team-mates</strong> shape day-to-day decisions more than any single poster or leaflet ever could.</li>\n<li>A team-mate who questions a risky choice, or reports a concern, can stop doping before it starts; a team-mate who treats it as normal makes doping feel more acceptable.</li>\n</ul>\n<h4>Family</h4>\n<ul>\n<li><strong>Family</strong> shape an athlete''s attitude to fairness and honesty from a young age, long before any formal anti-doping education ever begins.</li>\n<li>A family that values effort and fair competition over winning at any cost reduces the pressure a young athlete feels to look for a shortcut later on.</li>\n</ul>", "check": {"question": "Why are peers and team-mates an important part of educating athletes against PED use?", "options": ["They are legally responsible for drug-testing every single athlete in their squad each week", "They train alongside the athlete most days, so their everyday attitudes shape real choices", "They make posters and leaflets unnecessary for any governing body ever again", "They only matter once an athlete has already reached full international level"], "answer": 1, "explain": "Team-mates are around an athlete constantly, so what they treat as normal or unacceptable has a daily influence that a poster or a one-off talk cannot match."}}, {"title": "What athletes must know — risks and clean sport", "html": "<h4>The serious health risks</h4>\n<ul>\n<li>Education programmes teach athletes that performance-enhancing drugs are not a free shortcut — they carry <strong>serious health risks</strong>, including long-term damage to the body, disrupted hormones, and psychological effects such as dependency.</li>\n<li>Many of these risks only appear years later, which is exactly why athletes need to be warned about them in advance rather than finding out from experience.</li>\n</ul>\n<h4>The value of clean sport</h4>\n<ul>\n<li>Education also teaches the <strong>value of clean sport</strong> — the idea that a result only means something if every competitor had a genuinely fair chance of achieving it.</li>\n<li>Athletes are encouraged to see fair competition as something worth protecting for its own sake, rather than just a rule imposed on them by someone else.</li>\n</ul>\n<h4>Knowing exactly what is banned — and why</h4>\n<ul>\n<li>A large part of education is making sure athletes know <strong>precisely which substances and methods are banned</strong>, so that they never dope by accident — for example through an unchecked supplement or an everyday medicine.</li>\n<li>Athletes are taught to check any product against the current banned list, and to ask a doctor or official before taking anything unfamiliar, instead of assuming it must be fine.</li>\n<li>Understanding <em>why</em> something is banned (an unfair advantage, a health danger, or going against the spirit of sport) helps the rule make sense, rather than just feeling arbitrary.</li>\n</ul>", "check": {"question": "Why does education include teaching athletes exactly what is banned, rather than only that ''doping is against the rules''?", "options": ["So that they never accidentally take a banned substance in something like an unchecked supplement", "So that every athlete memorises the entire full banned list word for word before any single competition", "So that governing bodies can stop testing athletes at competitions altogether", "So that athletes never need to ask a doctor about any medicine again in future"], "answer": 0, "explain": "Knowing precisely what is banned, and why, protects athletes from doping by accident — the goal is informed choices, not word-for-word memorising or removing testing."}}]}, "terms": {"enabled": true, "pairs": [{"term": "Anti-doping campaign", "definition": "Posters/workshops/talks aimed at putting athletes off PEDs before they are tempted"}, {"term": "Role model", "definition": "A respected figure whose visible behaviour shows what counts as normal"}, {"term": "Peer influence", "definition": "The everyday effect team-mates have on each other''s choices"}, {"term": "Family education", "definition": "Attitudes to fairness and honesty picked up at home from a young age"}, {"term": "Clean sport", "definition": "The value that a result only counts if every competitor had a fair chance"}, {"term": "Checking the banned list", "definition": "Confirming a product is allowed before taking it, to avoid doping by accident"}]}, "mcq": {"enabled": true, "questions": [{"question": "What is the main aim of an anti-doping awareness campaign run by a club or governing body?", "options": ["To put athletes off using banned substances before they are ever tempted to try them", "To remove the requirement for any athlete to ever be tested at a competition of any kind", "To reward athletes with prize money for reporting other competitors who dope", "To replace the entire set of written rules a sport has about banned substances"], "answer": 0, "explain": "Campaigns are a form of prevention — posters, workshops and talks aim to discourage use before an athlete ever considers it, not to change testing rules or offer rewards."}, {"question": "How can a respected role model help educate athletes against doping?", "options": ["By refusing to discuss the topic of doping with any athlete they coach or compete alongside", "By showing, through their own visible behaviour, that competing clean is the normal way to behave", "By guaranteeing that the athletes who copy them will win every future competition they ever enter", "By replacing the need for any official governing-body anti-doping campaign whatsoever"], "answer": 1, "explain": "A role model''s visible behaviour makes clean sport feel like the expected norm, which is far more persuasive than staying silent or claiming to remove the need for campaigns."}, {"question": "Why do peers and team-mates have such a strong influence on whether an athlete considers doping?", "options": ["They are with the athlete for most of their day-to-day training, shaping normal, everyday choices", "They are the only people who are ever legally allowed to discuss banned substances", "They are automatically better informed about doping than any qualified coach or governing body could ever be", "They have no real influence at all once an athlete has joined a senior squad"], "answer": 0, "explain": "Constant daily contact means peers shape what feels ''normal'', which is why their attitude matters more than a one-off talk from someone the athlete rarely sees."}, {"question": "What role can a family play in educating a young athlete against future PED use?", "options": ["Shaping the athlete''s early attitudes to fairness, so winning at any cost feels less acceptable", "Legally banning the athlete from ever taking part in competitive sport again", "Testing the athlete for banned substances before every single training session without exception", "Replacing the athlete''s coach as the only source of anti-doping information"], "answer": 0, "explain": "Family shape attitudes to honesty and fair play from a young age, long before formal education begins — they are not testers, and they do not replace coaches."}, {"question": "Why do anti-doping education programmes teach athletes about the health risks of PEDs?", "options": ["So athletes understand the real personal cost, since many risks only appear years later", "So athletes can safely reduce a health risk by taking a slightly smaller, measured dose", "So that governing bodies never need to mention the topic of health again after year one", "So that only elite, full-time professional athletes are ever warned about any risk at all"], "answer": 0, "explain": "Naming the real, often long-delayed health risks in advance is the point — there is no ''safe smaller dose'', and every level of athlete needs the same warning, not just elite ones."}, {"question": "An athlete is offered an unfamiliar supplement by a training partner. What has good anti-doping education taught them to do?", "options": ["Take it immediately, because a training partner would never suggest something risky", "Check it against the current banned list, or ask a doctor, before taking anything unfamiliar", "Assume it is safe as long as it was bought legally from an ordinary high-street shop", "Say nothing to anyone and decide entirely alone, since checking would waste valuable training time anyway"], "answer": 1, "explain": "Education teaches athletes to check anything unfamiliar against the banned list or ask a professional first — trusting a training partner or a shop label is exactly how accidental doping happens."}]}, "fib": {"enabled": true, "questions": [{"text": "Anti-doping [campaigns] use posters, workshops and talks to put athletes off using banned substances before they are ever tempted."}, {"text": "A role [model] who is clearly seen competing clean makes fair play feel like the normal way to behave."}, {"text": "Team-mates shape each other''s everyday choices, which is why [peers] matter so much in anti-doping education."}, {"text": "Athletes are taught to check any supplement against the banned list so they do not dope by [accident]."}, {"text": "Clean sport matters because a result should only count if every competitor had a genuinely fair [chance]."}]}, "tf": {"enabled": true, "questions": [{"statement": "Anti-doping education aims to stop athletes doping before it happens, not only to punish them afterwards.", "answer": true, "explain": "That is the whole point of education — prevention. Punishing athletes who have already doped is a separate, reactive response."}, {"statement": "Only elite, famous athletes can ever act as a role model who influences someone against doping.", "answer": false, "explain": "A role model can be a senior team-mate, a local coach or a family member — anyone an athlete looks up to and copies, not only famous professionals."}, {"statement": "Team-mates can influence each other''s day-to-day choices about whether to use banned substances.", "answer": true, "explain": "Because athletes train alongside team-mates constantly, what team-mates treat as normal has a real, daily influence on individual choices."}, {"statement": "Once a supplement is legal to buy in an ordinary shop, it is automatically safe for an athlete to take.", "answer": false, "explain": "Some legal supplements contain substances that are banned in sport but not clearly listed — athletes must check the banned list, not just the shop label."}, {"statement": "Understanding WHY a substance is banned can help the rule make more sense to an athlete.", "answer": true, "explain": "Knowing the reason (unfair advantage, health danger, or against the spirit of sport) turns a rule from something arbitrary into something an athlete understands and accepts."}, {"statement": "Family have no real influence on an athlete''s attitude to fair play because doping is entirely a personal decision.", "answer": false, "explain": "Family shape attitudes to honesty and fairness from a young age, well before any formal anti-doping education — so their influence is real, not irrelevant."}]}, "misc": {"enabled": true, "items": [{"myth": "Education against PEDs is basically the same thing as punishing athletes who get caught doping.", "truth": "Education and punishment are two separate tools. Education is PROACTIVE — it teaches facts, risks and values BEFORE any decision is made, aiming to stop doping happening at all. Punishment (sanctions) is REACTIVE — it responds after someone has already doped. An exam answer that only describes a sanction has not described an educational strategy.", "check": {"question": "What is the key difference between EDUCATION and PUNISHMENT in anti-doping work?", "options": ["There is no real difference between the two at all", "Education happens before a decision is made; punishment happens after doping has occurred", "Punishment is always run by family members rather than governing bodies", "Education can only ever be delivered to athletes who have already been caught doping in competition"], "answer": 1, "explain": "Education tries to prevent doping before it happens; punishment reacts once it already has. Mixing the two up loses marks in an exam that asks specifically about education."}}, {"myth": "Only elite, famous athletes can act as a role model who influences someone against doping.", "truth": "A role model is simply someone an athlete looks up to and copies — this can be a senior team-mate, a local coach, or a family member, just as much as a famous professional. Peers and family often have MORE day-to-day influence than a distant elite athlete an individual rarely meets in person.", "check": {"question": "Which of these could act as a genuine role model in anti-doping education?", "options": ["A famous international athlete the person has never actually met", "A respected senior team-mate the athlete trains with every week", "Both a well-known professional AND a respected senior team-mate", "Neither of these, because only official campaigns can educate athletes"], "answer": 2, "explain": "Role models exist at every level — a famous athlete AND a respected team-mate can both shape attitudes, so limiting it to elite athletes alone misses the closer, daily influence."}}, {"myth": "If a product is a legal supplement bought on the high street, it must be safe for an athlete to use in competition.", "truth": "Some legal, over-the-counter supplements can contain substances that are banned in sport without this being made obvious on the packaging. Education teaches athletes to check any unfamiliar product against the current banned list, or ask a doctor or official first, rather than trusting that ''legal to buy'' means ''safe to compete with''.", "check": {"question": "Why can a legal, high-street supplement still be risky for a competing athlete?", "options": ["Because all supplements are illegal to sell in ordinary shops", "Because it might contain a banned substance not made clear on the packaging", "Because supplements are always more expensive than banned substances", "Because shops are legally required to report every single customer who buys one"], "answer": 1, "explain": "''Legal to buy'' is not the same as ''safe to compete with'' — some supplements contain undisclosed banned substances, which is exactly why checking the list matters."}}]}, "tips": {"enabled": true, "items": [{"title": "Command words for this topic — what each one wants", "html": "<p>Questions on educating athletes against PEDs are usually short recall or applied, but Section C can extend into a levelled discussion. Match your answer to the command word and the mark tariff:</p>\n<ul>\n<li><strong>Identify / State</strong> — just name it. \"Identify two groups who can educate an athlete\" = two names, nothing more. 1 mark each.</li>\n<li><strong>Describe</strong> — give the features of a strategy, e.g. what an awareness campaign actually involves.</li>\n<li><strong>Explain</strong> — name a strategy AND give a reason it reduces doping. Use the word <em>because</em>.</li>\n<li><strong>Discuss</strong> — weigh up more than one side (for example education vs punishment) before reaching a judgement.</li>\n</ul>\n<p><strong>Read the mark tariff:</strong> [1]–[2] wants one or two clear points; higher marks in Section B want those points applied to the scenario in front of you.</p>", "check": {"question": "A question says: ''Identify two people or groups who can educate an athlete against doping [2]''. What is the safest answer?", "options": ["A detailed paragraph explaining only one group in full depth", "Two clearly named people or groups, such as a role model and family", "A list of every group you can possibly think of, however many that is", "A description of your own personal opinion about doping in sport"], "answer": 1, "explain": "''Identify'' plus [2] wants two clear names — role models, peers/team-mates or family, for example — not one long explanation, an endless list, or a personal opinion."}}, {"title": "The golden rule: name the strategy AND explain why it works", "html": "<p>The most common way to lose marks here is naming a strategy without saying why it reduces doping. Build every answer as <strong>strategy → who it reaches → why it helps</strong>:</p>\n<ul>\n<li><strong>❌ 0–1 marks:</strong> \"Campaigns.\"</li>\n<li><strong>✅ full marks:</strong> \"Awareness campaigns explain the health risks of PEDs, which puts athletes off before they are ever tempted to try them.\"</li>\n</ul>\n<p>In <strong>Section B</strong> the question gives you a scenario — a named club or athlete. You must link your strategy to a detail <em>from that scenario</em>, not a general example that ignores it.</p>", "check": {"question": "In a Section B scenario about a named athlete offered an unfamiliar supplement, your answer should link your strategy to...", "options": ["any general example you already happen to know well", "the specific detail given in the scenario", "a famous international athlete not mentioned anywhere in the question", "the exam board''s own official published guidance documents"], "answer": 1, "explain": "Section B rewards applying your knowledge to the scenario given — a general point that ignores the supplement detail in front of you is capped."}}, {"title": "Where this appears + sentence starters", "html": "<p><strong>Where it shows up:</strong> quick recall of who educates athletes (role models, peers, family, campaigns) in <strong>Section A</strong>; applied scenarios about a club or athlete in <strong>Section B</strong>; and it can feed a <strong>Section C</strong> discussion comparing education against punishment as ways to reduce doping.</p>\n<p><strong>Three punchy tips:</strong></p>\n<ul>\n<li>Keep education and punishment separate in your head — one prevents, the other reacts.</li>\n<li>For every strategy, memorise one reason it works — that reason is usually where the mark sits.</li>\n<li>Remember athletes can dope <em>by accident</em> — education about checking the banned list is a strategy in its own right.</li>\n</ul>\n<p><strong>Sentence starters for a longer answer:</strong></p>\n<ul>\n<li>\"One way athletes are educated against doping is… because…\"</li>\n<li>\"This matters because it reaches athletes before…\"</li>\n<li>\"On the other hand, education alone may not…\"</li>\n</ul>", "check": {"question": "Why is it useful to remember that education can prevent ACCIDENTAL doping, not just deliberate doping?", "options": ["It shows a strategy (checking the banned list) that punishment cannot replace", "It proves that deliberate doping no longer happens in any sport", "It means checking a banned list is now completely unnecessary", "It replaces every single other educational strategy covered anywhere on this entire topic"], "answer": 0, "explain": "Accidental doping is a real risk education specifically targets (via checking the banned list) — a point punishment cannot address, since it only reacts once doping has occurred."}}]}, "exam": {"enabled": true, "questions": [{"question": "Identify <strong>two</strong> people or groups who can play a role in educating an athlete against using banned substances.", "marks": 2, "hint": "Pick two from: role models, peers/team-mates, family, or anti-doping campaigns run by clubs or governing bodies.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks (AO1)</h5>\n<p><strong>1 mark for each correctly named group, to a maximum of two. Accept any two different groups, including:</strong></p>\n<ul>\n<li>Role models (experienced athletes, coaches)</li>\n<li>Peers / team-mates</li>\n<li>Family</li>\n<li>Clubs / schools running awareness campaigns</li>\n<li>National governing bodies</li>\n</ul>\n<p>Do not credit the same group written twice.</p>\n</div>"}, {"question": "Which of these best explains why family can play a role in educating a young athlete against future PED use?", "marks": 1, "hint": "Think about when family influence happens compared with formal anti-doping education.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: A — They shape the athlete''s early attitudes to fairness and honesty, long before formal education begins.</strong></p>\n<ul>\n<li>Family influence attitudes from a young age, before any club or governing body programme starts.</li>\n<li>Family are not testers, and they do not replace a coach — those are different roles entirely.</li>\n</ul>\n</div>"}, {"question": "Explain how Riverside Athletics Club could use education to reduce the risk of an athlete like Jamie using a banned substance, whether on purpose or by accident.", "marks": 4, "hint": "Give two different strategies. For each, name it and explain how it addresses the specific risk in the scenario (the unchecked supplement from the training partner).", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (AO2: application)</h5>\n<p><strong>Up to 2 marks per strategy: 1 for a relevant educational strategy, 1 for explaining how it addresses the risk in THIS scenario. Answers may include:</strong></p>\n<ul>\n<li><strong>Teaching Jamie to check the banned list</strong> — before taking any unfamiliar supplement, so the untested product from the training partner is not taken blindly, stopping accidental doping.</li>\n<li><strong>Using a role model or the coach to reinforce clean sport</strong> — a respected senior athlete or the coach speaking to Jamie directly can counter the training partner''s suggestion and make refusing it feel normal, not awkward.</li>\n</ul>\n<p>Accept any other reasonable, applied strategy. A strategy named with no link to Jamie''s scenario earns 1 of the 2 marks for that strategy.</p>\n</div>"}, {"question": "Discuss whether educating athletes or punishing them is more effective at stopping doping in sport.", "marks": 8, "hint": "Explain the strengths of education (prevention, reaching accidental doping, role models/peers/family). Explain the strengths of punishment (deterrence, dealing with those education doesn''t reach). Weigh them up and give a judgement.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 8 marks (level-of-response). Read the band you fit, then pick a mark.</h5>\n<ul>\n<li><strong>Band 3 (thorough), 6–8:</strong> a balanced, well-applied discussion of both education and punishment, showing clearly how each reduces doping AND weighing their limits, ending in a justified judgement.</li>\n<li><strong>Band 2 (reasonable), 3–5:</strong> sound understanding of at least one side with some analysis, but the discussion may be one-sided or the judgement unsupported.</li>\n<li><strong>Band 1 (basic), 1–2:</strong> names education and/or punishment with little explanation and no real evaluation; largely a list.</li>\n<li><strong>0 marks:</strong> nothing creditworthy.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Indicative content (indicative, not a checklist — reward valid alternatives)</h5>\n<ul>\n<li><strong>Education:</strong> prevents doping before it happens; reaches accidental doping (checking the banned list) which punishment cannot touch; role models, peers and family reinforce it daily.</li>\n<li><strong>Punishment:</strong> deters athletes who understand the risks but are tempted anyway; testing and sanctions catch those education fails to reach; gives the sport a visible consequence.</li>\n<li><strong>Limits of education:</strong> depends on athletes actually listening; slower to show results; cannot guarantee behaviour change on its own.</li>\n<li><strong>Limits of punishment:</strong> only reacts after harm is already done; can feel inconsistent or unfair if applied unevenly; does nothing to prevent accidental doping.</li>\n<li><strong>Judgement:</strong> education is arguably more effective long-term because it prevents the damage rather than reacting to it, but works best combined with punishment as a backstop for those education does not convince.</li>\n</ul>\n</div>"}]}}'::jsonb),
('sport-studies', '2-5-6-the-impact-of-peds-on-sport', '2.5.6 The Impact of PEDs on Sport', '{"learn": {"enabled": true, "items": [{"title": "Reputation and public trust — the sport takes the hit", "html": "<h4>It isn''t only the athlete''s name that suffers</h4>\n<ul>\n<li>When one performer is caught using a <strong>performance-enhancing drug (PED)</strong>, the story rarely stays about that person for long. Journalists, fans and rival competitors start asking whether the <strong>whole sport</strong> has a doping problem.</li>\n<li>That shift matters because it damages the <strong>sport''s reputation</strong> — not only the reputation of the individual who was caught.</li>\n</ul>\n<h4>Public trust and interest can fall</h4>\n<ul>\n<li>Once people suspect that some winners might be cheating, they can start to doubt <strong>every</strong> result in that sport — including performances that were completely clean.</li>\n<li>That loss of trust can shrink the audience: fewer people watch, follow or care about a sport they no longer believe is being won fairly, so <strong>public trust and interest can fall</strong>.</li>\n<li>A sport with a long history of doping cases can carry that damaged reputation for years, even long after it tightens its rules.</li>\n</ul>", "check": {"question": "A PED scandal involving one athlete breaks in the news. Why can this damage the sport as a whole?", "options": ["Because fans and the media can start to doubt every result in that sport, not only the athlete who was caught", "Because journalists automatically assume every single competitor in that sport must also be using banned substances", "Because the scandal has no effect on anyone except the one athlete who was actually caught doping", "Because governing bodies must permanently close down the sport within a year of any doping case being proven"], "answer": 0, "explain": "Doping scandals spread doubt onto the whole sport — damaging its reputation and public trust — not only the individual who was caught. The other options either overstate the effect or wrongly claim there is no wider effect at all."}}, {"title": "Unfair results — and the clean athletes who lose out", "html": "<h4>Records and results built on a lie</h4>\n<ul>\n<li>A performance boosted by PEDs is not a fair contest — the result is <strong>unfair or dishonest</strong>, because the performer gained an advantage that their rivals were not allowed to use.</li>\n<li>If a record is later shown to have been set by a doped athlete, the record itself becomes tainted, even if it takes years for testing to catch up with it.</li>\n</ul>\n<h4>Clean athletes are the ones who really lose out</h4>\n<ul>\n<li>Every place a doped athlete takes on a podium is a place a <strong>clean athlete</strong> did not get. That can mean lost medals, lost prize money, lost funding and lost sponsorship for someone who did nothing wrong.</li>\n<li>Some clean athletes only receive their medal, title or funding years later, once a doping case is finally proven — by which point the moment, and often the money, has already gone.</li>\n</ul>", "check": {"question": "Why are clean athletes described as the group who ''lose out'' when a rival uses PEDs?", "options": ["Because they are automatically banned from competing again once someone else is caught doping", "Because a doped rival can take the medals, funding and sponsorship that a clean performance would otherwise have earned", "Because clean athletes are always physically slower than any athlete who has ever used a PED", "Because the governing body always disqualifies the clean athlete instead of the one who actually doped, even years after the case is proven"], "answer": 1, "explain": "A doped rival can take the medal, funding or sponsorship a clean athlete''s genuine performance would have earned — that is the real cost to clean athletes, not a ban or a disqualification of the wrong person."}}, {"title": "The ongoing cost to the sport — money and policing", "html": "<h4>Sponsors do not want to be linked to a ''tainted'' sport</h4>\n<ul>\n<li>Sponsors pay to have their brand linked to something exciting and trustworthy. A sport with a doping scandal can become <strong>\"tainted\"</strong> in the public eye, so sponsors may pull their money out rather than risk being linked to cheating.</li>\n<li>That loss of sponsorship and broadcast income can hit the whole sport financially — from the top level down to grassroots clubs that relied on money trickling down from it.</li>\n</ul>\n<h4>Testing and policing never really stop</h4>\n<ul>\n<li>To protect its reputation, a sport has to keep testing and monitoring performers — that is an <strong>ongoing cost</strong>, in money and staff time, that never truly ends.</li>\n<li>People looking to cheat keep finding new substances and methods, so testers must keep updating what they test for. That constant effort is a direct cost of PED use existing in the sport at all.</li>\n</ul>", "check": {"question": "Why does PED use create an ''ongoing'' cost for a sport, rather than a one-off cost?", "options": ["Because testing and policing have to continue and adapt constantly, which keeps costing money and staff time", "Because testing only ever has to happen once, on the very first day an athlete joins a professional sporting team", "Because every sponsor is legally required to pay the exact same fine to the sport every single year", "Because testing equipment never needs to be replaced or updated once it has first been bought"], "answer": 0, "explain": "New substances and methods keep appearing, so testing and policing must keep adapting — that ongoing effort and expense is why the cost never truly stops, unlike a single one-off payment."}}]}, "terms": {"enabled": true, "pairs": [{"term": "Impact on reputation", "definition": "A doping scandal can make fans and the media doubt the whole sport, not just the athlete caught"}, {"term": "Public trust and interest", "definition": "Confidence results are genuine, and how much fans watch, follow and care about the sport"}, {"term": "Unfair / dishonest result", "definition": "An outcome shaped by an advantage rivals were not allowed to use"}, {"term": "Clean athletes losing out", "definition": "Missing medals, funding or sponsorship to a rival later proven to have doped"}, {"term": "Sponsors leaving", "definition": "Sponsors may withdraw money rather than be linked to a sport that looks ''tainted''"}, {"term": "Ongoing testing cost", "definition": "Money and staff time a sport must keep spending as new substances keep appearing"}]}, "mcq": {"enabled": true, "questions": [{"question": "Which of these best describes how a doping scandal can affect a SPORT, rather than just the one performer caught?", "options": ["It guarantees that the sport receives a large increase in government funding during the following season", "It has no lasting impact on anything once the individual performer has served their ban", "It can damage the sport''s overall reputation, because people start to question other results too", "It automatically doubles ticket sales for every future event the sport holds afterwards"], "answer": 2, "explain": "A scandal can damage the whole sport''s reputation, because people start doubting other results too — it does not guarantee extra funding, higher ticket sales, or simply vanish once one ban is served."}, {"question": "What can happen to public interest in a sport after repeated doping scandals?", "options": ["Public interest always rises very sharply after each scandal, because controversy makes the sport feel more exciting to watch", "Public trust and interest can fall, because fans no longer feel confident that results are genuine", "Nothing changes at all, because fans never pay attention to how a result was actually achieved", "Every broadcaster is legally required to stop showing the sport completely and permanently"], "answer": 1, "explain": "Repeated scandals can make fans doubt whether results are genuine, so trust and interest can fall — scandal does not reliably boost interest, and coverage is not simply banned outright."}, {"question": "Why is a result achieved using PEDs described as ''unfair or dishonest''?", "options": ["Because the performer received a harsher training schedule than everyone else in the competition", "Because the performer gained an advantage that their rivals were not allowed to use", "Because judges are legally required to disqualify every competitor immediately after the event", "Because the whole event has to be replayed in full from the very beginning the following week"], "answer": 1, "explain": "The result is unfair because the doped performer had an advantage rivals were not allowed to use — a harsher schedule, blanket disqualification and full replays are not what makes it dishonest."}, {"question": "A clean athlete finishes fourth behind a rival who is later proven to have doped. How does this show the impact of PEDs on a sport?", "options": ["It shows that clean athletes always end up receiving more prize money than any doped rival eventually does", "It shows that doping bans are automatically cancelled once a result has already been publicly announced", "It shows that governing bodies refuse to ever re-examine a result once the medals have been given out", "It shows that a clean athlete can lose medals, funding and recognition to a rival who cheated"], "answer": 3, "explain": "The clean athlete missed out on medals, funding and recognition that their genuine performance should have earned — that lost opportunity is the real impact, not a guaranteed pay-out or a frozen result."}, {"question": "Why might sponsors withdraw funding from a sport after a major doping scandal?", "options": ["Sponsors are legally forced by government regulators to withdraw all funding from that sport", "Sponsors always increase their funding straight away, because scandals attract more media coverage", "Sponsors do not want their brand linked to a sport that now looks ''tainted'' by cheating", "Sponsors are only ever interested in individual athletes and never fund a sport as a whole"], "answer": 2, "explain": "Sponsors protect their brand by avoiding a ''tainted'' sport — it is a reputational choice, not a legal requirement, and scandal does not reliably attract extra sponsorship money."}, {"question": "Which statement best explains why anti-doping testing is described as an ''ongoing cost'' for a sport?", "options": ["Testing only ever has to happen once, right at the very start of an athlete''s professional sporting career", "Testing and policing have to continue constantly, because new substances and methods keep appearing", "Testing is completely free for every governing body, so it has no real cost to the sport at all", "Testing is cancelled automatically for a sport as soon as one athlete is caught and banned"], "answer": 1, "explain": "New substances and methods keep appearing, so testing and policing must keep adapting — that is why the cost is ongoing, not a single free or one-off event."}]}, "fib": {"enabled": true, "questions": [{"text": "A doping scandal can damage a sport''s [reputation], making fans doubt every result."}, {"text": "Public trust and [interest] in a sport can fall once fans suspect cheating is happening."}, {"text": "A result boosted by PEDs is unfair because the performer gained an [advantage] that rivals were not allowed to use."}, {"text": "Clean athletes can lose medals and [funding] to a rival who is later proven to have doped."}, {"text": "Sponsors may pull their money out once a sport looks [tainted] by repeated doping cases."}]}, "tf": {"enabled": true, "questions": [{"statement": "A doping scandal involving one athlete can damage the reputation of the whole sport.", "answer": true, "explain": "Once one performer is caught, fans and the media often start to question the whole sport, not just that individual — the reputation damage spreads beyond one person."}, {"statement": "Public trust in a sport always increases straight after a doping scandal.", "answer": false, "explain": "The opposite is more likely — fans can start doubting whether results are genuine, so trust and interest tend to fall, not rise."}, {"statement": "A result achieved using PEDs is still fair, as long as the performer also trained hard.", "answer": false, "explain": "Training hard does not cancel out the unfair advantage a PED gives — the result is still dishonest because rivals were not allowed to use the same boost."}, {"statement": "Clean athletes can lose medals, funding or sponsorship to a rival who is later proven to have doped.", "answer": true, "explain": "Every podium place a doped athlete takes is one a clean athlete did not get, which can cost them medals, funding and sponsorship they otherwise would have earned."}, {"statement": "Sponsors always increase their spending on a sport straight after a doping scandal breaks.", "answer": false, "explain": "Sponsors more often pull money OUT of a sport that looks ''tainted'', because they do not want their brand linked to cheating."}, {"statement": "Anti-doping testing is an ongoing cost, because new substances and methods keep appearing.", "answer": true, "explain": "Cheats keep finding new ways to dope, so testers must keep adapting what they test for — that constant effort is a genuine ongoing cost, not a one-off payment."}]}, "misc": {"enabled": true, "items": [{"myth": "Doping only really affects the one athlete who gets caught — it''s their problem, not the sport''s.", "truth": "The exam wants you to explain the impact on the SPORT, not only the individual. A scandal can damage the sport''s reputation, reduce public trust and interest, disadvantage clean athletes who lose medals or funding, push sponsors to leave a ''tainted'' sport, and add an ongoing cost of testing and policing. An answer that only mentions the athlete''s own ban misses almost every mark available.", "check": {"question": "A question asks you to explain the impact of PED use ON A SPORT. What should your answer focus on?", "options": ["Only the length of the individual athlete''s ban", "Effects on the sport itself — reputation, trust, clean athletes, sponsors and testing costs", "Only what happens to the athlete''s own personal fitness and training programme in the years afterwards", "Only the name of the substance the athlete used"], "answer": 1, "explain": "''Impact on the sport'' means reputation, public trust, fairness to clean athletes, sponsor money and the cost of policing — not just the individual''s own ban or fitness."}}, {"myth": "If a doped result stood for years before anyone was caught, it doesn''t really matter any more.", "truth": "It still matters. The result was unfair or dishonest at the time it was won, and any clean athlete who missed out on a medal, funding or recognition lost that opportunity permanently — a late correction does not give them back the years they lost. It also shows why ongoing testing matters: cases can take years to prove, during which the sport''s reputation keeps being damaged.", "check": {"question": "A doping case is only proven years after the event. Why does this still matter to a clean athlete who finished just behind?", "options": ["It doesn''t matter, because the result cannot ever be looked at again by anyone", "They permanently lost medals, funding or recognition during the years before the case was proven", "It only matters to the governing body, never to the athlete", "The clean athlete automatically becomes ineligible to compete in any future event once the case is proven"], "answer": 1, "explain": "The clean athlete missed out on real opportunities — medals, funding, recognition — during the years before the case was proven, and that loss cannot simply be reversed later."}}, {"myth": "Testing and policing are a one-off cost a sport pays once, and then never worries about again.", "truth": "Testing and policing are an ONGOING cost. New substances and methods keep appearing, so a sport must keep updating what it tests for and keep paying staff and laboratories to do it — the effort never really stops as long as the temptation to dope exists.", "check": {"question": "Why can''t a sport just test athletes once and consider the job finished?", "options": ["Because testing laboratories always close down after their very first year of operation", "Because new substances and methods keep appearing, so testing must keep adapting", "Because athletes are only ever tested during their very first competition", "Because governing bodies are not allowed to test the same athlete twice"], "answer": 1, "explain": "New substances and methods keep appearing, which is exactly why testing and policing must be an ongoing effort rather than a single completed task."}}]}, "tips": {"enabled": true, "items": [{"title": "Command words for this topic — what each one wants", "html": "<p>Impact-of-PEDs questions vary a lot in length. Match your answer to the command word and the mark tariff:</p>\n<ul>\n<li><strong>Identify / State</strong> — just name an impact. \"Identify one impact of PED use on a sport\" = one named effect, e.g. \"loss of public trust\". 1 mark.</li>\n<li><strong>Describe</strong> — say what the impact actually looks like, not just its name.</li>\n<li><strong>Explain</strong> — give a reason. Use the word <em>because</em>. \"Explain how PED use can affect sponsorship\" = the impact, plus why it happens.</li>\n<li><strong>Discuss</strong> — weigh up more than one impact and reach a judgement about which matters most, or how serious the overall damage is.</li>\n</ul>\n<p><strong>Read the mark tariff:</strong> [1] wants one point; [4] in Section B wants two developed, applied points; [8] wants balanced analysis of several impacts plus a justified judgement.</p>", "check": {"question": "A question says: ''Identify one impact of PED use on a sport [1]''. What is the safest answer?", "options": ["A full paragraph explaining every possible impact", "One named impact, such as loss of public trust", "A list of every impact you can remember", "A description of the athlete''s own punishment"], "answer": 1, "explain": "''Identify'' + [1] = one named impact. A full paragraph or a long list wastes time for a single mark, and the athlete''s own punishment is not an impact on the sport."}}, {"title": "The golden rule: impact on the SPORT, not the individual", "html": "<p>The single most common way to lose marks here is writing about the athlete''s own ban instead of the sport. Keep asking yourself: <strong>who does this sentence actually affect?</strong></p>\n<ul>\n<li><strong>❌ Off-target:</strong> \"The athlete is banned for four years and loses their funding.\"</li>\n<li><strong>✅ On-target:</strong> \"The sport''s reputation is damaged, because fans start to doubt whether other results in the same competition were also achieved fairly.\"</li>\n</ul>\n<p>In <strong>Section B</strong> you are given a scenario. Use a detail <em>from that scenario</em> (a named event, sponsor or governing body) rather than a generic example.</p>", "check": {"question": "In a Section B scenario about a doping case, your answer should focus mainly on...", "options": ["the athlete''s personal fitness routine", "the impact on the sport itself, using detail from the scenario", "an unrelated sport you happen to prefer", "the exact chemical name of the banned substance that was used in the case"], "answer": 1, "explain": "Section B rewards applying the impact-on-the-sport idea to the scenario you are given — personal fitness, an unrelated sport, or the chemical name earn nothing here."}}, {"title": "Where this appears + sentence starters", "html": "<p><strong>Where it shows up:</strong> quick recall in <strong>Section A</strong> (identify/describe an impact); applied points in <strong>Section B</strong> scenarios about a specific doping case; and it feeds <strong>Section C</strong> 8-mark Discuss/Evaluate answers about how serious the overall damage to a sport really is.</p>\n<p><strong>Three punchy tips:</strong></p>\n<ul>\n<li>Learn the six impacts in pairs: reputation + trust, fairness + clean athletes, sponsors + testing cost.</li>\n<li>Always link an impact to WHY it happens — \"sponsors leave BECAUSE the sport now looks tainted.\"</li>\n<li>For a Discuss/Evaluate answer, pick two or three impacts and finish with a judgement on which does the most lasting damage.</li>\n</ul>\n<p><strong>Sentence starters for a longer answer:</strong></p>\n<ul>\n<li>\"One impact on the sport is… because…\"</li>\n<li>\"This matters because it affects…\"</li>\n<li>\"However, a bigger long-term impact might be… because…\"</li>\n</ul>", "check": {"question": "Why is it useful to link each impact to a reason (''because…'') in a longer answer?", "options": ["It fills space without adding anything", "It shows understanding of WHY the impact happens, which is what earns marks", "It replaces the need to ever mention more than one impact anywhere in the whole answer", "It means you never need to reach a judgement"], "answer": 1, "explain": "Explaining WHY an impact happens shows real understanding, rather than just naming it — and a longer answer still needs a range of impacts plus a final judgement."}}]}, "exam": {"enabled": true, "questions": [{"question": "Identify <strong>two</strong> ways in which PED use can impact a sport, other than the individual performer''s own ban.", "marks": 2, "hint": "Pick two from: reputation damage, loss of public trust/interest, unfair or dishonest results, clean athletes losing out, sponsors leaving, or the ongoing cost of testing and policing.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks (AO1)</h5>\n<p><strong>1 mark for each correct, DIFFERENT impact named, to a maximum of two. Accept any two from:</strong></p>\n<ul>\n<li>Damage to the sport''s reputation</li>\n<li>Loss of public trust and/or interest</li>\n<li>Unfair or dishonest results/records</li>\n<li>Clean athletes disadvantaged / losing out</li>\n<li>Sponsors and money leaving a ''tainted'' sport</li>\n<li>The ongoing cost and effort of testing and policing</li>\n</ul>\n<p>Do not credit the athlete''s own personal ban or fine — that is an impact on the individual, not the sport.</p>\n</div>"}, {"question": "Which of these is most likely to happen to sponsors after a sport suffers a major, repeated doping scandal?", "marks": 1, "hint": "Think about why a company pays to have its brand seen alongside a sport in the first place.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: B — Sponsors may withdraw funding, because they do not want their brand linked to a ''tainted'' sport.</strong></p>\n<ul>\n<li>Sponsors protect their own brand''s reputation, so a repeated scandal is a real financial risk to them.</li>\n<li>There is no legal requirement to keep funding, and scandal does not reliably increase sponsor spending.</li>\n</ul>\n</div>"}, {"question": "Explain <strong>two</strong> ways this doping case could impact the Elmsworth National Athletics Championships as an event, using details from the scenario.", "marks": 4, "hint": "Take one impact at a time. Name it, then use a detail from the scenario (the sponsor reviewing its deal, or falling ticket sales) to explain why it is happening.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (AO2: application)</h5>\n<p><strong>Up to 2 marks per impact: 1 for identifying a relevant impact, 1 for explaining it using a detail from the scenario. Answers may include:</strong></p>\n<ul>\n<li><strong>Loss of sponsorship / money leaving:</strong> the sponsor reviewing its three-year deal shows sponsors pulling back from a championships now linked with doping.</li>\n<li><strong>Loss of public trust and interest:</strong> falling ticket sales for next year''s event shows fans losing confidence in / interest in the championships.</li>\n<li><strong>Damage to reputation:</strong> the case linking the championships'' own showpiece final to doping harms how the event is seen more widely.</li>\n</ul>\n<p>Accept any other reasonable, applied impact. An impact with no scenario detail, or a scenario detail with no named impact, earns 1 of the 2 marks for that impact.</p>\n</div>"}, {"question": "Discuss how much a doping scandal like this can damage a sport such as cycling.", "marks": 8, "hint": "Choose two or three impacts (reputation, trust/interest, fairness to clean riders, sponsors, testing cost). Explain each using the scenario, then weigh up how serious and how lasting the damage really is, finishing with a judgement.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 8 marks (level-of-response). Read the band you fit, then pick a mark.</h5>\n<ul>\n<li><strong>Band 3 (thorough), 6–8:</strong> a balanced, well-applied discussion of several impacts, showing clearly how each damages the sport AND weighing how serious/lasting the damage is (e.g. some impacts recover, others don''t), ending in a justified judgement.</li>\n<li><strong>Band 2 (reasonable), 3–5:</strong> sound understanding applied to more than one impact with some analysis, but the discussion may be one-sided or the judgement unsupported.</li>\n<li><strong>Band 1 (basic), 1–2:</strong> names impacts with little application to the scenario and no real evaluation; largely a list.</li>\n<li><strong>0 marks:</strong> nothing creditworthy.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Indicative content (indicative, not a checklist — reward valid alternatives)</h5>\n<ul>\n<li><strong>Reputation and trust:</strong> repeated cases can make fans doubt every result, shown here by falling viewing figures.</li>\n<li><strong>Sponsors / money:</strong> a sponsor ending its deal early shows real, immediate financial damage.</li>\n<li><strong>Clean riders disadvantaged:</strong> riders who never doped can still lose recognition and opportunities because the whole Tour is viewed with suspicion.</li>\n<li><strong>Ongoing cost of testing:</strong> a much larger share of the budget now goes on testing, which is money the sport cannot spend elsewhere.</li>\n<li><strong>Evaluation:</strong> some damage may be temporary (viewing figures can recover if the sport is seen to act firmly), but reputational damage and higher testing costs can last for years; the scale of damage may depend on how the organisers respond, not only on the scandal itself.</li>\n<li><strong>Judgement:</strong> a doping scandal can seriously damage a sport across several fronts at once (trust, money, fairness, cost) — but the overall extent of the damage often depends on how quickly and visibly the sport responds, not on the scandal alone.</li>\n</ul>\n</div>"}]}}'::jsonb),
('sport-studies', '3-1-1-types-of-major-events', '3.1.1 Types of Major Events', '{"learn": {"enabled": true, "items": [{"title": "What a ''major sporting event'' is, and why its type matters", "html": "<h4>What counts as ''major''</h4>\n<ul>\n<li>A <strong>major sporting event</strong> is a large-scale competition that draws big numbers of participants, spectators, media coverage and often government or commercial money.</li>\n<li>The exam is far less interested in \"how big\" an event is and much more interested in <strong>how it is scheduled</strong> — where it is held, and whether it comes back to the same place.</li>\n</ul>\n<h4>Why the hosting pattern matters</h4>\n<ul>\n<li>A host city, governing body or sponsor plans very differently depending on whether an event visits <em>once only</em>, <em>every so often at a new venue</em>, or <em>every time at the same venue</em>.</li>\n<li>The key exam skill: correctly naming the type an event follows, and backing it up with a matching example — not just describing the sport itself.</li>\n</ul>", "check": {"question": "What does the specification mainly focus on when it sorts major sporting events into types?", "options": ["How much prize money the winning athlete or team receives", "The pattern of where, and how often, an event is hosted", "How many television channels choose to broadcast the event live", "Whether the event includes more than one sport in its programme"], "answer": 1, "explain": "The types are about the hosting pattern — whether the venue changes and how often the event repeats — not about prize money, broadcast reach or how many sports are involved."}}, {"title": "Regular events — a different host each time", "html": "<h4>The idea</h4>\n<ul>\n<li>A <strong>regular event</strong> repeats on a fixed schedule (for example, every year), but moves to a <strong>different host city or country</strong> each time it is held.</li>\n<li>Example: a major club competition''s final might be scheduled every year, yet a new city bids to stage it each time — one year in one country, the next year somewhere else entirely.</li>\n</ul>\n<h4>Why the moving host matters</h4>\n<ul>\n<li>Because the venue changes, each host usually has to build or adapt facilities almost from scratch, which can bring fresh investment and tourism to a new place every time.</li>\n<li>Fans and organisers cannot assume the same stadium or transport links will be used twice running, so planning restarts for every single edition.</li>\n</ul>", "check": {"question": "Which of these correctly describes a ''regular'' major sporting event?", "options": ["It is held only once, in a single host city, as a rare once-in-a-generation occasion for that host", "It is held every year at exactly the same fixed venue and never moves elsewhere", "It repeats on a schedule, but moves to a different host city each time it is held", "It has no fixed schedule and could be staged in any country at any random time"], "answer": 2, "explain": "''Regular'' means it repeats on a schedule AND changes host each time — unlike a once-only event, and unlike an event that stays at the same fixed venue every year."}}, {"title": "''One-off'' events, and regular and recurring events", "html": "<h4>''One-off'' events</h4>\n<ul>\n<li>A <strong>''one-off'' event</strong> is hosted in a particular city extremely rarely — often only once in a generation. It is a huge, once-in-a-lifetime undertaking for that host.</li>\n<li>Example: a summer multi-sport Games that a country might only get the chance to stage once every few decades, if it ever gets the chance at all.</li>\n</ul>\n<h4>Regular and recurring events</h4>\n<ul>\n<li>A <strong>regular and recurring event</strong> also repeats on a schedule (such as every year), but — unlike a regular event — it returns to the <strong>same venue</strong> every single time.</li>\n<li>Example: an annual tennis championship played at the same grounds every year, or a motor-racing event held at the same circuit every season.</li>\n</ul>\n<h4>The key difference to hold onto</h4>\n<ul>\n<li>All three types can repeat on a schedule — the real difference is entirely about whether, and how, the <strong>host location changes</strong>: a ''one-off'' event barely repeats at all; a regular event repeats but moves; a regular and recurring event repeats and stays exactly where it is.</li>\n</ul>", "check": {"question": "Which statement correctly describes a ''regular and recurring'' major sporting event?", "options": ["It is held on a repeating schedule and returns to the same venue every time it is staged", "It is held once only, in a single city, and is never staged again in future", "It repeats on a schedule but always moves to a completely new and different host city each time", "It has no fixed venue at all and no fixed schedule of any kind whatsoever"], "answer": 0, "explain": "Regular AND recurring means it repeats on a schedule (like a regular event) but keeps the SAME venue every time — the opposite of a regular event, which moves host each time."}}, {"title": "Telling the three types apart — the exam skill", "html": "<h4>Name the type AND give a matching example</h4>\n<ul>\n<li>Writing \"it''s a one-off event\" on its own earns little. Marks usually come from pairing the <strong>correct type</strong> with a <strong>correct, matching example or reason</strong>.</li>\n<li>Weak answer: <em>\"The Games are a one-off event.\"</em> Strong answer: <em>\"The Games are a ''one-off'' event because a host city gets the chance to stage them only very rarely, so this may be its only opportunity.\"</em></li>\n</ul>\n<h4>Comparing the three types side by side</h4>\n<ul>\n<li><strong>Regular</strong> = repeats + host changes each time (e.g. a club competition final moving city to city).</li>\n<li><strong>''One-off''</strong> = barely repeats + a rare, huge undertaking (e.g. a summer multi-sport Games).</li>\n<li><strong>Regular and recurring</strong> = repeats + host stays the same (e.g. an annual championship at the same grounds).</li>\n</ul>\n<h4>Why the type matters to a host or organiser</h4>\n<ul>\n<li>A ''one-off'' host often builds large, permanent infrastructure from scratch, since it may never host the event again — a lasting legacy matters hugely to that decision.</li>\n<li>A regular event''s rotating hosts can bid competitively and share the workload and cost of the event around different places over time.</li>\n<li>A regular and recurring host can reuse and gradually improve the same venue every year, so it makes long-term investment in that one fixed site.</li>\n</ul>", "check": {"question": "A candidate answers a question about a named event by writing only ''It is a one-off event''. What is missing from this answer?", "options": ["Nothing at all — naming the type alone is already enough for full marks", "A correct example or reason that shows understanding of that type", "A description of the closing ceremony held at the event", "The exact date on which tickets first went on general sale"], "answer": 1, "explain": "Naming a type without a matching example or reason rarely earns full marks — the mark scheme rewards showing you understand WHY that type fits, not just stating a label."}}]}, "terms": {"enabled": true, "pairs": [{"term": "Regular event", "definition": "Repeats on a schedule; hosted in a different city each time"}, {"term": "''One-off'' event", "definition": "Hosted in a city extremely rarely, often once in a generation"}, {"term": "Regular and recurring event", "definition": "Repeats on a schedule and returns to the same venue every time"}, {"term": "Rotating host", "definition": "A new city bids to stage the event each time it is held"}, {"term": "Fixed host venue", "definition": "The same venue stages the event every time it is held"}, {"term": "Legacy investment", "definition": "Long-term facilities a ''one-off'' host builds since it may not host again"}, {"term": "Applied example — regular", "definition": "A club competition final played in a newly chosen host city each year"}, {"term": "Applied example — recurring", "definition": "A motor-racing event held at the same circuit every season"}]}, "mcq": {"enabled": true, "questions": [{"question": "A major sporting event repeats on a schedule, but a different city is chosen to host it every time. Which type of event is this?", "options": ["This is a regular and recurring event, because the exact same host venue is used every single time without exception", "This is a regular event, because it repeats on a schedule but the host changes each time", "This is a ''one-off'' event, because the host city gets only one single chance ever", "This is not a scheduled event at all, since no city can ever host it twice running"], "answer": 1, "explain": "Repeating on a schedule but moving host each time is the definition of a regular event — a regular and recurring event keeps the same venue, and a ''one-off'' barely repeats at all."}, {"question": "A country gets the chance to stage a summer multi-sport Games only once every few decades, if at all. Which type of major event is this?", "options": ["A regular event, because the host changes to a new city on a fixed yearly schedule", "A regular and recurring event, since the same city keeps hosting it every year", "A ''one-off'' event, since a host city gets this rare chance only very occasionally", "An event with no type at all, because it is simply too large to be classified"], "answer": 2, "explain": "Being hosted extremely rarely, as a once-in-a-generation opportunity, is exactly what makes an event ''one-off'' — the other options describe events that repeat far more often."}, {"question": "A national motor-racing event is staged at the same circuit every single season, year after year. Which type of event is this?", "options": ["A ''one-off'' event, since the host city only gets to stage that particular circuit race a single time in its history", "A regular event, because a different circuit bids to host the race each season", "A regular and recurring event, because it repeats and always returns to that same circuit", "An event with an entirely random schedule that changes without any real pattern"], "answer": 2, "explain": "Repeating on a schedule AND staying at the same venue every time is the definition of regular and recurring — a ''one-off'' would happen rarely, and a regular event would change host."}, {"question": "Which of these is the best example of a regular event, rather than a regular and recurring one?", "options": ["An annual tennis championship that is always played at the same grounds every year", "A motor-racing event held at one fixed circuit for every single season of the calendar", "A club competition final that is played in a newly chosen host city every year", "A summer multi-sport Games that a country hosts only once in a generation"], "answer": 2, "explain": "A regular event repeats but changes host — a final moving to a new city each year fits that pattern, unlike the fixed-venue tennis or motor-racing examples, or the rare ''one-off'' Games."}, {"question": "Why does a host city for a ''one-off'' event usually invest so heavily in permanent, large-scale infrastructure?", "options": ["Because permanent infrastructure is always cheaper to build than temporary structures", "Because the national governing body legally requires permanent buildings for any event", "Because that host city may never get the chance to stage the event again", "Because temporary infrastructure is against the rules for every major sporting event"], "answer": 2, "explain": "Since a ''one-off'' host might never host the event again, it often builds for a lasting legacy — not because permanent building is cheaper or a strict rule of every event."}, {"question": "Why can a regular event''s rotating hosts share out the cost and workload of staging it over time?", "options": ["Because only one host city is ever legally permitted to bid for the event", "Because a new host bids to stage the event each time it is held", "Because regular events never actually require any facilities to be built", "Because the same single venue is reused for absolutely every edition"], "answer": 1, "explain": "A regular event moves between different bidding hosts, so the cost and effort of staging it is spread across several places over time — it is not stuck with one host or one venue."}]}, "fib": {"enabled": true, "questions": [{"text": "A [regular] event repeats on a schedule but is hosted in a different city each time it is held."}, {"text": "A ''one-off'' event is hosted in a particular city extremely [rarely], often only once in a generation."}, {"text": "A regular and [recurring] event returns to the same venue every time it is held."}, {"text": "All three types of major event can repeat on a [schedule], but they differ in whether the host changes."}, {"text": "A regular event''s rotating host means a new city can [bid] to stage it each time."}, {"text": "A ''one-off'' host often has to build permanent [infrastructure] from scratch, since it may never host again."}]}, "tf": {"enabled": true, "questions": [{"statement": "A regular event is hosted in a different city each time it is held.", "answer": true, "explain": "That''s the definition of a regular event — it repeats on a schedule, but a new host city is chosen every time."}, {"statement": "A ''one-off'' event is hosted in the same city every single year.", "answer": false, "explain": "That describes a regular and recurring event. A ''one-off'' event is the opposite — it is hosted in a particular city only extremely rarely."}, {"statement": "A regular and recurring event returns to the same venue each time it is held.", "answer": true, "explain": "Correct — it repeats on a schedule like a regular event, but unlike a regular event it keeps the same venue every time."}, {"statement": "All three types of major event happen only once and are never repeated.", "answer": false, "explain": "Only a ''one-off'' event barely repeats. Both a regular event and a regular and recurring event repeat on a fixed schedule — they just differ in whether the host changes."}, {"statement": "Naming the correct type of event, with no example or reason, is usually enough to earn full exam marks.", "answer": false, "explain": "Marks usually need a matching example or reason tied to the type, not just the type''s name on its own."}, {"statement": "A host city for a ''one-off'' event often builds permanent infrastructure because it may never get the chance to host again.", "answer": true, "explain": "Correct — since the chance may never come round again, a ''one-off'' host tends to invest for a lasting legacy rather than a temporary setup."}]}, "misc": {"enabled": true, "items": [{"myth": "All three types of major event basically mean the same thing — they all just happen ''sometimes''.", "truth": "They are three distinct patterns, and the exam rewards telling them apart. The difference is entirely about the HOST LOCATION: a regular event repeats but moves host; a ''one-off'' event barely repeats at all; a regular and recurring event repeats and stays at the same host. Saying an event ''happens sometimes'' shows none of that understanding.", "check": {"question": "What is the real difference between the three types of major sporting event?", "options": ["There is no real difference between any of the three named types at all, ever", "Whether, and how, the host location changes between times the event is held", "How many spectators attend the event in a typical host city", "How much prize money is on offer to the eventual overall winner"], "answer": 1, "explain": "The types are defined entirely by the hosting pattern — does the venue change, stay the same, or barely repeat — not by attendance figures or prize money."}}, {"myth": "''One-off'' must mean the event is small or unimportant, since it only happens once.", "truth": "''One-off'' describes the SCHEDULING PATTERN, not the size or importance of an event. In fact, ''one-off'' events (such as a summer multi-sport Games) are often among the very biggest events a host will ever stage — that is exactly why the chance to host one comes round so rarely.", "check": {"question": "What does the term ''one-off'' actually describe about a major sporting event?", "options": ["That the event is small in scale and attracts little media attention", "That a host city gets the chance to stage it only very rarely", "That the event has already been permanently cancelled by organisers", "That the event is not a real sporting competition at all"], "answer": 1, "explain": "''One-off'' is about how rarely a host gets the chance — not about the event being small or unimportant. ''One-off'' events are often huge, once-in-a-generation occasions."}}, {"myth": "A regular event and a regular and recurring event are the same thing, since both repeat on a schedule.", "truth": "Both do repeat on a schedule, which is exactly why students mix them up — but they differ in ONE key way: a regular event moves to a different host each time, while a regular and recurring event returns to the same host every time. That single difference is what the exam is testing.", "check": {"question": "What is the one key difference between a regular event and a regular and recurring event?", "options": ["A regular and recurring event never actually follows any fixed schedule of any kind", "Whether the event returns to the same host venue, or moves to a new one each time", "A regular event is always far bigger in scale than a recurring one", "There genuinely is no difference between these two named types"], "answer": 1, "explain": "Both repeat on a schedule — the difference is purely whether the host location changes (regular) or stays the same (regular and recurring)."}}, {"myth": "In an exam answer, just writing the correct type''s name earns the same marks as explaining it.", "truth": "Naming the type is usually only worth a mark on its own in the shortest ''Identify/State'' questions. For anything asking you to Describe or Explain, you must pair the type with a correct, matching example or reason — the name alone is not enough to reach full marks.", "check": {"question": "For an ''Explain'' question about the type of a named event, what is most likely to earn the marks?", "options": ["Writing only the correct type name and nothing else at all", "Naming the type, then giving a matching example or reason", "Listing all three types you have learned", "Describing the sport being played at the event"], "answer": 1, "explain": "''Explain'' rewards a type PLUS a reason or example that fits it — naming the type alone, listing every type, or describing the sport itself does not show that understanding."}}]}, "tips": {"enabled": true, "items": [{"title": "Command words for this topic — what each one wants", "html": "<p>Questions on event types are usually short. Match your answer length to the command word:</p>\n<ul>\n<li><strong>Identify / State</strong> — just name it. \"Identify one type of major sporting event\" = one type name, nothing more. 1 mark.</li>\n<li><strong>Describe</strong> — say what the type is like. \"Describe a ''one-off'' event\" = give its features (rare, huge, once-in-a-generation).</li>\n<li><strong>Explain</strong> — give a reason, and usually an example. \"Explain why an event is regular and recurring\" = the pattern (same venue) plus why it fits.</li>\n</ul>\n<p><strong>Read the mark tariff:</strong> [1] wants one point; [2]–[4] want the type named AND applied to a given example or scenario.</p>", "check": {"question": "A question says: ''Identify one type of major sporting event [1]''. What is the safest answer?", "options": ["A full paragraph describing every type you know", "One correct type name", "The type''s name along with a full worked example", "A list of all three types with definitions"], "answer": 1, "explain": "''Identify'' + [1] = one name, one mark. A full paragraph, or listing all three types, wastes time on a question only worth a single mark."}}, {"title": "The golden rule: name the type AND give a matching example", "html": "<p>The single most common way to lose marks here is stopping at the type''s name. Build every answer as <strong>type → example/reason</strong>:</p>\n<ul>\n<li><strong>❌ 0–1 marks:</strong> \"It''s a one-off event.\"</li>\n<li><strong>✅ full marks:</strong> \"It''s a ''one-off'' event because the host city only gets the chance to stage it very rarely, so this may be its only opportunity.\"</li>\n</ul>\n<p>In <strong>Section B</strong> the question gives you a scenario (a named place or event). Use a detail <em>from that scenario</em> to justify the type — not just a general fact you already knew.</p>", "check": {"question": "In a Section B scenario question about a named event, your justification should come from...", "options": ["absolutely any event that you happen to know about", "the scenario you are given in the question", "an event that was hosted many decades ago", "your own personal opinion about which type sounds best"], "answer": 1, "explain": "Section B is applied — the marks are for using the scenario in front of you. A justification that ignores the scenario is capped."}}, {"title": "Where this topic appears + sentence starters", "html": "<p><strong>Where it shows up:</strong> event types appear as quick recall in <strong>Section A</strong> (identify/state), and as applied justification in <strong>Section B</strong> scenarios about a specific bid or host. They also feed <strong>Section C</strong> 8-mark answers weighing up hosting decisions for different event types.</p>\n<p><strong>Three punchy tips:</strong></p>\n<ul>\n<li>Learn the three types by their ONE defining feature each: moves (regular), rare (one-off), stays put (recurring).</li>\n<li>For every example you give, check it genuinely matches the type — don''t reuse the same example for two different types.</li>\n<li>In a longer answer, weigh up BOTH the benefits and the drawbacks of a type before reaching a judgement.</li>\n</ul>\n<p><strong>Sentence starters for a longer answer:</strong></p>\n<ul>\n<li>\"One benefit of this type of event is… because…\"</li>\n<li>\"However, a drawback of this type is… because…\"</li>\n<li>\"Overall, this type is the stronger choice because…\"</li>\n</ul>", "check": {"question": "Why is weighing up BOTH a benefit and a drawback useful in a longer answer on event types?", "options": ["It fills space without adding any real understanding", "It shows balanced analysis, which is what levelled questions reward", "It means you no longer need to reach any final, justified judgement at the end", "It replaces the need to give a correct example altogether"], "answer": 1, "explain": "Levelled (banded) questions reward balanced analysis of both sides before a judgement — a one-sided answer is capped in the middle band at best."}}]}, "exam": {"enabled": true, "questions": [{"question": "Identify <strong>two</strong> of the three types of major sporting event, based on how they are hosted.", "marks": 2, "hint": "Name two from: regular, ''one-off'', regular and recurring.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks (AO1)</h5>\n<p><strong>1 mark for each correct type named, to a maximum of two. Accept any two of:</strong></p>\n<ul>\n<li>Regular event</li>\n<li>''One-off'' event</li>\n<li>Regular and recurring event</li>\n</ul>\n<p>Do not credit the same type written twice.</p>\n</div>"}, {"question": "Which type of major sporting event returns to the same host venue every time it is held?", "marks": 1, "hint": "Think about which type''s defining feature is a FIXED venue.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: B — A regular and recurring event.</strong></p>\n<ul>\n<li>It repeats on a schedule but stays at the same venue every time.</li>\n<li>A regular event moves host, and a ''one-off'' event is hosted only very rarely — neither returns to a fixed venue every time.</li>\n</ul>\n</div>"}, {"question": "Using the scenario, explain which type of major event the National Cup final is, and explain one way hosting it would differ for Meadow City compared with hosting a regular and recurring event.", "marks": 4, "hint": "First name the type and justify it using the scenario (a new city each year). Then compare: what does Meadow City NOT get, that a regular and recurring host would?", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (AO2: application)</h5>\n<p><strong>Up to 2 marks for identifying the type with a scenario reason; up to 2 marks for a correct, applied comparison. Answers may include:</strong></p>\n<ul>\n<li><strong>Identifying the type:</strong> a regular event, because the final repeats on a schedule (every year) but is hosted in a newly chosen city each time (Meadow City has never hosted it before).</li>\n<li><strong>Comparison:</strong> a regular and recurring host reuses and improves the SAME venue every year and builds a long-term reputation there, whereas Meadow City may get only this one chance to host and cannot rely on hosting the final again.</li>\n</ul>\n<p>Accept any other reasonable, applied answer. A type named with no scenario reason earns 1 of the 2 marks; a comparison with no application to Meadow City earns 1 of the 2 marks.</p>\n</div>"}, {"question": "Discuss whether Sanderford''s council should bid for the touring club competition final, or invest in a permanent circuit for the same-venue motor-racing event.", "marks": 8, "hint": "Weigh up both options: what does each type of event offer, and what does each cost or risk? Then give a judgement, using the scenario, on which is the stronger choice for Sanderford.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 8 marks (level-of-response). Read the band you fit, then pick a mark.</h5>\n<ul>\n<li><strong>Band 3 (thorough), 6–8:</strong> a balanced, well-applied discussion of BOTH options, weighing benefits and costs of each type using the scenario, ending in a justified judgement.</li>\n<li><strong>Band 2 (reasonable), 3–5:</strong> sound understanding applied to at least one option with some analysis, but the discussion may be one-sided or the judgement unsupported.</li>\n<li><strong>Band 1 (basic), 1–2:</strong> names the event types and/or a fact about each with little application and no real evaluation; largely a list.</li>\n<li><strong>0 marks:</strong> nothing creditworthy.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Indicative content (indicative, not a checklist — reward valid alternatives)</h5>\n<ul>\n<li><strong>Touring final (regular event):</strong> lower upfront cost since facilities are needed for one edition only; still brings a tourism and profile boost for that single year; but no guarantee Sanderford ever hosts it again, so new facilities may go unused afterwards.</li>\n<li><strong>Permanent circuit (regular and recurring event):</strong> far higher upfront cost to build; but delivers guaranteed, repeated hosting, spreading that cost over many years and building a lasting reputation and steady annual tourism and jobs.</li>\n<li><strong>Evaluation:</strong> the touring bid suits a council with limited funds and no appetite for long-term commitment; the permanent circuit suits a council that can afford the initial investment and wants sustained, repeated benefit rather than a single uncertain year.</li>\n<li><strong>Judgement:</strong> if Sanderford can afford the initial outlay, the permanent circuit is usually the stronger long-term choice, because repeated guaranteed hosting delivers more lasting benefit than a single touring bid with no certainty of a repeat.</li>\n</ul>\n</div>"}]}}'::jsonb),
('sport-studies', '3-1-2-participants-and-spectators', '3.1.2 Participants and Spectators', '{"learn": {"enabled": true, "items": [{"title": "Why a major event''s participants are international", "html": "<h4>The idea</h4>\n<ul>\n<li>A <strong>major sporting event</strong> (an Olympic Games, a World Cup, a continental championship) is not a domestic fixture. It is <strong>international</strong> — competitors normally travel in from <strong>two or more different countries</strong> to take part under one shared set of rules, in one host location.</li>\n<li>This is one of the features that separates a \"major event\" from a routine local or regional competition, where every competitor usually comes from the same area.</li>\n</ul>\n<h4>What this means for the host</h4>\n<ul>\n<li>Because competitors arrive from abroad, a host city or country has to plan for things a purely local competition never needs: visas and travel for overseas teams, translation, and accommodation for squads from many nations at once.</li>\n<li>The mix of nations competing is part of the spectacle itself — it is a large part of why people want to watch.</li>\n</ul>", "check": {"question": "What makes the participants at a major sporting event different from those at a small local competition?", "options": ["They usually travel in from two or more different countries to compete", "They must all be full-time professional athletes earning a large salary", "They are always selected using exactly the same method in every single country", "They only ever compete in events lasting a single afternoon"], "answer": 0, "explain": "A major event draws competitors from multiple nations, not just professional status, identical selection rules, or event length — none of those make an event ''major''."}}, {"title": "Two kinds of international spectator", "html": "<h4>Live, in-venue spectators</h4>\n<ul>\n<li>The crowd physically inside the stadium or venue is usually a mix of <strong>local residents</strong> and <strong>visitors who have travelled from other countries</strong> specifically to attend.</li>\n<li>These crowds are large — major events fill the biggest venues a host country has, often for many sessions in a row.</li>\n</ul>\n<h4>Remote spectators — the global audience</h4>\n<ul>\n<li>Far more people watch a major event on <strong>television or online</strong> than could ever fit in a venue. This remote audience is spread across <strong>many countries at once</strong>, often watching in different languages and time zones.</li>\n<li>This global broadcast audience is usually the biggest reason a major event reaches so many more people than any domestic fixture.</li>\n</ul>\n<h4>Putting the two together</h4>\n<ul>\n<li>A major event therefore has an international mix on both sides: <strong>participants</strong> from many nations, and <strong>spectators</strong> split between an international live crowd and a far larger international broadcast audience.</li>\n</ul>", "check": {"question": "Which statement correctly separates the two kinds of spectator at a major sporting event?", "options": ["Live spectators are inside the venue; remote spectators watch worldwide via TV or online", "Live spectators only ever exist for indoor events, while remote spectators only exist for outdoor ones", "Remote spectators are always fewer in number than the people inside the venue", "There is no real difference between a live spectator and a remote spectator"], "answer": 0, "explain": "Live spectators attend in person; remote spectators are the much larger worldwide TV/online audience. The other options invert or deny that split."}}, {"title": "Why the international scale matters", "html": "<h4>It is part of what makes an event \"major\"</h4>\n<ul>\n<li>An event only really counts as <strong>major</strong> once its competitors and its audience stretch across national borders. Scale is a defining feature, not a side effect — a competition with one nation''s athletes and only local spectators stays a domestic event, however well it is run.</li>\n</ul>\n<h4>It drives the impact on the host</h4>\n<ul>\n<li>The international scale is <strong>why</strong> a major event attracts heavy media coverage, sponsorship and investment — broadcasters and sponsors are paying for access to a huge, worldwide audience, not a local one.</li>\n<li>It is also why hosting brings the host country international exposure: the whole point of a global audience is that people <em>outside</em> the host country are watching it.</li>\n</ul>\n<h4>Exam skill: link scale to reason</h4>\n<ul>\n<li>A weak answer just states the scale (\"lots of people watch\"). A strong answer explains <strong>why the scale matters</strong> — for example, that a global TV audience is what makes broadcast rights and sponsorship so valuable to a host.</li>\n</ul>", "check": {"question": "Why does the international scale of participants and spectators matter to a host country?", "options": ["It is a large part of what makes an event ''major'' and drives its media and investment value", "It has no real effect at all on how much investment or media coverage an event ever receives", "It only ever matters for events that are held in winter rather than in the summer months", "It matters solely because it makes ticket prices slightly cheaper for local residents"], "answer": 0, "explain": "The international scale is what defines ''major'' and is why broadcasters, sponsors and investors are interested — it isn''t irrelevant, seasonal, or about ticket price."}}]}, "terms": {"enabled": true, "pairs": [{"term": "Major sporting event", "definition": "A competition whose competitors and spectators are drawn from two or more countries"}, {"term": "Participants", "definition": "Competitors who typically travel in from multiple different nations to compete"}, {"term": "Live spectators", "definition": "The crowd physically inside the venue — usually a mix of local and overseas visitors"}, {"term": "Remote spectators", "definition": "The much larger TV/online audience, spread across many countries at once"}, {"term": "Global audience", "definition": "The combined worldwide viewership that makes broadcast rights and sponsorship valuable"}, {"term": "Why scale matters", "definition": "It is part of what makes an event ''major'' and drives its media, sponsorship and investment value"}]}, "mcq": {"enabled": true, "questions": [{"question": "Which feature best shows that a sporting event has reached ''major'' international scale?", "options": ["The event being organised entirely by unpaid local volunteers from the host town", "Every ticket for the event being sold to a local resident only, with none sold abroad", "Competitors and spectators drawn from two or more different countries", "The competition using exactly the same rules as it did in last year''s edition"], "answer": 2, "explain": "International scale means competitors and audiences crossing borders — ticket buyers being local, volunteer organisation and unchanged rules do not make an event major."}, {"question": "A host venue is full of people watching live, while millions more follow on television across dozens of countries. What are the millions on television called?", "options": ["The remote or broadcast spectators", "The participants competing in the event", "The host nation''s own athletes", "The in-venue crowd, who are physically inside the stadium watching live"], "answer": 0, "explain": "People watching via TV/online rather than in person are remote (broadcast) spectators — not participants, home athletes, or the physical in-venue crowd."}, {"question": "Why do broadcasters and sponsors pay large amounts of money for access to a major sporting event?", "options": ["Because a global audience across many countries makes that access highly valuable", "Because every major event legally requires at least one paying sponsor to proceed", "Because the host country''s government fixes each sponsor''s price by law", "Because local spectators alone are usually enough to justify the cost"], "answer": 0, "explain": "It is the huge, international audience that makes broadcast rights and sponsorship valuable — not a legal requirement, a fixed government price, or local attendance alone."}, {"question": "A small regional five-a-side tournament features only teams and fans from the same town. Why would this NOT be classed as a major sporting event?", "options": ["Its participants and spectators are local rather than drawn from other countries", "Because five-a-side football can never be considered a serious, competitive sport", "Because it does not charge any of its spectators an entry fee to attend at all", "Because it is organised by a school rather than by a national governing body"], "answer": 0, "explain": "Scale — international participants and spectators — is what ''major'' requires; the sport itself, entry fees and who organises it are not the deciding factor here."}, {"question": "Which of these best describes the make-up of a live, in-venue crowd at a major sporting event?", "options": ["Usually a mix of local residents and visitors who have travelled from abroad", "Always made up entirely of people from the host country and nowhere else", "Always made up entirely of overseas visitors, with no local residents at all", "Exactly the same in size as the remote television audience"], "answer": 0, "explain": "In-venue crowds typically blend local residents with international visitors — they are not purely local, purely overseas, nor the same size as the (much bigger) TV audience."}, {"question": "A student writes: ''A major event matters because lots of people watch it.'' What is missing from this answer?", "options": ["A very detailed description of the exact stadium seating capacity, given in the total number of seats", "A mention of the word ''sport'' occurring anywhere at all in the sentence", "The full official name of the sporting event that is being discussed", "An explanation of why that huge international scale actually matters to the host country"], "answer": 3, "explain": "Naming the scale isn''t enough — the mark comes from explaining why that scale matters (media value, investment, exposure), which this answer never reaches."}]}, "fib": {"enabled": true, "questions": [{"text": "A major sporting event usually has competitors travelling in from two or more different [countries]."}, {"text": "People watching a major event live inside the stadium are called [live] spectators."}, {"text": "People following a major event on television or online, often from many countries at once, are called [remote] spectators."}, {"text": "The huge, worldwide television audience is what makes broadcast rights and sponsorship so [valuable] to a host."}, {"text": "International scale is part of what makes an event count as [major], rather than a purely local competition."}]}, "tf": {"enabled": true, "questions": [{"statement": "A major sporting event usually has competitors from two or more different countries.", "answer": true, "explain": "That international mix of competitors is one of the defining features of a ''major'' event, as opposed to a purely local competition."}, {"statement": "The live, in-venue crowd at a major event is always made up entirely of people from the host country.", "answer": false, "explain": "In-venue crowds are usually a mix of local residents and visitors who have travelled from other countries to attend."}, {"statement": "Remote (television/online) spectators are usually far more numerous than the live in-venue crowd.", "answer": true, "explain": "A stadium can only hold so many people, but the broadcast/online audience reaches many more people across many countries."}, {"statement": "The international scale of a major event is irrelevant to how much money broadcasters and sponsors are willing to pay.", "answer": false, "explain": "It is the opposite — the size and international reach of the audience is exactly why broadcast rights and sponsorship are so valuable."}, {"statement": "A small tournament with only local teams and local fans could still be classed as a ''major'' sporting event.", "answer": false, "explain": "Without competitors and spectators from other countries, an event stays local/regional rather than reaching ''major'' international scale."}, {"statement": "Simply stating that ''a lot of people watch'' a major event is enough to explain why its scale matters.", "answer": false, "explain": "Naming the scale only gets you started — the mark is for explaining why that scale matters, e.g. its effect on media value and investment."}]}, "misc": {"enabled": true, "items": [{"myth": "Any event with a big crowd inside the stadium counts as a ''major'' international sporting event.", "truth": "A big local crowd is not the same as international scale. What defines a major event is competitors AND spectators being drawn from two or more different countries — including the much larger remote (TV/online) audience across the world, not just how full one venue looks on the day.", "check": {"question": "What actually shows that a sporting event has reached ''major'' international scale?", "options": ["Competitors and spectators being drawn from two or more countries, including the global broadcast audience", "The stadium simply being full to its absolute maximum seating capacity on every single day of the entire event", "The event lasting for more than one single day from start to finish in total", "The home nation''s team winning the majority of its matches at the event"], "answer": 0, "explain": "A full stadium, a long event, or the home team winning does not define ''major'' — the cross-border reach of competitors and viewers does."}}, {"myth": "''Spectators'' at a major event just means the people sitting in the stadium.", "truth": "That only covers HALF the spectators. The specification splits spectators into live, in-venue spectators AND the much bigger remote audience watching on television or online across many countries. Forgetting the remote audience under-states the true scale of a major event.", "check": {"question": "Which group of spectators is often forgotten when students describe a major event''s audience?", "options": ["The remote television or online audience, following the event across many different countries", "The athletes who are actually competing directly in the event itself, out on the field of play", "The officials who referee and run the competition throughout the whole event", "The volunteers who help to run the venue on the day of the event"], "answer": 0, "explain": "Students often only picture the in-venue crowd and forget the far larger remote broadcast audience — both make up ''spectators''."}}, {"myth": "Explaining why international scale ''matters'' just means repeating that lots of people are involved.", "truth": "Restating the scale earns little on its own. The exam rewards a REASON: the scale matters because it is what makes broadcast rights, sponsorship and investment so valuable, and because it is what gives the host country genuine international exposure — not just the raw number of people.", "check": {"question": "What is most likely to earn marks when a question asks why international scale ''matters'' to a host?", "options": ["A reason linking the scale to its effect, such as its media value or investment", "Simply repeating, in different words, that a very large number of people are involved", "Listing as many different countries as you can possibly remember off by heart", "A description of what the host country''s national flag actually looks like"], "answer": 0, "explain": "''Why it matters'' questions need a linked reason (media value, sponsorship, exposure) — restating the number or listing countries does not explain anything."}}]}, "tips": {"enabled": true, "items": [{"title": "Command words on this topic — what each one wants", "html": "<p>Questions on participants and spectators are usually short recall or one step of application. Match your answer length to the command word and the marks:</p>\n<ul>\n<li><strong>Identify / State [1 mark each]</strong> — name a feature. \"State one way a major event''s spectators are international\" = one short point, nothing more.</li>\n<li><strong>Describe [2 marks]</strong> — add a feature or detail. Two linked points, or one point plus a detail.</li>\n<li><strong>Explain [2–4 marks]</strong> — give a reason, using the word <em>because</em>. Say WHY the international scale matters, not just that it exists.</li>\n</ul>\n<p><strong>Read the mark tariff</strong>: a [1] wants one point; a [4] in Section B wants points applied to the scenario you are given, not a general list.</p>", "check": {"question": "A question says: ''State one feature that shows a major event''s participants are international [1]''. What is the safest answer?", "options": ["One short, clear point", "A long paragraph covering several ideas", "A list of every country you can name", "A description of your favourite sport"], "answer": 0, "explain": "''State'' plus [1] mark wants a single clear point — a long paragraph, a list of countries or an unrelated description all waste time for no extra credit."}}, {"title": "The golden rule: name the scale AND why it matters", "html": "<p>The most common way to lose marks here is stopping at description. Build longer answers as <strong>feature → why it matters</strong>:</p>\n<ul>\n<li><strong>❌ weak:</strong> \"The event has spectators from lots of countries.\"</li>\n<li><strong>✅ strong:</strong> \"The event has a global television audience across many countries, which is why broadcasters and sponsors pay so much for access to it.\"</li>\n</ul>\n<p>In <strong>Section B</strong> you will usually be given a scenario with numbers (countries represented, crowd size, broadcast reach). Use those exact figures in your answer instead of a general example.</p>", "check": {"question": "In a Section B scenario question with numbers for crowd size and countries represented, your answer should...", "options": ["use those specific figures from the scenario", "ignore the figures given and describe a different event entirely", "only describe the host country''s own fans", "avoid mentioning numbers of any kind"], "answer": 0, "explain": "Section B rewards application — using the scenario''s own figures shows you can apply the idea, rather than writing a generic answer."}}, {"title": "Where this appears + sentence starters", "html": "<p><strong>Where it shows up:</strong> short recall in <strong>Section A</strong> (identify/state a feature of international participants or spectators); applied points in <strong>Section B</strong> scenarios with real numbers; and it can feed a <strong>Section C</strong> 8-mark discussion of why hosting a major event matters to a country.</p>\n<p><strong>Three punchy tips:</strong></p>\n<ul>\n<li>Always split spectators into two groups: live, in-venue AND remote/broadcast — examiners often want both.</li>\n<li>Never just restate the scale (\"lots of people watch\") — pair it with a reason it matters.</li>\n<li>In Section B, quote the scenario''s own numbers (countries, crowd size) rather than a generic example.</li>\n</ul>\n<p><strong>Sentence starters for a longer answer:</strong></p>\n<ul>\n<li>\"One way the participants/spectators here are international is… because…\"</li>\n<li>\"This matters because a bigger, international audience means…\"</li>\n<li>\"However, this scale also brings…\"</li>\n</ul>", "check": {"question": "Why is it useful to split ''spectators'' into live and remote in a longer answer?", "options": ["It shows you understand both parts of the true international audience, not just half of it", "It fills space in a longer written answer without adding any real understanding of the topic at all", "It proves that the host venue itself was too small for the event to take place", "It replaces the need to explain why the scale actually matters at all"], "answer": 0, "explain": "Naming both live and remote spectators shows a fuller, more accurate picture of the audience — but you still need to explain why the scale matters."}}]}, "exam": {"enabled": true, "questions": [{"question": "Identify <strong>two</strong> features that show a major sporting event''s participants and spectators are international, rather than local.", "marks": 2, "hint": "Think about who is competing, who is in the crowd, and who is watching remotely — pick any two different features.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks (AO1)</h5>\n<p><strong>1 mark for each correct feature identified, to a maximum of two. Accept any two DIFFERENT features, including:</strong></p>\n<ul>\n<li>Competitors travel in from two or more different countries</li>\n<li>The live, in-venue crowd includes visitors from other countries, not only local residents</li>\n<li>A remote/broadcast audience follows the event on television or online across many countries</li>\n</ul>\n<p>Do not credit the same feature written twice in different words.</p>\n</div>"}, {"question": "Which of these best explains why broadcasters pay large amounts of money for the rights to show a major sporting event?", "marks": 1, "hint": "Think about what makes the audience for a major event so much bigger than a local match.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: A — Because the event reaches a huge, international audience across many countries.</strong></p>\n<ul>\n<li>It is the scale and international reach of the audience that makes broadcast access valuable.</li>\n<li>There is no fixed legal minimum price, the in-venue crowd alone is far smaller than the broadcast audience, and major events do not stay in one country.</li>\n</ul>\n</div>"}, {"question": "Explain how the details above show that the Dunholm City Games has reached the international scale of a major sporting event.", "marks": 4, "hint": "Take participants and spectators in turn. Use the exact figures given (45 countries, 60,000 crowd, 90+ countries broadcast) rather than a general example.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (AO2: application)</h5>\n<p><strong>Up to 2 marks for participants, up to 2 marks for spectators. 1 mark for identifying the relevant scenario detail, 1 mark for linking it to international scale. Answers may include:</strong></p>\n<ul>\n<li><strong>Participants</strong> — competitors from 45 different countries are taking part, which shows the event is drawing competitors from across the world rather than one nation.</li>\n<li><strong>Spectators</strong> — a 60,000 live crowd including overseas visitors, plus a broadcast reaching over 90 countries, shows both the live and remote audiences are international in scale.</li>\n</ul>\n<p>Accept any other reasonable answer that correctly uses a figure from the scenario. A figure quoted with no link to international scale earns 1 of the 2 marks for that half.</p>\n</div>"}, {"question": "Discuss why the international scale of participants and spectators matters to a host country like Dunholm.", "marks": 8, "hint": "Explain at least two reasons the scale matters (media/sponsorship value, international exposure). Then weigh up limits — does scale alone guarantee benefit for local residents? Finish with a judgement.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 8 marks (level-of-response). Read the band you fit, then pick a mark.</h5>\n<ul>\n<li><strong>Band 3 (thorough), 6–8:</strong> a balanced, well-applied discussion linking the scenario''s scale to at least two clear reasons it matters, AND weighing genuine limits, ending in a justified judgement.</li>\n<li><strong>Band 2 (reasonable), 3–5:</strong> sound understanding applied with some reasoning, but may cover only one side or reach an unsupported judgement.</li>\n<li><strong>Band 1 (basic), 1–2:</strong> restates the scenario''s figures with little explanation and no real evaluation; largely descriptive.</li>\n<li><strong>0 marks:</strong> nothing creditworthy.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Indicative content (indicative, not a checklist — reward valid alternatives)</h5>\n<ul>\n<li><strong>Media and sponsorship value:</strong> a broadcast reaching 90+ countries makes broadcast rights and sponsorship far more valuable to Dunholm than a local fixture ever could be.</li>\n<li><strong>International exposure:</strong> competitors and visitors from 45 countries, plus a worldwide broadcast, put Dunholm''s name in front of an audience it could never otherwise reach.</li>\n<li><strong>Investment case:</strong> that exposure and revenue can help justify investment in facilities and transport that outlast the event.</li>\n<li><strong>Evaluation:</strong> scale alone does not guarantee local benefit — a 60,000 crowd and global broadcast can bring costs (policing, congestion) that residents feel more than any media value; benefits depend on how the revenue and exposure are actually used afterwards.</li>\n<li><strong>Judgement:</strong> the international scale matters because it is what creates Dunholm''s media, sponsorship and exposure opportunity in the first place — but it only translates into a real benefit for residents if that opportunity is managed and reinvested well.</li>\n</ul>\n</div>"}]}}'::jsonb),
('sport-studies', '3-2-pre-event-aspects', '3.2 Pre-Event Aspects', '{"learn": {"enabled": true, "items": [{"title": "Bidding for a major event — a costly gamble", "html": "<h4>What a ''bid'' actually is</h4>\n<ul>\n<li>Before any major event can happen, cities or countries have to <strong>bid</strong> for the right to host it — a formal, competitive process in which each applicant puts forward a detailed proposal to the sport''s governing body.</li>\n<li>Bidding is <strong>expensive in itself</strong>. Putting a bid together — presentations, site visits, financial guarantees, planning documents — costs large sums of money, and that money is spent <em>before</em> anyone knows whether the bid will succeed.</li>\n<li>Because several places usually compete for the same event, most bids <strong>fail</strong>. The losing places still have to pay for the process; only one place gets the event at the end of it.</li>\n</ul>\n<h4>Justifications FOR bidding</h4>\n<ul>\n<li>A strong bid can raise a place''s <strong>international profile</strong> long before the event starts.</li>\n<li>Chasing a bid can unlock political and public support for <strong>investment</strong> that might never have been approved otherwise.</li>\n<li>Working towards a shared bid can build a sense of <strong>national pride</strong> and common purpose.</li>\n</ul>\n<h4>Justifications AGAINST bidding</h4>\n<ul>\n<li>The bidding process costs real money with <strong>no guarantee of success</strong> — if the bid fails, that spending produces nothing.</li>\n<li>Critics argue that money spent chasing a bid could instead go on more certain local needs, such as schools, hospitals or grassroots sport.</li>\n<li>The exam skill here is to <strong>weigh the two sides of the same aspect</strong>: bidding can attract benefits, but it is also a genuine financial risk — never present only one side.</li>\n</ul>", "check": {"question": "Which of these best describes why bidding for a major sporting event is risky for the applicant?", "options": ["The process itself is costly and competitive, so a failed bid still leaves a large, unrecovered bill", "The process is free of charge for every applicant, so nobody ever loses out even if their bid ultimately fails", "Only one place is ever allowed to submit a bid for any single major event", "A bid is approved automatically as soon as it is formally submitted for review"], "answer": 0, "explain": "Bidding costs real money on presentations, guarantees and planning before a winner is known — if the bid fails, that spending is lost, which is the genuine risk."}}, {"title": "Infrastructure and transport development", "html": "<h4>The positive side</h4>\n<ul>\n<li>Hosting a major event usually forces new or upgraded <strong>stadiums and venues</strong>, plus improved <strong>roads, rail lines and transport links</strong>, to be finished by a fixed deadline.</li>\n<li>These improvements can <strong>outlive the event</strong> — residents can keep using an upgraded rail line or a new sports venue for years after the closing ceremony.</li>\n</ul>\n<h4>The negative side of the SAME building programme</h4>\n<ul>\n<li>This construction is very costly, and projects built to a hard deadline commonly run <strong>over budget</strong>.</li>\n<li>Venues rushed to meet the event date may not actually suit <strong>local needs</strong> once the event has finished.</li>\n<li>The building work itself causes <strong>years of disruption</strong> beforehand — dug-up roads, noise and congestion for local residents.</li>\n</ul>\n<p>Notice this is <strong>one</strong> aspect (infrastructure) with a genuine upside and a genuine downside — the exam rewards students who can hold both in mind at once, not just list the positive.</p>", "check": {"question": "What is a genuine risk attached to infrastructure built before a major sporting event?", "options": ["Every improved transport link instantly becomes free to use for local residents forever", "New stadiums are always demolished the day after they are finished being built", "Rushed building work can run over budget and cause years of local disruption beforehand", "Transport development is banned everywhere a major sporting event takes place"], "answer": 2, "explain": "Building to a fixed deadline commonly overruns its budget and disrupts local life for years beforehand — a genuine cost that sits alongside the lasting benefit."}}, {"title": "Financial investment and the jobs it creates", "html": "<h4>The positive side</h4>\n<ul>\n<li>Major events attract <strong>commercial investment</strong> — sponsors and investors are willing to put money behind an event that draws global attention, funding facilities that public money alone might never stretch to.</li>\n<li>Preparing for the event creates <strong>employment</strong>: construction jobs building venues and transport links, plus further jobs preparing and staffing the event as it approaches.</li>\n</ul>\n<h4>The negative side of the SAME investment and jobs</h4>\n<ul>\n<li>Much of this employment is <strong>temporary</strong> — construction jobs largely disappear once the building work finishes, often well before the event even begins.</li>\n<li>Sponsor interest is usually tied to the event itself, so it can fade quickly once the event is over, meaning any employment boost may not last.</li>\n<li>Relying on private investment can mean handing real decisions — such as naming rights or ticket allocation — over to the sponsors and investors who paid for them.</li>\n</ul>", "check": {"question": "Why is the employment created before a major sporting event often described as a limited benefit?", "options": ["No construction jobs are ever created in the years before a major sporting event", "Every job created before the event is guaranteed to last for the entire remainder of that worker''s whole career", "Employment always increases at exactly the same rate that commercial investment falls", "Most of these jobs are tied to construction and preparation, and usually end once that work is finished"], "answer": 3, "explain": "Construction and preparation jobs are largely temporary — they tend to disappear once the building work is complete, often before the event has even started."}}, {"title": "Objections to bidding — weighing positives against negatives", "html": "<h4>Why people object to a bid</h4>\n<ul>\n<li>Local residents and national pressure groups often object to a bid <strong>before it is even submitted</strong>, arguing that the huge sums involved would do more good spent on other social needs — schools, hospitals or local sport facilities — than on chasing a bid that might fail.</li>\n<li>Objections can also focus on the years of <strong>disruption</strong> construction brings, or on doubts that the promised jobs and infrastructure will really benefit local people once contractors move on.</li>\n</ul>\n<h4>The exam skill: don''t just list, WEIGH</h4>\n<ul>\n<li><strong>Weak answer:</strong> \"Bidding costs money.\" This names a fact but shows no real understanding.</li>\n<li><strong>Strong answer:</strong> \"Bidding is expensive and competitive, so a city risks spending heavily on a bid that fails; but if it succeeds, the investment attracted can fund lasting infrastructure — the real question is whether that gamble is worth taking.\"</li>\n<li>Every pre-event aspect (bidding, infrastructure, investment, employment) has a positive AND a negative side, and top answers compare <strong>the same aspect''s two sides</strong> rather than one positive from one aspect against one negative from a different aspect.</li>\n</ul>", "check": {"question": "A question asks you to discuss objections to bidding for a major event. What shows the strongest understanding?", "options": ["Naming a single positive of hosting the event, with absolutely no further comment added", "Weighing a genuine benefit of bidding against a genuine risk of the same bid", "Listing as many unrelated sports facts as you can possibly recall from memory", "Stating that objections to bidding never happen anywhere in real life"], "answer": 1, "explain": "Discuss questions reward comparing the benefit and the risk of the SAME aspect (bidding) — naming one fact alone, or listing unrelated facts, does not show that skill."}}]}, "terms": {"enabled": true, "pairs": [{"term": "Bidding", "definition": "Costly, competitive process of applying to be chosen as host of a major event"}, {"term": "Infrastructure development", "definition": "New or upgraded stadiums and venues built before an event, to a fixed deadline"}, {"term": "Transport development", "definition": "Improved roads, rail and other links built or upgraded before an event"}, {"term": "Commercial investment", "definition": "Money from sponsors and investors funding event preparation"}, {"term": "Pre-event employment", "definition": "Jobs building venues and preparing for the event; usually temporary"}, {"term": "Local objection", "definition": "Residents'' concern that bid money could serve other local needs instead"}, {"term": "National objection", "definition": "Country-level concern about spending public money on a bid"}]}, "mcq": {"enabled": true, "questions": [{"question": "What is a ''bid'' for a major sporting event best described as?", "options": ["A costly, competitive process in which places apply to be chosen as host", "A free vote among fans deciding which city they would most like to visit next", "A short local meeting held only after a winning host has already been confirmed", "A guaranteed contract signed automatically as soon as a stadium design is drawn up"], "answer": 0, "explain": "Bidding is a costly, competitive process — several places apply and only one is chosen, so it is neither free, automatic, nor something that happens after the decision."}, {"question": "Which of these is a genuine risk of the infrastructure built before a major sporting event?", "options": ["Ticket sales from the event always cover the entire cost of every stadium and transport link built", "Building to a fixed deadline can run over budget and disrupt local residents for years beforehand", "Local roads are never affected by construction work carried out for a major sporting event", "New venues are only ever built well away from where any local residents actually live"], "answer": 1, "explain": "Construction to a hard deadline commonly overruns its budget and disrupts local life well before the event — the other options describe outcomes that do not reliably happen."}, {"question": "Why might commercial investment attracted by a bid be seen as only a limited benefit?", "options": ["Sponsors and investors never provide any funding towards a major sporting event", "Sponsor interest is usually tied to the event and can fade once it has finished", "Commercial investment always replaces every penny of public spending completely", "Investors are legally required to fund the event for at least twenty years afterwards"], "answer": 1, "explain": "Investment is often tied closely to the event itself, so interest and funding can fall away once it ends — that is the limit on this benefit, not that investment never happens."}, {"question": "A city''s bid for a major event fails after months of costly preparation. What does this best show?", "options": ["Bidding guarantees the city a financial return no matter what the final outcome is", "Bidding is a genuine risk, since the cost of preparing it is spent whether it succeeds or fails", "A bid can only ever be submitted once by the same city in its entire history", "Every failed bid is fully refunded in cash by the sport''s international governing body without any exception"], "answer": 1, "explain": "The money spent preparing a bid is spent regardless of the result, which is exactly why bidding is described as a genuine financial risk, not a safe investment."}, {"question": "Which reason is most likely to be given by local residents objecting to a bid?", "options": ["The bid money could be better spent on other local needs such as schools or hospitals", "Residents object because major sporting events are against the law in every country", "Residents object because bidding always guarantees the event will be hosted successfully", "Residents object because construction work never affects any nearby homes at all"], "answer": 0, "explain": "A common objection is that the large sums spent chasing a bid could instead fund more certain local needs — the other options describe things that are not true or not the reason given."}, {"question": "Which sentence best shows the exam skill of weighing pre-event aspects, rather than just listing them?", "options": ["Hosting a major event simply involves bidding, infrastructure and investment all happening", "Bidding can attract investment, but that gain only follows if the costly bid succeeds", "Major sporting events happen in many different countries around the world today", "Infrastructure, investment and employment are all things that genuinely exist"], "answer": 1, "explain": "Weighing the SAME aspect''s benefit against its risk (bidding can attract investment, but only if it succeeds) shows real understanding — the other options merely list topics."}]}, "fib": {"enabled": true, "questions": [{"text": "Bidding to host a major event is a [competitive] process, meaning several places apply for the same event."}, {"text": "Because a bid can fail, the money spent preparing it is often described as a financial [risk]."}, {"text": "New stadiums, roads and transport links built before an event are examples of [infrastructure] development."}, {"text": "Sponsors and investors provide [commercial] investment that can fund facilities public money alone might not cover."}, {"text": "Construction work before a major event usually creates [temporary] employment that ends once the building finishes."}, {"text": "Objectors often argue that bid money could be better spent on other local or national [needs]."}]}, "tf": {"enabled": true, "questions": [{"statement": "Bidding to host a major sporting event is a free and simple process.", "answer": false, "explain": "Bidding is costly and competitive — bid teams spend large sums on presentations, guarantees and planning before any decision is made."}, {"statement": "New stadiums, roads and transport links built before an event can go on to benefit local residents for years afterwards.", "answer": true, "explain": "Infrastructure delivered to the event''s deadline can keep serving residents long after the event has finished — a genuine lasting positive."}, {"statement": "Every city or country that submits a bid is guaranteed to be chosen as host.", "answer": false, "explain": "Bidding is competitive — usually only one place wins, so every other bidder has spent heavily on a bid that did not succeed."}, {"statement": "Jobs created constructing venues before an event usually last only until the building work finishes.", "answer": true, "explain": "Most pre-event construction employment is temporary, tied to the build itself, and tends to disappear once the venues are finished."}, {"statement": "Local and national objections to a bid are only ever about damage to the environment.", "answer": false, "explain": "Objections mainly focus on whether bid money could be better spent on other social needs, and on the disruption of construction — not only the environment."}, {"statement": "Commercial investment from sponsors can help pay for facilities that public money alone might not cover.", "answer": true, "explain": "Sponsors and investors are drawn to an event''s global attention, and their money can fund facilities beyond what public spending alone could stretch to."}]}, "misc": {"enabled": true, "items": [{"myth": "Bidding for a major event is basically free advertising, so there''s no real cost involved.", "truth": "The bidding process itself costs large sums of money — presentations, site visits, guarantees and planning documents all have to be paid for, whether or not the bid succeeds. If the bid fails, that spending is simply lost. Bidding is a genuine financial gamble, not free publicity.", "check": {"question": "What is the truth about the cost of bidding for a major sporting event?", "options": ["Bidding costs nothing at all for any of the places that choose to apply for it", "Only the winning bid ever has to pay for the cost of preparing its own bid", "The process itself is costly, whether or not the bid goes on to succeed", "Bids are always fully refunded by the governing body if they are unsuccessful"], "answer": 2, "explain": "The cost of preparing a bid is spent regardless of the outcome, which is exactly why a failed bid is a real financial loss for the applicant."}}, {"myth": "New infrastructure built before an event is only ever a good thing for local people.", "truth": "Infrastructure has a genuine positive AND a genuine negative side. Yes, new venues and transport links can serve residents for years — but rushed builds may not fit local needs afterwards, projects can run over budget, and the construction itself disrupts local life for years beforehand. A strong answer holds both sides in mind.", "check": {"question": "Which statement best captures the full picture of pre-event infrastructure?", "options": ["It can bring lasting benefits, but also cost overruns and years of disruption", "It only ever benefits local residents, with no downside of any kind at all", "It never affects local residents in any way at all, whether positive or negative", "It is always finished many years before the event actually needs it to be ready"], "answer": 0, "explain": "Infrastructure carries a real upside (lasting facilities) and a real downside (overruns, disruption) — a one-sided answer misses half the picture."}}, {"myth": "The jobs created before a major event are permanent, long-term jobs for local people.", "truth": "Most pre-event jobs are tied to construction and preparation, and they tend to disappear once the building work is finished — often well before the event itself even starts. Treating this employment boost as permanent overstates the benefit.", "check": {"question": "What is true about most jobs created in the run-up to a major sporting event?", "options": ["They are guaranteed to continue for the rest of the worker''s entire career", "No jobs of any kind are ever created before a major sporting event takes place", "They only ever begin on the very same day that the event itself starts", "They are largely temporary, tied to construction and preparation work"], "answer": 3, "explain": "Construction and preparation jobs are mostly temporary and tend to end once the building phase is complete, which limits how lasting this benefit really is."}}, {"myth": "Objecting to a bid means you don''t want your country to host any sport at all.", "truth": "Objections are usually about priorities, not about opposing sport itself. Residents and pressure groups typically question whether the money spent chasing a bid is better used on other local or national needs, such as schools, hospitals or grassroots sport — not that sport shouldn''t happen.", "check": {"question": "What do most objections to a bidding process actually argue?", "options": ["That sport itself should not be allowed to take place anywhere at all", "That the money involved could be better spent on other social needs", "That every major sporting event should be cancelled immediately as a result", "That bidding always succeeds, no matter which city or country applies"], "answer": 1, "explain": "Objections are usually about spending priorities — whether the money could do more good elsewhere — rather than opposition to sport itself."}}]}, "tips": {"enabled": true, "items": [{"title": "Command words for pre-event questions — what each one wants", "html": "<p>Pre-event questions range from quick recall to full evaluation. Match your answer length to the command word and the mark tariff:</p>\n<ul>\n<li><strong>Identify / State</strong> — just name it. \"Identify two pre-event aspects [2]\" = two names, one mark each, nothing more.</li>\n<li><strong>Describe</strong> — say what it involves. \"Describe the bidding process\" = give its features (competitive, costly, run by the governing body).</li>\n<li><strong>Explain</strong> — give a reason. \"Explain why bidding is risky\" = a point <em>plus</em> why (because the cost is spent whether or not it succeeds).</li>\n<li><strong>Discuss</strong> — weigh both sides. This is where pre-event questions are usually won or lost — see the next tip.</li>\n</ul>\n<p><strong>Read the mark tariff:</strong> [1] wants one point; [4] in Section B wants points applied to the scenario; [8] wants a balanced discussion with a judgement.</p>", "check": {"question": "A question says: ''Identify two pre-event aspects of hosting a major event [2]''. What is the safest answer?", "options": ["A long paragraph that only explores one single aspect in real detail", "Two named aspects, such as bidding and infrastructure", "A list of every single aspect that you can possibly remember", "One aspect explained in full, with a supporting reason given"], "answer": 1, "explain": "''Identify'' + [2] = two names, one mark each. Exploring one aspect in depth, or listing far more than asked, wastes time without extra reward."}}, {"title": "The golden rule: weigh the positive against the negative of the SAME aspect", "html": "<p>The single most common way to lose marks on this topic is treating positives and negatives as separate lists. Build every longer answer as <strong>aspect → benefit → but → risk</strong>:</p>\n<ul>\n<li><strong>❌ weak:</strong> \"Bidding is good because it brings investment. Infrastructure is bad because it costs money.\" (two different aspects, no real comparison)</li>\n<li><strong>✅ strong:</strong> \"Bidding can attract investment that funds lasting infrastructure, but that gain only follows if the costly bid actually succeeds.\"</li>\n</ul>\n<p>In <strong>Section B</strong> the question gives you a scenario. Use a detail <em>from that scenario</em> when you weigh the aspect, rather than a general example.</p>", "check": {"question": "Which of these best follows the ''aspect → benefit → but → risk'' structure?", "options": ["Bidding is competitive, and infrastructure is expensive to build", "Infrastructure and employment are both things that simply exist before an event", "Objections happen, and investment also happens, in some countries", "Bidding can raise a city''s profile, but the cost is lost if the bid fails"], "answer": 3, "explain": "This links ONE aspect''s benefit to ITS OWN risk (profile gained, but cost lost if it fails) — the other options just list separate facts side by side."}}, {"title": "Where pre-event aspects appear + sentence starters", "html": "<p><strong>Where it shows up:</strong> pre-event aspects appear as quick recall in <strong>Section A</strong> (identify/state), as applied points in <strong>Section B</strong> scenarios about a specific bidding city, and as balanced <strong>Section C</strong> 8-mark discussions weighing up whether hosting is worth it.</p>\n<p><strong>Three punchy tips:</strong></p>\n<ul>\n<li>Learn the five aspects (bidding, infrastructure/transport, investment, employment, objections) so you always have material to draw on.</li>\n<li>For every aspect, memorise <em>one</em> benefit and <em>one</em> risk — that pairing is usually where the marks sit.</li>\n<li>Watch for temporary vs lasting effects: infrastructure often lasts, jobs and sponsor interest usually don''t — a sharp evaluation point.</li>\n</ul>\n<p><strong>Sentence starters for a longer answer:</strong></p>\n<ul>\n<li>\"One benefit of bidding for this event is… because…\"</li>\n<li>\"However, this comes with a risk, because…\"</li>\n<li>\"Overall, whether this is worth it depends on…\"</li>\n</ul>", "check": {"question": "Why is noticing ''temporary vs lasting'' effects a useful evaluation point?", "options": ["It shows some benefits fade quickly while others can last for years", "It fills space without adding any real understanding to the answer given here at all", "It proves that pre-event aspects never have any real effect on anyone", "It means a Section C answer can skip giving any kind of final judgement"], "answer": 0, "explain": "Spotting that jobs and sponsor interest are often temporary, while infrastructure can last, shows the kind of balanced thinking that lifts a Section C answer."}}]}, "exam": {"enabled": true, "questions": [{"question": "Identify <strong>two</strong> different pre-event aspects a city must plan for before hosting a major sporting event.", "marks": 2, "hint": "Just name two — pick from bidding, infrastructure/transport development, commercial investment, employment, or objections to the bid.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks (AO1)</h5>\n<p><strong>1 mark for each correct pre-event aspect named, to a maximum of two. Accept any two different aspects, including:</strong></p>\n<ul>\n<li>Bidding for the event</li>\n<li>Infrastructure development</li>\n<li>Transport development</li>\n<li>Commercial/financial investment</li>\n<li>Potential increased employment</li>\n<li>Local or national objections to the bid</li>\n</ul>\n<p>Do not credit the same aspect written twice.</p>\n</div>"}, {"question": "Which of these is most likely to be a reason local residents object to their city bidding for a major sporting event?", "marks": 1, "hint": "Think about what residents usually argue the money could be used for instead.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: A — the bid money could be better spent on other local needs.</strong></p>\n<ul>\n<li>This is the most common real objection: priorities, not opposition to sport itself.</li>\n<li>The other options describe things that are not true of bidding or its effects.</li>\n</ul>\n</div>"}, {"question": "Explain one benefit and one risk Port Hendon faces by bidding for the International Coastal Games.", "marks": 4, "hint": "Take the benefit first: what could winning the bid unlock, using the scenario? Then the risk: what happens to the millions already spent if the bid fails?", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (AO2: application)</h5>\n<p><strong>Up to 2 marks for the benefit, up to 2 marks for the risk: 1 for identifying it, 1 for linking it to the scenario. Answers may include:</strong></p>\n<ul>\n<li><strong>Benefit</strong> — a successful bid could fund a new stadium and an upgraded rail link (infrastructure/transport development named in the scenario), or raise Port Hendon''s profile.</li>\n<li><strong>Risk</strong> — the several million pounds spent on the bid itself is lost if the bid fails, since that cost is paid whether or not Port Hendon is chosen.</li>\n</ul>\n<p>Accept any other reasonable, applied answer. A benefit or risk with no link to the scenario earns 1 of the 2 marks available for that part.</p>\n</div>"}, {"question": "Discuss whether the potential benefits of Port Hendon''s bid outweigh the risks it involves.", "marks": 8, "hint": "Cover at least two pre-event aspects (e.g. infrastructure, employment, objections). For each, weigh the benefit against its own risk, using the scenario. Finish with a judgement on whether the gamble is worth it.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 8 marks (level-of-response). Read the band you fit, then pick a mark.</h5>\n<ul>\n<li><strong>Band 3 (thorough), 6–8:</strong> a balanced, well-applied discussion of several pre-event aspects, weighing each aspect''s own benefit against its own risk using the scenario, ending in a justified judgement on whether bidding is worthwhile.</li>\n<li><strong>Band 2 (reasonable), 3–5:</strong> sound understanding applied to more than one aspect with some analysis, but the discussion may be one-sided or the judgement unsupported.</li>\n<li><strong>Band 1 (basic), 1–2:</strong> names aspects and/or effects with little application and no real weighing of benefit against risk; largely a list.</li>\n<li><strong>0 marks:</strong> nothing creditworthy.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Indicative content (indicative, not a checklist — reward valid alternatives)</h5>\n<ul>\n<li><strong>Infrastructure/transport:</strong> the promised stadium and rail link could serve Port Hendon for years, but building to a fixed deadline risks running over budget and disrupting the town beforehand.</li>\n<li><strong>Employment:</strong> construction creates jobs preparing the bid''s facilities, but most of this work is temporary and ends once building finishes, well before the Games themselves.</li>\n<li><strong>Objections:</strong> the pressure group''s concern that the cost could instead fund schools and the hospital is a genuine risk if the bid does not deliver the promised gains.</li>\n<li><strong>Investment:</strong> a successful bid may attract sponsors funding facilities the town could not otherwise afford, but that interest may fade once the event is over.</li>\n<li><strong>Judgement:</strong> the bid could be worthwhile if the infrastructure genuinely outlasts the event and the promised facilities are delivered — but it is a real gamble, since the cost is committed and the objectors'' concerns stand regardless of whether the bid ultimately succeeds.</li>\n</ul>\n</div>"}]}}'::jsonb),
('sport-studies', '3-3-1-during-the-event', '3.3.1 During the Event', '{"learn": {"enabled": true, "items": [{"title": "During the event — the middle stage of hosting", "html": "<h4>Three stages, one event</h4>\n<ul>\n<li>Hosting a major event is usually looked at in three stages: <strong>before</strong> the event (bidding, building, investing), <strong>during</strong> the event (this page), and <strong>after</strong> the event (the long-term legacy).</li>\n<li>The during-event stage covers everything that happens <strong>while the event is actually running</strong> — from the opening moment to the final result, whatever the sport.</li>\n</ul>\n<h4>Why the exam keeps the stages separate</h4>\n<ul>\n<li>Some effects only exist <strong>while the crowds, athletes and media are physically there</strong> — a full stadium, live rolling coverage, a short-term spike in visitor numbers. These fade away once the event finishes.</li>\n<li>You must keep the stages straight in an answer: an effect that happens <strong>during</strong> the event (like a burst of national interest) is not the same as one that happens <strong>before</strong> it (like a construction job) or <strong>after</strong> it (like an empty stadium sitting unused).</li>\n<li>Just like the other two stages, during-event effects can be <strong>positive or negative</strong> at the very same time, for the very same event.</li>\n</ul>", "check": {"question": "Which of these best describes the ''during the event'' stage that this page covers?", "options": ["Everything that happens while the event is actually running, from start to finish", "The years spent bidding for the right to host the event before it is even confirmed", "What happens to the venues once the whole event has completely finished and closed", "The construction of new stadiums and transport links that takes place before the event opens"], "answer": 0, "explain": "During-the-event effects only exist while the event is running. Bidding and building happen before it; what happens to venues afterwards is the post-event/legacy stage."}}, {"title": "The positives while the event is on", "html": "<h4>Community and pride</h4>\n<ul>\n<li><strong>Improved national morale and social cohesion</strong> — a shared, feel-good sense of pride can bring people from across the country together while the event is running.</li>\n<li><strong>Increased national status</strong> — hosting successfully can raise how the country is seen and respected by other nations while it is in the international spotlight.</li>\n<li><strong>Greater national interest in the sport(s)</strong> — people who do not normally follow the sport(s) often start watching and talking about them while the event is on home soil.</li>\n</ul>\n<h4>Facilities, tourism and jobs</h4>\n<ul>\n<li><strong>Improved social infrastructure in use</strong> — venues, transport links and facilities that were built or upgraded beforehand are now genuinely being used, by visitors and local residents alike.</li>\n<li><strong>A rise in direct tourism</strong> — spending tied straight to the event itself, such as match tickets and hotel stays close to a venue.</li>\n<li><strong>A rise in indirect tourism</strong> — extra spending nearby that is not part of the event itself, such as restaurants, shops and sightseeing that visitors pay for while they are in the area.</li>\n<li><strong>An increase in short-term employment</strong> — temporary jobs (stewarding, security, hospitality, transport) created just to cover the event period.</li>\n</ul>\n<h4>Media</h4>\n<ul>\n<li><strong>Increased media coverage of the sport(s)</strong> — a rise in the amount of national and international press, TV and online coverage the sport(s) receive, well above their usual level.</li>\n</ul>", "check": {"question": "A shared feeling of pride that brings people across the country together while a major event is on is best described as...", "options": ["increased national morale and social cohesion", "an increase in short-term employment created just for the event period", "a rise in indirect tourism spending near the venues while visitors are in town", "extra litter, noise and transport pressure around the host venues, which local residents notice straight away"], "answer": 0, "explain": "That shared feel-good sense of pride and unity is national morale/social cohesion — the other options describe jobs, tourism spending and a negative effect, not this one."}}, {"title": "The negatives while the event is on", "html": "<h4>Everyday strain on the host area</h4>\n<ul>\n<li><strong>Increased transport, litter and noise</strong> — large crowds moving through a host area put real pressure on roads, public transport, rubbish collection and general noise levels.</li>\n</ul>\n<h4>Safety and security</h4>\n<ul>\n<li><strong>Potential for increased terrorism and crime</strong> — a major event gathers huge crowds and international attention in one place, which can raise the security risk for the time it is running.</li>\n</ul>\n<h4>Performance and fairness</h4>\n<ul>\n<li><strong>Poor performance by the home nation or team</strong> — if the host team does badly, it can damage the very national pride and morale that hosting was supposed to build.</li>\n<li><strong>Regional areas not involved can feel neglected</strong> — parts of the country away from the actual venues may feel under-invested and left out, while attention and spending are focused on the host area only.</li>\n</ul>\n<h4>Media</h4>\n<ul>\n<li><strong>Negative media coverage of organisational or facility problems</strong> — issues such as ticketing chaos, transport failures or an unfinished venue getting reported instead of the sport itself.</li>\n</ul>", "check": {"question": "What does ''regional areas feeling neglected'' mean as a during-event negative?", "options": ["Parts of the country away from the host venues feeling left out while investment and attention focus on the host area", "The host nation''s team losing every single one of its matches at every different venue right through the whole event and every round", "A rise in litter and noise directly around the main stadium during the opening ceremony", "Extra security staff being hired only for the week the event is taking place"], "answer": 0, "explain": "Regional neglect is about non-host areas feeling overlooked and under-invested — not about results, litter, or extra security staffing."}}, {"title": "Weighing positives against negatives — the exam skill", "html": "<h4>Naming effects is only the start</h4>\n<ul>\n<li>Weak answer: <em>\"A positive is national pride. A negative is crime.\"</em> That names two effects but shows no real understanding.</li>\n<li>Strong answer: <em>\"National morale can rise if the home team does well in front of a home crowd, but if the venue suffers ticketing problems, the negative media coverage of that failure can cancel out the goodwill just as quickly.\"</em></li>\n<li>Higher-mark questions want you to <strong>weigh</strong> positives against negatives — which one matters more, in this specific situation, and why — before reaching a judgement.</li>\n</ul>\n<h4>Using a scenario properly</h4>\n<ul>\n<li>Section B and C questions usually give you a made-up event or host area. Pick out a detail from <em>that</em> scenario — a named area, a named problem — rather than writing a general answer that ignores it.</li>\n<li>A good during-event answer often shows that the <strong>same event</strong> can be producing a positive and a negative <strong>at the same time</strong>, for different groups of people.</li>\n</ul>", "check": {"question": "In a scenario question about a named host city, the strongest answers usually...", "options": ["use a detail from the scenario and weigh it against another effect before reaching a judgement", "name as many user groups and pieces of technology as can possibly be remembered from earlier topics", "describe only the positives, because negatives are not worth mentioning", "copy the exact wording printed in the question back into the answer"], "answer": 0, "explain": "The best answers apply a detail from the scenario, set a positive against a negative, and reach a judgement — not a one-sided list or a repeat of the question."}}]}, "terms": {"enabled": true, "pairs": [{"term": "Social infrastructure in use", "definition": "Venues, transport and facilities built beforehand now genuinely being used during the event"}, {"term": "National morale / social cohesion", "definition": "A shared, feel-good sense of pride and unity across the country while the event is on"}, {"term": "National status", "definition": "How the host country is seen and respected by OTHER nations during the event"}, {"term": "Direct tourism", "definition": "Visitor spending tied straight to the event, e.g. tickets and hotels near the venue"}, {"term": "Indirect tourism", "definition": "Extra spending nearby that isn''t the event itself, e.g. meals and sightseeing"}, {"term": "Short-term employment", "definition": "Temporary jobs (stewarding, security) created only to cover the event period"}, {"term": "Regional neglect", "definition": "Non-host areas feeling left out while attention and money focus elsewhere"}, {"term": "Negative media coverage", "definition": "Reporting on organisational or facility problems, e.g. ticketing chaos"}]}, "mcq": {"enabled": true, "questions": [{"question": "Which of these is an example of ''improved social infrastructure in use'' during a major event?", "options": ["Trains and roads that were built for the event are now busy carrying spectators and staff", "A national team is knocked out in the opening round in front of a disappointed home crowd", "Newspapers and broadcasters give the sport far more coverage than it usually receives", "Temporary stewarding and security jobs are created just to cover the event period, then end"], "answer": 0, "explain": "Using new or upgraded transport and venues that were built beforehand is social infrastructure in use. The other options describe results, media coverage and employment instead."}, {"question": "Which of these is most likely to be a NEGATIVE effect while a major event is being staged?", "options": ["Increased litter, noise and transport pressure building up around the busy host venues", "A rise in national interest in the sport(s) being played across the whole country", "An increase in short-term jobs, such as stewarding and security, created just to cover the event period", "A rise in direct tourism spending on tickets and hotels close to the venues"], "answer": 0, "explain": "Extra litter, noise and transport pressure on the host area is a during-event negative. The other three are all named positives of the during-event stage."}, {"question": "A host nation''s team performs badly and is knocked out early. What is the most likely effect of this?", "options": ["It can damage the national pride and morale that hosting the event was meant to build", "It always causes a permanent, nationwide collapse in interest in every sport forever", "It automatically leads to every local business near the venues closing down immediately", "It has no effect at all on how people in the host country feel about the event"], "answer": 0, "explain": "Poor performance by the host nation can hurt national pride and morale — it does not wipe out all sport forever, close businesses, or leave feelings unaffected."}, {"question": "What is meant by ''indirect tourism'' during a major event?", "options": ["Spending nearby that is not part of the event itself, such as meals, shops and sightseeing", "Money spent directly on match tickets and hotel rooms right next to the venue itself", "The wages paid to permanent, full-time staff who already worked at the venue long beforehand", "The cost of building a brand new stadium in the years before the event even opens"], "answer": 0, "explain": "Indirect tourism is extra spending near the event that is not the event itself, like meals and sightseeing. Ticket/hotel spend is direct tourism; wages and construction are different effects."}, {"question": "Why might regional areas away from the host venues feel neglected during a major event?", "options": ["Investment, media attention and spending can focus heavily on the host area, leaving them out", "Every part of the country always receives an exactly identical share of investment and coverage", "Regional areas are legally required to close all of their sports facilities during the event", "National governing bodies are banned from operating anywhere outside the host city itself"], "answer": 0, "explain": "Attention and investment concentrate on the host area, so non-host regions can feel left out and under-invested — the other options are not real effects of hosting."}, {"question": "A stadium suffers ticketing chaos and this is widely reported by journalists during the event. This is best described as...", "options": ["negative media coverage of an organisational or facility problem", "an increase in short-term employment created for the event period", "a rise in direct tourism spending on tickets close to the venue", "improved national status because the event is receiving so much coverage"], "answer": 0, "explain": "Reporting on an organisational failure like ticketing chaos is negative media coverage — it is not employment, tourism spend, or a status boost."}]}, "fib": {"enabled": true, "questions": [{"text": "Venues and transport built for the event now being used is called social [infrastructure] in use."}, {"text": "A shared sense of national pride and unity while the event is on is called national morale and social [cohesion]."}, {"text": "Temporary jobs created only to cover the event period, such as stewarding, are called [short-term] employment."}, {"text": "Spending tied straight to the event itself, like tickets and nearby hotels, is called [direct] tourism."}, {"text": "Areas away from the host venues can feel [neglected] if attention and money focus elsewhere."}, {"text": "If the host team performs badly, this can damage the national [pride] that hosting was meant to build."}]}, "tf": {"enabled": true, "questions": [{"statement": "Using new venues and transport links that were built for the event is a during-event positive.", "answer": true, "explain": "This is ''improved social infrastructure in use'' — a genuine positive that only exists once the built infrastructure is actually being used."}, {"statement": "Regional areas away from the host venues almost always benefit just as much as the host area itself.", "answer": false, "explain": "Attention and investment concentrate on the host area, so other regions can feel neglected and under-invested instead of benefiting equally."}, {"statement": "An increase in short-term jobs, such as stewarding and security, is a during-event positive.", "answer": true, "explain": "Temporary roles created just to cover the event period are a genuine short-term employment positive of the during-event stage."}, {"statement": "Negative media coverage during a major event is always about which team wins or loses.", "answer": false, "explain": "Negative coverage is often about organisational or facility problems, like ticketing chaos or transport failures, not just results."}, {"statement": "Gathering huge crowds in one place for a major event can raise the risk of crime.", "answer": true, "explain": "Large crowds and high-profile international attention can increase the potential for terrorism and crime while the event is on."}, {"statement": "A poor performance by the host nation''s team has no effect on national morale.", "answer": false, "explain": "The opposite is true — poor home performance can directly damage the national pride and morale that hosting was meant to build."}]}, "misc": {"enabled": true, "items": [{"myth": "The ''during the event'' stage is basically the same as the pre-event stage, since it''s all just part of ''hosting''.", "truth": "The exam treats them as separate stages with separate effects. Pre-event (3.2) covers bidding, building and investing BEFORE the event opens. During-event (this page) only covers effects that exist WHILE the event is actually running — a busy stadium, live coverage, a short-term tourism spike. Mixing the two loses marks because you have named the wrong stage''s effect.", "check": {"question": "A question specifically asks about the ''during the event'' stage. Which answer fits?", "options": ["A short-term rise in visitor spending while the event is actually taking place", "The years spent putting together the bid to host the event in the first place", "Construction jobs created while building a brand new stadium before the event opens", "Money spent maintaining an empty stadium for years after the whole event has ended"], "answer": 0, "explain": "Only the visitor-spending answer happens while the event is running. The others describe the pre-event bidding/building stage or the post-event legacy stage."}}, {"myth": "A good answer on this topic only needs to list positives, because that''s what hosting is ''supposed'' to bring.", "truth": "Higher-mark questions want a BALANCED answer — genuine negatives (transport strain, crime risk, regional neglect, negative coverage) sit alongside the positives, often for the very same event. A one-sided list of only positives is capped in the higher bands, even if every point named is accurate.", "check": {"question": "Why does a one-sided list of only positives lose marks on a higher-tariff question?", "options": ["Because higher bands reward a balanced discussion, weighing positives against negatives", "Because positives are never actually true at any single point during a major sporting event", "Because examiners only ever accept negative points on this specific topic", "Because listing more than three positives is against the exam''s rules"], "answer": 0, "explain": "Level-of-response marking rewards weighing both sides and reaching a judgement — a one-sided list, however accurate, cannot reach the top band."}}, {"myth": "''National status'' and ''national morale'' mean exactly the same thing, so you can use either word for either idea.", "truth": "They are related but different. National STATUS is about how the country is seen and respected by OTHER nations while it hosts. National MORALE/cohesion is about how people INSIDE the country feel — their own shared pride and unity. A strong answer keeps the two separate rather than treating them as interchangeable.", "check": {"question": "Which of these describes ''national status'' rather than ''national morale''?", "options": ["How the host country is seen and respected by other nations during the event", "A shared feel-good sense of pride felt by people within the host country itself", "The temporary jobs created to help run the event while it is taking place", "The rubbish, noise and transport pressure that builds up around a busy venue"], "answer": 0, "explain": "National status is about the country''s external reputation abroad. Internal shared pride is morale/cohesion; the other two options are unrelated effects."}}, {"myth": "Negative media coverage during a major event must mean the athletes played badly.", "truth": "It is usually about organisational or facility problems instead — things like ticketing chaos, transport failures, or an unfinished venue. A country can host superb sport and still receive negative coverage because of how the event itself was run, not how anyone actually performed.", "check": {"question": "Negative media coverage during a major event most often reports on...", "options": ["organisational or facility problems, such as ticketing chaos or transport failures", "the exact final score of every single fixture played right through the whole event", "the weather forecast for the week the event is scheduled to take place", "the total number of tickets sold before the event had even opened"], "answer": 0, "explain": "It is problems with how the event is organised or run — not scores, weather, or advance ticket sales — that usually generate negative coverage."}}]}, "tips": {"enabled": true, "items": [{"title": "Command words for this topic — what each one wants", "html": "<p>Questions on this topic range from quick recall to a full extended response. Match your answer to the command word and the mark tariff:</p>\n<ul>\n<li><strong>Identify / State</strong> — just name it. \"Identify one negative during-event effect [1]\" = one named effect, nothing more.</li>\n<li><strong>Describe</strong> — add a feature or detail. \"Describe a during-event positive\" = say what it involves, not just its name.</li>\n<li><strong>Explain</strong> — give a reason, usually using the word <em>because</em>. \"Explain why regional areas may feel neglected\" wants the effect PLUS why it happens.</li>\n<li><strong>Discuss / Evaluate</strong> — the 6/8-mark levelled question. Weigh positives against negatives, apply the scenario, and end with a judgement.</li>\n</ul>\n<p><strong>Read the mark tariff:</strong> [1]–[2] wants named points; a 4-mark Section B question wants points applied to a scenario; an 8-mark Section C question wants balance and a judgement.</p>", "check": {"question": "A question says: ''State one positive effect during a major event [1]''. What is the safest answer?", "options": ["One named positive effect", "A full paragraph weighing several positives and negatives", "Two negative effects instead of a positive", "A description of the event''s opening ceremony"], "answer": 0, "explain": "''State'' + [1] = one named point. Writing a full discussion, giving negatives instead, or describing a ceremony all miss what a 1-mark ''state'' question wants."}}, {"title": "The golden rule: weigh it up, don''t just list it", "html": "<p>The most common way to lose marks on Discuss/Evaluate questions here is writing a one-sided list. Build a higher-mark answer as <strong>positive → negative → judgement</strong>:</p>\n<ul>\n<li><strong>❌ low band:</strong> \"A positive is national pride. Another positive is tourism. Another positive is jobs.\"</li>\n<li><strong>✅ higher band:</strong> \"National pride can rise if the home team performs well, HOWEVER a facility problem reported in the media can undo that goodwill just as quickly — so the overall effect during the event depends heavily on how smoothly things run.\"</li>\n</ul>\n<p>In <strong>Section B</strong>, use a detail FROM the scenario you are given — a named area, a named problem — not a general example that ignores it.</p>", "check": {"question": "What turns a list of positives into a higher-band Discuss answer?", "options": ["Weighing a positive against a negative and reaching a judgement", "Naming as many different positives as possible in the time you have available", "Repeating the exact same point using slightly different words", "Leaving out any mention of negatives completely"], "answer": 0, "explain": "Higher bands reward balance and a judgement, not volume — a longer list of only positives still caps in the lower bands."}}, {"title": "Where this appears + sentence starters", "html": "<p><strong>Where it shows up:</strong> during-event effects appear as quick recall in <strong>Section A</strong> (identify/state a positive or negative), as applied points in <strong>Section B</strong> scenarios about a named host area, and feed <strong>Section C</strong> 8-mark answers discussing how successful hosting an event has been.</p>\n<p><strong>Three punchy tips:</strong></p>\n<ul>\n<li>Learn the positives and negatives in themes (community/pride, facilities/tourism/jobs, media, safety) so you can always recall several.</li>\n<li>Remember the same event can produce a positive AND a negative at the same time — that overlap is a strong evaluation point.</li>\n<li>Keep the three stages (before/during/after) straight — an effect from the wrong stage earns nothing, however accurate it is.</li>\n</ul>\n<p><strong>Sentence starters for a longer answer:</strong></p>\n<ul>\n<li>\"One positive during the event is… because…\"</li>\n<li>\"This matters because…\"</li>\n<li>\"On the other hand, a negative effect is… because…\"</li>\n</ul>", "check": {"question": "Why is it useful to notice that the same event can produce a positive AND a negative at once?", "options": ["It gives you a strong point for a balanced, higher-band Discuss answer", "It means the whole event has definitely failed and cannot be defended by anyone", "It proves that user groups and during-event effects are the same idea", "It replaces the need to name any effects at all in your answer"], "answer": 0, "explain": "Showing that one event produces both at once is exactly the kind of balanced, applied point that lifts a Section C answer into a higher band."}}]}, "exam": {"enabled": true, "questions": [{"question": "Identify <strong>two</strong> positive effects a major sporting event can have while it is actually taking place.", "marks": 2, "hint": "Pick two different ones from: social infrastructure in use, national morale/cohesion, national status, interest in the sport, media coverage, direct/indirect tourism, short-term employment.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks (AO1)</h5>\n<p><strong>1 mark for each correct, DIFFERENT during-event positive named, to a maximum of two. Accept any two from:</strong></p>\n<ul>\n<li>Improved social infrastructure in use</li>\n<li>Improved national morale / social cohesion</li>\n<li>Increased national status</li>\n<li>Greater national interest in the sport(s)</li>\n<li>Increased media coverage of the sport(s)</li>\n<li>A rise in direct and/or indirect tourism</li>\n<li>An increase in short-term employment during the event</li>\n</ul>\n<p>Do not credit the same effect written twice, or a pre-event/post-event effect.</p>\n</div>"}, {"question": "Which of these is most likely to be a NEGATIVE effect while a major sporting event is being staged?", "marks": 1, "hint": "Three of these are named during-event positives. Only one is a genuine negative.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: A — Increased litter, noise and transport pressure around the busy host venues.</strong></p>\n<ul>\n<li>This is a genuine during-event negative — the strain large crowds put on the host area.</li>\n<li>Interest, jobs and tourism are all named during-event positives, not negatives.</li>\n</ul>\n</div>"}, {"question": "Using the scenario, explain <strong>one</strong> positive and <strong>one</strong> negative effect that Northgate is experiencing during the event.", "marks": 4, "hint": "Use the tram line/stadium detail for the positive, and the villages'' comment for the negative. For each, name the effect and explain it using a detail from the scenario.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (AO2: application)</h5>\n<p><strong>Up to 2 marks for the positive, up to 2 marks for the negative: 1 for identifying the effect, 1 for linking it to a detail in the scenario.</strong></p>\n<ul>\n<li><strong>Positive</strong> — improved social infrastructure in use: the new tram line and stadium, built for the event, are now genuinely being used at full capacity by spectators and staff.</li>\n<li><strong>Negative</strong> — regional neglect: villages away from Northgate received none of the investment and feel overlooked, showing that non-host areas can be left out.</li>\n</ul>\n<p>Accept any other reasonable, scenario-linked positive or negative. A named effect with no scenario link earns 1 of the 2 marks for that half.</p>\n</div>"}, {"question": "Discuss how successfully Northgate is managing the effects of hosting its Games <strong>during</strong> the event itself.", "marks": 8, "hint": "Pick two or three effects from the scenario, both positive and negative. Explain each, then weigh which matters more here, and finish with a judgement on how successful the during-event stage has been overall.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 8 marks (level-of-response). Read the band you fit, then pick a mark.</h5>\n<ul>\n<li><strong>Band 3 (thorough), 6–8:</strong> a balanced, well-applied discussion of several during-event effects, showing clearly how the positives and negatives interact in Northgate''s case AND weighing which matters more, ending in a justified judgement.</li>\n<li><strong>Band 2 (reasonable), 3–5:</strong> sound understanding applied to more than one effect with some analysis, but the discussion may be one-sided or the judgement unsupported.</li>\n<li><strong>Band 1 (basic), 1–2:</strong> names effects with little application to Northgate and no real evaluation; largely a list.</li>\n<li><strong>0 marks:</strong> nothing creditworthy.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Indicative content (indicative, not a checklist — reward valid alternatives)</h5>\n<ul>\n<li><strong>Positives:</strong> social infrastructure in use (tram/stadium busy daily); improved national morale after the host nation''s win; increased media coverage.</li>\n<li><strong>Negatives:</strong> increased transport and litter around the host town; regional neglect (villages feeling forgotten).</li>\n<li><strong>Evaluation:</strong> the win-driven morale boost could reverse quickly if the home nation performs badly later; heavy traffic/litter could itself generate negative media coverage, undoing some of the goodwill; the neglected villages show that success is not shared evenly across the whole country.</li>\n<li><strong>Judgement:</strong> Northgate is managing the during-event stage reasonably well because the infrastructure and morale gains are real and visible — but it is not a complete success, since the traffic/litter strain and the regional neglect mean the benefits are concentrated narrowly rather than shared.</li>\n</ul>\n</div>"}]}}'::jsonb),
('sport-studies', '3-3-2-post-event-and-legacy', '3.3.2 Post-Event and Legacy', '{"learn": {"enabled": true, "items": [{"title": "What happens after the event — and what ''legacy'' means", "html": "<h4>The three stages the spec splits an event into</h4>\n<ul>\n<li>The specification looks at hosting a major event in three separate stages: <strong>before</strong> the event (bidding and building), <strong>during</strong> the event itself, and <strong>after</strong> the event has finished.</li>\n<li>This page covers the <strong>after</strong> stage only — what a host city or nation is left with once the event is over. (Pre-event aspects and during-event aspects are covered on their own pages.)</li>\n</ul>\n<h4>What ''legacy'' means</h4>\n<ul>\n<li><strong>Legacy</strong> is the lasting effect an event leaves behind once the excitement of the event itself has faded — the facilities, habits, reputation and investment that remain months or years later.</li>\n<li>A legacy can show up <strong>immediately</strong> (within months) or only become clear <strong>long-term</strong> (years later), and it can be <strong>positive, negative, or both at the same time</strong>.</li>\n<li>The exam keeps testing whether you can treat legacy as a <strong>balance</strong> to weigh up — not just list one side of it.</li>\n</ul>", "check": {"question": "Which stage of hosting a major event does the word ''legacy'' describe?", "options": ["The stage where cities compete to be chosen as the host", "What is left behind once the event itself has finished", "The build-up in the weeks immediately before the opening ceremony", "The rules officials use to run the competition during the event"], "answer": 1, "explain": "Legacy is the after-stage — what remains once the event has ended. Bidding is the before-stage, and officiating rules apply during the event, not after it."}}, {"title": "The positives: the legacy a major event can leave behind", "html": "<h4>Facilities, transport and infrastructure</h4>\n<ul>\n<li>A host city is often left with a <strong>legacy of improved or new sporting facilities</strong> — stadiums, pools and tracks built or upgraded for the event that local people can keep using for years afterwards.</li>\n<li>Preparing to host often forces a city to improve its <strong>transport and social infrastructure</strong> too — new roads, rail links or wider town regeneration that outlasts the event itself.</li>\n</ul>\n<h4>Participation and profile</h4>\n<ul>\n<li>Watching a sport at a major event can inspire people to try it, giving an <strong>increase in participation</strong> in the sports involved — local clubs often report more new members in the years after.</li>\n<li>The same exposure can raise a sport''s <strong>profile</strong> — more media coverage, more sponsorship and more public interest than it had before the event.</li>\n</ul>\n<h4>Status and future money</h4>\n<ul>\n<li>A well-run event can leave the host with a <strong>raised international profile and status</strong> — the world now associates that place with successfully staging a huge event.</li>\n<li>That reputation can attract <strong>increased future financial investment</strong>, since businesses, tourists and future event organisers are more willing to invest once a host has proved it can deliver.</li>\n</ul>", "check": {"question": "A local swimming club reports far more new junior members two years after their city hosted a major swimming event. This is best described as...", "options": ["a rise in participation, one of the positive legacies of hosting", "clear proof that the event lost far more money than it earned", "an example of a pre-event objection raised before the bid succeeded", "evidence that the pool built for the event has become a white elephant"], "answer": 0, "explain": "More people taking up the sport afterwards is a participation legacy — a positive outcome, not evidence of financial loss, a bidding objection, or an unused venue."}}, {"title": "The negatives: when the legacy goes wrong", "html": "<h4>Cost versus revenue</h4>\n<ul>\n<li>Hosting is hugely expensive, and there is no guarantee the money comes back: the <strong>event may end up costing more to host than the revenue it generates</strong>, leaving the host with a bill long after the closing ceremony.</li>\n</ul>\n<h4>''White elephants''</h4>\n<ul>\n<li>Purpose-built venues need a use afterwards. When a stadium or arena is <strong>left unused once the event is over</strong>, it is often nicknamed a <strong>''white elephant''</strong> — expensive to build and maintain, but bringing in little or no ongoing income.</li>\n<li>A venue is more likely to become a white elephant if it was built for a sport with a small local following, or if nobody planned what it would be used for after the closing ceremony.</li>\n</ul>\n<h4>Reputational loss</h4>\n<ul>\n<li>A negative legacy is not only financial. A host nation can suffer a <strong>loss of national reputation or status</strong> if the event was <strong>badly organised</strong>, if the <strong>host nation''s own athletes performed poorly</strong>, or if a <strong>scandal</strong> (for example, corruption or a doping story) emerged during or after the event.</li>\n</ul>", "check": {"question": "A purpose-built arena stands empty and unused for years after the event it was built for. What is this usually called?", "options": ["a legacy of improved social infrastructure that benefits residents", "a ''white elephant''", "a rise in participation across the sports involved", "a positive transport legacy for the host city"], "answer": 1, "explain": "A costly venue with no ongoing use is a ''white elephant'' — the opposite of a positive facility or transport legacy."}}, {"title": "Weighing it up — the exam skill", "html": "<h4>Legacy is rarely all good or all bad</h4>\n<ul>\n<li>Most real events produce <strong>both</strong> positives and negatives at once — a new pool that boosts participation, and an arena that stands empty, in the very same city.</li>\n<li>Weak answer: naming a single positive or a single negative in isolation. Strong answer: weighing the lasting <strong>benefits</strong> against the lasting <strong>costs</strong>, then reaching a judgement about whether the legacy was worth it overall.</li>\n</ul>\n<h4>Building a balanced answer</h4>\n<ul>\n<li>Use a scenario''s actual detail — a named facility, a stated cost, a stated rise in membership — rather than a generic point that could apply to any host city.</li>\n<li>Finish with a <strong>justified judgement</strong>: say which side of the balance is bigger, and explain why, given what the scenario shows.</li>\n</ul>", "check": {"question": "A question asks you to discuss a city''s post-event legacy. What is most likely to earn the highest marks?", "options": ["Listing every positive legacy you can remember, one after another", "Weighing lasting benefits against lasting costs and reaching a judgement", "Describing the opening ceremony of the event in as much detail as possible", "Naming only the host city, without any further detail at all"], "answer": 1, "explain": "Discuss/evaluate questions reward a balanced weigh-up finishing in a judgement — a one-sided list of positives, ceremony detail, or a bare name earns little."}}]}, "terms": {"enabled": true, "pairs": [{"term": "Legacy", "definition": "The lasting effect an event leaves behind once it has finished — can be positive or negative"}, {"term": "Facility legacy", "definition": "New or improved venues that stay in public use after the event"}, {"term": "Participation legacy", "definition": "More people taking up the sports that featured at the event"}, {"term": "Profile legacy", "definition": "More media coverage, sponsorship and public interest in a sport after the event"}, {"term": "Transport and infrastructure legacy", "definition": "New roads, rail links or regeneration that outlast the event itself"}, {"term": "International status", "definition": "Being seen worldwide as capable of successfully staging a major event"}, {"term": "''White elephant''", "definition": "A purpose-built venue left unused once the event has finished"}, {"term": "Reputational loss", "definition": "Damage to standing from poor organisation, poor host performance, or scandal"}]}, "mcq": {"enabled": true, "questions": [{"question": "What does the word ''legacy'' mean in the context of hosting a major sporting event?", "options": ["The lasting effect that remains once the event itself has finished", "The total number of tickets sold across every day of the event", "The official title given to the host city during the opening ceremony", "The list of sports included in that particular event''s programme"], "answer": 0, "explain": "Legacy is what is left behind afterwards — facilities, participation, profile, reputation and investment — not ticket sales, a ceremonial title, or the sports list."}, {"question": "Which of these is an example of a positive transport and infrastructure legacy?", "options": ["A new rail line built for the event that continues to serve the city for years afterwards", "A temporary road closure put in place for the event that is lifted the moment the closing ceremony finally ends", "A short-term security operation that stops once the last spectator has left", "A rise in hotel prices during the fortnight the event is actually taking place"], "answer": 0, "explain": "A rail line that keeps serving the city afterwards is a lasting infrastructure legacy. Temporary closures, short-term security and event-week price rises all end when the event does."}, {"question": "A national governing body notices far more people signing up for its sport in the two years after a major event was held in the country. This shows...", "options": ["a legacy of increased participation and a raised profile for that sport", "that the international status and reputation of the host nation has clearly fallen since the event finished", "that the event''s main facilities have become white elephants", "that ticket revenue exceeded the total cost of hosting the event"], "answer": 0, "explain": "More people taking up the sport, and more attention on it, is exactly what a participation-and-profile legacy looks like — the other options describe unrelated or opposite outcomes."}, {"question": "A city spends far more hosting an event than it earns back from tickets, sponsorship and tourism. This is best described as...", "options": ["a legacy of improved social infrastructure for local residents", "the event costing more to host than the revenue it generated", "a rise in participation across the sports that were involved", "an increase in future financial investment in the city"], "answer": 1, "explain": "Spending more than the event earns back is the cost-versus-revenue negative — not an infrastructure legacy, a participation rise, or increased investment."}, {"question": "Which best describes a raised international profile as a legacy of hosting a major event?", "options": ["The host is seen worldwide as capable of delivering a major event, attracting future investment", "The host nation''s own athletes are permanently guaranteed to win more medals at every single major event held after this one", "The host city automatically loses the right to bid for any future event", "Ticket prices for the event rise sharply during the closing ceremony itself"], "answer": 0, "explain": "A raised profile is about international reputation and future investment, not guaranteed medals, losing future bidding rights, or ceremony-week ticket prices."}, {"question": "A newly built arena stands empty for years after the closing ceremony, while the host nation is also criticised internationally for how badly the event was organised. This scenario shows...", "options": ["two positive legacies: new facilities in constant use, and a raised international profile", "a ''white elephant'' venue combined with a loss of national reputation", "an increase in participation together with a rise in the sport''s profile", "improved transport infrastructure alongside increased future investment"], "answer": 1, "explain": "An unused venue is a white elephant, and international criticism of the organisation is reputational loss — both negative legacies, not the positive pairs in the other options."}]}, "fib": {"enabled": true, "questions": [{"text": "The lasting effect that remains after a major event has finished is called its [legacy]."}, {"text": "New or upgraded stadiums that local clubs keep using for years afterwards are an example of a [facility] legacy."}, {"text": "A rise in the number of people trying a sport after watching it at a major event is a legacy of increased [participation]."}, {"text": "A venue that is built for an event but then stands [unused] afterwards is nicknamed a ''white elephant''."}, {"text": "If a host nation''s event is badly organised, it can suffer a loss of national [reputation]."}, {"text": "An event that costs more to host than the [revenue] it generates leaves the host with a financial loss."}]}, "tf": {"enabled": true, "questions": [{"statement": "A ''legacy'' can only ever be a positive result of hosting a major event.", "answer": false, "explain": "Legacy can be positive, negative, or both at once — a host can gain a busy new pool AND an empty arena from the same event."}, {"statement": "A rise in participation in the sports featured at an event is an example of a positive legacy.", "answer": true, "explain": "More people taking up the sports involved, inspired by watching the event, is exactly what a positive participation legacy looks like."}, {"statement": "A ''white elephant'' is the nickname for a venue that stays in constant public use long after the event has finished.", "answer": false, "explain": "It is the opposite — a ''white elephant'' is a venue left unused once the event is over, not one that is thriving afterwards."}, {"statement": "Hosting a major event is always guaranteed to bring in more revenue than it costs to host.", "answer": false, "explain": "There is no such guarantee — the event may end up costing more to host than the revenue it generates, leaving a financial loss."}, {"statement": "A host nation''s international reputation can be damaged by poor organisation or a scandal, even after the event has ended.", "answer": true, "explain": "Reputational loss is a genuine negative legacy — bad organisation, poor host performance, or a scandal can all damage standing that outlasts the event."}, {"statement": "Improved transport and social infrastructure built for an event can continue to benefit the local area long after the event finishes.", "answer": true, "explain": "That is exactly what a positive transport and infrastructure legacy means — new roads, rail links or regeneration that outlast the event itself."}]}, "misc": {"enabled": true, "items": [{"myth": "The ''legacy'' of hosting an event is really just whether it made a profit or a loss.", "truth": "Legacy is much broader than the finances. It includes facilities (are they still used?), participation (did more people take up the sport?), profile (did the sport get more attention?), transport and infrastructure, and international status and reputation — as well as the money. A financially break-even event can still have a strong or weak legacy depending on these other factors.", "check": {"question": "Which of these is part of an event''s legacy, alongside its finances?", "options": ["Only whether the event made a profit or a loss overall, once the final accounts were settled", "Facilities, participation, profile, infrastructure and reputation as well as finances", "Only the number of tickets sold on the very first day of the event", "Only the weather recorded during the opening ceremony itself"], "answer": 1, "explain": "Legacy covers facilities, participation, profile, infrastructure and reputation together with the finances — not the finances alone, ticket sales, or the weather."}}, {"myth": "If a stadium is built specifically for an event, it is automatically a ''white elephant'' afterwards.", "truth": "A purpose-built venue only becomes a white elephant if it is left unused once the event has finished. Plenty of purpose-built facilities go on to be busy, well-used venues for years — that is a positive facility legacy, not a white elephant. The difference is what happens to the venue AFTER the closing ceremony, not how or why it was built.", "check": {"question": "What actually decides whether a purpose-built venue becomes a ''white elephant''?", "options": ["Whether it was built specifically for the event in the first place", "Whether it is left unused once the event has finished", "How expensive the venue was to construct originally", "How many spectators attended on the opening night"], "answer": 1, "explain": "It''s ongoing use afterwards that matters, not the fact it was purpose-built, its original cost, or opening-night attendance."}}, {"myth": "Post-event legacy is only about the first few months right after the event finishes.", "truth": "Legacy includes long-term effects too — a rise in participation or a facility''s popularity may only become clear years later, and a reputational or financial legacy can take just as long to settle. Judging legacy well means looking beyond the first few months.", "check": {"question": "Why is it wrong to judge an event''s legacy only from its first few months?", "options": ["Because legacy includes long-term effects that may only become clear years later", "Because legacy is only ever measured in the very first month after the closing ceremony", "Because only the opening ceremony counts towards legacy", "Because legacy is decided entirely before the event even begins"], "answer": 0, "explain": "Legacy can take years to become clear — participation, facility use and reputation can all shift long after the first few months."}}, {"myth": "One positive legacy point, like new facilities, automatically cancels out any negative legacy point, like a cost overrun.", "truth": "The exam wants you to weigh both sides against each other and reach a justified judgement — not assume one positive automatically outweighs a negative, or the other way round. Sometimes a strong facility legacy genuinely outweighs a cost overrun; sometimes it doesn''t. You have to argue it using the scenario, not assume it.", "check": {"question": "How should a positive legacy point and a negative legacy point be treated in a discuss/evaluate answer?", "options": ["The positive point should always be assumed to automatically cancel out any negative point in every single case", "They should be weighed against each other, with a judgement based on the scenario", "The negative point should always be assumed to win automatically, whatever the scenario shows", "Only the positive points need to be mentioned at all"], "answer": 1, "explain": "A good answer weighs both sides against the scenario''s actual detail and reaches a judgement — it never just assumes one side automatically wins."}}]}, "tips": {"enabled": true, "items": [{"title": "Command words for this topic — what each one wants", "html": "<p>Post-event and legacy questions range from quick recall to full evaluation. Match your answer length to the command word:</p>\n<ul>\n<li><strong>Identify / State</strong> — just name it. \"Identify one positive legacy\" = write one legacy, nothing more. 1 mark each.</li>\n<li><strong>Describe</strong> — say what it is or what it looks like in practice, without needing a reason.</li>\n<li><strong>Explain</strong> — give a reason, using the word <em>because</em>. \"Explain why an unused venue is a negative legacy\" = the point plus why it costs the host.</li>\n<li><strong>Discuss / Evaluate</strong> — weigh positives against negatives and give a justified judgement.</li>\n</ul>\n<p><strong>Read the mark tariff:</strong> [1] wants one point; [4] in Section B wants points applied to the scenario; [6]/[8] levelled answers want both sides plus a judgement.</p>", "check": {"question": "A question says: ''Identify one negative legacy of hosting a major event [1]''. What is the safest answer?", "options": ["A full paragraph explaining several negative legacies in detail", "One negative legacy, named", "A list of every negative legacy you can remember", "An explanation of a positive legacy instead"], "answer": 1, "explain": "''Identify'' + [1] = one clearly named point. A long paragraph, a long list, or the wrong side of the argument all waste time for no extra credit."}}, {"title": "The golden rule: weigh the benefit against the cost", "html": "<p>The single most common way to lose marks on this topic is answering only one side. Build longer answers as <strong>benefit vs cost, then judgement</strong>:</p>\n<ul>\n<li><strong>❌ weak:</strong> \"Hosting the event gave the city a new stadium.\" (one-sided, no weighing up)</li>\n<li><strong>✅ stronger:</strong> \"Hosting gave the city a busy new stadium, but the cost ran well over budget, so the legacy is genuinely mixed rather than simply good.\"</li>\n</ul>\n<p>In <strong>Section B and C</strong>, the question usually gives you a scenario (a named host city, a stated cost or membership figure). Use that detail directly — a generic point that could apply to any city earns less.</p>", "check": {"question": "In a scenario question about a named host city''s legacy, your answer should be built around...", "options": ["only the positive side of the argument, ignored entirely for negatives", "weighing the benefit and the cost using detail from the scenario", "a completely different event that you happen to know more about", "the opening ceremony, regardless of what the question actually asks"], "answer": 1, "explain": "Weighing benefit against cost, using the scenario''s own detail, is what separates a strong legacy answer from a one-sided list."}}, {"title": "Where this appears + sentence starters", "html": "<p><strong>Where it shows up:</strong> post-event legacy appears as quick recall in <strong>Section A</strong> (identify a positive or negative legacy), as applied points in <strong>Section B</strong> scenarios about a specific host, and it regularly feeds <strong>Section C</strong> 8-mark discuss/evaluate answers about whether hosting was \"worth it\".</p>\n<p><strong>Three punchy tips:</strong></p>\n<ul>\n<li>Learn the positives and negatives as two short lists so you can always recall at least one of each.</li>\n<li>For every point you make, tie it to a scenario detail (a named facility, a stated cost, a stated membership figure).</li>\n<li>Always end a longer answer with a judgement — don''t just stop after listing both sides.</li>\n</ul>\n<p><strong>Sentence starters for a longer answer:</strong></p>\n<ul>\n<li>\"One positive legacy here is… because…\"</li>\n<li>\"However, a negative legacy is… because…\"</li>\n<li>\"Overall, the legacy is… because…\"</li>\n</ul>", "check": {"question": "Why does a strong Section C legacy answer always finish with a judgement?", "options": ["Because a judgement is entirely optional and adds nothing at all to the final mark awarded", "Because discuss/evaluate questions reward weighing both sides and then deciding", "Because judgements replace the need to use the scenario at all", "Because only Section A questions require any kind of ending"], "answer": 1, "explain": "Discuss/evaluate questions are marked on balance AND judgement — stopping after listing both sides leaves the strongest mark band unreached."}}]}, "exam": {"enabled": true, "questions": [{"question": "Identify <strong>two</strong> different positive legacies a host country might gain after a major sporting event.", "marks": 2, "hint": "Pick two from different areas — for example facilities, participation, profile, transport/infrastructure, international status, or future investment.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks (AO1)</h5>\n<p><strong>1 mark for each correct positive legacy named, to a maximum of two. Accept any two DIFFERENT legacies from the specification, including:</strong></p>\n<ul>\n<li>A legacy of improved or new sporting facilities</li>\n<li>An increase in participation in the sports involved</li>\n<li>A rise in the profile of those sports</li>\n<li>A legacy of improved transport and social infrastructure</li>\n<li>A raised international profile/status for the city or nation</li>\n<li>Increased future financial investment</li>\n</ul>\n<p>Do not credit the same legacy written twice, and do not credit a negative legacy.</p>\n</div>"}, {"question": "Which best describes a ''white elephant'' in the context of an event''s legacy?", "marks": 1, "hint": "Think about which option describes a venue with no ongoing use, rather than a positive outcome.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: A — A purpose-built venue that is left unused once the event has finished.</strong></p>\n<ul>\n<li>A ''white elephant'' is specifically a venue with no ongoing use or income after the closing ceremony.</li>\n<li>The other options all describe positive legacies (a lasting transport link, a participation rise, or a profile rise), not a white elephant.</li>\n</ul>\n</div>"}, {"question": "Explain <strong>one positive legacy</strong> and <strong>one negative legacy</strong> shown in this scenario.", "marks": 4, "hint": "Take each legacy in turn. Name it, then explain why it counts as positive or negative using a detail from the scenario (the pool, the membership figure, the empty arena, or the £60 million figure).", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (AO2: application)</h5>\n<p><strong>Up to 2 marks for the positive legacy, up to 2 marks for the negative legacy: 1 for identifying it, 1 for explaining it using the scenario. Answers may include:</strong></p>\n<ul>\n<li><strong>Positive:</strong> a facility and/or participation legacy — the swimming centre is now the busiest pool in the region and club membership has doubled, showing the venue is genuinely being used and more people are taking part.</li>\n<li><strong>Negative:</strong> a ''white elephant'' and/or a cost overrun — the beach-volleyball arena has stood empty since the closing ceremony, and the event cost £60 million more than budgeted, showing a real financial and use-of-venue cost.</li>\n</ul>\n<p>Accept any other reasonable, scenario-linked answer. A legacy named with no explanation, or an explanation not linked to the scenario, earns 1 of the 2 marks for that side.</p>\n</div>"}, {"question": "Discuss whether hosting the International Combined Games has left Fenmouth with an overall positive legacy.", "marks": 8, "hint": "Use the scenario''s positives (the busy pool, doubled membership) and negatives (the empty arena, the £60 million overrun). Weigh them against each other before giving your judgement.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 8 marks (level-of-response). Read the band you fit, then pick a mark.</h5>\n<ul>\n<li><strong>Band 3 (thorough), 6–8:</strong> a balanced, well-applied discussion using both the positive and negative detail in the scenario, weighing them against each other, and ending in a justified judgement about the overall legacy.</li>\n<li><strong>Band 2 (reasonable), 3–5:</strong> sound understanding applied to the scenario with some analysis, but the discussion may be one-sided (mostly positives or mostly negatives) or the judgement unsupported.</li>\n<li><strong>Band 1 (basic), 1–2:</strong> names a positive and/or negative legacy with little application to the scenario and no real evaluation; largely a list.</li>\n<li><strong>0 marks:</strong> nothing creditworthy.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Indicative content (indicative, not a checklist — reward valid alternatives)</h5>\n<ul>\n<li><strong>Positive legacy:</strong> the swimming centre is now the busiest pool in the region, showing a genuine facility legacy; local club membership has doubled, showing a real participation legacy.</li>\n<li><strong>Negative legacy:</strong> the beach-volleyball arena has stood empty since the closing ceremony — a ''white elephant'' with no ongoing income; the final cost was £60 million over budget, showing the event cost more to host than planned.</li>\n<li><strong>Evaluation:</strong> a busy, well-used pool does not automatically outweigh an unused arena and a large budget overrun, and vice versa; the scale of the overrun (£60 million) compared with the ongoing value of a doubled membership is central to the judgement; a purely short-term view (three years on) may understate or overstate the legacy compared to a longer-term view.</li>\n<li><strong>Judgement:</strong> Fenmouth''s legacy is genuinely mixed — strong facility and participation gains sit alongside a costly unused venue and a large overspend — so it cannot fairly be called simply positive or simply negative; whether it counts as \"worth it\" depends on how much weight is placed on the ongoing sporting benefit versus the financial cost.</li>\n</ul>\n</div>"}]}}'::jsonb),
('sport-studies', '4-1-the-role-of-ngbs', '4.1 The Role of NGBs', '{"learn": {"enabled": true, "items": [{"title": "What a National Governing Body (NGB) is", "html": "<h4>The idea</h4>\n<ul>\n<li>A <strong>National Governing Body (NGB)</strong> is the official organisation put in charge of running and developing one sport across the whole country.</li>\n<li>Every major sport in the UK has its own NGB — for example, there is a national governing body for football, one for rugby union, one for swimming and one for tennis. Each one oversees its sport from complete beginners right up to the national team.</li>\n</ul>\n<h4>What NGBs are actually for</h4>\n<ul>\n<li>An NGB is not just a name on a badge — it carries out a wide range of jobs that keep its sport running, growing and fair.</li>\n<li>The exam does not want you to simply name what an NGB does; it wants you to explain the <strong>purpose</strong> behind each role — what the NGB does, and <em>why</em> that helps the sport.</li>\n<li>Build a habit of turning every role into a \"so that\" sentence: \"an NGB runs coaching qualifications <strong>so that</strong> more good coaches come through, which raises the standard of the sport.\"</li>\n</ul>", "check": {"question": "Which of these best describes what a National Governing Body (NGB) is?", "options": ["The official organisation in charge of running and developing one sport nationally", "A private company that manufactures and sells replica kit for one sport''s fans", "A local leisure centre that runs a single weekly beginners'' session for one particular sport", "A supporters'' group that arranges travel to a national team''s away fixtures"], "answer": 0, "explain": "An NGB is the official body overseeing a whole sport nationally — not a kit manufacturer, a single venue, or a supporters'' group."}}, {"title": "Growing the sport: participation, coaching and competitions", "html": "<h4>Promoting participation</h4>\n<ul>\n<li>NGBs run schemes and campaigns to get more people playing their sport — for example, running a taster scheme in schools, or advertising through the media to reach new audiences.</li>\n<li>Part of this job is making sure the sport offers <strong>equal opportunities</strong> — actively encouraging groups who are currently under-represented, such as girls, disabled players or older beginners, so the sport grows rather than staying with the same small audience.</li>\n</ul>\n<h4>Developing coaching and officiating</h4>\n<ul>\n<li>An NGB designs and runs <strong>coaching qualifications</strong>, usually organised into levels — for instance a Level 1 award for a helper, up to advanced awards for coaching representative teams.</li>\n<li>It does the same for <strong>officiating</strong> — training and qualifying referees, umpires or judges through levels — so that games at every level are run by people who know the rules properly.</li>\n<li><strong>Why this matters:</strong> without a steady supply of qualified coaches and officials, clubs cannot run new sessions or fixtures, so the sport cannot grow.</li>\n</ul>\n<h4>Organising tournaments and competitions</h4>\n<ul>\n<li>NGBs organise the fixture list and competition structure for their sport — from local leagues, through regional and national cups, up to the national representative team''s matches.</li>\n<li>This gives performers of every standard somewhere to test themselves and something to aim for, which keeps people motivated to keep training and playing.</li>\n</ul>", "check": {"question": "An NGB trains and qualifies referees through a system of levels. Which NGB role does this show?", "options": ["Lobbying central government for extra funding for elite facilities", "Developing the sport''s coaching and officiating infrastructure", "Applying disciplinary procedures against a professional club", "Organising the national representative team''s next fixture list"], "answer": 1, "explain": "Training and qualifying officials through levels is part of developing coaching and officiating infrastructure — not funding, discipline, or fixtures on their own."}}, {"title": "Keeping the sport fair and safe: rules, discipline and safety", "html": "<h4>Amending rules and applying discipline</h4>\n<ul>\n<li>An NGB owns the official rulebook for its sport and can <strong>amend (change) the rules</strong> when it needs to — for example to make a contact sport safer, or to close a loophole players are exploiting.</li>\n<li>When a player, coach or club breaks the rules, the NGB applies its <strong>disciplinary procedures</strong> — this can mean a warning, a fine, a suspension, or in serious cases a much longer ban.</li>\n<li><strong>Purpose:</strong> without a body willing to enforce the rules, breaking them would carry no real consequence, and the sport would stop being fair for everyone else taking part.</li>\n</ul>\n<h4>Ensuring safety</h4>\n<ul>\n<li>NGBs set minimum safety standards for equipment, facilities and how sessions are run, and expect affiliated clubs and coaches to follow them.</li>\n<li>They may also set rules around player welfare — for instance concussion protocols in contact sports — so participants are protected from unnecessary injury.</li>\n</ul>\n<h4>Support, insurance and technical guidance</h4>\n<ul>\n<li>NGBs provide <strong>support</strong> to their affiliated clubs and members, such as advice on running a club or a helpline for questions.</li>\n<li>Many arrange or require <strong>insurance</strong> cover, so that clubs, coaches and players are protected if an accident happens during the sport.</li>\n<li>They also give <strong>technical guidance</strong> — coaching resources, skill breakdowns and best-practice advice — so members do not have to work everything out for themselves.</li>\n</ul>", "check": {"question": "A club is fined and a player is suspended after a serious breach of the rules. Which NGB role is being shown here?", "options": ["Providing detailed technical guidance and coaching resources to affiliated members", "Promoting participation through a national media campaign", "Organising a tournament for the sport''s top regional teams", "Amending the rules and applying disciplinary procedures for rule-breaking"], "answer": 3, "explain": "A fine and a suspension are disciplinary procedures being applied after the rules were broken — not guidance, promotion, or fixture organisation."}}, {"title": "Steering the sport''s future: policies, funding — and the exam skill", "html": "<h4>Developing policies and initiatives</h4>\n<ul>\n<li>An NGB writes <strong>policies</strong> — official written plans covering things like safeguarding, anti-discrimination or long-term development — that clubs and members are expected to follow.</li>\n<li>It also launches <strong>initiatives</strong> — new projects designed to solve a specific problem the sport faces, such as a shortage of coaches in one region or falling participation among one user group.</li>\n</ul>\n<h4>Lobbying for funding</h4>\n<ul>\n<li>NGBs <strong>lobby</strong> (formally argue their case to) government bodies and other funding organisations for money to invest in facilities, coaching and grassroots development.</li>\n<li>Extra funding lets an NGB build or improve facilities, subsidise coaching courses, or fund talent pathways — all of which grow and improve the sport over time.</li>\n</ul>\n<h4>Naming a role is only the start</h4>\n<ul>\n<li>Weak answer: <em>\"An NGB organises competitions.\"</em> That names a role but shows no real understanding.</li>\n<li>Strong answer: <em>\"An NGB organises competitions at every level, so that players of all abilities have a clear pathway and stay motivated to keep training.\"</em></li>\n<li>Whichever role you are asked about, build your answer as <strong>role → what it involves → why it helps the sport</strong>.</li>\n</ul>", "check": {"question": "A question asks you to explain how an NGB lobbies for funding. What is most likely to earn full marks?", "options": ["Just naming ''lobbying for funding'' with no further detail at all", "Saying the NGB argues for funding, and explaining what that funding is then used for", "Listing every other NGB role you can possibly remember, in as much detail as possible", "Describing how a private sponsor pays one professional athlete''s wages"], "answer": 1, "explain": "Naming plus what the funding achieves (facilities, coaching, pathways) shows the understanding the mark scheme rewards — naming alone, or listing unrelated roles, does not."}}]}, "terms": {"enabled": true, "pairs": [{"term": "National Governing Body (NGB)", "definition": "The official organisation in charge of running and developing one sport nationally"}, {"term": "Promoting participation", "definition": "Schemes and media campaigns that grow the sport, including targeting under-represented groups"}, {"term": "Coaching and officiating infrastructure", "definition": "Qualification levels for coaches and for referees, umpires or judges"}, {"term": "Organising competitions", "definition": "Setting up leagues, cups and fixtures at every level of the sport"}, {"term": "Rules and discipline", "definition": "Amending the rulebook and punishing players or clubs who break the rules"}, {"term": "Safety", "definition": "Setting minimum safety standards for equipment, facilities and session delivery"}, {"term": "Support, insurance and guidance", "definition": "Advice, insurance cover and coaching resources for affiliated clubs"}, {"term": "Policies, initiatives and funding", "definition": "Official plans, new projects, and arguing the case for outside investment"}]}, "mcq": {"enabled": true, "questions": [{"question": "What is the main purpose of a National Governing Body (NGB)?", "options": ["To run and develop a single sport nationally, from grassroots to elite level", "To sell official replica kit and matchday merchandise for one sport''s national team", "To broadcast every fixture in a sport live to a subscription-only audience", "To organise one single local competition, held once a year in one town"], "answer": 0, "explain": "An NGB runs and develops its whole sport nationally, across every level — not merchandise, broadcasting rights, or a single yearly event."}, {"question": "Why might an NGB run a scheme that specifically targets an under-represented group, such as girls or older beginners?", "options": ["To meet a legal quota requiring exactly equal numbers of people from every group", "To grow the sport by giving equal opportunities to groups who are not yet taking part", "To reduce overall participation numbers so that facilities stay quieter", "To guarantee that this particular group wins every regional competition it enters this season"], "answer": 1, "explain": "Targeted schemes widen participation by removing the barriers a specific group faces — they are not about quotas, quieter facilities, or guaranteed wins."}, {"question": "An NGB runs a Level 1 coaching award and trains new referees through a levels system. What is this an example of?", "options": ["Lobbying central government for extra funding for elite facilities", "Applying disciplinary procedures against a professional club", "Developing the sport''s coaching and officiating infrastructure", "Organising the national team''s fixtures for the coming season"], "answer": 2, "explain": "Coaching awards and refereeing levels build up the sport''s coaching and officiating infrastructure — not funding, discipline, or fixture-organising."}, {"question": "A club is fined and a player is suspended after a serious breach of the rules. Which NGB role is being shown here?", "options": ["Providing detailed technical guidance and coaching resources to affiliated members", "Promoting participation through a national media campaign", "Organising a tournament for the sport''s top regional teams", "Amending the rules and applying disciplinary procedures for rule-breaking"], "answer": 3, "explain": "A fine and a suspension show disciplinary procedures being applied — the guidance, promotion and tournament options describe different NGB jobs."}, {"question": "A local club asks its NGB for advice on running sessions safely and for insurance cover. Which role is this?", "options": ["Lobbying government bodies for extra grassroots funding", "Providing support, insurance and technical guidance to members", "Organising national and regional competitions for the sport", "Developing a brand-new policy on player welfare and safeguarding"], "answer": 1, "explain": "Advice and insurance cover for an affiliated club are exactly what the support, insurance and technical guidance role covers."}, {"question": "An NGB spends time formally arguing its case to government for more investment in facilities and coaching. What is this called?", "options": ["Ensuring safety within the sport at every level of competition", "Applying disciplinary procedures for serious rule-breaking", "Lobbying for funding to invest in the sport", "Developing new policies and initiatives for its members"], "answer": 2, "explain": "Formally arguing the case to government or funding bodies for investment is lobbying for funding — a different job from safety, discipline or policy-writing."}]}, "fib": {"enabled": true, "questions": [{"text": "A National Governing Body is the organisation officially in charge of running and [developing] a single sport nationally."}, {"text": "NGBs promote [participation] by running schemes and media campaigns that reach new audiences."}, {"text": "An NGB trains and qualifies coaches and officials through a system of [levels]."}, {"text": "When a player seriously breaks the rules, the NGB can apply its [disciplinary] procedures."}, {"text": "Many NGBs arrange or require [insurance] cover so clubs and players are protected if an accident happens."}, {"text": "NGBs [lobby] government and other funding bodies for investment in facilities and coaching."}]}, "tf": {"enabled": true, "questions": [{"statement": "A National Governing Body is responsible for running and developing one sport nationally.", "answer": true, "explain": "That''s the definition of an NGB — one official organisation overseeing its sport from grassroots to elite level."}, {"statement": "An NGB has no involvement in training referees or officials — clubs are left to sort that out alone.", "answer": false, "explain": "NGBs design and run officiating qualifications through levels, so officials at every level of the sport are properly trained."}, {"statement": "An NGB can amend (change) the rules of its own sport when it needs to.", "answer": true, "explain": "NGBs own the official rulebook and can change it, for example to improve safety or close a loophole."}, {"statement": "Because NGBs never target under-represented groups, every session is aimed at exactly the same audience.", "answer": false, "explain": "Promoting participation includes running schemes for under-represented groups, such as girls or older beginners, to widen who takes part."}, {"statement": "Lobbying for funding means an NGB formally argues its case to government or other funding bodies for investment.", "answer": true, "explain": "That''s exactly what lobbying means here — making the case for money to invest in facilities, coaching and development."}, {"statement": "Because clubs run their own sessions, an NGB never sets safety standards for facilities or equipment.", "answer": false, "explain": "Ensuring safety is a core NGB role — it sets minimum safety standards that affiliated clubs and coaches are expected to follow."}]}, "misc": {"enabled": true, "items": [{"myth": "Explaining an NGB''s role just means naming what it does, like ''organises competitions''.", "truth": "Naming is only the first mark at most. The examiner wants you to link the role to its purpose. Weak answer: \"An NGB organises competitions.\" Full-marks answer: \"An NGB organises competitions at every level, so that players of all abilities have a clear pathway and stay motivated to keep training.\" The difference is the reason.", "check": {"question": "An ''Explain'' question asks about one NGB role. What earns the marks?", "options": ["Naming as many different NGB roles as you possibly can, quickly", "Naming the role, then explaining why it helps the sport", "Writing the role''s name in capital letters", "Describing your own favourite sporting event in detail"], "answer": 1, "explain": "Explain = point + reason. Naming the role alone, or listing several roles, does not show the understanding the mark scheme rewards."}}, {"myth": "An NGB only deals with the best professional players and elite competitions.", "truth": "An NGB oversees its ENTIRE sport, not only the elite end. The same organisation that runs the national team''s fixtures also sets up beginner coaching levels, safety standards for a small local club, and insurance advice for grassroots members. ''National'' means the whole country and every level, not just the top.", "check": {"question": "Which of these best shows the true scope of an NGB''s work?", "options": ["Running only the national representative team''s own annual fixture list", "Overseeing the sport from grassroots beginners up to elite level", "Managing only the training of already-professional athletes", "Advising a single elite club on its transfer policy"], "answer": 1, "explain": "An NGB''s roles — coaching, safety, competitions, support — apply across the whole sport, from complete beginners through to the national team."}}, {"myth": "''Lobbying for funding'' means the NGB hands out money to clubs itself, like a bank.", "truth": "Lobbying is arguing the CASE for funding to somebody else — usually government or another funding body — not giving money out directly. The NGB persuades others to invest, and then uses any funding it secures to improve facilities, coaching and development.", "check": {"question": "What does ''lobbying for funding'' actually involve?", "options": ["The NGB directly paying every affiliated club from its own bank account each year", "The NGB formally arguing its case to government or funding bodies for investment", "The NGB refusing to accept any outside investment at all", "The NGB selling shares in the sport to private investors"], "answer": 1, "explain": "Lobbying means making the case for investment to an outside body — it is not the NGB acting as a bank and handing out its own money."}}, {"myth": "Ensuring safety and applying disciplinary procedures are really just the same NGB role.", "truth": "They are related but different. Ensuring safety is about setting standards BEFORE anything goes wrong (equipment, facilities, welfare rules). Applying disciplinary procedures is about punishing rule-breaking AFTER it has already happened (fines, suspensions, bans). A question can ask about either, so keep them separate in your answer.", "check": {"question": "Which of these is part of ''ensuring safety'', rather than ''discipline''?", "options": ["Suspending a player from every competitive fixture for a full six months", "Fining a club for a rule-breaking incident", "Setting minimum safety standards for all equipment before sessions begin", "Banning a coach for repeated rule violations"], "answer": 2, "explain": "Setting standards before anything goes wrong is safety; fines, suspensions and bans are all discipline applied after a rule has been broken."}}]}, "tips": {"enabled": true, "items": [{"title": "Command words for this topic — what each one wants", "html": "<p>NGB questions are usually short recall or applied questions. Match your answer length to the command word:</p>\n<ul>\n<li><strong>Identify / State</strong> — just name it. \"Identify two roles of an NGB\" = two role names, nothing more. 1 mark each.</li>\n<li><strong>Describe</strong> — say what the role involves. \"Describe how an NGB supports coaching\" = give the features of that role.</li>\n<li><strong>Explain</strong> — give a reason. Use the word <em>because</em> or <em>so that</em>. \"Explain why an NGB applies disciplinary procedures\" = the role <em>plus</em> why it matters.</li>\n</ul>\n<p><strong>Read the mark tariff:</strong> [1] wants one point; [2]-[4] usually wants points developed or applied to a scenario; a levelled 6/8-mark question wants a balanced, judged answer.</p>", "check": {"question": "A question says: ''Identify two roles of a National Governing Body [2]''. What is the safest answer?", "options": ["A long paragraph about one role", "Two role names", "One role name explained in detail", "A list of six roles"], "answer": 1, "explain": "''Identify'' + [2] = two names, one mark each. Explaining one role, or listing six, wastes time and risks the examiner marking only the first two anyway."}}, {"title": "The golden rule: name the role AND its purpose", "html": "<p>The single most common way to lose marks here is stopping at the name. Build every answer as <strong>role → purpose</strong>:</p>\n<ul>\n<li><strong>❌ 0–1 marks:</strong> \"It organises competitions.\"</li>\n<li><strong>✅ full marks:</strong> \"It organises competitions at every level, so players of all abilities have a pathway and stay motivated.\"</li>\n</ul>\n<p>In <strong>Section B</strong> the question gives you a scenario (a named club, a named problem). You must then use a detail <em>from that scenario</em>, not a general example.</p>", "check": {"question": "In a Section B scenario question about a named club''s problem, your example should come from...", "options": ["absolutely any sport that you happen to like", "the scenario you are given", "a famous athlete", "your own school only"], "answer": 1, "explain": "Section B is applied — the marks are for using the scenario in front of you. A general example that ignores the scenario is capped."}}, {"title": "Where NGB roles appear + sentence starters", "html": "<p><strong>Where it shows up:</strong> NGB roles appear as quick recall in <strong>Section A</strong> (identify/state), and as applied points in <strong>Section B</strong> scenarios about a club''s problem. They also feed <strong>Section C</strong> 8-mark answers about how effectively an NGB balances growing a sport with policing it.</p>\n<p><strong>Three punchy tips:</strong></p>\n<ul>\n<li>Learn the roles in pairs (growth roles: participation, coaching, competitions, policies, funding; policing roles: rules, discipline, safety, support) so you can always recall a few from each side.</li>\n<li>For every role, memorise <em>one</em> reason it helps the sport — that reason is usually where the mark is.</li>\n<li>Watch for the link between roles: weak discipline can undo good promotion work, which is a great evaluation point.</li>\n</ul>\n<p><strong>Sentence starters for a longer answer:</strong></p>\n<ul>\n<li>\"One way an NGB develops the sport is… which helps because…\"</li>\n<li>\"On the policing side, the NGB…\"</li>\n<li>\"However, a limit of this is…\"</li>\n</ul>", "check": {"question": "Why is the link between ''growth'' roles and ''policing'' roles a useful evaluation point?", "options": ["It fills space", "It shows the two sides of an NGB''s work can affect each other", "It means NGBs do not really need rules", "It completely replaces the need to name any individual roles at all"], "answer": 1, "explain": "Noticing that weak discipline can undermine participation growth (or vice versa) shows deeper understanding — the kind of point that lifts a Section C answer."}}]}, "exam": {"enabled": true, "questions": [{"question": "Identify <strong>two</strong> roles that a National Governing Body (NGB) carries out for its sport.", "marks": 2, "hint": "Just name two — pick from growth (participation, coaching/officiating, competitions, policies, funding) or policing (rules/discipline, safety, support/insurance/guidance).", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks (AO1)</h5>\n<p><strong>1 mark for each correct NGB role named, to a maximum of two. Accept any two different roles, including:</strong></p>\n<ul>\n<li>Promoting participation</li>\n<li>Developing coaching and officiating infrastructure</li>\n<li>Organising tournaments and competitions</li>\n<li>Amending rules and applying disciplinary procedures</li>\n<li>Ensuring safety</li>\n<li>Providing support, insurance and technical guidance</li>\n<li>Developing policies and initiatives</li>\n<li>Lobbying for funding</li>\n</ul>\n<p>Do not credit the same role written twice.</p>\n</div>"}, {"question": "Which of these is a genuine role of a National Governing Body (NGB)?", "marks": 1, "hint": "Think about which option matches building up the sport''s coaching and officiating infrastructure.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: B — Training and qualifying coaches and officials through a system of levels.</strong></p>\n<ul>\n<li>This is the NGB''s coaching and officiating infrastructure role.</li>\n<li>TV advertising, club transfers and one local event''s pricing are not NGB roles.</li>\n</ul>\n</div>"}, {"question": "Explain how the national governing body for hockey could respond to <strong>each</strong> of Northfield Hockey Club''s two concerns.", "marks": 4, "hint": "Take each concern in turn. Name the NGB role that fits it, then explain how that role would actually solve the problem described.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (AO2: application)</h5>\n<p><strong>Up to 2 marks per concern: 1 for identifying a relevant NGB role, 1 for explaining how it solves the scenario''s problem. Answers may include:</strong></p>\n<ul>\n<li><strong>Coaching shortage</strong> — the NGB''s coaching qualification levels; training more coaches through these awards would let Northfield''s junior teams train properly instead of missing sessions.</li>\n<li><strong>Unpunished serious foul</strong> — the NGB''s disciplinary procedures; reviewing the incident and sanctioning the offending player enforces the rules and helps prevent similar injuries in future.</li>\n</ul>\n<p>Accept any other reasonable, applied answer. A role with no explanation, or an explanation not linked to the scenario, earns 1 of the 2 marks for that concern.</p>\n</div>"}, {"question": "Discuss how effectively a national governing body could balance developing a sport with policing rule-breaking within it.", "marks": 8, "hint": "Cover both sides: growth roles (participation, coaching/officiating, competitions, policies, funding) AND policing roles (rules, discipline, safety). Weigh up the strengths and limits of each, then reach a judgement.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 8 marks (level-of-response). Read the band you fit, then pick a mark.</h5>\n<ul>\n<li><strong>Band 3 (thorough), 6–8:</strong> a balanced, well-applied discussion of BOTH growth and policing roles, showing clearly how each supports the sport AND weighing the limits (resources, a badly-handled case undermining trust), ending in a justified judgement.</li>\n<li><strong>Band 2 (reasonable), 3–5:</strong> sound understanding applied to more than one role with some analysis, but the discussion may be one-sided (growth OR policing, not both) or the judgement unsupported.</li>\n<li><strong>Band 1 (basic), 1–2:</strong> names roles with little application and no real evaluation; largely a list.</li>\n<li><strong>0 marks:</strong> nothing creditworthy.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Indicative content (indicative, not a checklist — reward valid alternatives)</h5>\n<ul>\n<li><strong>Growth roles:</strong> coaching/officiating qualifications and organised competitions attract and keep participants; policies, initiatives and lobbying for funding add resources to support that growth.</li>\n<li><strong>Policing roles:</strong> amending rules and applying disciplinary procedures (as with Northfield''s unpunished foul) keeps the sport fair; ensuring safety protects participants so they keep taking part.</li>\n<li><strong>Link between the two:</strong> new participants are more likely to stay if they trust the sport is properly refereed and enforced — growth and policing support each other.</li>\n<li><strong>Evaluation:</strong> an NGB has limited money and staff, so investing heavily in growth can leave fewer resources for slower discipline processes; a badly-handled case (like Northfield''s) can undermine confidence built by development work; one job without the other is unlikely to work long-term.</li>\n<li><strong>Judgement:</strong> an NGB balances the two most effectively when it treats growth and enforcement as connected — participation without safety and fairness will not last.</li>\n</ul>\n</div>"}]}}'::jsonb),
('sport-studies', '5-1-1-technology-to-enhance-performance', '5.1.1 Technology to Enhance Performance', '{"learn": {"enabled": true, "items": [{"title": "Streamlined clothing and aerodynamic materials", "html": "<h4>Why ''aerodynamic'' and ''streamlined'' matter</h4>\n<ul>\n<li><strong>Aerodynamic</strong> equipment or clothing is shaped and made from materials that let air or water flow around the body with less resistance (\"drag\"). Less drag means a performer can move faster for the same amount of effort.</li>\n<li><strong>Streamlined</strong> clothing is cut close to the body, often from smooth, tight-fitting fabric, so it does not \"catch\" the air or water as the performer moves.</li>\n</ul>\n<h4>Named examples</h4>\n<ul>\n<li><strong>Swimming</strong> — competitive swimmers wear low-drag racing suits made from smooth, compressive fabric that reduces resistance moving through water, letting them hold a faster pace for longer.</li>\n<li><strong>Track cycling</strong> — sprint and time-trial cyclists wear one-piece aerodynamic skinsuits and aero helmets shaped to cut through the air, which matters hugely at high speed.</li>\n<li><strong>Alpine skiing</strong> — skiers wear tight, smooth racing suits so wind resistance does not slow their descent.</li>\n<li><strong>Athletics</strong> — sprinters often wear fitted, lightweight suits rather than loose kit, again to reduce air resistance over a short, explosive race.</li>\n</ul>\n<h4>The exam point</h4>\n<ul>\n<li>Always link the material/design feature to the actual effect: <em>close-fitting, smooth material → less drag → more speed for the same effort</em>. Naming \"swimsuits\" alone earns little; explaining the drag reduction is what earns marks.</li>\n</ul>", "check": {"question": "Why do elite cyclists and swimmers often wear tight-fitting, streamlined suits during competition?", "options": ["To reduce drag/resistance so they can move through air or water more efficiently", "To display sponsor logos more clearly to television audiences watching at home", "To meet a required uniform colour scheme set by the event''s organising committee", "To keep the performer warmer throughout a long, low-intensity training session"], "answer": 0, "explain": "Streamlined suits reduce drag through air or water, letting the performer move faster for the same effort — the other options describe branding, rules or warmth, not performance."}}, {"title": "Lighter, better-designed equipment", "html": "<h4>Why lighter, stiffer equipment helps</h4>\n<ul>\n<li>Modern materials (such as carbon fibre and graphite) let manufacturers build equipment that is <strong>lighter</strong> (less effort to move) and <strong>stiffer</strong> (less energy wasted flexing), so more of the performer''s effort turns into speed, power or control.</li>\n</ul>\n<h4>Named examples</h4>\n<ul>\n<li><strong>Rackets</strong> — modern tennis and badminton rackets use carbon-fibre frames that are lighter and stiffer than older wooden or metal frames, giving players more power and control with less arm fatigue.</li>\n<li><strong>Bikes</strong> — competitive road and track bikes use carbon-fibre frames and wheels that are lighter and more aerodynamic than steel frames, so cyclists produce more speed for the same pedalling effort.</li>\n<li><strong>Footwear</strong> — running shoes with cushioned, energy-returning soles (some with a stiff supportive plate) help runners push off with less wasted effort; football boots are made lighter with studs designed for grip and quick changes of direction.</li>\n</ul>\n<h4>The exam point</h4>\n<ul>\n<li>Explain the mechanism, not just the object: a lighter racket lets a player swing faster with less effort; a stiffer frame transfers more of the rider''s power into speed instead of losing it to flex.</li>\n</ul>", "check": {"question": "Why do elite road cyclists usually race on carbon-fibre bike frames rather than heavier steel frames?", "options": ["Steel frames are banned outright by every national governing body across world cycling", "Carbon fibre is lighter and stiffer, so more of the rider''s effort converts into speed", "Carbon-fibre frames are the only frame type that cycling events officially allow riders to use", "Carbon fibre is simply a cheaper material for manufacturers to buy in bulk than steel tubing"], "answer": 1, "explain": "Carbon fibre is lighter and stiffer than steel, so less of the rider''s effort is wasted and more converts into speed — it is not a rule, a ban or mainly about cost."}}, {"title": "Data, GPS and video analysis for training and technique", "html": "<h4>Using data to improve training</h4>\n<ul>\n<li><strong>GPS trackers</strong> (worn in a vest between the shoulder blades) are common in football and rugby. They record distance covered, sprint speed and how hard a player worked in a match or session.</li>\n<li>Coaches use this data to see whether a player is overtraining, undertraining, or ready to return after injury, and to plan the next session''s intensity.</li>\n</ul>\n<h4>Using video to improve technique</h4>\n<ul>\n<li><strong>Video analysis</strong> lets a coach slow footage down, frame by frame, to spot a technical fault a player cannot feel themselves — for example a golfer''s swing plane, a sprinter''s start position, or a swimmer''s stroke technique.</li>\n<li>Comparing footage of a performer over time (or against a model performer) helps target practice on the exact part of the technique that needs work.</li>\n</ul>\n<h4>The exam point</h4>\n<ul>\n<li>The link the exam wants: <em>data/video → spot a specific weakness → adjust training → improved performance.</em> Simply saying \"GPS is used in football\" without this chain earns little.</li>\n</ul>", "check": {"question": "What is the main reason a football coach uses GPS-tracking vests during training?", "options": ["To broadcast a player''s exact live location to supporters watching in the stadium seats", "To automatically award a yellow card whenever a player runs at an unsafe sprinting speed", "To collect data on distance and speed so training load can be planned accurately", "To replace the need for a referee to make any decisions at all during the match"], "answer": 2, "explain": "GPS vests collect data on distance, speed and effort so a coach can plan training load accurately — they do not broadcast locations, issue cards or replace referees."}}]}, "terms": {"enabled": true, "pairs": [{"term": "Streamlined", "definition": "Shaped/cut close to the body to reduce drag through air or water"}, {"term": "Aerodynamic", "definition": "Designed so air flows past with less resistance, aiding speed"}, {"term": "Carbon-fibre equipment", "definition": "Lighter and stiffer than older materials — more power, less fatigue"}, {"term": "Energy-returning sole", "definition": "Cushioned shoe sole that reduces wasted effort on push-off"}, {"term": "GPS tracking vest", "definition": "Worn between the shoulders; records distance, speed and effort"}, {"term": "Video analysis", "definition": "Slowed footage used to spot a specific technical fault"}]}, "mcq": {"enabled": true, "questions": [{"question": "A time-trial cyclist wears a one-piece skinsuit and an aero helmet. What is this designed to do?", "options": ["Reduce air resistance so the cyclist can hold a faster speed for the same effort", "Make it easier for television commentators to identify which team the rider is racing for", "Meet a strict minimum-weight rule set out by the event''s national governing body", "Keep the cyclist noticeably warmer during a long, cold winter training ride outdoors"], "answer": 0, "explain": "A skinsuit and aero helmet cut air resistance, letting the cyclist hold a faster speed for the same effort — identification, weight rules and warmth are not the purpose."}, {"question": "Why might a badminton player choose a modern carbon-fibre racket over an old wooden one?", "options": ["It is heavier overall, which helps generate much more power on every single shot played", "It is lighter and stiffer, giving more power and control with less arm fatigue", "It is the only racket type that badminton''s national governing body allows in competition", "It is made from the same dense wood that professional rackets always used in the past"], "answer": 1, "explain": "Carbon fibre is lighter and stiffer than wood, giving more power and control with less fatigue. It is not heavier, not the only legal type, and not the same material as before."}, {"question": "Which feature of modern running shoes helps some runners push off the ground with less wasted effort?", "options": ["A heavier sole added purely to increase the overall stability of the shoe", "An extra-wide sole shaped only to make the shoe more comfortable to walk in", "A cushioned, energy-returning sole, sometimes with a stiff supportive plate", "A plain rubber sole identical to the design used in football boots decades ago"], "answer": 2, "explain": "A cushioned, energy-returning sole reduces wasted effort on push-off. Extra weight, comfort-only width and an old plain design do not give this performance benefit."}, {"question": "A rugby coach studies a player''s GPS data from a match. What is this mainly used for?", "options": ["To broadcast the player''s exact position live to spectators in the crowd around the pitch", "To decide automatically which player should be sent off for an unsafe, high tackle", "To replace the referee''s decisions on foul play during the whole ninety minutes", "To see how much distance and effort the player covered, to plan future training"], "answer": 3, "explain": "GPS data mainly shows distance and effort so the coach can plan training — it does not broadcast positions, send players off, or replace refereeing decisions."}, {"question": "A swimming coach films a swimmer''s stroke and slows the footage down frame by frame. Why?", "options": ["To check the swimmer''s racing suit matches the exact colour of their team''s kit", "To spot a technical fault in the stroke that the swimmer cannot feel themselves", "To measure how loudly the crowd is cheering for that swimmer during the race", "To confirm the swimming pool itself is exactly the regulation length required"], "answer": 1, "explain": "Slowed footage lets a coach spot a technical fault the swimmer cannot feel — kit colour, crowd noise and pool length are unrelated to this use of video."}, {"question": "Why do some elite sprinters wear tight-fitting, lightweight racing suits rather than loose training kit?", "options": ["Loose kit is banned completely under global athletics competition clothing rules", "Tight kit is required so photo-finish cameras can read the sprinter''s race number", "Tight, lightweight kit reduces air resistance over the short, explosive race", "Tight kit keeps the sprinter''s whole body noticeably warmer throughout the race"], "answer": 2, "explain": "Tight, lightweight kit reduces air resistance over a short sprint, aiding speed — it is not about a ban, reading race numbers, or keeping warm."}]}, "fib": {"enabled": true, "questions": [{"text": "Close-fitting, smooth-fabric clothing is described as [streamlined] because it reduces drag through air or water."}, {"text": "Carbon-fibre rackets and bike frames are lighter and [stiffer], so less effort is wasted flexing."}, {"text": "GPS trackers are usually worn in a [vest] between the shoulder blades to record distance and speed."}, {"text": "Video analysis lets a coach slow footage down to spot a technical [fault] in a performer''s technique."}, {"text": "Cushioned, energy-returning soles help runners push off the ground with less wasted [effort]."}]}, "tf": {"enabled": true, "questions": [{"statement": "Streamlined swimwear is designed to reduce drag so a swimmer can hold a faster pace.", "answer": true, "explain": "Low-drag, close-fitting racing suits reduce resistance moving through water, letting a swimmer hold a faster pace for longer."}, {"statement": "A carbon-fibre racket is heavier than an old wooden racket, which is why it improves performance.", "answer": false, "explain": "It is the opposite — carbon fibre is lighter and stiffer than wood, giving more power and control with less arm fatigue."}, {"statement": "GPS trackers mainly measure a player''s distance covered and effort during a session.", "answer": true, "explain": "GPS vests record distance, speed and effort so a coach can plan training load — that is their main use."}, {"statement": "Video analysis is used to spot technical faults a performer cannot feel themselves.", "answer": true, "explain": "Slowing footage down lets a coach see a specific fault, such as a start position or swing plane, that the performer cannot feel while doing it."}, {"statement": "Any equipment worn during a match, including a padded headguard, counts as technology that enhances performance.", "answer": false, "explain": "A headguard''s main job is protecting the performer, not improving their performance — that makes it safety technology, not performance technology."}, {"statement": "Naming a piece of technology without linking it to an effect on performance is usually enough to earn full marks.", "answer": false, "explain": "Naming alone earns little. Marks come from linking the named technology to its specific effect on performance (lighter, stiffer, more aerodynamic, or better data)."}]}, "misc": {"enabled": true, "items": [{"myth": "Any new piece of sports equipment counts as ''technology to enhance performance'', including things like padded headguards or shin pads.", "truth": "This topic is specifically about equipment, clothing or data that helps a performer produce a BETTER performance (more speed, power, accuracy or improved technique) — not equipment whose main job is protecting the performer from injury. A shin pad protecting a footballer is safety technology, not performance technology, even though it is worn during a match. Keep the two ideas separate in an exam answer.", "check": {"question": "A boxer wears a padded headguard during sparring. Which type of technology is this?", "options": ["Performance technology, because every headguard is specifically designed to increase the accuracy of each punch thrown", "Safety technology, because its main purpose is to protect the boxer rather than improve performance", "Officiating technology, because referees use it to help decide who has won a bout", "Spectator technology, because it helps the crowd see the fight more clearly from their seats"], "answer": 1, "explain": "A headguard''s main purpose is protecting the boxer, so it is safety technology — it is not mainly about accuracy, officiating, or the spectator''s view."}}, {"myth": "Writing ''technology helps performance'' is enough to answer a question on this topic.", "truth": "A vague answer like that earns almost nothing. You must name the actual technology or equipment (for example a carbon-fibre racket, or a GPS vest), the sport it is used in, and the specific effect it has (lighter, so less arm fatigue and more power). Point + named example + effect is what the mark scheme rewards.", "check": {"question": "Which answer would earn the most marks on this topic?", "options": ["''Technology helps sport a lot these days in many different ways.''", "''Equipment is important because absolutely everybody uses some kind of equipment whenever they play any sport at all.''", "''Athletes today have access to a very large amount of modern sporting technology.''", "''Carbon-fibre tennis rackets are lighter and stiffer, giving players more power with less arm fatigue.''"], "answer": 3, "explain": "The last answer names a real technology, links it to a mechanism (lighter/stiffer) and a specific effect (more power). The others are vague statements that name nothing specific."}}, {"myth": "GPS trackers and video analysis are only used to measure fitness, never to improve technique.", "truth": "GPS data mainly tracks physical output (distance, speed, effort) so coaches can manage training load — but video analysis is used specifically to improve TECHNIQUE, by spotting faults a performer cannot feel themselves. The two tools do different jobs: one is about physical workload, the other about movement quality.", "check": {"question": "What is the key difference between GPS data and video analysis in training?", "options": ["GPS mainly tracks physical output; video analysis mainly targets technique", "There is no real difference at all — the two tools do exactly the same job", "GPS is only used in swimming, while video analysis is only used in football", "Video analysis measures distance covered, while GPS measures technique quality"], "answer": 0, "explain": "GPS tracks physical workload (distance, speed, effort); video analysis targets technique by spotting faults. They are not identical, not sport-locked, and not swapped round."}}]}, "tips": {"enabled": true, "items": [{"title": "Command words and mark tariffs for this topic", "html": "<p>Technology questions are usually short recall or short explain. Match your answer length to the command word:</p>\n<ul>\n<li><strong>Identify / State</strong> — just name the technology or equipment. \"Identify one piece of equipment used to enhance performance [1]\" = one named item, nothing more.</li>\n<li><strong>Describe</strong> — say what the technology is or does, in your own words, without necessarily explaining why it helps.</li>\n<li><strong>Explain</strong> — give the mechanism. Use the chain: named technology → named sport → the specific effect on performance (speed, power, control or technique).</li>\n</ul>\n<p><strong>Read the mark tariff:</strong> [1] wants one point; [2] usually wants a named example plus one linked effect; [4] wants two developed examples, each with its own effect.</p>", "check": {"question": "A question says ''Explain how one piece of equipment enhances performance [2]''. What earns both marks?", "options": ["Naming a general sport without describing any specific piece of equipment at all", "Listing as many different pieces of equipment as you can possibly think of", "Naming the equipment, then linking it to a specific effect on performance", "Describing how much the equipment usually costs to buy in a shop"], "answer": 2, "explain": "Explain [2] wants the named equipment linked to its effect on performance — a general sport name, a long list, or the cost do not earn these marks."}}, {"title": "Where this appears in the exam + sentence starters", "html": "<p><strong>Where it shows up:</strong> this topic appears as quick recall in <strong>Section A</strong> (identify/state a technology), and as an applied point in <strong>Section B</strong> scenarios about a named performer or team wanting to improve. It can also feed a <strong>Section C</strong> 8-mark answer discussing technology''s overall impact.</p>\n<p><strong>Sentence starters for a longer answer:</strong></p>\n<ul>\n<li>\"One piece of technology that enhances performance is… because…\"</li>\n<li>\"This helps the performer because it… which means…\"</li>\n<li>\"However, the same technology only helps if…\"</li>\n</ul>", "check": {"question": "In a Section B scenario about a named athlete, your equipment example should come from...", "options": ["the scenario you are given, applied to that athlete''s situation", "any sport you personally enjoy watching at the weekend", "a piece of equipment you happen to own yourself", "a famous athlete who is never actually mentioned anywhere in the question"], "answer": 0, "explain": "Section B is applied — the marks are for using the scenario in front of you, not a general example unconnected to it."}}, {"title": "Three habits that lift a performance-technology answer", "html": "<p>Three punchy tips:</p>\n<ul>\n<li>Always name a <strong>real sport</strong> alongside the technology — \"swimwear\" on its own is vague; \"low-drag racing suits in competitive swimming\" is precise.</li>\n<li>State the <strong>effect</strong>, not just the object: lighter, stiffer, or more aerodynamic → less wasted effort/drag → faster, more powerful or more accurate performance.</li>\n<li>Keep this topic separate from safety, officiating and spectator technology — here, the technology''s job is specifically to make the performer BETTER, not safer or better refereed.</li>\n</ul>", "check": {"question": "Which of these best fits THIS topic (technology to enhance performance)?", "options": ["A carbon-fibre racket that is lighter and stiffer, giving more power and control", "A big screen that lets stadium spectators watch a controversial decision replayed", "A padded headguard that protects a boxer''s head during sparring sessions", "A video-review system that helps a referee confirm a marginal decision"], "answer": 0, "explain": "A lighter, stiffer racket improves the performer''s power and control — the other options are spectator, safety and officiating technology, covered on other pages."}}]}, "exam": {"enabled": true, "questions": [{"question": "State one piece of technology, equipment or clothing used to enhance performance in a named sport, and explain the effect it has on performance.", "marks": 2, "hint": "Name something specific (not just ''equipment'') and a named sport, then say exactly what it does — lighter, stiffer, more aerodynamic, or gives better data — and how that helps performance.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks (AO1/AO2)</h5>\n<p><strong>1 mark for naming a specific piece of technology, equipment or clothing linked to a named sport; 1 mark for explaining an effect that matches it, such as:</strong></p>\n<ul>\n<li>Streamlined/aerodynamic clothing (e.g. swimming, cycling, skiing) — reduces drag, so faster movement for the same effort.</li>\n<li>Lighter/stiffer equipment (e.g. rackets, bikes, footwear) — less wasted effort, more power/control.</li>\n<li>GPS trackers or video analysis — provides data or footage that identifies a training or technique improvement.</li>\n</ul>\n<p>Accept any other valid, named technology with a matching effect.</p>\n</div>"}, {"question": "Which of these is an example of technology used to <strong>enhance performance</strong>?", "marks": 1, "hint": "Think about which option is about improving performance, not safety, officiating or spectators.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: B — A GPS vest that records a footballer''s distance and sprint speed in training.</strong></p>\n<ul>\n<li>GPS data is used to inform training decisions and improve performance.</li>\n<li>The big screen, headguard and video-review system are spectator, safety and officiating technology — covered elsewhere.</li>\n</ul>\n</div>"}, {"question": "Explain how <strong>two</strong> different pieces of sporting technology could help Priya improve her performance.", "marks": 4, "hint": "Pick two DIFFERENT types of technology (for example clothing, and a data or video tool). For each, name it, then explain its specific effect on Priya''s performance, using details from the scenario.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (AO2: application)</h5>\n<p><strong>Up to 2 marks per technology: 1 for naming a technology relevant to sprinting, 1 for an effect that uses the scenario. Answers may include:</strong></p>\n<ul>\n<li><strong>Streamlined/lightweight racing kit</strong> — replacing Priya''s loose kit would reduce air resistance and help her hold a faster pace over the short sprint distance.</li>\n<li><strong>Video analysis</strong> — filming her races and slowing the footage down would let her coach spot a specific fault in her start or technique, instead of relying on how the session \"feels\".</li>\n<li><strong>GPS/timing data</strong> — would let the coach measure her sprint speed accurately and track whether training is actually improving it.</li>\n</ul>\n<p>Accept any other reasonable, applied answer. A named technology with no scenario-linked effect earns 1 of the 2 marks for that item.</p>\n</div>"}, {"question": "Discuss how far technology, equipment and clothing can improve the performance of Kelso Harriers'' sprint squad.", "marks": 8, "hint": "Cover more than one type of technology and explain how each genuinely helps performance. Then weigh up the limits — cost, whether every athlete benefits equally, whether hard training still matters most — before giving a judgement.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 8 marks (level-of-response). Read the band you fit, then pick a mark.</h5>\n<ul>\n<li><strong>Band 3 (thorough), 6–8:</strong> a balanced, well-applied discussion of several technologies (clothing, equipment, data/video), showing clearly HOW each raises performance, AND weighing genuine limits (cost, uneven benefit across the squad, technology not replacing training or effort), ending in a justified judgement.</li>\n<li><strong>Band 2 (reasonable), 3–5:</strong> sound understanding applied to more than one technology with some analysis, but the discussion may be one-sided or the judgement unsupported.</li>\n<li><strong>Band 1 (basic), 1–2:</strong> names technologies with little application and no real evaluation; largely a list.</li>\n<li><strong>0 marks:</strong> nothing creditworthy.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Indicative content (indicative, not a checklist — reward valid alternatives)</h5>\n<ul>\n<li><strong>Streamlined/lightweight kit:</strong> reduces drag and fatigue, directly raising sprint speed.</li>\n<li><strong>GPS trackers:</strong> give the coach real data on distance, speed and effort, so training load can be planned precisely instead of guessed.</li>\n<li><strong>Video analysis:</strong> lets the coach spot a specific technical fault (e.g. a slow start) an athlete cannot feel themselves, and correct it.</li>\n<li><strong>Evaluation:</strong> these tools only help if the club can afford them and the coach is trained to use the data; technology cannot replace natural ability, sound coaching or the athlete''s own training effort; benefits may be uneven across a squad, since different athletes need different support.</li>\n<li><strong>Judgement:</strong> technology can meaningfully improve performance because it removes small inefficiencies (drag, fatigue, unseen technical faults) a coach could otherwise miss — but it only works alongside good coaching, not instead of it.</li>\n</ul>\n</div>"}]}}'::jsonb),
('sport-studies', '5-1-2-technology-to-increase-safety', '5.1.2 Technology to Increase Safety', '{"learn": {"enabled": true, "items": [{"title": "Why sport invests in safety technology", "html": "<h4>One of four jobs technology does in sport</h4>\n<ul>\n<li>Technology in sport is usually built for one of four jobs: making performers <strong>better</strong>, keeping performers <strong>safer</strong>, helping officials be <strong>fairer and more accurate</strong>, or making the experience for <strong>spectators</strong> better.</li>\n<li>This page is only about the <strong>safety</strong> job — technology that lowers the chance of a performer getting hurt, or lowers how bad an injury turns out to be. The other three jobs are covered elsewhere and should not be mixed into an answer here.</li>\n</ul>\n<h4>Three broad kinds of safety technology</h4>\n<ul>\n<li><strong>Protective equipment</strong> worn by the performer — helmets, padding, mouthguards and similar items that absorb or block a force before it reaches the body.</li>\n<li><strong>Playing surfaces and equipment design</strong> — pitches, tracks, mats and landing areas engineered so that a fall or a collision does less damage.</li>\n<li><strong>Medical and monitoring technology</strong> — devices that detect an injury (such as a head impact) or track a performer''s condition so problems are caught before they get serious.</li>\n</ul>\n<h4>Why it matters</h4>\n<ul>\n<li>A serious injury can end a performer''s career, and repeated injuries damage trust in a sport. Safety technology lets performers compete and train with a lower level of risk than they otherwise would face.</li>\n</ul>", "check": {"question": "Which of these best describes what ''safety technology'' does in sport?", "options": ["Helps spectators see the action more clearly on a big screen inside a stadium", "Lowers the chance or the severity of an injury to a performer", "Helps officials reach faster, more accurate decisions during a contest", "Helps a performer train harder so they can beat a personal best"], "answer": 1, "explain": "Safety technology is aimed at reducing the likelihood or severity of injury. Spectator viewing, officiating accuracy and performance gains are the other three jobs technology does — not this one."}}, {"title": "Protective equipment and safer playing surfaces", "html": "<h4>Protective equipment: helmets, padding, mouthguards</h4>\n<ul>\n<li><strong>Helmets</strong> use a hard outer shell and an energy-absorbing liner to spread and reduce the force of an impact before it reaches the skull. Cycling helmets protect a rider''s head in a fall; cricket helmets add a steel or titanium grille to protect the face from a fast-bowled ball; American football helmets combine a shell with a face cage for collision sport.</li>\n<li><strong>Padding</strong> cushions a specific body part. Hockey and football players wear shin pads; cricket wicketkeepers and batters wear pads and body armour; motorsport drivers wear fire-resistant padded race suits.</li>\n<li><strong>Mouthguards / gum shields</strong> are moulded to a performer''s teeth and cushion the jaw and teeth from an impact. They are common in boxing, rugby and hockey. Some newer mouthguards also contain a sensor — that use is covered in the next card.</li>\n<li><strong>Exam note:</strong> protective equipment mostly <em>absorbs or cushions</em> a force. It reduces certain injuries (cuts, broken teeth, fractures) but does not remove every risk — a scrum cap, for example, gives little protection against concussion.</li>\n</ul>\n<h4>Safer playing surfaces and equipment design</h4>\n<ul>\n<li>Many football and hockey clubs have replaced old, hard artificial pitches with modern <strong>3G/4G surfaces</strong>, which use a cushioned rubber-crumb layer under the fibres to reduce the impact on a player''s joints when they fall or land badly.</li>\n<li>Athletics tracks now use a springy, shock-absorbing surface rather than hard cinder, and events like high jump and pole vault use deep <strong>crash mats or landing airbags</strong> so a fall from height does not cause serious injury.</li>\n<li>Gymnastics uses sprung floors and thick crash mats for the same reason, and some pitches use padded goalposts or posts to reduce injury from a collision.</li>\n</ul>", "check": {"question": "What is the main safety purpose of a mouthguard worn in boxing or rugby?", "options": ["To cushion the jaw and teeth from the force of a blow to the head or face", "To let the referee check a player''s identity before a contest begins", "To help a coach analyse exactly how hard a player has been training that particular week", "To make a fast decision on a disputed refereeing call during a match"], "answer": 0, "explain": "A mouthguard is moulded to a performer''s teeth and cushions the jaw and teeth from an impact. It has nothing to do with identity checks, training analysis or officiating decisions."}}, {"title": "Detecting concussion and monitoring player welfare", "html": "<h4>Detecting a head injury</h4>\n<ul>\n<li>Some rugby union teams now fit a sensor inside a scrum cap or mouthguard. The sensor measures the <strong>force of a blow to the head</strong> and sends an alert to side-line medical staff so they know to check that player straight away, rather than waiting for the player to report symptoms themselves.</li>\n<li>Sport also uses a structured, timed <strong>pitch-side head-injury assessment</strong> — medical staff use a fixed set of checks to judge whether a player who has taken a blow can safely return to play, instead of relying on a quick, informal look.</li>\n</ul>\n<h4>Medical and monitoring technology</h4>\n<ul>\n<li>Endurance athletes and team-sport players often train and compete wearing a <strong>heart-rate monitor and GPS vest</strong>. These track how hard a performer is working, so a coach can spot overtraining or fatigue building up and adjust a session before it causes an injury.</li>\n<li>In motorsport, Formula 1 drivers wear a <strong>HANS device</strong> (a rigid frame linking the helmet to the shoulders) which restrains the head and neck and reduces whiplash-type injury in a high-speed crash. Some race suits and gloves also carry biometric sensors that tell medical staff a driver''s condition seconds after an impact.</li>\n</ul>\n<h4>Exam skill: name the sport AND the specific benefit</h4>\n<ul>\n<li>A weak answer says \"technology helps safety.\" A strong answer names the technology, the sport, and exactly what it protects against or detects — for example, \"an instrumented mouthguard in rugby union measures head-impact force and alerts side-line staff to check the player.\"</li>\n</ul>", "check": {"question": "A sensor fitted inside a rugby player''s mouthguard is mainly used to...", "options": ["broadcast the player''s exact heart rate live to supporters in the stadium", "measure the force of a head impact and alert side-line staff to check the player", "automatically award a penalty against the opposing team whenever an illegal tackle occurs in play", "record tackle numbers purely so they can be used in a highlights programme"], "answer": 1, "explain": "Instrumented mouthguards measure head-impact force and flag it to side-line medical staff — a safety use. Awarding penalties is an officiating job, not a safety one, and the sensor is not a heart-rate or highlights tool."}}]}, "terms": {"enabled": true, "pairs": [{"term": "Safety technology", "definition": "Technology designed to reduce the likelihood or severity of injury to performers"}, {"term": "Instrumented mouthguard", "definition": "Sensor-fitted mouthguard measuring head-impact force, alerting side-line staff"}, {"term": "Shock-absorbing helmet", "definition": "Headwear with an energy-absorbing liner that lowers force reaching the skull"}, {"term": "3G/4G playing surface", "definition": "Artificial pitch with a cushioned layer that reduces impact on joints"}, {"term": "HANS device", "definition": "Motorsport equipment restraining the head and neck in a high-speed crash"}, {"term": "Heart-rate / GPS monitor", "definition": "Wearable tracking workload so fatigue or overtraining is caught early"}]}, "mcq": {"enabled": true, "questions": [{"question": "What is the best definition of ''safety technology'' in sport?", "options": ["Technology that helps officials make faster and more accurate decisions during a contest", "Technology that gives spectators a clearer view of the action inside a stadium", "Technology designed to reduce the likelihood or severity of injury to participants", "Technology that helps a performer train harder and shave time off a personal best"], "answer": 2, "explain": "Safety technology is aimed at reducing the likelihood or severity of injury. Faster officiating decisions, a clearer spectator view and improved performance are the other three jobs technology can do, not this one."}, {"question": "Rugby and boxing performers often wear a mouthguard. What is its main safety purpose?", "options": ["To let the referee check a player''s identity before a contest begins", "To cushion the jaw and teeth from the force of a blow to the head or face", "To help a coach analyse how hard a player has been training that week", "To help review a disputed refereeing decision in slow motion after the match"], "answer": 1, "explain": "A mouthguard is moulded to a performer''s teeth and cushions the jaw and teeth from a blow. Identity checks, training analysis and reviewing decisions are unrelated jobs."}, {"question": "Why have many football and hockey clubs replaced old hard artificial pitches with modern 3G/4G surfaces?", "options": ["The synthetic fibres are a more consistent shade of green than a real grass pitch", "It lets a video review system display replays on a big screen beside the pitch", "It guarantees that no match is ever postponed for any reason at any time of year", "The cushioned rubber-crumb layer reduces the impact on joints when a player falls"], "answer": 3, "explain": "The cushioned layer under a 3G/4G pitch reduces the impact on a falling player''s joints — that is the safety benefit. Pitch colour, replay screens and never postponing matches are not why clubs make the change."}, {"question": "Some rugby union teams fit sensors inside a scrum cap or mouthguard. What do these sensors mainly do?", "options": ["Measure the force of a blow to the head and alert side-line staff to check the player", "Automatically award a penalty against the other team whenever an illegal high tackle occurs", "Broadcast a player''s exact heart rate live to supporters watching in the stadium", "Record the number of tackles a player makes purely for a post-match highlights reel"], "answer": 0, "explain": "These sensors measure head-impact force and flag it to side-line medical staff so the player can be checked. Awarding penalties is an officiating job; the sensors are not heart-rate monitors or highlights tools."}, {"question": "Why might an endurance athlete train wearing a heart-rate monitor and GPS vest?", "options": ["So a match official can check the athlete has not started running before the whistle", "So spectators at home can follow a live leaderboard of split times during a broadcast", "So coaches can spot overtraining or fatigue early and adjust the session before injury occurs", "So a governing body can confirm the exact make, model and size of the athlete''s footwear before every race begins"], "answer": 2, "explain": "A heart-rate monitor and GPS vest track workload so a coach can catch overtraining or fatigue before it causes an injury. Checking a false start, entertaining spectators and confirming footwear are unrelated uses."}, {"question": "In Formula 1, what is the main safety purpose of the HANS device worn by drivers?", "options": ["To let race stewards review a start-line incident in extra slow motion after a race", "To restrain the head and neck and reduce whiplash-type injury in a high-speed crash", "To increase the top speed a car can reach on the longest straight of a circuit", "To give TV commentators live data on a driver''s exact heart rate throughout a race"], "answer": 1, "explain": "The HANS device links the helmet to the shoulders and restrains the head and neck, reducing whiplash-type injury in a crash. Reviewing incidents, increasing speed and broadcasting heart-rate data are not its job."}]}, "fib": {"enabled": true, "questions": [{"text": "Cricket and American football helmets use a reinforced shell to reduce the [force] of a blow reaching the head."}, {"text": "Modern 3G/4G pitches use a shock-absorbing layer to reduce the impact on a falling player''s [joints]."}, {"text": "An instrumented mouthguard can measure the force of a head impact and alert [side-line] medical staff."}, {"text": "In Formula 1, the HANS device restrains the head and [neck] during a high-speed crash."}, {"text": "A heart-rate and GPS monitor helps a coach spot [fatigue] before it leads to injury."}]}, "tf": {"enabled": true, "questions": [{"statement": "Safety technology in sport is designed to reduce the likelihood or severity of injury.", "answer": true, "explain": "That is the whole point of safety technology — lowering the chance of injury happening, or how serious it turns out to be, for the performer."}, {"statement": "A rugby scrum cap gives a player full protection against concussion.", "answer": false, "explain": "A scrum cap mainly reduces cuts and abrasions from soft padding — it gives little protection against concussion, which is exactly why sport also uses separate impact-detecting technology."}, {"statement": "Modern 3G/4G pitches are used partly because their shock-absorbing layer reduces impact on a player''s joints.", "answer": true, "explain": "The cushioned rubber-crumb layer under a 3G/4G pitch is a genuine safety benefit, reducing joint impact compared with older, harder artificial surfaces."}, {"statement": "An instrumented mouthguard''s main job is to help a coach plan the following season''s training fixtures.", "answer": false, "explain": "Its job is to measure the force of a head impact and alert side-line staff so the player can be checked — nothing to do with planning a fixture list."}, {"statement": "The HANS device used in Formula 1 helps restrain a driver''s head and neck during a crash.", "answer": true, "explain": "The HANS device links the helmet to the shoulders, restraining the head and neck and reducing whiplash-type injury in a high-speed crash."}, {"statement": "Heart-rate and GPS monitoring technology is mainly used to give spectators live entertainment statistics.", "answer": false, "explain": "Its main safety use is tracking a performer''s workload so a coach can catch fatigue or overtraining before it causes injury — any spectator use is a different job of technology."}]}, "misc": {"enabled": true, "items": [{"myth": "Any padding a performer wears counts as the same kind of safety technology as an instrumented mouthguard.", "truth": "They do two different jobs. Protective equipment (helmets, pads, mouthguards, padded goalposts) mostly ABSORBS or CUSHIONS a force before it does damage. Detection and monitoring technology (an instrumented mouthguard''s sensor, a heart-rate/GPS monitor) does not stop the force — it DETECTS an impact, or tracks a condition, and alerts someone. A strong answer says which job a piece of technology is actually doing.", "check": {"question": "What is the key difference between protective equipment and detection/monitoring technology?", "options": ["There is no real difference between the two types of technology at all", "Protective equipment cushions a force; monitoring technology detects and alerts staff instead", "Protective equipment is only ever used by professional motorsport teams, never in any other sport", "Monitoring technology removes the need for a performer to ever wear protective equipment again"], "answer": 1, "explain": "One kind reduces the force reaching the body; the other kind detects a problem (an impact, or a worrying condition) and flags it, rather than physically absorbing anything."}}, {"myth": "Once a rugby player is wearing a scrum cap or mouthguard, head injury basically stops being a risk.", "truth": "Protective gear cushions certain impacts (cuts, jaw and tooth injury) but does not remove concussion risk. That is exactly why sport ALSO uses separate detection technology — impact sensors and structured pitch-side head-injury checks — as well as protective gear. Equipment and detection technology work together; neither one on its own makes a performer fully safe.", "check": {"question": "Why does sport use head-impact sensors and pitch-side checks as well as protective headwear?", "options": ["Because protective headwear alone does not remove the risk of concussion", "Because protective headwear has been banned completely in most contact sports now", "Because sensors are only ever used to replace worn-out scrum caps", "Because pitch-side checks are required only for spectators, not players"], "answer": 0, "explain": "Protective gear reduces some injuries but does not eliminate concussion risk, so detection technology and structured checks are used alongside it, not instead of it."}}, {"myth": "Because this topic is about technology and safety, goal-line technology and video review are good examples to use in an answer here.", "truth": "Goal-line technology and video review help an OFFICIAL make a fair, accurate decision — that is a different job of technology from SAFETY. Using them in a safety-technology answer describes the wrong page''s content and will not earn the marks. Keep officiating examples (like video review) out of a question specifically about safety.", "check": {"question": "Why would goal-line technology be the wrong example to use in a question specifically about safety technology?", "options": ["It does not exist in real sport", "It is officiating technology, aimed at fair and accurate decisions, not safety", "It is too expensive for most amateur clubs to install and maintain properly", "It has exactly the same safety purpose in every sport as an instrumented mouthguard"], "answer": 1, "explain": "Goal-line technology supports officiating decisions, not player safety, so using it as a safety example answers a different question and would not be credited here."}}]}, "tips": {"enabled": true, "items": [{"title": "Command words for this topic — what each one wants", "html": "<p>Safety-technology questions are usually short recall or short application. Match your answer length to the command word:</p>\n<ul>\n<li><strong>Identify / State</strong> — just name it. \"State one piece of technology used to increase safety\" = one named example, nothing more. 1 mark.</li>\n<li><strong>Describe</strong> — say what it is or does. \"Describe how an instrumented mouthguard increases safety\" = explain what the sensor detects.</li>\n<li><strong>Explain</strong> — give a reason, using the word <em>because</em>. \"Explain why a 3G pitch is safer than an old artificial pitch\" = the feature <em>plus</em> the injury it reduces.</li>\n</ul>\n<p><strong>Read the mark tariff:</strong> [1] wants one named example; [2–4] wants the example PLUS how it works or why it helps; higher tariffs in Section B/C want it applied to a named sport or scenario.</p>", "check": {"question": "A question says: ''Identify one piece of technology that can increase safety in sport [1]''. What is the safest answer?", "options": ["A full paragraph explaining several different technologies", "One named piece of technology", "A list of every safety technology you can remember", "An explanation of how officiating technology works instead"], "answer": 1, "explain": "''Identify'' + [1] wants one named example. A long explanation, a long list, or an officiating example all waste the mark or answer the wrong question."}}, {"title": "The golden rule: name the sport AND the specific safety benefit", "html": "<p>The most common way to lose marks here is staying vague. Build every answer as <strong>technology → sport → specific benefit</strong>:</p>\n<ul>\n<li><strong>❌ 0–1 marks:</strong> \"Technology makes sport safer.\"</li>\n<li><strong>✅ full marks:</strong> \"An instrumented mouthguard in rugby union measures the force of a head impact and alerts side-line staff to check the player.\"</li>\n</ul>\n<p>In <strong>Section B</strong> you will usually be given a scenario. Use a detail <em>from that scenario</em> — the sport it names, the problem it describes — rather than a generic example.</p>", "check": {"question": "In a Section B scenario about a specific club or sport, your safety-technology example should come from...", "options": ["any sport you happen to prefer, regardless of the scenario", "the scenario you are actually given", "a piece of officiating technology instead", "a technology that improves performance rather than safety"], "answer": 1, "explain": "Section B rewards applying your knowledge to the scenario given, not a generic or unrelated example."}}, {"title": "Where this topic appears + sentence starters", "html": "<p><strong>Where it shows up:</strong> safety technology appears as quick recall in <strong>Section A</strong> (name a technology, name a benefit), as an applied point in <strong>Section B</strong> scenarios about a club or performer, and it can feed a <strong>Section C</strong> discussion on how effective technology has been for a sport overall.</p>\n<p><strong>Three punchy tips:</strong></p>\n<ul>\n<li>Keep a mental list of three types: protective equipment, safer surfaces/equipment design, and detection/monitoring technology — you can always pull an example from one of the three.</li>\n<li>Never let a safety answer drift into officiating (video review, goal-line technology) — that is a different page''s content and will not be credited.</li>\n<li>Remember protective equipment reduces some injuries but does not remove all risk — that is a strong evaluation point for a longer answer.</li>\n</ul>\n<p><strong>Sentence starters for a longer answer:</strong></p>\n<ul>\n<li>\"One way technology increases safety in this sport is… because…\"</li>\n<li>\"This matters because, without it, a performer would risk…\"</li>\n<li>\"However, this technology does not remove every risk, because…\"</li>\n</ul>", "check": {"question": "Why is ''protective equipment reduces some injuries but not all risk'' a useful evaluation point?", "options": ["It shows understanding that safety technology has real limits, not just benefits", "It proves that safety technology should never be used in any sport at all, under any circumstances", "It fills space without adding anything useful to the answer", "It replaces the need to name any technology in the answer"], "answer": 0, "explain": "Noticing the limits of a technology (not just its benefit) shows deeper understanding — exactly the kind of point that lifts a Section C answer beyond a simple list."}}]}, "exam": {"enabled": true, "questions": [{"question": "State <strong>two</strong> different pieces of technology that can be used to increase the safety of participants in sport.", "marks": 2, "hint": "Name two — pick from protective equipment, safer surfaces/equipment design, or detection/monitoring technology (for example an instrumented mouthguard, a 3G pitch, a HANS device).", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks (AO1)</h5>\n<p><strong>1 mark for each correct piece of safety technology named, to a maximum of two. Accept any two different examples, including:</strong></p>\n<ul>\n<li>A protective helmet (cycling, cricket, American football)</li>\n<li>Padding (shin pads, body armour, a padded race suit)</li>\n<li>A mouthguard / gum shield</li>\n<li>An instrumented mouthguard / head-impact sensor</li>\n<li>A shock-absorbing 3G/4G playing surface</li>\n<li>A crash mat or landing airbag</li>\n<li>A heart-rate or GPS monitor</li>\n<li>A HANS device</li>\n</ul>\n<p>Do not credit the same example written twice, and do not credit officiating or spectator technology.</p>\n</div>"}, {"question": "Which piece of technology mainly reduces the force reaching a cyclist''s skull in a fall?", "marks": 1, "hint": "Think about which item is worn on the head and physically absorbs an impact.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: B — A shock-absorbing cycling helmet.</strong></p>\n<ul>\n<li>The helmet''s outer shell and liner absorb and spread the force of a fall, reducing what reaches the skull.</li>\n<li>A GPS/heart-rate monitor and a video replay screen do not absorb any force, and a mouthguard protects the jaw and teeth, not the skull.</li>\n</ul>\n</div>"}, {"question": "Explain how <strong>two</strong> different pieces of technology could help increase the safety of players at Ashcombe Rugby Club.", "marks": 4, "hint": "Pick one piece of protective equipment and one detection/monitoring technology. For each, say what it does and how it meets the club''s problem in the scenario (protection during play, and spotting a head injury quickly).", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (AO2: application)</h5>\n<p><strong>Up to 2 marks per technology: 1 for naming a relevant technology, 1 for explaining how it meets the club''s problem using the scenario. Answers may include:</strong></p>\n<ul>\n<li><strong>Protective equipment</strong> — a well-fitted scrum cap and mouthguard would cushion impacts to the head and face during matches, reducing cuts and jaw/teeth injuries (though not removing all head-injury risk).</li>\n<li><strong>Detection technology</strong> — an instrumented mouthguard or scrum-cap sensor would measure the force of any head impact and alert side-line staff immediately, so a player showing warning signs is checked straight away rather than staying on the pitch.</li>\n</ul>\n<p>Accept any other reasonable, applied answer (e.g. a structured pitch-side head-injury check). A technology named with no link to the scenario earns 1 of the 2 marks for that item.</p>\n</div>"}, {"question": "Discuss how effective the use of technology has been in increasing the safety of participants in a sport such as rugby union.", "marks": 8, "hint": "Cover more than one type of technology (protective equipment AND detection/monitoring). For each, say what it achieves, then weigh up its limits. Finish with a judgement on how effective technology really is overall.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 8 marks (level-of-response). Read the band you fit, then pick a mark.</h5>\n<ul>\n<li><strong>Band 3 (thorough), 6–8:</strong> a balanced, well-applied discussion of more than one type of safety technology, showing clearly how each increases safety AND weighing its real limits, ending in a justified judgement.</li>\n<li><strong>Band 2 (reasonable), 3–5:</strong> sound understanding applied to more than one technology with some analysis, but the discussion may be one-sided or the judgement unsupported.</li>\n<li><strong>Band 1 (basic), 1–2:</strong> names technology with little explanation and no real evaluation; largely a list.</li>\n<li><strong>0 marks:</strong> nothing creditworthy.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Indicative content (indicative, not a checklist — reward valid alternatives)</h5>\n<ul>\n<li><strong>Protective equipment (scrum caps, mouthguards, padding):</strong> cushions impacts and reduces cuts, fractures and jaw/teeth injury during a collision-heavy sport.</li>\n<li><strong>Detection/monitoring technology (instrumented mouthguards, pitch-side head-injury checks):</strong> catches a head impact or worrying symptom quickly, so a player is not left on the pitch after a serious blow.</li>\n<li><strong>Safer surfaces/equipment design:</strong> a well-maintained, shock-absorbing surface reduces the impact of a heavy fall or tackle.</li>\n<li><strong>Evaluation:</strong> protective equipment does not remove concussion risk on its own, so it works best alongside detection technology; monitoring only helps if staff act on the alert; smaller or lower-budget clubs may not be able to afford every piece of technology, limiting how far the benefit reaches.</li>\n<li><strong>Judgement:</strong> technology is genuinely effective because it both reduces certain impacts AND catches head injuries faster than relying on a player self-reporting — but it is not a complete solution, since no piece of equipment removes all risk, and its benefit depends on being affordable and actually used correctly by every club.</li>\n</ul>\n</div>"}]}}'::jsonb),
('sport-studies', '5-1-3-technology-and-officiating', '5.1.3 Technology and Officiating', '{"learn": {"enabled": true, "items": [{"title": "Video review technology: giving officials a second look", "html": "<h4>What it does</h4>\n<ul>\n<li>Video review technology lets officials pause and study a <strong>replay</strong> of a contentious moment, often in slow motion and from more than one camera angle, instead of relying only on what they saw live at full speed.</li>\n<li>This matters because live sport moves fast — a single glance from one angle can miss a foul, an offside position, or contact that happened out of sight.</li>\n</ul>\n<h4>Named examples you must know</h4>\n<ul>\n<li><strong>TMO (Television Match Official)</strong> in rugby union — an off-field official who watches video feeds and advises the referee on tries and serious foul play.</li>\n<li><strong>VAR (Video Assistant Referee)</strong> in football — a team of officials who review footage of goals, penalties, red cards and mistaken identity, then advise the referee, who still makes the final decision.</li>\n<li><strong>DRS (Decision Review System)</strong> in cricket — lets a player formally challenge an umpire''s decision (such as lbw or a catch), which is then checked using replays and ball-tracking data.</li>\n</ul>\n<h4>Why it increases fair play</h4>\n<ul>\n<li>It gives officials extra recorded evidence before a big decision is finalised, so a mistake made at normal speed can be corrected.</li>\n<li>Players and fans can see that a decision was checked properly, which builds trust that the result was fair.</li>\n</ul>", "check": {"question": "What is the main purpose of video review technology such as VAR or the TMO?", "options": ["To let officials check a contentious decision using recorded replay footage before it is finalised", "To automatically overturn any refereeing decision the instant a TV camera happens to catch a replay of it", "To replace the referee completely so that no human ever has to make a decision during a match", "To slow every match down by pausing play the moment any fan on social media disagrees with a call"], "answer": 0, "explain": "Video review gives officials extra recorded evidence to check a decision — it does not remove the referee, and no decision is made automatically or by outside fans."}}, {"title": "Goal-line and ball-tracking technology: proving exactly where the ball went", "html": "<h4>What it does</h4>\n<ul>\n<li>Goal-line technology uses cameras or sensors positioned around the goal to detect the exact moment the whole ball crosses the line, sending an instant signal to the referee''s watch.</li>\n<li>Ball-tracking technology follows the path of a ball across many camera frames per second and can show precisely where it landed or where it was heading.</li>\n</ul>\n<h4>Named examples</h4>\n<ul>\n<li><strong>Goal-line technology</strong> in football — confirms whether a goal should be given when the ball crosses the line at speed and players'' bodies block the officials'' view.</li>\n<li><strong>Hawk-Eye (ball-tracking)</strong> in tennis — shows whether a serve or shot landed inside or outside the line when a player challenges the call.</li>\n<li><strong>Ball-tracking</strong> in cricket — part of DRS, used to predict the ball''s path and help decide lbw appeals.</li>\n</ul>\n<h4>Why it increases accuracy</h4>\n<ul>\n<li>A ball can cross a line in a fraction of a second — far faster than the human eye can judge reliably from pitch-side or on the baseline.</li>\n<li>Because the technology gives an instant, evidence-based answer, the correct decision is given even in very close, fast-moving situations.</li>\n</ul>", "check": {"question": "Why is goal-line technology needed in football, even though officials are already watching the game?", "options": ["Because the ball can cross the line faster than the human eye can reliably judge when players block the view", "Because a photo-finish camera can only ever be used to separate sprinters at the end of an athletics race, never in football", "Because referees are not permitted to make any decisions at all about goals under the laws of the game", "Because it gives spectators extra time to buy refreshments while officials wait for a signal"], "answer": 0, "explain": "The ball can cross the line too fast for a human to judge reliably, especially when players block the view — goal-line technology exists for exactly that gap, not because referees are banned from deciding goals."}}, {"title": "Electronic timing and measurement: officiating close finishes fairly", "html": "<h4>What it does</h4>\n<ul>\n<li>In sports decided by very small differences in time or distance, electronic timing and measurement systems record results far more precisely than a human with a stopwatch or the naked eye ever could.</li>\n<li>Electronic timing usually starts automatically from the starting gun or blocks and stops the instant a competitor''s body or a touchpad crosses the line, removing human reaction-time error from the recorded result.</li>\n</ul>\n<h4>Named examples</h4>\n<ul>\n<li><strong>Photo-finish cameras</strong> in athletics — take a continuous image of the finish line so officials can separate sprinters who finish within hundredths of a second of one another.</li>\n<li><strong>Electronic touchpads</strong> in swimming — detect the exact moment each swimmer touches the wall, ending any argument over who finished first.</li>\n</ul>\n<h4>Why it increases fair play</h4>\n<ul>\n<li>A human judge glancing at a finish line simply cannot separate athletes who cross within a hundredth of a second of each other — the camera can.</li>\n<li>Because every competitor is timed by the same automatic system, no athlete can be given an unfair advantage or disadvantage by an official''s reaction time.</li>\n</ul>", "check": {"question": "Why do athletics and swimming rely on electronic timing rather than an official''s stopwatch alone?", "options": ["Because electronic timing removes human reaction-time error and can separate finishes within hundredths of a second", "Because a stopwatch is completely banned under the official rules of every athletics and swimming competition in the world", "Because officials are no longer allowed to attend athletics or swimming events once the race has started", "Because it makes each race last considerably longer than it otherwise would without the equipment"], "answer": 0, "explain": "Electronic timing removes human reaction-time error and can separate finishes within hundredths of a second — something a stopwatch or the naked eye cannot do reliably."}}]}, "terms": {"enabled": true, "pairs": [{"term": "VAR (Video Assistant Referee)", "definition": "Reviews goals, penalties, red cards & mistaken identity in football; referee makes the final call"}, {"term": "TMO (Television Match Official)", "definition": "Rugby union off-field official checking tries & serious foul play via video replay"}, {"term": "DRS (Decision Review System)", "definition": "Cricket system letting players challenge umpire calls using replay & ball-tracking"}, {"term": "Goal-line technology", "definition": "Sensors/cameras confirming whether the whole ball crossed the football goal line"}, {"term": "Hawk-Eye (ball-tracking)", "definition": "Camera system tracking a ball''s path in tennis & cricket"}, {"term": "Photo-finish / electronic timing", "definition": "Camera & automatic timing separating athletics/swimming finishes by hundredths of a second"}]}, "mcq": {"enabled": true, "questions": [{"question": "Which of these is something VAR (Video Assistant Referee) checks in football?", "options": ["Whether a player''s boots meet the technical specifications set by the competition organisers", "Goals, penalty decisions, red cards and cases of mistaken identity", "The exact wind speed recorded pitch-side during the match", "How many replacement footballs are stored behind each goal"], "answer": 1, "explain": "VAR reviews goals, penalties, red cards and mistaken identity — it is not used to check equipment, weather or spare footballs."}, {"question": "What does the TMO (Television Match Official) do in rugby union?", "options": ["Sells tickets for international rugby union fixtures at the stadium entrance", "Coaches the players during every break in play by showing them video replays on a pitch-side screen", "Watches video replays and advises the on-field referee about tries and serious foul play", "Times each half of the match using a handheld stopwatch on the touchline"], "answer": 2, "explain": "The TMO is an off-field official who reviews video and advises the referee on tries and serious foul play — not a coach, ticket seller or timekeeper."}, {"question": "How does goal-line technology confirm a goal in football?", "options": ["By asking a panel of supporters in the crowd to vote on whether they believe the ball crossed the line", "By replaying slow-motion footage exclusively to television pundits sitting in a studio, without informing the match officials at all", "By measuring the exact weight of the match ball before kick-off", "By using cameras or sensors around the goal to detect the ball crossing the line and signalling the referee"], "answer": 3, "explain": "Sensors or cameras around the goal detect the ball fully crossing the line and send a signal straight to the referee — there is no crowd vote, weigh-in, or studio-only replay."}, {"question": "What does Hawk-Eye (ball-tracking technology) show in tennis?", "options": ["Whether a serve or shot landed inside or outside the line when a player challenges the call", "The exact heart rate of each player during a five-set match", "Whether the crowd noise exceeded the stadium''s permitted decibel limit", "The manufacturer of the tennis balls being used in the tournament, printed on-screen for viewers at home"], "answer": 0, "explain": "Hawk-Eye tracks the ball''s path to show whether it landed in or out — it does not measure heart rate, crowd noise, or display the ball brand."}, {"question": "Why is a photo-finish camera used at the end of an athletics sprint?", "options": ["Because it allows the race organisers to sell far more advertising space around the finish line during a televised event", "Because human eyes cannot reliably separate sprinters who finish within hundredths of a second of one another", "Because it decides which athlete receives a post-race media interview first", "Because it replaces the need for a starting gun at the beginning of the race"], "answer": 1, "explain": "A photo-finish camera exists because the human eye cannot reliably split sprinters finishing hundredths of a second apart — it is about accuracy, not advertising, interviews or starts."}, {"question": "What do video review, goal-line technology and electronic timing all have in common?", "options": ["They all rely on the crowd''s reaction to decide whether a call was correct", "They all give officials extra, evidence-based information so decisions are more accurate and fair", "They all replace officials completely so that no human judgement is ever required at any point during a match or race", "They are all only used once every four years at major international events"], "answer": 1, "explain": "Each technology gives officials additional recorded or automatic evidence to make more accurate, fairer decisions — none of them hand the decision to the crowd or remove officials entirely."}]}, "fib": {"enabled": true, "questions": [{"text": "VAR stands for Video [Assistant] Referee, and reviews goals, penalties, red cards and mistaken identity."}, {"text": "The TMO advises the rugby union referee using video [replays] of tries and serious foul play."}, {"text": "Goal-line technology sends an instant [signal] to the referee''s watch once the ball fully crosses the line."}, {"text": "Hawk-Eye is a [ball]-tracking system used in tennis and cricket to show exactly where the ball went."}, {"text": "A photo-finish camera lets officials separate sprinters who finish within [hundredths] of a second of each other."}]}, "tf": {"enabled": true, "questions": [{"statement": "VAR reviews replay footage, but the final decision in football is still made by the on-field referee.", "answer": true, "explain": "VAR advises using recorded footage — the referee watches the review and makes the final call, so the human decision-maker is not removed."}, {"statement": "The TMO in rugby union is a player on the pitch who reviews decisions during a break in play.", "answer": false, "explain": "The TMO is an off-field official, not a player — they watch video feeds and advise the referee on tries and serious foul play."}, {"statement": "Goal-line technology can confirm a goal even when the ball crosses the line too fast for officials to see clearly.", "answer": true, "explain": "That is exactly why it exists — cameras and sensors detect the crossing far faster and more reliably than the human eye can from pitch-side."}, {"statement": "Hawk-Eye ball-tracking is the technology football uses to confirm whether a goal has been scored.", "answer": false, "explain": "Football uses goal-line technology for that job. Hawk-Eye ball-tracking is used in sports like tennis and cricket to show where a ball landed or was heading."}, {"statement": "Electronic timing in athletics removes human reaction-time error from the recorded result.", "answer": true, "explain": "Because the system starts and stops automatically, it takes the timekeeper''s own reaction speed out of the recorded time completely."}, {"statement": "A photo-finish camera is needed because human eyes can reliably separate two sprinters who finish a hundredth of a second apart.", "answer": false, "explain": "The opposite is true — human eyes cannot reliably separate finishes that close, which is precisely why the camera is needed."}]}, "misc": {"enabled": true, "items": [{"myth": "VAR takes the decision away from the referee completely — the computer decides.", "truth": "VAR only reviews and advises. In football, the on-field referee still watches the review footage and makes the final decision — the technology provides extra evidence, it does not decide the outcome on its own.", "check": {"question": "Who makes the final decision after a VAR review in football?", "options": ["The on-field referee, using the additional evidence from the replay", "A computer program that calculates the outcome automatically without any human input at all", "The two team captains, who vote together on the correct outcome", "The television broadcaster''s commentary team covering the match"], "answer": 0, "explain": "The referee reviews the footage and still makes the call — VAR supplies evidence, it does not replace human judgement, a vote, or the commentary team."}}, {"myth": "Goal-line technology and the TMO are basically the same system, just used in different sports.", "truth": "They are different systems doing different jobs. Goal-line technology is specific to football and only checks whether the ball fully crossed the line. The TMO is a rugby union official who reviews general video replay of tries and foul play — not a single shared piece of equipment.", "check": {"question": "What is the key difference between goal-line technology and the TMO?", "options": ["Goal-line technology is a football system checking the ball crossing the line; the TMO is a rugby union official reviewing footage", "There is no real difference at all — they are exactly the same system used in every single sport", "Goal-line technology is used only in cricket to time each ball that is bowled, while the TMO is a type of stopwatch used only in swimming", "The TMO is a type of camera, while goal-line technology is a type of human official standing pitch-side"], "answer": 0, "explain": "Goal-line technology is a football-specific sensor system for one narrow job (the line crossing); the TMO is a rugby union person reviewing broader video evidence — not interchangeable, and not the reverse of what the other options claim."}}, {"myth": "All of this technology is only there to slow the game down and annoy players and fans.", "truth": "That criticism does exist, but the core purpose of video review, goal-line and timing technology is to increase the accuracy of decisions and support fair play — giving officials extra evidence so the correct outcome is more likely to be given. Its wider effect on the flow of the game is a separate debate.", "check": {"question": "What is the core purpose of officiating technology like VAR, goal-line technology and electronic timing?", "options": ["To increase the accuracy of decisions and support fair play by giving officials extra evidence", "To make the sport last as long as possible so that broadcasters can sell more advertising space", "To remove all officials from professional sport within the next few years", "To give spectators something new to complain about during a match"], "answer": 0, "explain": "The purpose taught here is accuracy and fairness — extra advertising time, removing officials and giving fans something to complain about are not why this technology exists."}}]}, "tips": {"enabled": true, "items": [{"title": "Command words for this topic — what each one wants", "html": "<p>Officiating-technology questions test recall and application. Match your answer length to the command word:</p>\n<ul>\n<li><strong>State / Identify</strong> — just name the technology. \"State one technology that helps officials [1]\" = one name, nothing more.</li>\n<li><strong>Explain</strong> — say what the technology does, <em>then</em> use <em>because</em> to link it to accuracy or fairness. Name plus reason, not name alone.</li>\n<li><strong>Discuss / Evaluate</strong> (8 marks) — apply the technology to the scenario, weigh a benefit against a limitation (cost, or that a human still interprets the footage), then give a judgement.</li>\n</ul>\n<p><strong>Read the mark tariff:</strong> [1] wants one point; [2] often wants a technology plus its sport, or two named technologies; [4] in Section B wants each technology linked to the scenario.</p>", "check": {"question": "A question says: ''State two technologies used to help officials make accurate decisions [2]''. What is the safest answer?", "options": ["A long paragraph explaining one piece of technology in great detail", "Two named technologies, one for each mark", "Six different named technologies, even though only two marks are on offer", "One technology explained fully, with no second one given at all"], "answer": 1, "explain": "''State'' + [2] = two names, one mark each. A long explanation of one, six names, or only one name each miss the tariff."}}, {"title": "The golden rule: name the technology AND link it to accuracy or fairness", "html": "<p>The most common way to lose marks here is stopping at the name. Build every answer as <strong>technology → what it does → why that improves accuracy or fairness</strong>:</p>\n<ul>\n<li><strong>❌ 0–1 marks:</strong> \"VAR.\"</li>\n<li><strong>✅ full marks:</strong> \"VAR lets officials review footage of an incident, so a clear mistake made at full speed can be corrected before a goal is given.\"</li>\n</ul>\n<p>In <strong>Section B</strong> you get a scenario (a named match, league or event). Marks come from linking your technology to the <em>specific</em> problem in that scenario — not a general example.</p>", "check": {"question": "In a Section B scenario about a specific match or event, your example of technology should…", "options": ["ignore the scenario completely and describe your favourite team instead", "list as many different technologies as you can recall, regardless of the scenario", "link to the specific detail given in the scenario you have been given", "repeat the question word for word without adding any new information"], "answer": 2, "explain": "Section B is applied — the marks are for using the detail in front of you, not for ignoring it, listing everything you know, or restating the question."}}, {"title": "Where this topic appears in the exam + sentence starters", "html": "<p><strong>Where it shows up:</strong> quick recall of named technologies in <strong>Section A</strong>; an applied scenario in <strong>Section B</strong> asking how a technology would help officials in a specific situation; and a balanced <strong>Section C</strong> discussion of how far this technology actually delivers fairer, more accurate officiating.</p>\n<p><strong>Sentence starters for a longer answer:</strong></p>\n<ul>\n<li>\"One piece of technology that could help here is… because…\"</li>\n<li>\"This would improve accuracy by… so the official could…\"</li>\n<li>\"However, the extent to which this guarantees a fair decision depends on…\"</li>\n</ul>", "check": {"question": "Why is ''however, the extent to which this guarantees fairness depends on…'' a useful sentence starter in an 8-mark answer?", "options": ["It fills space without needing any real content behind it", "It signals that you are about to weigh up a limitation before giving a judgement", "It means you never need to reach an overall judgement at the end", "It completely replaces the need to mention any named piece of technology or sport at all in your answer"], "answer": 1, "explain": "The phrase signals a shift into evaluation — weighing a limitation before the final judgement — which is exactly what Section C rewards, not empty filler or an excuse to skip named technology."}}]}, "exam": {"enabled": true, "questions": [{"question": "Identify <strong>one</strong> piece of technology that helps officials make accurate decisions, and name a sport in which it is used.", "marks": 2, "hint": "Pick a technology you know well and match it to a sport that actually uses it (e.g. VAR/goal-line technology → football; TMO → rugby union; DRS/ball-tracking → cricket; Hawk-Eye → tennis; photo-finish/electronic timing → athletics or swimming).", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 2 marks (AO1)</h5>\n<p><strong>1 mark for naming a valid technology used to help officials. A further 1 mark ONLY if the sport named actually uses that technology. Accept any correct pairing, including:</strong></p>\n<ul>\n<li>VAR or goal-line technology → football</li>\n<li>TMO → rugby union</li>\n<li>DRS or ball-tracking → cricket</li>\n<li>Hawk-Eye / ball-tracking → tennis</li>\n<li>Photo-finish camera or electronic timing → athletics or swimming</li>\n</ul>\n<p>A correct technology paired with a sport that does not use it earns 1 mark only.</p>\n</div>"}, {"question": "Which of these best describes what goal-line technology does in football?", "marks": 1, "hint": "Think about the one specific job goal-line technology does — and only in football.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: A — confirms whether the whole ball has crossed the goal line, using cameras or sensors around the goal.</strong></p>\n<ul>\n<li>This is goal-line technology''s one specific job in football.</li>\n<li>The other options describe VAR (penalties/mistaken identity), the TMO (rugby union) and DRS (cricket) — different systems, different sports.</li>\n</ul>\n</div>"}, {"question": "Explain how introducing goal-line technology and a video review system could help Cranmoor''s officials make more accurate decisions in future cup finals.", "marks": 4, "hint": "Take each technology in turn: say what it does, then link it to the exact problem in the scenario (players blocking the referee''s view of the goal line).", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 4 marks (AO2: application)</h5>\n<p><strong>Up to 2 marks per technology: 1 for what it does, 1 for linking it to the scenario. Answers may include:</strong></p>\n<ul>\n<li><strong>Goal-line technology</strong> — uses cameras/sensors around the goal to confirm the whole ball crossed the line, signalling the referee instantly. This would help because it does not rely on eyesight, so it would still give the correct decision even when players blocked the referee''s view during the scramble.</li>\n<li><strong>Video review system</strong> — lets an official check recorded replay footage of an incident again, often from more than one angle. This would help because the goalmouth incident could be reviewed after the scramble, correcting a decision the referee missed live.</li>\n</ul>\n<p>Accept any other reasonable, applied answer. A technology described with no link to the scenario earns 1 of the 2 marks for that technology.</p>\n</div>"}, {"question": "Discuss how far introducing goal-line technology and video review would actually make officiating at Cranmoor''s cup finals fairer and more accurate.", "marks": 8, "hint": "Apply both technologies to the scenario, weigh up a genuine limitation (cost for a small league, or that a review still needs human interpretation), then give a supported overall judgement.", "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 8 marks (level-of-response). Read the band you fit, then pick a mark.</h5>\n<ul>\n<li><strong>Band 3 (thorough), 6–8:</strong> a balanced, well-applied discussion of both technologies, showing clearly how they would improve accuracy/fairness at Cranmoor AND weighing a genuine limitation (cost, sustainability for a small league, technology still needing human interpretation), ending in a justified judgement.</li>\n<li><strong>Band 2 (reasonable), 3–5:</strong> sound understanding applied to the scenario with some analysis, but the discussion may be one-sided or the judgement unsupported.</li>\n<li><strong>Band 1 (basic), 1–2:</strong> names the technologies and/or a general benefit with little application to Cranmoor and no real evaluation; largely a list.</li>\n<li><strong>0 marks:</strong> nothing creditworthy.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Indicative content (indicative, not a checklist — reward valid alternatives)</h5>\n<ul>\n<li><strong>Goal-line technology:</strong> removes the exact problem seen last season (players blocking the referee''s view), giving an instant, evidence-based answer rather than relying on eyesight.</li>\n<li><strong>Video review:</strong> allows any other contested goalmouth incident to be checked from multiple angles after the event, correcting mistakes made at full speed.</li>\n<li><strong>Evaluation:</strong> a small Sunday league may struggle to afford or maintain this equipment every season; a video review still depends on an official correctly interpreting what the footage shows, so it cannot guarantee a perfect decision every single time; the benefit may be greatest specifically for cup finals, where a wrong decision matters most.</li>\n<li><strong>Judgement:</strong> the technology would meaningfully reduce the kind of error seen last season, but how much fairer Cranmoor''s officiating becomes depends on whether the league can sustain the cost and whether officials use the review evidence correctly.</li>\n</ul>\n</div>"}]}}'::jsonb)
